# Native park-state parsing resolves c.59 low16 through the c.46 object slot.
# The c.46 low32 values below are therefore derived from the exact canonical
# product ids in the client gamedata, whose identifier is CRC32(product id).
LIMITED_PRODUCT_HASHES_BY_PARK_KEY = {
    park_key: {
        product_id: zlib.crc32(product_id.encode("utf-8")) & 0xFFFFFFFF
        for product_id in rotation
    }
    for park_key, rotation in LIMITED_ROTATIONS_BY_PARK_KEY.items()
}
LIMITED_PRODUCTS_BY_HASH_AND_PARK_KEY = {
    park_key: {
        product_hash: product_id
        for product_id, product_hash in product_hashes.items()
    }
    for park_key, product_hashes in LIMITED_PRODUCT_HASHES_BY_PARK_KEY.items()
}
