LOG_MESSAGE_MAX_CHARS = 16384


def now_text():
    return datetime.datetime.now().strftime("%H:%M:%S.%f")[:-3]


def bounded_log_message(message, max_chars=LOG_MESSAGE_MAX_CHARS):
    """Replace oversized diagnostics with non-sensitive correlation metadata."""
    text = str(message)
    if max_chars is None or max_chars <= 0 or len(text) <= max_chars:
        return text
    tag_match = re.match(r"^\[([A-Za-z0-9_-]{1,64})\]", text)
    tag = tag_match.group(1) if tag_match else "untagged"
    payload = text.encode("utf-8", "replace")
    summary = (
        f"[LOG-BOUNDED] tag={tag} chars={len(text)} bytes={len(payload)} "
        f"sha256={hashlib.sha256(payload).hexdigest()[:16]} "
        "detail=use --debug-packet-payloads"
    )
    return summary[:max_chars]


class Logger:
    def __init__(self, quiet=False, max_message_chars=LOG_MESSAGE_MAX_CHARS):
        os.makedirs(LOG_DIR, exist_ok=True)
        stamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        self.path = os.path.join(LOG_DIR, f"jpb_{SERVER_VERSION}_{stamp}.log")
        self.quiet = quiet
        self.max_message_chars = max_message_chars
        self.lock = threading.Lock()
        self.file = open(self.path, "a", encoding="utf-8")

    def write(self, msg):
        line = f"[{now_text()}] {bounded_log_message(msg, self.max_message_chars)}"
        with self.lock:
            self.file.write(line + "\n")
            self.file.flush()
            if not self.quiet:
                try:
                    print(line, flush=True)
                except OSError:
                    pass

    def close(self):
        with self.lock:
            self.file.close()


def start_logcat_capture(args, log):
    if not args.adb_logcat:
        return None

    markers = [item.strip().lower() for item in args.logcat_filter.split(",") if item.strip()]
    if not markers:
        markers = list(DEFAULT_LOGCAT_MARKERS)
    log(f"[LOGCAT] active markers={markers!r}")

    adb_path = args.adb_path
    adb_prefix = [adb_path]
    if getattr(args, "adb_serial", ""):
        adb_prefix.extend(["-s", args.adb_serial])
    if args.clear_logcat:
        try:
            subprocess.run([*adb_prefix, "logcat", "-c"], stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL, timeout=5)
            log("[LOGCAT] cleared old Android log buffer")
        except Exception as exc:
            log(f"[LOGCAT] could not clear old Android log buffer: {exc}")

    try:
        log(f"[LOGCAT] starting capture: {' '.join(adb_prefix)} logcat -v time")
        proc = subprocess.Popen(
            [*adb_prefix, "logcat", "-v", "time"],
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            text=True,
            encoding="utf-8",
            errors="replace",
        )
    except Exception as exc:
        log(f"[LOGCAT] failed to start adb logcat: {exc}")
        return None

    def worker():
        crash_passthrough = 0
        try:
            for line in proc.stdout:
                stripped = line.rstrip()
                lower = stripped.lower()
                starts_crash = (
                    "fatal signal" in lower
                    or " f/debug" in lower
                    or "backtrace:" in lower
                    or "tombstone" in lower
                )
                if starts_crash:
                    crash_passthrough = max(crash_passthrough, args.logcat_crash_lines)
                keep = crash_passthrough > 0 or any(marker in lower for marker in markers)
                if keep:
                    log(f"[LOGCAT] {stripped}")
                    handle_logcat_notification(stripped, log)
                if crash_passthrough > 0:
                    crash_passthrough -= 1
        except Exception as exc:
            log(f"[LOGCAT] capture stopped with error: {exc}")

    threading.Thread(target=worker, daemon=True).start()
    return proc


def adb_run(adb_path, adb_args, timeout=8, adb_serial=""):
    try:
        command = [adb_path]
        if adb_serial:
            command.extend(["-s", adb_serial])
        command.extend(adb_args)
        completed = subprocess.run(
            command,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=timeout,
        )
        return completed.returncode, completed.stdout.strip(), completed.stderr.strip()
    except Exception as exc:
        return 1, "", repr(exc)


def adb_first_device(adb_path, log, adb_serial=""):
    if adb_serial:
        return adb_serial
    code, stdout, stderr = adb_run(adb_path, ["devices"], timeout=8)
    if code != 0:
        log(f"[ADB-CLOCK] adb devices failed code={code} stderr={stderr!r}")
        return None
    for line in stdout.splitlines()[1:]:
        parts = line.split()
        if len(parts) >= 2 and parts[1] == "device":
            return parts[0]
    log("[ADB-CLOCK] no attached ADB device; skipping clock sync")
    return None


def adb_shell(adb_path, shell_args, timeout=8, adb_serial=""):
    return adb_run(adb_path, ["shell", *shell_args], timeout=timeout, adb_serial=adb_serial)


def adb_epoch_seconds(adb_path, adb_serial=""):
    code, stdout, stderr = adb_shell(adb_path, ["date", "+%s"], timeout=8, adb_serial=adb_serial)
    if code != 0:
        return None, f"date +%s failed code={code} stderr={stderr!r}"
    match = re.search(r"\d+", stdout or "")
    if not match:
        return None, f"date +%s returned unparsable stdout={stdout!r}"
    return int(match.group(0)), ""


