def detect_host_android_timezone(log):
    env_timezone = os.environ.get("TZ", "").strip()
    if env_timezone and ("/" in env_timezone or env_timezone.upper() == "UTC"):
        log(f"[ADB-CLOCK] auto timezone from TZ={env_timezone!r}")
        return env_timezone

    if os.name == "nt":
        try:
            completed = subprocess.run(
                ["tzutil", "/g"],
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                text=True,
                timeout=5,
            )
        except Exception as exc:
            log(f"[ADB-CLOCK] auto timezone failed to run tzutil: {exc!r}")
            return ""
        windows_timezone = completed.stdout.strip()
        mapped = WINDOWS_TO_ANDROID_TIMEZONE.get(windows_timezone, "")
        if mapped:
            log(
                f"[ADB-CLOCK] auto timezone mapped "
                f"windows={windows_timezone!r} android={mapped!r}"
            )
            return mapped
        log(
            f"[ADB-CLOCK] auto timezone unknown windows={windows_timezone!r} "
            f"stderr={completed.stderr.strip()!r}; preserving emulator timezone"
        )
        return ""

    log("[ADB-CLOCK] auto timezone unsupported on this OS; timezone sync skipped")
    return ""


def sync_adb_clock(args, log):
    if not getattr(args, "sync_adb_clock", False):
        return

    adb_path = args.adb_path
    adb_serial = getattr(args, "adb_serial", "") or ""
    device = adb_first_device(adb_path, log, adb_serial)
    if not device:
        return

    pc_epoch = int(time.time())
    before_epoch, error = adb_epoch_seconds(adb_path, adb_serial)
    if before_epoch is None:
        log(f"[ADB-CLOCK] could not read emulator clock: {error}")
        return

    drift = before_epoch - pc_epoch
    code, timezone, timezone_error = adb_shell(adb_path, ["getprop", "persist.sys.timezone"], timeout=8, adb_serial=adb_serial)
    timezone = timezone if code == 0 else ""
    log(
        f"[ADB-CLOCK] device={device} pc_epoch={pc_epoch} "
        f"emulator_epoch={before_epoch} drift_seconds={drift} "
        f"timezone={timezone!r}"
    )

    max_drift = max(0, _as_int(getattr(args, "adb_clock_max_drift_seconds", 5), 5))
    configured_timezone = str(getattr(args, "adb_timezone", "") or "").strip()
    if configured_timezone.lower() == "auto":
        target_timezone = detect_host_android_timezone(log)
    else:
        target_timezone = configured_timezone
    timezone_needs_sync = bool(target_timezone and timezone != target_timezone)
    if abs(drift) <= max_drift and not timezone_needs_sync:
        log(f"[ADB-CLOCK] clock within threshold={max_drift}s; no sync needed")
        return

    if target_timezone:
        for command in (
            ["su", "0", "setprop", "persist.sys.timezone", target_timezone],
            ["setprop", "persist.sys.timezone", target_timezone],
        ):
            code, stdout, stderr = adb_shell(adb_path, command, timeout=8, adb_serial=adb_serial)
            log(
                f"[ADB-CLOCK] timezone sync command={' '.join(command)!r} "
                f"code={code} stdout={stdout!r} stderr={stderr!r}"
            )
            if code == 0:
                break

    pc_epoch = int(time.time())
    utc_stamp = datetime.datetime.utcfromtimestamp(pc_epoch).strftime("%m%d%H%M%Y.%S")
    synced = False
    for command in (
        ["su", "0", "toybox", "date", "-u", f"@{pc_epoch}"],
        ["su", "0", "date", "-u", utc_stamp],
        ["toybox", "date", "-u", f"@{pc_epoch}"],
        ["date", "-u", utc_stamp],
    ):
        code, stdout, stderr = adb_shell(adb_path, command, timeout=8, adb_serial=adb_serial)
        log(
            f"[ADB-CLOCK] time sync command={' '.join(command)!r} "
            f"code={code} stdout={stdout!r} stderr={stderr!r}"
        )
        if code == 0:
            synced = True
            break

    after_epoch, error = adb_epoch_seconds(adb_path, adb_serial)
    if after_epoch is None:
        log(f"[ADB-CLOCK] could not re-read emulator clock after sync: {error}")
        return
    after_drift = after_epoch - int(time.time())
    log(
        f"[ADB-CLOCK] sync_result attempted=True command_success={synced} "
        f"after_epoch={after_epoch} after_drift_seconds={after_drift} "
        f"threshold={max_drift}s"
    )


def start_adb_clock_sync_loop(args, log):
    if not getattr(args, "sync_adb_clock", False):
        return None
    interval = max(0, _as_int(getattr(args, "adb_clock_sync_interval_seconds", 0), 0))
    if interval <= 0:
        return None

    def worker():
        log(f"[ADB-CLOCK] periodic sync enabled interval_seconds={interval}")
        while True:
            time.sleep(interval)
            try:
                sync_adb_clock(args, log)
            except Exception as exc:
                log(f"[ADB-CLOCK] periodic sync failed: {exc!r}")

    thread = threading.Thread(target=worker, daemon=True)
    thread.start()
    return thread


def e_null():
    return bytes([T_NULL])


def e_bool(value):
    return bytes([T_BOOL, 1 if value else 0])


def e_byte(value):
    return bytes([T_BYTE, value & 0xFF])


def e_short(value):
    return bytes([T_SHORT]) + struct.pack(">h", value)


def e_int(value):
    return bytes([T_INT]) + struct.pack(">i", value)


def e_long(value):
    return bytes([T_LONG]) + struct.pack(">q", value)


def e_float(value):
    return bytes([T_FLOAT]) + struct.pack(">f", value)


def e_double(value):
    return bytes([T_DOUBLE]) + struct.pack(">d", value)


def e_str(value):
    data = str(value).encode("utf-8")
    return bytes([T_UTF]) + struct.pack(">H", len(data)) + data


def e_arr(items):
    return bytes([T_SFS_ARRAY]) + struct.pack(">H", len(items)) + b"".join(items)


def e_obj(fields):
    body = b""
    for key, value in fields:
        key_data = str(key).encode("utf-8")
        body += struct.pack(">H", len(key_data)) + key_data + value
    return bytes([T_SFS_OBJECT]) + struct.pack(">H", len(fields)) + body


def e_value(value):
    if value is None:
        return e_null()
    if isinstance(value, bool):
        return e_bool(value)
    if isinstance(value, int):
        return e_long(value)
    if isinstance(value, float):
        return e_double(value)
    if isinstance(value, str):
        return e_str(value)
    if isinstance(value, list):
        return e_arr([e_value(item) for item in value])
    if isinstance(value, dict):
        return e_obj([(key, e_value(item)) for key, item in value.items()])
    return e_str(str(value))


def e_utf_arr(items):
    body = bytes([T_UTF_ARR]) + struct.pack(">H", len(items))
    for item in items:
        item_data = str(item).encode("utf-8")
        body += struct.pack(">H", len(item_data)) + item_data
    return body


def build_packet(ctrl, action, fields, compressed=False):
    inner = e_obj(fields)
    outer = e_obj([("c", e_byte(ctrl)), ("a", e_short(action)), ("p", inner)])
    if compressed:
        body = zlib.compress(outer, level=6)
        header = 0xA0
    else:
        body = outer
        header = 0x80
    if len(body) > 65535:
        return bytes([header | 0x08]) + struct.pack(">I", len(body)) + body
    return bytes([header]) + struct.pack(">H", len(body)) + body


class Reader:
    def __init__(self, data):
        self.data = data
        self.pos = 0

    def read(self, size):
        if size < 0:
            raise ValueError(f"negative read size {size} at {self.pos}")
        if self.pos + size > len(self.data):
            raise ValueError(f"short read at {self.pos}, need {size}, have {len(self.data) - self.pos}")
        chunk = self.data[self.pos:self.pos + size]
        self.pos += size
        return chunk

    def u8(self):
        return self.read(1)[0]

    def s8(self):
        return struct.unpack("b", self.read(1))[0]

    def u16(self):
        return struct.unpack(">H", self.read(2))[0]

    def s16(self):
        return struct.unpack(">h", self.read(2))[0]

    def s32(self):
        return struct.unpack(">i", self.read(4))[0]

    def s64(self):
        return struct.unpack(">q", self.read(8))[0]

    def f32(self):
        return struct.unpack(">f", self.read(4))[0]

    def f64(self):
        return struct.unpack(">d", self.read(8))[0]

    def value(self):
        type_id = self.u8()
        if type_id == T_NULL:
            return None
        if type_id == T_BOOL:
            return self.u8() != 0
        if type_id == T_BYTE:
            return self.s8()
        if type_id == T_SHORT:
            return self.s16()
        if type_id == T_INT:
            return self.s32()
        if type_id == T_LONG:
            return self.s64()
        if type_id == T_FLOAT:
            return self.f32()
        if type_id == T_DOUBLE:
            return self.f64()
        if type_id == T_UTF:
            size = self.u16()
            return self.read(size).decode("utf-8", "replace")
        if type_id == T_BOOL_ARR:
            size = self.u16()
            return [self.u8() != 0 for _ in range(size)]
        if type_id == T_BYTE_ARR:
            size = self.s32()
            return {"__bytes__": self.read(size).hex()}
        if type_id == T_SHORT_ARR:
            size = self.u16()
            return [self.s16() for _ in range(size)]
        if type_id == T_INT_ARR:
            size = self.u16()
            return [self.s32() for _ in range(size)]
        if type_id == T_LONG_ARR:
            size = self.u16()
            return [self.s64() for _ in range(size)]
        if type_id == T_FLOAT_ARR:
            size = self.u16()
            return [self.f32() for _ in range(size)]
        if type_id == T_DOUBLE_ARR:
            size = self.u16()
            return [self.f64() for _ in range(size)]
        if type_id == T_UTF_ARR:
            size = self.u16()
            result = []
            for _ in range(size):
                item_size = self.u16()
                result.append(self.read(item_size).decode("utf-8", "replace"))
            return result
        if type_id == T_SFS_ARRAY:
            return self.array()
        if type_id == T_SFS_OBJECT:
            return self.object()
        return f"<unknown_sfs_type_{type_id}>"

    def object(self):
        size = self.u16()
        result = {}
        for _ in range(size):
            key_size = self.u16()
            key = self.read(key_size).decode("utf-8", "replace")
            result[key] = self.value()
        return result

    def array(self):
        size = self.u16()
        return [self.value() for _ in range(size)]

    def sfs_object(self):
        type_id = self.u8()
        if type_id != T_SFS_OBJECT:
            raise ValueError(f"expected SFS_OBJECT type 18, found {type_id}")
        return self.object()


def decode_packet(body):
    outer = Reader(body).sfs_object()
    return outer.get("c", 0), outer.get("a", 0), outer.get("p", {}), outer


def short_hex(data, limit=512):
    text = data[:limit].hex(" ")
    if len(data) > limit:
        text += f" ... (+{len(data) - limit} bytes)"
    return text


def compact_json(value):
    return json.dumps(value, ensure_ascii=False, sort_keys=True, separators=(",", ":"))


LOG_SUMMARY_MAX_KEYS = 32
LOG_SUMMARY_MAX_KEY_CHARS = 80
SENSITIVE_LOG_KEY_NAMES = {
    "account",
    "accountid",
    "auth",
    "authorization",
    "cookie",
    "credential",
    "credentials",
    "deviceid",
    "deviceuid",
    "did",
    "du",
    "email",
    "h",
    "hash",
    "password",
    "passcode",
    "passwd",
    "pw",
    "requesthash",
    "saveid",
    "sc",
    "secret",
    "session",
    "sessionid",
    "setcookie",
    "tk",
    "token",
    "un",
    "user",
    "username",
}
SENSITIVE_LOG_KEY_HINTS = (
    "accountid",
    "accesstoken",
    "authorization",
    "credential",
    "deviceid",
    "deviceuid",
    "password",
    "refreshtoken",
    "requesthash",
    "saveid",
    "sessionid",
    "token",
    "username",
)


def _normalized_log_key(value):
    return re.sub(r"[^a-z0-9]", "", str(value or "").lower())


def is_sensitive_log_key(value):
    normalized = _normalized_log_key(value)
    return normalized in SENSITIVE_LOG_KEY_NAMES or any(
        hint in normalized for hint in SENSITIVE_LOG_KEY_HINTS
    )


def _log_value_bytes(value):
    if isinstance(value, bytes):
        return value
    if isinstance(value, bytearray):
        return bytes(value)
    if isinstance(value, memoryview):
        return value.tobytes()
    try:
        rendered = json.dumps(
            value,
            ensure_ascii=True,
            sort_keys=True,
            separators=(",", ":"),
            default=lambda item: f"<{type(item).__name__}>",
        )
    except Exception:
        rendered = f"<{type(value).__name__}>"
    return rendered.encode("utf-8", "replace")


def log_payload_fingerprint(value):
    payload = _log_value_bytes(value)
    return hashlib.sha256(payload).hexdigest()[:16], len(payload)


def redacted_log_descriptor(value):
    digest, payload_size = log_payload_fingerprint(value)
    return {
        "redacted": True,
        "type": type(value).__name__,
        "length": payload_size,
        "sha256": digest,
    }


def redact_log_payload(value, field_name=None, _active=None):
    """Return a non-mutating diagnostic copy with sensitive values removed."""
    if field_name is not None and is_sensitive_log_key(field_name):
        return redacted_log_descriptor(value)
    if isinstance(value, (bytes, bytearray, memoryview)):
        return redacted_log_descriptor(value)
    if _active is None:
        _active = set()
    if isinstance(value, dict):
        identity = id(value)
        if identity in _active:
            return {"cycle": True, "type": type(value).__name__}
        _active.add(identity)
        try:
            return {
                str(key): redact_log_payload(item, str(key), _active)
                for key, item in value.items()
            }
        finally:
            _active.remove(identity)
    if isinstance(value, (list, tuple)):
        identity = id(value)
        if identity in _active:
            return {"cycle": True, "type": type(value).__name__}
        _active.add(identity)
        try:
            return [redact_log_payload(item, None, _active) for item in value]
        finally:
            _active.remove(identity)
    if isinstance(value, set):
        return [redact_log_payload(item, None, _active) for item in sorted(value, key=str)]
    return value


def sensitive_log_reference(value):
    return compact_json(redacted_log_descriptor(value))


def sensitive_log_token(value):
    digest, payload_size = log_payload_fingerprint(value)
    return f"{type(value).__name__}:{payload_size}:{digest}"


def diagnostic_exception_summary(exc):
    summary = {"type": type(exc).__name__}
    for field in ("errno", "winerror"):
        value = getattr(exc, field, None)
        if isinstance(value, int):
            summary[field] = value
    digest, payload_size = log_payload_fingerprint(str(exc))
    summary["message_bytes"] = payload_size
    summary["message_sha256"] = digest
    return summary


def packet_bytes_log_summary(data):
    payload = bytes(data or b"")
    digest = hashlib.sha256(payload).hexdigest()[:16]
    return f"bytes={len(payload)} sha256={digest}"


def _bounded_log_text(value):
    text = str(value or "").replace("\r", "\\r").replace("\n", "\\n")
    if len(text) <= LOG_SUMMARY_MAX_KEY_CHARS:
        return text
    return text[:LOG_SUMMARY_MAX_KEY_CHARS] + "..."


def _bounded_log_keys(mapping):
    if not isinstance(mapping, dict):
        return [], 0
    keys = sorted(_bounded_log_text(key) for key in mapping)
    return keys[:LOG_SUMMARY_MAX_KEYS], max(0, len(keys) - LOG_SUMMARY_MAX_KEYS)


def trace_packet_params_summary(params):
    digest, payload_size = log_payload_fingerprint(params)
    summary = {
        "type": type(params).__name__,
        "payload_bytes": payload_size,
        "payload_sha256": digest,
    }
    if not isinstance(params, dict):
        return summary

    keys, omitted = _bounded_log_keys(params)
    summary.update({
        "key_count": len(params),
        "keys": keys,
        "keys_omitted": omitted,
    })
    command = params.get("c")
    if isinstance(command, str):
        summary["command"] = _bounded_log_text(command)

    payload = params.get("p")
    candidates = [params]
    if isinstance(payload, dict):
        candidates.append(payload)
        payload_keys, payload_omitted = _bounded_log_keys(payload)
        summary.update({
            "payload_key_count": len(payload),
            "payload_keys": payload_keys,
            "payload_keys_omitted": payload_omitted,
        })
    for candidate in candidates:
        sequence = candidate.get("s") if isinstance(candidate, dict) else None
        if isinstance(sequence, (int, float)) and not isinstance(sequence, bool):
            summary["sequence"] = sequence
            break

    requests = None
    for candidate in reversed(candidates):
        possible = candidate.get("c") if isinstance(candidate, dict) else None
        if isinstance(possible, list):
            requests = possible
            break
    if isinstance(requests, list):
        request_commands = []
        requested_keys = []
        for item in requests:
            if not isinstance(item, dict):
                continue
            item_command = item.get("co")
            if isinstance(item_command, str):
                request_commands.append(_bounded_log_text(item_command))
            item_key = item.get("k")
            if isinstance(item_key, str):
                requested_keys.append(_bounded_log_text(item_key))
        summary["request_count"] = len(requests)
        summary["request_commands"] = request_commands[:LOG_SUMMARY_MAX_KEYS]
        summary["request_commands_omitted"] = max(
            0, len(request_commands) - LOG_SUMMARY_MAX_KEYS
        )
        summary["requested_keys"] = requested_keys[:LOG_SUMMARY_MAX_KEYS]
        summary["requested_keys_omitted"] = max(
            0, len(requested_keys) - LOG_SUMMARY_MAX_KEYS
        )
    return summary


class SFSStream:
    def __init__(self, conn):
        self.conn = conn
        self.buffer = b""

    def fill(self, timeout):
        self.conn.settimeout(timeout)
        chunk = self.conn.recv(8192)
        if not chunk:
            raise ConnectionError(CLIENT_CLOSED)
        self.buffer += chunk

    def read_frame(self, timeout=30.0):
        while len(self.buffer) < 3:
            self.fill(timeout)

        header = self.buffer[0]
        is_big = bool(header & 0x08)
        is_compressed = bool(header & 0x20)

        if is_big:
            while len(self.buffer) < 5:
                self.fill(timeout)
            body_size = struct.unpack(">I", self.buffer[1:5])[0]
            header_size = 5
        else:
            body_size = struct.unpack(">H", self.buffer[1:3])[0]
            header_size = 3

        total_size = header_size + body_size
        while len(self.buffer) < total_size:
            self.fill(timeout)

        frame = self.buffer[:total_size]
        body = self.buffer[header_size:total_size]
        self.buffer = self.buffer[total_size:]

        if is_compressed:
            decoded_body = zlib.decompress(body)
        else:
            decoded_body = body

        return {
            "header": header,
            "body_size": body_size,
            "is_big": is_big,
            "is_compressed": is_compressed,
            "frame": frame,
            "body": decoded_body,
        }


