def make_login_profile_android_confirmed(username, zone, login_params):
    now_ms = current_network_time_milliseconds()
    returning_guest = bool(login_params.get("_server_returning_guest"))
    coppa_status = str(login_params.get("_server_coppa_status") or SERVER_COPPA_STATUS)
    account_id = int(login_params.get("_server_account_id") or 1)
    fields = [
        # FUN_003dd558: login success gate and salt storage.
        ("r", e_str("ok")),
        ("s", e_str("jpb-v38-local-salt")),
        # FUN_003dd344 unconditionally reads getString("as") after success.
        # The Android binary stores it at /COPPA/ageStatus and defines the
        # states n/o/u. `o` is the accepted overage state; `y` is invalid.
        ("as", e_str(coppa_status)),
        # AGNetworkTimeManager stores `t` directly as its epoch-ms base.
        ("t", e_long(now_ms)),
        ("ll", e_long(0)),
        ("a", e_long(account_id)),
        ("oo", e_long(online_options_cache_version(current_scheduler_game_time()))),
    ]
    # The handler tests presence, not the boolean value. Never include `np`
    # for a returning device or it will repeat guest onboarding and the DOB gate.
    if not returning_guest:
        fields.append(("np", e_bool(True)))
    return fields


