def make_handshake_response():
    return build_packet(0, 0, [
        ("tk", e_str("DummyToken")),
        ("ct", e_int(100000)),
        ("ms", e_int(10000000)),
    ])


def make_login_ok(username, zone, login_params, profile_name, shape="normal"):
    profile = LOGIN_PROFILES[profile_name]
    p_fields = profile(username, zone, login_params)
    fields = [
        ("rl", e_arr([])),
        ("id", e_int(1)),
        ("un", e_str(username)),
        ("pi", e_short(1)),
        ("rs", e_short(0)),
        ("zn", e_str(zone)),
    ]
    if shape == "normal":
        fields.append(("p", e_obj(p_fields)))
    elif shape == "missing_p":
        pass
    elif shape == "null_p":
        fields.append(("p", e_null()))
    elif shape == "string_p":
        fields.append(("p", e_str(compact_json(dict((k, "<value>") for k, _v in p_fields)))))
    else:
        raise ValueError(f"unknown login response shape: {shape}")
    return build_packet(0, 1, fields)


def make_jw_observed_login_ok(username, zone, login_params):
    return build_packet(1, 1, [
        ("c", e_str("c.lv")),
        ("p", e_obj(make_login_profile_jw_observed(username, zone, login_params))),
    ])


def make_login_error(message):
    return build_packet(0, 1, [
        ("ec", e_short(28)),
        ("ep", e_utf_arr([message])),
    ])


def make_ext_response(cmd, fields):
    return build_packet(1, 13, [
        ("c", e_str(cmd or "unknown")),
        ("p", e_obj(fields)),
    ])


class StoredSaveStem(str):
    """Internal marker for an already-encoded filename stem from SAVE_DIR."""


CANONICAL_SAVE_ID_RE = re.compile(r"^[a-z0-9_-]+$")
MAX_CANONICAL_SAVE_ID_LENGTH = 246  # leaves room for the longest '.json.tmp' suffix
WINDOWS_RESERVED_SAVE_IDS = {
    "con", "prn", "aux", "nul", "clock$",
    *(f"com{index}" for index in range(1, 10)),
    *(f"lpt{index}" for index in range(1, 10)),
}


def safe_save_name(value):
    if isinstance(value, StoredSaveStem):
        return str(value)
    raw_name = str(value or "")
    if not raw_name:
        return "guest"
    if (
        len(raw_name) <= MAX_CANONICAL_SAVE_ID_LENGTH
        and CANONICAL_SAVE_ID_RE.fullmatch(raw_name)
        and raw_name not in WINDOWS_RESERVED_SAVE_IDS
    ):
        # Preserve every active and registered device-id path exactly.
        return raw_name
    # The marker is outside the passthrough alphabet, making the encoded and
    # canonical namespaces disjoint.  A fixed digest also bounds Windows temp
    # and backup filename components.
    identity_digest = hashlib.sha256(raw_name.encode("utf-8", "surrogatepass")).hexdigest()
    return f"~{identity_digest}"


def guest_save_path(save_id):
    return os.path.join(SAVE_DIR, f"{safe_save_name(save_id)}.json")


def stable_guest_save_id(username, login_params):
    if isinstance(login_params, dict):
        for key in ("du", "DID", "did", "Device UID"):
            value = login_params.get(key)
            if value:
                return f"device-{value}"
    return username or "guest"


def latest_legacy_save_path(excluded_ids):
    if not os.path.isdir(SAVE_DIR):
        return None
    excluded_names = {safe_save_name(item) for item in excluded_ids if item}
    candidates = []
    for name in os.listdir(SAVE_DIR):
        if not name.endswith(".json"):
            continue
        stem = name[:-5]
        if stem in excluded_names or stem.startswith("device-"):
            continue
        path = os.path.join(SAVE_DIR, name)
        if os.path.isfile(path):
            candidates.append((os.path.getmtime(path), path))
    if not candidates:
        return None
    return max(candidates)[1]


def load_save_file(path, log):
    with SAVE_FILE_LOCK:
        try:
            with open(path, "r", encoding="utf-8") as handle:
                data = json.load(handle)
            if isinstance(data, dict):
                try:
                    meta = data.setdefault("__meta", {})
                    if isinstance(meta, dict):
                        meta["_loaded_file_mtime"] = int(os.path.getmtime(path))
                except OSError:
                    pass
            if repair_inflated_hardcash_meta(data, log):
                data.setdefault("__meta", {})["hardcash_meta_repaired"] = True
            ensure_timer_key_walls(data, log, label="load")
            scrub_server_metadata(data, log, label="load")
            clear_profile_tournament_score_timer_pollution(
                saved_content(data.get("prof")),
                log,
                "save load",
            )
            repair_completed_dna_rescue_state(
                data,
                now_ms=int(time.time() * 1000),
                log=log,
                label="save load",
            )
            log(
                f"[SAVE] loaded path_ref={sensitive_log_token(path)!r} "
                f"keys={sorted(data.keys())!r}"
            )
            return data
        except Exception as exc:
            log(
                f"[SAVE] could not load path_ref={sensitive_log_token(path)!r} "
                f"error={compact_json(diagnostic_exception_summary(exc))}"
            )
            return {}


def load_guest_save(save_id, log, fallback_save_ids=None):
    checked = []
    for candidate in [save_id] + list(fallback_save_ids or []):
        if not candidate or candidate in checked:
            continue
        checked.append(candidate)
        path = guest_save_path(candidate)
        if os.path.exists(path):
            if candidate != save_id:
                log(
                    f"[SAVE] using fallback save_ref={sensitive_log_token(candidate)!r}; "
                    f"next_write_ref={sensitive_log_token(save_id)!r}"
                )
            return load_save_file(path, log)

    return {}


def list_guest_save_ids():
    if not os.path.isdir(SAVE_DIR):
        return []
    result = []
    for name in os.listdir(SAVE_DIR):
        if not name.endswith(".json"):
            continue
        save_id = StoredSaveStem(name[:-5])
        path = guest_save_path(save_id)
        try:
            if os.path.getsize(path) > 16:
                result.append(save_id)
        except OSError:
            pass
    return sorted(set(result))


def owner_id_for_save_id(save_id):
    return 1_000_000 + (zlib.crc32(str(save_id).encode("utf-8")) % 900_000_000)


def save_id_for_owner_id(owner_id):
    for save_id in list_guest_save_ids():
        if owner_id_for_save_id(save_id) == owner_id:
            return save_id
    return ""


def save_has_visitable_park(save_id):
    try:
        data = load_guest_save(save_id, lambda _message: None)
    except Exception:
        return False
    return (
        isinstance(data, dict)
        and isinstance(data.get("park"), dict)
        and isinstance(data.get("road"), dict)
    )


def list_visitable_parks(current_save_id=""):
    parks = []
    for save_id in list_guest_save_ids():
        if not save_has_visitable_park(save_id):
            continue
        parks.append({
            "save_id": save_id,
            "owner_id": owner_id_for_save_id(save_id),
            "name": save_id[2:] if save_id.startswith("D-") else save_id,
        })
    current_key = str(current_save_id or "")
    parks.sort(key=lambda item: (item["save_id"] == current_key, item["save_id"]))
    return parks


def choose_visit_save_id(current_save_id, requested_owner_id, session_state, log):
    if not isinstance(session_state, dict):
        session_state = {}
    owner_map = session_state.setdefault("visit_owner_map", {})
    try:
        owner_id = int(requested_owner_id)
    except Exception:
        owner_id = 0
    if owner_id <= 1:
        return ""
    if owner_id in owner_map:
        return owner_map[owner_id]

    current_key = str(current_save_id or "")
    direct = save_id_for_owner_id(owner_id)
    if direct and direct != current_key:
        owner_map[owner_id] = direct
        return direct
    if direct == current_key:
        log(f"[VISIT] direct owner_id={owner_id} matched current save; choosing another park")

    parks = [item for item in list_visitable_parks(current_save_id) if item["save_id"] != current_key]
    if not parks:
        parks = list_visitable_parks(current_save_id)
    if not parks:
        return ""
    index = int(session_state.get("visit_rotation_index", 0)) % len(parks)
    session_state["visit_rotation_index"] = index + 1
    target = parks[index]["save_id"]
    owner_map[owner_id] = target
    log(
        f"[VISIT] mapped requested owner_id={owner_id} "
        f"to save_ref={sensitive_log_token(target)!r} "
        f"rotation_index={index}/{len(parks)}"
    )
    return target


def visit_identity_value(requested_owner_id, save_id, slot):
    seed = f"{requested_owner_id}:{save_id}:{slot}".encode("utf-8")
    high = 0x10000000 + (zlib.crc32(seed) & 0x0FFFFFFF)
    low = zlib.crc32(seed[::-1]) & 0xFFFFFFFF
    return (high << 32) | low


def _visit_identity_trace_fields(key, content):
    if not isinstance(content, dict):
        return {}
    if key in ("park", "aqpk", "arpk"):
        return {
            field: json.loads(json.dumps(content.get(field)))
            for field in ("13", "14", "49", "50", "51")
            if field in content
        }
    if key == "gen":
        return {
            field: json.loads(json.dumps(content.get(field)))
            for field in ("15", "16", "17")
            if field in content
        }
    if key == "prof":
        return {
            field: json.loads(json.dumps(content.get(field)))
            for field in ("10", "91")
            if field in content
        }
    return {}


def rewrite_visit_content_identity(key, content, requested_owner_id, visit_save_id, log=None):
    if not isinstance(content, dict):
        return content
    before = _visit_identity_trace_fields(key, content)
    if key == "gen":
        content["15"] = visit_identity_value(requested_owner_id, visit_save_id, "gen15")
        content["16"] = visit_identity_value(requested_owner_id, visit_save_id, "gen16")
        content["17"] = visit_identity_value(requested_owner_id, visit_save_id, "gen17")
    elif key == "prof":
        content["10"] = f"G-VISIT-{int(requested_owner_id)}"
        content["91"] = f"Random Park {int(requested_owner_id)}"
    if log and before:
        after = _visit_identity_trace_fields(key, content)
        if key == "prof":
            before = {
                field: redacted_log_descriptor(value)
                for field, value in before.items()
            }
            after = {
                field: redacted_log_descriptor(value)
                for field, value in after.items()
            }
        log(
            f"[VISIT] rewrite key={key!r} owner_id={requested_owner_id} "
            f"source_ref={sensitive_log_token(visit_save_id)!r} "
            f"before={compact_json(before)} after={compact_json(after)}"
        )
    return content


def visit_snapshot_session_state(session_state):
    snapshot_state = dict(session_state or {})
    snapshot_state["server_offline_elapsed_seconds"] = 0
    snapshot_state["timer_replay_source"] = "visit"
    return snapshot_state


def storage_read_visit_context(save_id, key, item, saved, session_state, log):
    requested_owner_id = _as_int(item.get("o", 1), 1)
    visit_save_id = ""
    if key in VISIT_READ_KEYS and requested_owner_id > 1:
        visit_save_id = choose_visit_save_id(save_id, requested_owner_id, session_state, log)
    read_saved = load_guest_save(visit_save_id, log) if visit_save_id else saved
    replay_elapsed_seconds = None
    if visit_save_id:
        session_state.setdefault("visit_started_monotonic", time.monotonic())
    elif key in PARK_OFFLINE_TIMER_KEYS:
        visit_started = session_state.pop("visit_started_monotonic", None)
        if isinstance(visit_started, (int, float)):
            # The native seven-day notification horizon is not a gameplay
            # timer cap. Family-specific advancement below already stops at
            # each timer's real terminal state.
            replay_elapsed_seconds = max(0, int(time.monotonic() - visit_started))
            if replay_elapsed_seconds > 0:
                log(
                    f"[VISIT] applying return-home elapsed={replay_elapsed_seconds}s "
                    f"key={key!r} to own park replay"
                )
        session_state.pop("visit_owner_map", None)
    return read_saved, visit_save_id, replay_elapsed_seconds, requested_owner_id


def replay_storage_content(
    key,
    content,
    session_state,
    log,
    visit_save_id="",
    replay_elapsed_seconds=None,
):
    if not isinstance(content, dict):
        return content, False
    if visit_save_id:
        if key not in VISIT_READ_KEYS:
            return content, False
        normalized = normalize_saved_content_for_replay(
            key,
            json.loads(json.dumps(content)),
            visit_snapshot_session_state(session_state),
            log,
        )
        return normalized, normalized != content
    if key not in OFFLINE_TIMER_REPLAY_KEYS:
        return content, False
    return apply_offline_replay_content(
        key,
        content,
        session_state,
        log,
        replay_elapsed_seconds=replay_elapsed_seconds,
    )


def make_random_park_friend_fields(command, sequence, current_save_id, mode, log):
    parks = list_visitable_parks(current_save_id)
    other_parks = [item for item in parks if item["save_id"] != current_save_id]
    visible = other_parks or parks
    if mode == "random_user_stub":
        owner_id = visible[0]["owner_id"] if visible else 0
        name = visible[0]["name"] if visible else ""
        info = compact_json({
            "id": owner_id,
            "un": name,
            "n": name,
            "sn": name,
            "lvl": 1,
            "xp": 0,
        }) if visible else ""
        if visible:
            log(
                f"[FRIENDS] random park stub owner_id={owner_id} "
                f"save_ref={sensitive_log_token(visible[0]['save_id'])!r}"
            )
            log(
                "[IDENTITY-TRACE] "
                + compact_json({
                    "label": "friend-random-user-stub",
                    "owner_id": owner_id,
                    "save_ref": sensitive_log_token(visible[0]["save_id"]),
                    "name_ref": sensitive_log_token(name),
                    "fields": ["co", "s", "id", "fi"],
                    "fi_fields": ["id", "un", "n", "sn", "lvl", "xp"],
                    "avatar_fields": [],
                    "picture_fields": [],
                })
            )
        else:
            log("[FRIENDS] random park stub unavailable")
        return [
            ("co", e_str(command)),
            ("s", e_long(sequence)),
            ("id", e_long(owner_id)),
            ("fi", e_str(info)),
        ]

    id_values = [e_long(item["owner_id"]) for item in visible]
    friend_values = []
    for item in visible:
        friend_values.append(e_obj([
            ("id", e_long(item["owner_id"])),
            ("un", e_str(item["name"])),
            ("n", e_str(item["name"])),
            ("sn", e_str(item["name"])),
            ("lvl", e_long(1)),
            ("xp", e_long(0)),
        ]))
    log(f"[FRIENDS] random parks available={len(visible)} total_saves={len(parks)}")
    log(
        "[IDENTITY-TRACE] "
        + compact_json({
            "label": "friend-random-list",
            "count": len(visible),
            "total_saves": len(parks),
            "fields": ["co", "s", "id", "fa"],
            "fa_fields": ["id", "un", "n", "sn", "lvl", "xp"],
            "entries": [
                {
                    "owner_id": item["owner_id"],
                    "save_ref": sensitive_log_token(item["save_id"]),
                    "name_ref": sensitive_log_token(item["name"]),
                }
                for item in visible[:10]
            ],
            "avatar_fields": [],
            "picture_fields": [],
        })
    )
    return [
        ("co", e_str(command)),
        ("s", e_long(sequence)),
        ("id", e_arr(id_values)),
        ("fa", e_arr(friend_values)),
    ]


def battle_random_bot_ids(requested_count):
    try:
        count_value = int(requested_count)
    except (TypeError, ValueError):
        count_value = BATTLE_RANDOM_BOT_MAX
    count_value = max(1, min(count_value, BATTLE_RANDOM_BOT_MAX))
    return [BATTLE_RANDOM_BOT_ID_BASE + index for index in range(1, count_value + 1)]


def battle_random_bot_account_tokens(bot_ids):
    return [f"{BATTLE_RANDOM_BOT_ACCOUNT_PREFIX}-{bot_id}" for bot_id in bot_ids]


def make_game_random_search_fields(request_params, log=None):
    payload = request_params.get("p") if isinstance(request_params, dict) else None
    if not isinstance(payload, dict):
        payload = request_params if isinstance(request_params, dict) else {}

    bot_ids = battle_random_bot_ids(payload.get("n"))
    bot_account_tokens = battle_random_bot_account_tokens(bot_ids)
    id_array = e_arr([e_long(bot_id) for bot_id in bot_ids])
    fa_array = e_arr([e_str(account_token) for account_token in bot_account_tokens])

    fields = []
    serial = payload.get("s")
    if isinstance(serial, int):
        fields.append(("s", e_long(serial)))
    hash_value = payload.get("h")
    if isinstance(hash_value, str):
        fields.append(("h", e_str(hash_value)))

    fields.extend([
        ("r", e_int(0)),
        ("ok", e_bool(True)),
        ("v", e_int(0)),
        ("c", e_int(0)),
        ("n", e_int(0)),
        ("vs", e_arr([])),
    ])
    fields.extend(empty_notification_fields())
    fields.extend([
        ("id", id_array),
        ("fa", fa_array),
        ("p", e_obj([
            ("id", id_array),
            ("fa", fa_array),
            ("v", e_int(0)),
            ("c", e_int(0)),
            ("n", e_int(0)),
            ("vs", e_arr([])),
            *empty_notification_fields(),
        ])),
    ])

    if log:
        log(
            f"[BATTLE] c.grs random opponents sent "
            f"requested={payload.get('n')!r} count={len(bot_ids)}"
        )
        log(
            "[BOT-TRACE] "
            + compact_json({
                "label": "c.grs-random-opponents",
                "request": {
                    "s": payload.get("s"),
                    "h": (
                        redacted_log_descriptor(payload.get("h"))
                        if "h" in payload
                        else None
                    ),
                    "n": payload.get("n"),
                    "keys": sorted(str(key) for key in payload.keys()),
                },
                "bot_ids": bot_ids,
                "bot_account_token_refs": [
                    sensitive_log_token(item) for item in bot_account_tokens
                ],
                "response_fields": trace_sfs_field_names(fields),
                "nested_p_fields": ["id", "fa", "v", "c", "n", "vs", "nt"],
                "name_fields_sent": [],
                "avatar_fields_sent": [],
                "picture_fields_sent": [],
                "note": "current stub only sends bot ids and account tokens; watch following client commands for identity/profile fetches",
            })
        )
    return fields


_ONLINE_OPTIONS_CACHE = None
_ONLINE_OPTIONS_HEADER = None
_ONLINE_OPTIONS_ORDER = None


def utc_now():
    return datetime.datetime.now(datetime.timezone.utc)


def current_network_time_milliseconds():
    """Return the epoch-millisecond unit consumed by AGNetworkTimeManager."""
    return int((time.time() + int(_SCHEDULER_CLOCK_OFFSET_SECONDS)) * 1000)


def scheduler_local_timezone():
    return datetime.datetime.now().astimezone().tzinfo


def scheduler_local_now(now=None):
    now = now or utc_now()
    local_tz = scheduler_local_timezone()
    if now.tzinfo is None:
        return now.replace(tzinfo=local_tz)
    return now.astimezone(local_tz)


def game_time_seconds_from_saved(saved, fallback=None):
    fallback = int(fallback if fallback is not None else time.time())
    if not isinstance(saved, dict):
        return fallback
    gen = saved.get("gen")
    if not isinstance(gen, dict):
        return fallback
    content = saved_content(gen)
    game_time = content_int(content, 1, 0)
    game_time_ms = _client_epoch_milliseconds(game_time)
    if game_time_ms is not None:
        return game_time_ms // 1000
    legacy_fallback = content_int(content, 64, 0)
    return int(legacy_fallback) if _plausible_epoch_seconds(legacy_fallback) else fallback


def current_scheduler_game_time(fallback=None):
    wall_time = int(fallback if fallback is not None else time.time())
    return wall_time + int(_SCHEDULER_CLOCK_OFFSET_SECONDS)


def client_scheduler_lookahead_details(timestamp, now_seconds=None):
    timestamp = _as_int(timestamp, 0)
    if timestamp <= 0:
        return None
    if now_seconds is None:
        now_seconds = current_scheduler_game_time()
    now_seconds = int(now_seconds)
    drift_milliseconds = timestamp - now_seconds * 1000
    if (
        abs(drift_milliseconds - CLIENT_SCHEDULER_LOOKAHEAD_MILLISECONDS)
        <= CLIENT_SCHEDULER_LOOKAHEAD_TOLERANCE_MILLISECONDS
    ):
        return {
            "semantics": "client_lookahead_24h_ms",
            "units": "epoch_milliseconds",
            "drift_milliseconds": drift_milliseconds,
        }
    legacy_drift_seconds = timestamp - now_seconds
    if (
        abs(legacy_drift_seconds - CLIENT_SCHEDULER_LEGACY_LOOKAHEAD_SECONDS)
        <= CLIENT_SCHEDULER_LOOKAHEAD_TOLERANCE_SECONDS
    ):
        return {
            "semantics": "client_lookahead_legacy_1000d",
            "units": "legacy_seconds_as_milliseconds",
            "drift_seconds": legacy_drift_seconds,
        }
    return None


def is_client_scheduler_lookahead_tt(timestamp, now_seconds=None):
    return client_scheduler_lookahead_details(timestamp, now_seconds) is not None


def scheduler_game_time_seconds(session_state, saved=None, fallback=None):
    """Return authoritative server time; c.sg horizons are never clock input."""
    wall_time = int(fallback if fallback is not None else time.time())
    return current_scheduler_game_time(wall_time)


def remember_scheduler_game_time(session_state, item):
    if not isinstance(session_state, dict) or not isinstance(item, dict):
        return
    command = str(item.get("co", ""))
    # c.se.t is an event deadline, not a current-time sample.
    if command != "c.sg" or "tt" not in item:
        return
    incoming_tt = _as_int(item.get("tt"), 0)
    sequence = _as_int(item.get("s"), None)
    previous_sequence = _as_int(session_state.get("scheduler_tt_sequence"), None)
    if isinstance(sequence, int) and isinstance(previous_sequence, int):
        if sequence < previous_sequence:
            session_state["scheduler_tt_stale"] = incoming_tt
            return
        if sequence == previous_sequence:
            session_state["scheduler_tt_duplicate"] = incoming_tt
            return
    if isinstance(sequence, int):
        session_state["scheduler_tt_sequence"] = sequence
    if incoming_tt > 0:
        now_seconds = current_scheduler_game_time()
        lookahead = client_scheduler_lookahead_details(incoming_tt, now_seconds)
        if lookahead:
            session_state["scheduler_tt_lookahead"] = incoming_tt
            session_state["scheduler_tt_semantics"] = lookahead["semantics"]
            session_state["scheduler_tt_units"] = lookahead["units"]
            if "drift_milliseconds" in lookahead:
                session_state["scheduler_tt_drift_milliseconds"] = lookahead["drift_milliseconds"]
                session_state.pop("scheduler_tt_drift_seconds", None)
            else:
                session_state["scheduler_tt_drift_seconds"] = lookahead["drift_seconds"]
                session_state.pop("scheduler_tt_drift_milliseconds", None)
        else:
            session_state["scheduler_tt_rejected"] = incoming_tt
            session_state["scheduler_tt_semantics"] = "non_authoritative_unrecognized"


def scheduled_online_option_push_keys(cached_values):
    keys = list(ONLINE_OPTION_OVERRIDES)
    keys.extend(TOURNAMENT_ONLINE_OPTION_PUSH_KEYS)
    keys.extend(sorted(SCHEDULED_ONLINE_OPTION_KEYS))
    keys.extend(
        key for key in sorted(cached_values)
        if str(key).startswith("MARKET_LIMIT_")
    )
    seen = set()
    ordered = []
    for key in keys:
        if key not in seen:
            seen.add(key)
            ordered.append(key)
    return ordered


def queue_scheduled_online_options_push(session_state, saved, log, reason=""):
    game_time = scheduler_game_time_seconds(session_state, saved)
    last_game_time = session_state.get("schedule_push_game_time")
    if (
        session_state.get("schedule_options_pushed")
        and last_game_time == game_time
    ):
        return
    session_state.setdefault("pending_pushes", []).append(
        make_scheduled_online_options_push(
            log,
            game_time,
            sequence=0,
            saved=saved,
        )
    )
    session_state["schedule_push_game_time"] = game_time
    session_state["schedule_options_pushed"] = True
    schedule = compute_scheduled_online_options(game_time, saved=saved)
    log(
        f"[OPTIONS] queued scheduled online-options push reason={reason!r} "
        f"game_time={game_time} dna_active={schedule['dna_active']} "
        f"dna_dino={schedule['dna_dino']!r} dna_limit={schedule['dna_limit']} "
        f"ltd_active={schedule['ltd_active']} ltd_limit={schedule['ltd_limit']}"
    )
    log_tournament_timer_trace(
        log,
        "queued-online-options-push",
        saved_content(saved.get("prof")) if isinstance(saved, dict) else None,
        game_time=game_time,
        session_state=session_state,
        reason=reason,
    )


def sync_patched_onlineoptions_file(log):
    global _ONLINE_OPTIONS_CACHE
    body = build_onlineoptions_bytes(current_scheduler_game_time(), log)
    if not body:
        return
    backup = ONLINE_OPTIONS_FILE + ".orig"
    if not os.path.isfile(backup) and os.path.isfile(ONLINE_OPTIONS_FILE):
        shutil.copy2(ONLINE_OPTIONS_FILE, backup)
    with open(ONLINE_OPTIONS_FILE, "wb") as handle:
        handle.write(body)
    _ONLINE_OPTIONS_CACHE = None
    log(f"[OPTIONS] synced patched onlineoptions on disk bytes={len(body)}")


def scheduled_weekend_window(now, duration_days):
    if now.tzinfo is None:
        now = now.replace(tzinfo=ONLINE_EVENT_SCHEDULE_TZ)
    else:
        now = now.astimezone(ONLINE_EVENT_SCHEDULE_TZ)
    friday = now.date() - datetime.timedelta(days=(now.weekday() - 4) % 7)
    start = datetime.datetime.combine(
        friday,
        datetime.time(
            hour=ONLINE_EVENT_START_HOUR_UTC,
            tzinfo=ONLINE_EVENT_SCHEDULE_TZ,
        ),
    )
    if now < start:
        start -= datetime.timedelta(days=7)
    end = start + datetime.timedelta(days=duration_days)
    return (start, end) if start <= now < end else (None, None)


def dna_rescue_end(now):
    _start, end = scheduled_weekend_window(now, DNA_RESCUE_DURATION_DAYS)
    return end


def weekend_ltd_end(now):
    _start, end = scheduled_weekend_window(now, WEEKEND_LTD_DURATION_DAYS)
    return end


def _schedule_saved_content(saved, storage_key):
    if not isinstance(saved, dict):
        return None
    record = saved.get(storage_key)
    if not isinstance(record, dict):
        return None
    content = record.get("c", record)
    return content if isinstance(content, dict) else None


def _schedule_int(value, default=None):
    try:
        return int(value)
    except (TypeError, ValueError):
        return default


def _event_friday(day):
    return day - datetime.timedelta(days=(day.weekday() - 4) % 7)


def _ownership_event_friday(now_ms=None):
    now_ms = int(now_ms if now_ms is not None else time.time() * 1000)
    day = datetime.datetime.fromtimestamp(
        now_ms / 1000,
        tz=ONLINE_EVENT_SCHEDULE_TZ,
    ).date()
    return _event_friday(day)


def _parse_ownership_date(value):
    if isinstance(value, datetime.datetime):
        return value.date()
    if isinstance(value, datetime.date):
        return value
    try:
        return datetime.date.fromisoformat(str(value))
    except (TypeError, ValueError):
        return None


def _creature_ownership_ledger(saved):
    if not isinstance(saved, dict):
        return {}
    meta = saved.get("__meta")
    if not isinstance(meta, dict):
        return {}
    root = meta.get(META_CREATURE_ROTATION_OWNERSHIP_KEY)
    return root if isinstance(root, dict) else {}


def _creature_ownership_entries(saved, category, park_key=None):
    root = _creature_ownership_ledger(saved)
    entries = root.get(category)
    if category == "limited":
        entries = entries.get(park_key) if isinstance(entries, dict) else None
    return dict(entries) if isinstance(entries, dict) else {}


def _ledger_entry_counts_as_owned(acquired_value, event_friday):
    acquired_friday = _parse_ownership_date(acquired_value)
    # The only temporary exception is an acquisition made in this exact event
    # week: keep that week's offer pinned, then exclude it from the next Friday.
    # A malformed server-ledger value fails closed as permanently owned.
    return acquired_friday is None or acquired_friday != event_friday


def _ledger_entry_was_acquired_this_event_week(acquired_value, event_friday):
    return _parse_ownership_date(acquired_value) == event_friday


def _dna_rescue_bitmap_owned_products(saved):
    content = _schedule_saved_content(saved, "prof")
    park_masks = content.get("132") if isinstance(content, dict) else None
    if not isinstance(park_masks, (list, tuple)):
        return set()
    owned = set()
    for product_id, (park_type, rescue_id) in DNA_RESCUE_UNLOCK_BITS.items():
        if park_type >= len(park_masks):
            continue
        mask = _schedule_int(park_masks[park_type])
        if mask is not None and mask & (1 << rescue_id):
            owned.add(product_id)
    return owned


def saved_dna_rescue_owned_products(saved, day=None):
    day = day or datetime.datetime.now(tz=ONLINE_EVENT_SCHEDULE_TZ).date()
    event_friday = _event_friday(day)
    bitmap_owned = _dna_rescue_bitmap_owned_products(saved)
    ledger = _creature_ownership_entries(saved, "dna")
    owned = set()
    for product_id in DNA_RESCUE_UNLOCK_BITS:
        if product_id in ledger:
            if _ledger_entry_counts_as_owned(ledger[product_id], event_friday):
                owned.add(product_id)
            continue
        if product_id in bitmap_owned:
            owned.add(product_id)
    return owned


def limited_product_states(saved, park_key):
    """Return client-proven limited product rows without mutating the save."""
    content = _schedule_saved_content(saved, park_key)
    if not isinstance(content, dict):
        return {}
    objects = content.get("46")
    dino_values = content.get("58")
    dino_states = content.get("59")
    if not all(isinstance(values, (list, tuple)) for values in (objects, dino_values, dino_states)):
        return {}
    object_count = max(0, _schedule_int(content.get("45"), len(objects)))
    dino_count = max(0, _schedule_int(content.get("57"), len(dino_states)))
    object_limit = min(object_count, len(objects))
    row_limit = min(dino_count, len(dino_values), len(dino_states))
    products_by_hash = LIMITED_PRODUCTS_BY_HASH_AND_PARK_KEY.get(park_key, {})
    states = {}
    for row_index in range(row_limit):
        raw58 = _schedule_int(dino_values[row_index], 0) & 0xFFFFFFFFFFFFFFFF
        raw59 = _schedule_int(dino_states[row_index], 0) & 0xFFFFFFFFFFFFFFFF
        object_slot = raw59 & 0xFFFF
        if object_slot >= object_limit:
            continue
        object_value = _schedule_int(objects[object_slot])
        if object_value is None:
            continue
        product_id = products_by_hash.get(object_value & 0xFFFFFFFF)
        if not product_id:
            continue
        bare = raw58 == 0 and raw59 == object_slot
        state = states.setdefault(product_id, {
            "present": False,
            "initialized": False,
            "slots": [],
        })
        state["present"] = True
        state["initialized"] = state["initialized"] or not bare
        if object_slot not in state["slots"]:
            state["slots"].append(object_slot)
    return states


def saved_limited_owned_products(saved, park_key, day=None):
    day = day or datetime.datetime.now(tz=ONLINE_EVENT_SCHEDULE_TZ).date()
    event_friday = _event_friday(day)
    states = limited_product_states(saved, park_key)
    ledger = _creature_ownership_entries(saved, "limited", park_key)
    owned = set()
    for product_id in LIMITED_ROTATIONS_BY_PARK_KEY.get(park_key, ()):
        if product_id in ledger:
            if _ledger_entry_counts_as_owned(ledger[product_id], event_friday):
                owned.add(product_id)
            continue
        if states.get(product_id, {}).get("initialized"):
            owned.add(product_id)
    return owned


def remaining_creature_rotation(rotation, owned_products):
    owned_products = set(owned_products or ())
    return tuple(product_id for product_id in rotation if product_id not in owned_products)


def _rotation_week_index(day, anchor_date):
    event_friday = _event_friday(day)
    return (event_friday - anchor_date).days // 7


def rotation_creature_for_week(rotation, owned_products, week_index):
    """Scan the original weekly order so removed entries never reindex it."""
    owned_products = set(owned_products or ())
    if not rotation:
        return None
    for offset in range(len(rotation)):
        product_id = rotation[(week_index + offset) % len(rotation)]
        if product_id not in owned_products:
            return product_id
    return None


def dna_rescue_dino_for_date(day, saved=None):
    week_index = _rotation_week_index(day, DNA_RESCUE_ANCHOR_DATE)
    product_id = rotation_creature_for_week(
        DNA_RESCUE_ROTATION,
        saved_dna_rescue_owned_products(saved, day=day),
        week_index,
    )
    if not product_id:
        return None
    # Same-week acquisitions are deliberately omitted from the owned set above
    # so removing one creature cannot advance the rotation to next week's
    # candidate early. Once that pinned candidate has actually been acquired,
    # consume the current slot without advertising the completed rescue again.
    event_friday = _event_friday(day)
    ledger = _creature_ownership_entries(saved, "dna")
    if (
        product_id in ledger
        and _ledger_entry_was_acquired_this_event_week(
            ledger[product_id],
            event_friday,
        )
    ):
        return None
    return product_id


def _dna_rescue_descriptor_product(value):
    raw = _schedule_int(value)
    if raw is None:
        return None
    product_hash = ((raw & 0xFFFFFFFFFFFFFFFF) >> 32) & 0xFFFFFFFF
    return DNA_RESCUE_PRODUCTS_BY_HASH.get(product_hash)


def _dna_rescue_deadline_ms(value):
    """Normalize prof.134 rescue deadlines that may be seconds or milliseconds."""
    raw = _schedule_int(value, 0) or 0
    if raw <= 0:
        return 0
    if raw < 1_000_000_000_000:
        return raw * 1000
    return raw


def _profile_dna_rescue_completion_product(previous_entry, incoming_entry):
    """Return the one client-proven DNA product completed by a prof write."""
    previous = saved_content(previous_entry)
    incoming = saved_content(incoming_entry)
    if not isinstance(previous, dict) or not isinstance(incoming, dict):
        return None
    previous_masks = previous.get("132")
    incoming_masks = incoming.get("132")
    if not isinstance(previous_masks, (list, tuple)) or not isinstance(
        incoming_masks,
        (list, tuple),
    ):
        return None
    if _schedule_int(incoming.get("134")) != 0 or _schedule_int(incoming.get("135")) != 0:
        return None
    if _schedule_int(previous.get("134"), 0) <= 0:
        return None

    descriptor_product = _dna_rescue_descriptor_product(previous.get("135"))
    if not descriptor_product:
        return None
    newly_unlocked = []
    for product_id, (park_type, rescue_id) in DNA_RESCUE_UNLOCK_BITS.items():
        if park_type >= len(previous_masks) or park_type >= len(incoming_masks):
            continue
        previous_mask = _schedule_int(previous_masks[park_type], 0)
        incoming_mask = _schedule_int(incoming_masks[park_type], 0)
        bit = 1 << rescue_id
        if not previous_mask & bit and incoming_mask & bit:
            newly_unlocked.append(product_id)
    if newly_unlocked != [descriptor_product]:
        return None
    return descriptor_product


def _profile_dna_rescue_abandon_clear(previous_entry, incoming_entry):
    """True when the client abandons an incomplete rescue (zeros 134/135)."""
    previous = saved_content(previous_entry)
    incoming = saved_content(incoming_entry)
    if not isinstance(previous, dict) or not isinstance(incoming, dict):
        return False
    if _schedule_int(incoming.get("134"), 0) != 0 or _schedule_int(incoming.get("135"), 0) != 0:
        return False
    if not _dna_rescue_descriptor_product(previous.get("135")):
        return False
    if _schedule_int(previous.get("134"), 0) <= 0 and _schedule_int(previous.get("135"), 0) <= 0:
        return False
    # Completion unlocks the descriptor product in prof.132; abandon does not.
    if _profile_dna_rescue_completion_product(previous_entry, incoming_entry):
        return False
    return True


def composite_dna_rescue_completion_products(requests, saved):
    previous_entry = saved.get("prof") if isinstance(saved, dict) else None
    products = []
    for item in requests or ():
        if not isinstance(item, dict):
            continue
        if item.get("co") not in ("c.zw", "c.ow") or str(item.get("k", "")) != "prof":
            continue
        product_id = _profile_dna_rescue_completion_product(
            previous_entry,
            {"c": item.get("c")},
        )
        if product_id and product_id not in products:
            products.append(product_id)
    return tuple(products)


def record_dna_rescue_completion_ownership(
    saved,
    product_id,
    now_ms=None,
    log=None,
    label="completion",
):
    if not isinstance(saved, dict) or product_id not in DNA_RESCUE_UNLOCK_BITS:
        return 0
    meta = saved.setdefault("__meta", {})
    if not isinstance(meta, dict):
        meta = {}
        saved["__meta"] = meta
    old_root = meta.get(META_CREATURE_ROTATION_OWNERSHIP_KEY)
    root = copy.deepcopy(old_root) if isinstance(old_root, dict) else {}
    dna = root.get("dna")
    dna = copy.deepcopy(dna) if isinstance(dna, dict) else {}
    before = json.dumps(dna, ensure_ascii=True, sort_keys=True)
    event_friday = _ownership_event_friday(now_ms)
    _merge_ownership_entry(dna, product_id, event_friday)
    root["version"] = CREATURE_ROTATION_OWNERSHIP_VERSION
    root["dna"] = dict(sorted(dna.items()))
    meta[META_CREATURE_ROTATION_OWNERSHIP_KEY] = root
    changed = int(before != json.dumps(dna, ensure_ascii=True, sort_keys=True))
    if changed and log:
        log(
            "[DNA-RESCUE] recorded completed rescue ownership "
            f"product={product_id!r} event_friday={event_friday.isoformat()} "
            f"label={label!r}"
        )
    return changed


def repair_completed_dna_rescue_state(saved, now_ms=None, log=None, label="repair"):
    """Clear completed or expired incomplete DNA rescue state (prof.134/135)."""
    if not isinstance(saved, dict):
        return 0
    profile = saved_content(saved.get("prof"))
    if not isinstance(profile, dict):
        return 0
    descriptor_product = _dna_rescue_descriptor_product(profile.get("135"))
    if not descriptor_product:
        return 0
    if _schedule_int(profile.get("134"), 0) == 0 and _schedule_int(profile.get("135"), 0) == 0:
        return 0
    now_ms = int(now_ms if now_ms is not None else time.time() * 1000)
    event_friday = _ownership_event_friday(now_ms)
    ledger = _creature_ownership_entries(saved, "dna")
    completed = (
        _ledger_entry_was_acquired_this_event_week(
            ledger.get(descriptor_product),
            event_friday,
        )
        and descriptor_product in _dna_rescue_bitmap_owned_products(saved)
    )
    deadline_ms = _dna_rescue_deadline_ms(profile.get("134"))
    expired_incomplete = (not completed) and deadline_ms > 0 and now_ms >= deadline_ms
    if not completed and not expired_incomplete:
        return 0
    previous_deadline = profile.get("134")
    previous_descriptor = profile.get("135")
    profile["134"] = 0
    profile["135"] = 0
    if log:
        if completed:
            log(
                "[DNA-RESCUE] cleared completed rescue state "
                f"product={descriptor_product!r} event_friday={event_friday.isoformat()} "
                f"deadline={previous_deadline!r}->0 descriptor={previous_descriptor!r}->0 "
                f"label={label!r}"
            )
        else:
            log(
                "[DNA-RESCUE] cleared expired incomplete rescue state "
                f"product={descriptor_product!r} event_friday={event_friday.isoformat()} "
                f"deadline={previous_deadline!r}->0 descriptor={previous_descriptor!r}->0 "
                f"now_ms={now_ms} deadline_ms={deadline_ms} label={label!r}"
            )
    return 2


def limited_offer_dino_for_date(
    day,
    rotation,
    saved=None,
    park_key=None,
):
    owned = saved_limited_owned_products(saved, park_key, day=day) if park_key else set()
    week_index = _rotation_week_index(day, LIMITED_OFFER_ANCHOR_DATE)
    return rotation_creature_for_week(rotation, owned, week_index)


def _merge_ownership_entry(entries, product_id, acquired_value):
    if not product_id or acquired_value in (None, ""):
        return
    acquired_text = (
        acquired_value.isoformat()
        if isinstance(acquired_value, (datetime.date, datetime.datetime))
        else str(acquired_value)
    )
    if product_id not in entries:
        entries[product_id] = acquired_text
        return
    previous_text = str(entries[product_id])
    previous_date = _parse_ownership_date(previous_text)
    acquired_date = _parse_ownership_date(acquired_text)
    if previous_date is None:
        return
    if acquired_date is not None and acquired_date < previous_date:
        entries[product_id] = acquired_text


def _valid_unseen_build_transaction_ids(requests, saved_before_writes, now_ms=None):
    request_items = list(requests or ())
    plan = composite_hardcash_transaction_plan(
        request_items,
        saved_before_writes,
        now_seconds=(int(now_ms) // 1000 if now_ms is not None else None),
    )
    accepted_indexes = plan.get("accepted_indexes", ())
    result = []
    for index, item in enumerate(request_items):
        if not isinstance(item, dict):
            continue
        if item.get("co") != "c.rt" or str(item.get("t", "")) != "BUILD":
            continue
        transaction_id = str(item.get("o", "")).strip()
        if (
            build_transaction_validation_reason(item)
            or index not in accepted_indexes
        ):
            continue
        if transaction_id not in result:
            result.append(transaction_id)
    return result


def limited_purchase_evidence_for_batch(
    requests,
    saved_before_writes,
    now_ms=None,
    log=None,
):
    """Freeze pure BUILD evidence before wallet transaction ids are recorded."""
    transaction_ids = _valid_unseen_build_transaction_ids(
        requests,
        saved_before_writes,
        now_ms=now_ms,
    )
    if not transaction_ids:
        return None
    evidence = {
        "build_transaction_ids": transaction_ids,
        "event_friday": _ownership_event_friday(now_ms).isoformat(),
        "preexisting_products": {
            park_key: sorted(limited_product_states(saved_before_writes, park_key))
            for park_key in LIMITED_ROTATIONS_BY_PARK_KEY
        },
    }
    if log:
        log(
            "[CREATURE-OWNERSHIP] captured BUILD evidence "
            f"transactions={transaction_ids!r} "
            f"preexisting={evidence['preexisting_products']!r}"
        )
    return evidence


def sync_creature_rotation_ownership(
    existing,
    candidate,
    limited_purchase_evidence=None,
    now_ms=None,
    existing_present=None,
    log=None,
):
    """Union server-owned acquisition evidence into the candidate save."""
    if not isinstance(candidate, dict):
        return 0
    existing = existing if isinstance(existing, dict) else {}
    existing_present = bool(existing) if existing_present is None else bool(existing_present)
    now_friday = _ownership_event_friday(now_ms)
    legacy_friday = now_friday - datetime.timedelta(days=7)
    limited = {park_key: {} for park_key in LIMITED_ROTATIONS_BY_PARK_KEY}
    dna = {}

    # Merge both append-only ledgers before inference. This is what preserves a
    # same-week acquisition date against stale sessions and legacy row scans.
    for source in (existing, candidate):
        source_root = _creature_ownership_ledger(source)
        source_limited = source_root.get("limited")
        if isinstance(source_limited, dict):
            for park_key, products in limited.items():
                source_products = source_limited.get(park_key)
                if not isinstance(source_products, dict):
                    continue
                allowed = set(LIMITED_ROTATIONS_BY_PARK_KEY[park_key])
                for product_id, acquired_value in source_products.items():
                    if product_id in allowed:
                        _merge_ownership_entry(products, product_id, acquired_value)
        source_dna = source_root.get("dna")
        if isinstance(source_dna, dict):
            for product_id, acquired_value in source_dna.items():
                if product_id in DNA_RESCUE_UNLOCK_BITS:
                    _merge_ownership_entry(dna, product_id, acquired_value)

    existing_states = {
        park_key: limited_product_states(existing, park_key)
        for park_key in LIMITED_ROTATIONS_BY_PARK_KEY
    }
    candidate_states = {
        park_key: limited_product_states(candidate, park_key)
        for park_key in LIMITED_ROTATIONS_BY_PARK_KEY
    }
    if existing_present:
        for park_key, states in existing_states.items():
            for product_id, state in states.items():
                if state.get("initialized") and product_id not in limited[park_key]:
                    _merge_ownership_entry(limited[park_key], product_id, legacy_friday)

    evidence = limited_purchase_evidence if isinstance(limited_purchase_evidence, dict) else {}
    transaction_ids = evidence.get("build_transaction_ids")
    preexisting = evidence.get("preexisting_products")
    if isinstance(transaction_ids, list) and len(transaction_ids) == 1 and isinstance(preexisting, dict):
        newly_present = []
        for park_key, states in candidate_states.items():
            prior_products = set(preexisting.get(park_key, ()))
            newly_present.extend(
                (park_key, product_id)
                for product_id, state in states.items()
                if state.get("present") and product_id not in prior_products
            )
        if len(newly_present) == 1:
            evidence_friday = _parse_ownership_date(evidence.get("event_friday")) or now_friday
            park_key, product_id = newly_present[0]
            _merge_ownership_entry(limited[park_key], product_id, evidence_friday)
            if log:
                log(
                    "[CREATURE-OWNERSHIP] correlated one BUILD with one new limited product "
                    f"park={park_key!r} product={product_id!r} "
                    f"event_friday={evidence_friday.isoformat()}"
                )
        elif log:
            log(
                "[CREATURE-OWNERSHIP] BUILD evidence left uncorrelated "
                f"new_limited_products={newly_present!r}"
            )
    elif transaction_ids and log:
        log(
            "[CREATURE-OWNERSHIP] BUILD evidence left uncorrelated "
            f"transaction_count={len(transaction_ids) if isinstance(transaction_ids, list) else 0}"
        )

    for park_key, states in candidate_states.items():
        previous_states = existing_states.get(park_key, {})
        for product_id, state in states.items():
            if not state.get("initialized") or product_id in limited[park_key]:
                continue
            previous_initialized = bool(previous_states.get(product_id, {}).get("initialized"))
            acquired_friday = (
                now_friday
                if existing_present and not previous_initialized
                else legacy_friday
            )
            _merge_ownership_entry(limited[park_key], product_id, acquired_friday)

    existing_dna = _dna_rescue_bitmap_owned_products(existing)
    candidate_dna = _dna_rescue_bitmap_owned_products(candidate)
    if existing_present:
        for product_id in existing_dna:
            if product_id not in dna:
                _merge_ownership_entry(dna, product_id, legacy_friday)
    for product_id in candidate_dna:
        if product_id in dna:
            continue
        acquired_friday = (
            now_friday
            if existing_present and product_id not in existing_dna
            else legacy_friday
        )
        _merge_ownership_entry(dna, product_id, acquired_friday)

    old_root = _creature_ownership_ledger(candidate)
    root = copy.deepcopy(old_root) if isinstance(old_root, dict) else {}
    root["version"] = CREATURE_ROTATION_OWNERSHIP_VERSION
    root["limited"] = {
        park_key: dict(sorted(products.items()))
        for park_key, products in limited.items()
        if products
    }
    root["dna"] = dict(sorted(dna.items()))
    if not root["limited"] and not root["dna"] and not old_root:
        return 0
    before = json.dumps(old_root, ensure_ascii=True, sort_keys=True)
    meta = candidate.setdefault("__meta", {})
    if not isinstance(meta, dict):
        meta = {}
        candidate["__meta"] = meta
    meta[META_CREATURE_ROTATION_OWNERSHIP_KEY] = root
    after = json.dumps(root, ensure_ascii=True, sort_keys=True)
    changed = int(before != after)
    if changed and log:
        limited_counts = {
            key: len(value)
            for key, value in root["limited"].items()
        }
        log(
            "[CREATURE-OWNERSHIP] synchronized append-only ledger "
            f"limited={limited_counts!r} "
            f"dna={len(root['dna'])}"
        )
    return changed


def online_options_cache_version(game_time=None):
    game_time = int(
        game_time if game_time is not None else current_scheduler_game_time()
    )
    anchor = datetime.datetime.combine(
        LIMITED_OFFER_ANCHOR_DATE,
        datetime.time(
            hour=ONLINE_EVENT_START_HOUR_UTC,
            tzinfo=ONLINE_EVENT_SCHEDULE_TZ,
        ),
    )
    week_index = (game_time - int(anchor.timestamp())) // (7 * 24 * 60 * 60)
    return (
        ONLINE_OPTIONS_CACHE_VERSION_REVISION
        * ONLINE_OPTIONS_CACHE_VERSION_REVISION_SCALE
        + week_index
    )


def compute_scheduled_online_options(game_time, now=None, saved=None):
    game_time = int(
        game_time if game_time is not None else current_scheduler_game_time()
    )
    if now is None:
        schedule_now = datetime.datetime.fromtimestamp(
            game_time,
            tz=ONLINE_EVENT_SCHEDULE_TZ,
        )
    elif now.tzinfo is None:
        schedule_now = now.replace(tzinfo=ONLINE_EVENT_SCHEDULE_TZ)
    else:
        schedule_now = now.astimezone(ONLINE_EVENT_SCHEDULE_TZ)
    current_time_ms = int(schedule_now.timestamp() * 1000)
    dna_end = dna_rescue_end(schedule_now)
    ltd_end = weekend_ltd_end(schedule_now)
    dna_dino = dna_rescue_dino_for_date(schedule_now.date(), saved=saved)
    surface_ltd_dino = limited_offer_dino_for_date(
        schedule_now.date(),
        SURFACE_LIMITED_ROTATION,
        saved=saved,
        park_key="park",
    )
    aquatic_ltd_dino = limited_offer_dino_for_date(
        schedule_now.date(),
        AQUATIC_LIMITED_ROTATION,
        saved=saved,
        park_key="aqpk",
    )
    arctic_ltd_dino = limited_offer_dino_for_date(
        schedule_now.date(),
        ARCTIC_LIMITED_ROTATION,
        saved=saved,
        park_key="arpk",
    )
    dna_active = dna_end is not None and dna_dino is not None
    ltd_active = ltd_end is not None and any((
        surface_ltd_dino,
        aquatic_ltd_dino,
        arctic_ltd_dino,
    ))
    dna_limit = (
        int(dna_end.timestamp()) * 1000
        if dna_active
        else max(0, current_time_ms - 1)
    )
    ltd_limit = (
        int(ltd_end.timestamp()) * 1000
        if ltd_active
        else max(0, current_time_ms - 1)
    )
    return {
        "dna_active": dna_active,
        "dna_dino": dna_dino or "",
        "dna_limit": dna_limit,
        "ltd_active": ltd_active,
        "ltd_limit": ltd_limit,
        "surface_ltd_dino": surface_ltd_dino or "",
        "aquatic_ltd_dino": aquatic_ltd_dino or "",
        "arctic_ltd_dino": arctic_ltd_dino or "",
    }


def tournament_time_hours_from_options(online_options=None):
    options = online_options if isinstance(online_options, dict) else {}
    raw_value = options.get("TOURNAMENT_TIME")
    if raw_value is None:
        raw_value = json.dumps(BATTLE_TOURNAMENT_TIME, separators=(",", ":"))
    if isinstance(raw_value, str):
        try:
            raw_value = json.loads(raw_value)
        except Exception:
            raw_value = BATTLE_TOURNAMENT_TIME
    if not isinstance(raw_value, dict):
        raw_value = BATTLE_TOURNAMENT_TIME

    hours = []
    for value in raw_value.values():
        hour = _as_int(value, None)
        if hour is None or hour < 0 or hour > 23:
            continue
        hours.append(hour)
    if not hours:
        hours = list(BATTLE_TOURNAMENT_SCHEDULE_HOURS)
    return tuple(sorted(set(hours)))


def tournament_schedule_clock_now(now_epoch):
    # libJurassicPark.so uses gmtime() when building visible tournament cards.
    return datetime.datetime.fromtimestamp(int(now_epoch), tz=BATTLE_TOURNAMENT_CLIENT_CLOCK_TZ)


def tournament_schedule_slot_bounds(game_time=None, online_options=None):
    now_epoch = int(game_time if game_time is not None else current_scheduler_game_time())
    clock_now = tournament_schedule_clock_now(now_epoch)
    today = clock_now.date()
    schedule_hours = tournament_time_hours_from_options(online_options)
    slots = [
        datetime.datetime.combine(
            today,
            datetime.time(hour=hour, tzinfo=BATTLE_TOURNAMENT_CLIENT_CLOCK_TZ),
        )
        for hour in schedule_hours
    ]
    next_slot = next((slot for slot in slots if slot > clock_now), None)
    previous_slot = None
    for slot in slots:
        if slot <= clock_now:
            previous_slot = slot
    if next_slot is None:
        next_slot = datetime.datetime.combine(
            today + datetime.timedelta(days=1),
            datetime.time(hour=schedule_hours[0], tzinfo=BATTLE_TOURNAMENT_CLIENT_CLOCK_TZ),
        )
    if previous_slot is None:
        previous_slot = datetime.datetime.combine(
            today - datetime.timedelta(days=1),
            datetime.time(hour=schedule_hours[-1], tzinfo=BATTLE_TOURNAMENT_CLIENT_CLOCK_TZ),
        )
    return now_epoch, clock_now, schedule_hours, previous_slot, next_slot


def trace_tournament_schedule_summary(game_time=None, online_options=None):
    now_epoch, clock_now, schedule_hours, previous_slot, next_slot = (
        tournament_schedule_slot_bounds(game_time, online_options)
    )
    local_tz = scheduler_local_timezone()
    local_now = datetime.datetime.fromtimestamp(now_epoch, tz=local_tz)
    seconds_until_next = int((next_slot - clock_now).total_seconds())
    seconds_since_previous = int((clock_now - previous_slot).total_seconds())
    options = online_options if isinstance(online_options, dict) else {}
    summary = {
        "game_time": now_epoch,
        "client_schedule_clock": "utc_gmtime",
        "client_utc_now": clock_now.isoformat(),
        "local_now": local_now.isoformat(),
        "local_timezone": str(local_tz),
        "schedule_hours": list(schedule_hours),
        "previous_slot": previous_slot.isoformat(),
        "seconds_since_previous_slot": seconds_since_previous,
        "next_slot": next_slot.isoformat(),
        "seconds_until_next_slot": seconds_until_next,
        "minutes_until_next_slot": round(seconds_until_next / 60, 3),
        "option_values": {
            key: str(options[key])
            for key in (
                "TOURNAMENT_START",
                "TOURNAMENT_TIME",
                "TOURNAMENT_TYPE",
                "TNT_SEASON_DURATION",
                "TNT_SEASONE_WRN",
            )
            if key in options
        },
    }
    season_start = _as_int(options.get("TOURNAMENT_START"), 0)
    season_duration = _as_int(options.get("TNT_SEASON_DURATION"), 0)
    if season_duration > 0:
        summary["season_duration_cycle_projection"] = (
            trace_tournament_duration_cycle_projection(now_epoch, season_duration)
        )
    if season_start > 0 and season_duration > 0:
        season_end = season_start + season_duration
        summary["season"] = {
            "start": season_start,
            "duration_seconds": season_duration,
            "duration_days": round(season_duration / 86400.0, 6),
            "end": season_end,
            "remaining_seconds": season_end - now_epoch,
            "remaining_days": round((season_end - now_epoch) / 86400.0, 6),
        }
        summary["native_season_projection"] = trace_native_tournament_projection(
            now_epoch,
            season_start,
            season_duration,
        )
    return summary


def trace_tournament_duration_cycle_projection(game_time, season_duration):
    now = _as_int(game_time, 0)
    duration = _as_int(season_duration, 0)
    if now <= 0 or duration <= 0:
        return {
            "present": False,
            "game_time": now,
            "duration_seconds": duration,
        }
    cycle_time = now
    elapsed = cycle_time % duration
    remaining = duration - elapsed if elapsed else duration
    return {
        "present": True,
        "game_time": now,
        "cycle_time_seconds": cycle_time,
        "duration_seconds": duration,
        "duration_days": round(duration / 86400.0, 6),
        "elapsed_mod_seconds": elapsed,
        "remaining_seconds": remaining,
        "remaining_days": round(remaining / 86400.0, 6),
        "semantic": (
            "diagnostic projection observed from live Season Ends UI; "
            "game_time seconds cycle against TNT_SEASON_DURATION"
        ),
    }


def _signed_div_trunc_zero(value, divisor):
    if divisor == 0:
        return 0
    quotient = abs(value) // abs(divisor)
    if (value < 0) != (divisor < 0):
        quotient = -quotient
    return quotient


def trace_native_tournament_projection(game_time, season_start, season_duration):
    now = _as_int(game_time, 0)
    start = _as_int(season_start, 0)
    duration = _as_int(season_duration, 0)
    if now <= 0 or start <= 0 or duration <= 0:
        return {
            "present": False,
            "now": now,
            "start": start,
            "duration_seconds": duration,
        }
    diff = now - start
    cycle_index = _signed_div_trunc_zero(diff, duration)
    next_boundary = start + ((cycle_index + 1) * duration)
    remaining = next_boundary - now
    first_boundary = start + duration
    second_boundary = start + (2 * duration)
    next_plus_one_boundary = start + ((cycle_index + 2) * duration)
    return {
        "present": True,
        "now": now,
        "start": start,
        "duration_seconds": duration,
        "duration_days": round(duration / 86400.0, 6),
        "start_age_seconds": diff,
        "start_in_future": start > now,
        "client_signed_cycle_index": cycle_index,
        "client_next_boundary": next_boundary,
        "client_remaining_seconds": remaining,
        "client_remaining_days": round(remaining / 86400.0, 6),
        "first_boundary": first_boundary,
        "first_boundary_remaining_seconds": first_boundary - now,
        "first_boundary_remaining_days": round((first_boundary - now) / 86400.0, 6),
        "second_boundary": second_boundary,
        "second_boundary_remaining_seconds": second_boundary - now,
        "second_boundary_remaining_days": round((second_boundary - now) / 86400.0, 6),
        "next_plus_one_boundary": next_plus_one_boundary,
        "next_plus_one_remaining_seconds": next_plus_one_boundary - now,
        "next_plus_one_remaining_days": round(
            (next_plus_one_boundary - now) / 86400.0,
            6,
        ),
        "semantic": "diagnostic native-style projection; not a protocol claim",
    }


def next_tournament_slot_epoch_seconds(game_time=None, online_options=None):
    _now_epoch, _clock_now, _schedule_hours, _previous_slot, next_slot = (
        tournament_schedule_slot_bounds(game_time, online_options)
    )
    return int(next_slot.timestamp())


def tournament_season_cycle_start_seconds(game_time, duration_seconds=None):
    now = _as_int(game_time, int(time.time()))
    duration = _as_int(duration_seconds, _as_int(BATTLE_ONLINE_OPTION_DEFAULTS.get("TNT_SEASON_DURATION"), 1296000))
    if duration <= 0:
        duration = 1296000
    return now - (now % duration)


def current_tournament_season_start_seconds(game_time, duration_seconds=None, cached_start_seconds=None):
    global TOURNAMENT_SEASON_START_SECONDS
    cycle_start = tournament_season_cycle_start_seconds(game_time, duration_seconds)
    with TOURNAMENT_SEASON_START_LOCK:
        TOURNAMENT_SEASON_START_SECONDS = cycle_start
        return cycle_start


def scheduled_online_option_value(
    key,
    game_time,
    log,
    online_options=None,
    saved=None,
):
    key = str(key)
    if key not in SCHEDULED_ONLINE_OPTION_KEYS and not key.startswith("MARKET_LIMIT_"):
        return None
    if key == "TOURNAMENT_START":
        options = online_options if isinstance(online_options, dict) else {}
        duration = options.get("TNT_SEASON_DURATION", BATTLE_ONLINE_OPTION_DEFAULTS.get("TNT_SEASON_DURATION"))
        cached_start = options.get("TOURNAMENT_START")
        return str(current_tournament_season_start_seconds(game_time, duration, cached_start))
    schedule = compute_scheduled_online_options(game_time, saved=saved)
    if key == "EVENT_DNA_DINO":
        return schedule["dna_dino"] if schedule["dna_active"] else ""
    if key == "ADDON_DINO_ID":
        return schedule["surface_ltd_dino"]
    if key == "AQ_ADDON_DINO_ID":
        return schedule["aquatic_ltd_dino"]
    if key == "AR_ADDON_DINO_ID":
        return schedule["arctic_ltd_dino"]
    if key == "EVENT_DNA_LIMIT":
        return str(schedule["dna_limit"])
    if key in ("ADDON_DINO_LIMIT", "AQ_ADDON_DINO_LIMIT", "AR_ADDON_DINO_LIMIT"):
        return str(schedule["ltd_limit"])
    if key.startswith("MARKET_LIMIT_"):
        return str(schedule["ltd_limit"])
    return None


def encode_online_option_pair(key, value):
    key_bytes = str(key).encode("utf-8")
    value_bytes = str(value).encode("utf-8")
    return (
        ONLINE_OPTIONS_KEY_MARKER
        + struct.pack("<I", len(key_bytes))
        + key_bytes
        + ONLINE_OPTIONS_VALUE_MARKER
        + struct.pack("<I", len(value_bytes))
        + value_bytes
    )


def parse_online_options_blob(data):
    header_end = data.find(ONLINE_OPTIONS_KEY_MARKER)
    if header_end < 0:
        return b"", []
    header = data[:header_end]
    pairs = []
    offset = header_end
    while True:
        offset = data.find(ONLINE_OPTIONS_KEY_MARKER, offset)
        if offset < 0:
            break
        key_length_at = offset + len(ONLINE_OPTIONS_KEY_MARKER)
        if key_length_at + 4 > len(data):
            break
        key_length = struct.unpack_from("<I", data, key_length_at)[0]
        key_at = key_length_at + 4
        value_at = key_at + key_length
        if value_at + len(ONLINE_OPTIONS_VALUE_MARKER) + 4 > len(data):
            break
        if data[value_at:value_at + len(ONLINE_OPTIONS_VALUE_MARKER)] != ONLINE_OPTIONS_VALUE_MARKER:
            offset += 1
            continue
        value_length_at = value_at + len(ONLINE_OPTIONS_VALUE_MARKER)
        value_length = struct.unpack_from("<I", data, value_length_at)[0]
        text_at = value_length_at + 4
        text_end = text_at + value_length
        if text_end > len(data):
            break
        key = data[key_at:value_at].decode("utf-8", errors="replace")
        value = data[text_at:text_end].decode("utf-8", errors="replace")
        pairs.append((key, value))
        offset += 1
    return header, pairs


def read_onlineoptions_source_bytes(log=None):
    """Load onlineoptions bytes from disk, or rebuild from built-in defaults."""
    try:
        with open(ONLINE_OPTIONS_FILE, "rb") as handle:
            return handle.read()
    except OSError:
        pass
    try:
        from online_options_defaults import (
            ONLINE_OPTIONS_DEFAULT_PAIRS,
            ONLINE_OPTIONS_HEADER_HEX,
        )

        header = bytes.fromhex(ONLINE_OPTIONS_HEADER_HEX)
        pairs = [(str(key), str(value)) for key, value in ONLINE_OPTIONS_DEFAULT_PAIRS]
        data = header + b"".join(
            encode_online_option_pair(key, value) for key, value in pairs
        )
        if log:
            log(
                f"[OPTIONS] rebuilt onlineoptions from built-in defaults "
                f"entries={len(pairs)} bytes={len(data)}"
            )
        return data
    except (ImportError, TypeError, ValueError) as exc:
        if log:
            log(f"[OPTIONS] unable to read onlineoptions source: {exc!r}")
        return b""


def build_onlineoptions_bytes(game_time, log):
    data = read_onlineoptions_source_bytes(log)
    if not data:
        return b""
    header, pairs = parse_online_options_blob(data)
    if not pairs:
        return data
    option_values = {str(key): str(value) for key, value in pairs}
    # Scheduled values can depend on other options.  Build that dependency map
    # from the effective contract, not the raw cached resource, so a first run
    # cannot align TOURNAMENT_START to the old 26-day duration and then emit the
    # client-default 15-day duration in the same response.
    option_values.update(ONLINE_OPTION_OVERRIDES)
    patched = []
    touched = []
    for key, value in pairs:
        scheduled = scheduled_online_option_value(key, game_time, log, option_values)
        if scheduled is not None and scheduled != value:
            touched.append(f"{key}={scheduled}")
            value = scheduled
        elif key in ONLINE_OPTION_OVERRIDES and ONLINE_OPTION_OVERRIDES[key] != value:
            value = ONLINE_OPTION_OVERRIDES[key]
            touched.append(f"{key}={value}")
        patched.append((key, value))
    if touched:
        log(
            f"[OPTIONS] HTTP onlineoptions patched game_time={int(game_time)} "
            f"keys={touched!r}"
        )
    body = header + b"".join(encode_online_option_pair(key, value) for key, value in patched)
    log(
        f"[OPTIONS] HTTP onlineoptions values game_time={int(game_time)} "
        f"watched_values={online_option_watched_values(dict(patched))}"
    )
    log_tournament_timer_trace(
        log,
        "http-onlineoptions",
        game_time=int(game_time),
        online_options=dict(patched),
        source="cached-file-http",
    )
    return body


def load_cached_online_options(log):
    """Extract the original c.pb `k`/`v` entries from cached onlineoptions."""
    global _ONLINE_OPTIONS_CACHE
    if _ONLINE_OPTIONS_CACHE is not None:
        return _ONLINE_OPTIONS_CACHE

    values = {}
    data = read_onlineoptions_source_bytes(log)
    if not data:
        _ONLINE_OPTIONS_CACHE = values
        return values

    _header, pairs = parse_online_options_blob(data)
    for key, value in pairs:
        values[key] = value

    for key, override in ONLINE_OPTION_OVERRIDES.items():
        previous = values.get(key)
        if previous is not None and previous != override:
            log(f"[OPTIONS] override '{key}'='{override}' (was '{previous}')")
        values[key] = override

    _ONLINE_OPTIONS_CACHE = values
    log(f"[OPTIONS] parsed cached onlineoptions entries={len(values)}")
    return values


def apply_online_option_value(
    key,
    cached_values,
    log,
    game_time=None,
    saved=None,
):
    key = str(key)
    scheduled = scheduled_online_option_value(
        key,
        game_time,
        log,
        cached_values,
        saved=saved,
    )
    if scheduled is not None:
        return scheduled
    value = cached_values.get(key, "")
    if key in ONLINE_OPTION_OVERRIDES:
        override = ONLINE_OPTION_OVERRIDES[key]
        if value != override:
            log(f"[OPTIONS] override '{key}'='{override}' (was '{value!r}')")
        return override
    if key in TOURNAMENT_ONLINE_OPTION_PUSH_KEYS and value != "":
        return value
    if key in BATTLE_ONLINE_OPTION_DEFAULTS:
        return BATTLE_ONLINE_OPTION_DEFAULTS[key]
    return value


def online_option_watched_values(values):
    return compact_json({
        key: str(values[key])
        for key in ONLINE_OPTION_TRACE_KEYS
        if key in values
    })


def check_battle_asset_cache(log):
    missing = []
    for name in BATTLE_CORE_CACHE_FILES:
        path = os.path.join(CACHE_DIR, name)
        if not os.path.isfile(path):
            missing.append(name)
    if missing:
        log(f"[BOOT] battle asset cache missing files={missing!r}")
        return False
    log(f"[BOOT] battle asset cache ok ({len(BATTLE_CORE_CACHE_FILES)} core files present)")
    return True


def file_md5(path):
    digest = hashlib.md5()
    with open(path, "rb") as handle:
        for chunk in iter(lambda: handle.read(1024 * 1024), b""):
            digest.update(chunk)
    return digest.hexdigest()


def build_local_manifest(log):
    """
    Reconcile template metadata with the converted cache files we serve.

    Converted LPKG files legitimately differ in size and MD5 from their iOS
    sources. Advertising the source metadata makes the client reject or crash
    while loading battle packages such as battlehud_hd. Rows without a local
    file are omitted so the client cannot select a stale package that this
    server cannot provide.
    """
    try:
        with open(MANIFEST_FILE, "r", encoding="utf-8") as handle:
            rows = json.load(handle)
    except Exception as exc:
        log(f"[MANIFEST] unable to parse {MANIFEST_FILE!r}: {exc!r}")
        return read_file_or_empty(MANIFEST_FILE) or b"[]"

    if not isinstance(rows, list):
        log("[MANIFEST] root is not an array; serving the template unchanged")
        return json.dumps(rows, separators=(",", ":")).encode("utf-8")

    updated = 0
    missing = []
    unsafe = []
    served_rows = []
    for row in rows:
        if not isinstance(row, dict):
            served_rows.append(row)
            continue
        filename = str(row.get("filename", ""))
        if not filename or os.path.basename(filename) != filename:
            unsafe.append(filename)
            served_rows.append(row)
            continue
        cache_path = os.path.join(CACHE_DIR, filename)
        if not os.path.isfile(cache_path):
            missing.append(filename)
            continue

        actual_size = str(os.path.getsize(cache_path))
        actual_checksum = file_md5(cache_path)
        checksum_changed = (
            str(row.get("checksum", "")).lower() != actual_checksum
        )
        if (
            str(row.get("size", "")) != actual_size
            or checksum_changed
        ):
            row["size"] = actual_size
            row["checksum"] = actual_checksum
            if checksum_changed:
                try:
                    row["version"] = str(int(row["version"]) + 1)
                except (KeyError, TypeError, ValueError):
                    pass
            updated += 1
        served_rows.append(row)

    body = json.dumps(served_rows, ensure_ascii=True, separators=(",", ":")).encode("utf-8")
    log(
        f"[MANIFEST] local cache reconciled entries={len(rows)} updated={updated} "
        f"missing={len(missing)} unsafe={len(unsafe)} served={len(served_rows)} "
        f"bytes={len(body)}"
    )
    if missing:
        log(f"[MANIFEST] files missing from cache={missing!r}")
    if unsafe:
        log(f"[MANIFEST] rejected unsafe filenames={unsafe!r}")
    return body


def make_scheduled_online_options_push(log, game_time, sequence=0, saved=None):
    cached_values = load_cached_online_options(log)
    option_items = []
    schedule_log = []
    sent_values = {}
    for key in scheduled_online_option_push_keys(cached_values):
        sent = apply_online_option_value(
            key,
            cached_values,
            log,
            game_time=game_time,
            saved=saved,
        )
        sent_values[key] = sent
        option_items.append(e_obj([
            ("k", e_str(key)),
            ("v", e_str(sent)),
        ]))
        if (
            key in SCHEDULED_ONLINE_OPTION_KEYS
            or key.startswith("MARKET_LIMIT_")
        ):
            schedule_log.append(f"{key}={sent}")
    if schedule_log:
        log(
            f"[OPTIONS] scheduled push game_time={int(game_time)} "
            f"keys={schedule_log!r} "
            f"watched_values={online_option_watched_values(sent_values)} "
            f"values={compact_json(sent_values)}"
        )
    log_tournament_timer_trace(
        log,
        "scheduled-online-options-push",
        game_time=int(game_time),
        online_options=sent_values,
        response_seq=sequence,
        returned_keys=len(sent_values),
    )
    # c.pb is an extension callback; the proven client-requested path uses action 13.
    return make_server_push("c.pb", [
        ("s", e_long(sequence)),
        ("vs", e_arr(option_items)),
    ], action=ONLINE_OPTIONS_PUSH_ACTION)


def make_online_options_push(log, sequence=0, game_time=None, saved=None):
    return make_scheduled_online_options_push(
        log,
        scheduler_game_time_seconds(None, saved, game_time or time.time()),
        sequence=sequence,
        saved=saved,
    )


def content_int(content, key, default=0):
    if not isinstance(content, dict):
        return default
    if key in content:
        raw = content[key]
    elif str(key) in content:
        raw = content[str(key)]
    else:
        return default
    try:
        return int(raw)
    except (TypeError, ValueError):
        return default


def content_copy(record):
    content = saved_content(record)
    return copy.deepcopy(content) if isinstance(content, dict) else {}


def park_layout_lengths(content):
    if not isinstance(content, dict):
        return {}
    layouts = {}
    for key in ("46", "47", "49", "50"):
        value = content.get(key)
        if isinstance(value, list):
            layouts[key] = len(value)
    return layouts


def count_dino_cells(content):
    total = 0
    if not isinstance(content, dict):
        return total
    for key in ("46", "47"):
        grid = content.get(key)
        if not isinstance(grid, list):
            continue
        for cell in grid:
            try:
                if int(cell) != 0:
                    total += 1
            except (TypeError, ValueError):
                continue
    return total


def trim_park_grid(content, grid_key, target_len, log):
    grid = content.get(str(grid_key))
    if not isinstance(grid, list) or len(grid) <= target_len:
        return
    log(f"[BATTLE] park grid trim park/{grid_key} len {len(grid)} -> {target_len}")
    content[str(grid_key)] = grid[:target_len]


def zero_park_deco_grids(content, log):
    changed = False
    for key in ("49", "50"):
        grid = content.get(key)
        if isinstance(grid, list) and any(int(v) != 0 for v in grid if isinstance(v, (int, float))):
            content[key] = [0] * len(grid)
            changed = True
    if changed:
        log("[BATTLE] park read: zeroed deco grids (aquatic markers in 49/50)")


def zero_park_dino_grids(content, grid_len, log):
    changed = False
    for key in ("46", "47"):
        grid = content.get(key)
        if not isinstance(grid, list) or len(grid) != grid_len or any(
            int(v) != 0 for v in grid if isinstance(v, (int, float))
        ):
            content[key] = [0] * grid_len
            changed = True
    if changed:
        log(f"[BATTLE] park read: zeroed dino grids 46/47 len={grid_len}")


def clear_profile_tournament_volatile_markers(content, log, reason):
    if not isinstance(content, dict):
        return content
    present = {
        key: content.get(key) for key in ("134", "135")
        if _profile_tournament_value_score(content.get(key)) > 0
    }
    if present:
        log(
            f"[TOURNAMENT] preserved opaque profile fields={present!r} "
            f"reason={reason}; no proven server ownership"
        )
    return content


PROFILE_TOURNAMENT_MARKER_MIN = 160


def _profile_has_large_tournament_marker(value):
    if isinstance(value, bool):
        return False
    if isinstance(value, int):
        return abs(value) >= PROFILE_TOURNAMENT_MARKER_MIN
    if isinstance(value, list):
        return any(_profile_has_large_tournament_marker(item) for item in value)
    if isinstance(value, dict):
        return any(_profile_has_large_tournament_marker(item) for item in value.values())
    return False


def _profile_has_rank_like_tournament_marker(content):
    if not isinstance(content, dict):
        return False
    return any(
        _profile_has_large_tournament_marker(content.get(key))
        for key in ("113", "114")
    )


def _profile_has_tournament_access_marker(content):
    if not isinstance(content, dict):
        return False
    if _profile_tournament_value_score(content.get("111")) > 0:
        return False
    if _profile_tournament_value_score(content.get("112")) > 0:
        return False
    if _profile_tournament_value_score(content.get("113")) > 0:
        return False
    return content.get("114") == [1, 0, 0]


def clear_profile_battle_cooldown_payload(content, log, reason):
    # prof.111-prof.114 are client-serialized, slot-oriented battle state.
    # Their full labels are not proven, and native/client captures only support
    # clearing them in explicit client transitions such as TNSEASON.  Ordinary
    # loads and writes must preserve them byte-for-byte.
    return 0


def clear_profile_tournament_score_timer_pollution(content, log, reason):
    if not isinstance(content, dict):
        return 0
    if _profile_has_tournament_activity(content):
        return 0
    if not _profile_has_rank_like_tournament_marker(content):
        return 0
    old_value = _as_int(content.get("144"), 0)
    if old_value <= 0:
        return 0
    log(
        f"[TOURNAMENT] preserved prof.144={old_value!r} reason={reason}; "
        "client trace identifies a separate profile timer, not Tournament pollution"
    )
    return 0


def clear_prof_error_flag(content, log, reason=""):
    if not isinstance(content, dict) or not content.get("93"):
        return False
    content["93"] = ""
    suffix = f" ({reason})" if reason else ""
    log(f"[BATTLE] cleared prof/93{suffix}")
    return True


def park_content_is_initialized(content):
    if not isinstance(content, dict):
        return False
    slot_count = content_int(content, "45", 0)
    if slot_count <= 0:
        return False
    for key in ("46", "47"):
        grid = content.get(key)
        if not isinstance(grid, list) or len(grid) < slot_count:
            return False
    return True


def park_zone_label(content):
    # Field 57 tracks the dino-row count; 58/59 lengths normally match it.
    # Older diagnostic builds treated it like a zone id, which corrupts
    # cross-park routing when a surface/aquatic park has 0, 1, or 2 dinos.
    dino_count = content_int(content, "57", None) if isinstance(content, dict) else None
    return f"dinos:{dino_count}"


def _park_list_nonzero_count(content, keys):
    total = 0
    if not isinstance(content, dict):
        return total
    for key in keys:
        values = content.get(str(key))
        if not isinstance(values, list):
            continue
        for value in values:
            try:
                if int(value) != 0:
                    total += 1
            except (TypeError, ValueError):
                if value not in (None, False, "", [], {}):
                    total += 1
    return total


def park_progress_score(content):
    if not isinstance(content, dict):
        return 0
    building_count = max(0, content_int(content, "60", 0))
    # 49/50 are omitted here because they often contain non-zero map markers
    # even in empty/bootstrap park payloads.
    placed_objects = _park_list_nonzero_count(
        content,
        ("46", "47", "51", "55", "56", "58", "59", "61", "62"),
    )
    return placed_objects + building_count * 5


def park_port_state_changed(previous_content, incoming_content):
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return False
    for field in ("55", "56"):
        previous_value = previous_content.get(field)
        incoming_value = incoming_content.get(field)
        if isinstance(previous_value, list) and isinstance(incoming_value, list):
            if previous_value != incoming_value:
                return True
    return False


def park_write_rollback_reason(key, previous_content, incoming_content):
    key = str(key or "")
    if key not in PARK_OFFLINE_TIMER_KEYS:
        return ""
    if not park_content_is_initialized(previous_content):
        return ""
    previous_slots = content_int(previous_content, "45", 0)
    incoming_slots = content_int(incoming_content, "45", 0)
    previous_score = park_progress_score(previous_content)
    incoming_score = park_progress_score(incoming_content)
    previous_dinos = content_int(previous_content, "57", 0)
    incoming_dinos = content_int(incoming_content, "57", 0)
    previous_buildings = content_int(previous_content, "60", 0)
    incoming_buildings = content_int(incoming_content, "60", 0)

    if not park_content_is_initialized(incoming_content):
        return (
            f"{key} uninitialized snapshot would replace initialized "
            f"{park_zone_label(previous_content)} park "
            f"slots {previous_slots}->{incoming_slots} "
            f"score {previous_score}->{incoming_score}"
        )

    drastic_slot_drop = (
        previous_slots >= 32
        and incoming_slots <= max(18, previous_slots // 2)
    )
    drastic_score_drop = (
        previous_score >= 3
        and incoming_score <= max(1, previous_score // 5)
        and incoming_slots <= previous_slots
    )
    if key == "arpk" and incoming_dinos > previous_dinos:
        drastic_slot_drop = False
        drastic_score_drop = False
    building_drop = (
        previous_buildings > 0
        and incoming_buildings <= 0
        and incoming_slots < previous_slots
    )
    if drastic_slot_drop or drastic_score_drop or building_drop:
        reasons = []
        if drastic_slot_drop:
            reasons.append(f"slot drop {previous_slots}->{incoming_slots}")
        if drastic_score_drop:
            reasons.append(f"content score {previous_score}->{incoming_score}")
        if building_drop:
            reasons.append(f"buildings {previous_buildings}->{incoming_buildings}")
        return (
            f"{key} rollback-like {park_zone_label(previous_content)} snapshot "
            f"({', '.join(reasons)})"
        )
    return ""


def stale_park_write_reject_reason(key, previous_content, incoming_content):
    if key not in PARK_OFFLINE_TIMER_KEYS:
        return ""
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        # Keep uninitialized-vs-initialized protection from the rollback helper.
        return park_write_rollback_reason(key, previous_content, incoming_content)

    previous_objects = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects = max(0, _as_int(incoming_content.get("45"), 0))
    previous_dinos = max(0, _as_int(previous_content.get("57"), 0))
    incoming_dinos = max(0, _as_int(incoming_content.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    object_drop = previous_objects - incoming_objects
    building_drop = previous_buildings - incoming_buildings
    dino_drop = previous_dinos - incoming_dinos

    # Proven player sells must win over "drastic slot drop" rollback heuristics.
    # Bulk building deletes can halve park.45 while still being intentional.
    if building_drop > 0 and park_write_has_verified_client_building_removal(
        previous_content,
        incoming_content,
    ):
        return ""
    if dino_drop > 0 and park_write_has_verified_client_dino_removal(
        previous_content,
        incoming_content,
    ):
        return ""

    rollback_reason = park_write_rollback_reason(
        key,
        previous_content,
        incoming_content,
    )
    if rollback_reason:
        return rollback_reason
    if object_drop <= 0 and building_drop <= 0:
        return ""

    # Do not reject object-only decreases here; debris / decoration removal can
    # legitimately lower object count. Building-row drops still need proof.
    if building_drop > 0:
        return (
            f"{key} stale lower-count building snapshot "
            f"objects {previous_objects}->{incoming_objects} "
            f"dinos {previous_dinos}->{incoming_dinos} "
            f"buildings {previous_buildings}->{incoming_buildings}; "
            "no proven building sell/remove transaction"
        )

    return ""


def park_write_looks_like_client_removed_zero_rows(previous_content, incoming_content):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_objects = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects = max(0, _as_int(incoming_content.get("45"), 0))
    previous_dinos = max(0, _as_int(previous_content.get("57"), 0))
    incoming_dinos = max(0, _as_int(incoming_content.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    if (
        incoming_objects >= previous_objects
        or incoming_dinos < previous_dinos
        or incoming_buildings <= 0
        or incoming_buildings >= previous_buildings
        or previous_objects - incoming_objects < previous_buildings - incoming_buildings
    ):
        return False
    previous_slots = previous_content.get("62")
    incoming_slots = incoming_content.get("62")
    previous_values = previous_content.get("61")
    if not (
        isinstance(previous_slots, list)
        and isinstance(incoming_slots, list)
        and isinstance(previous_values, list)
    ):
        return False
    if len(incoming_slots) < incoming_buildings or len(previous_slots) < previous_buildings:
        return False
    incoming_head = list(incoming_slots[:incoming_buildings])
    previous_head = list(previous_slots[:incoming_buildings])
    if incoming_head != previous_head:
        return False
    omitted_limit = min(previous_buildings, len(previous_slots), len(previous_values))
    if omitted_limit <= incoming_buildings:
        return False
    for index in range(incoming_buildings, omitted_limit):
        value = previous_values[index]
        if _high_u32(value) != 0 or _low_u32(value) != 0:
            return False
    return True


def record_version_increased(previous_record, current_record):
    if not isinstance(previous_record, dict) or not isinstance(current_record, dict):
        return False
    previous_version = _as_int(previous_record.get("v"), None)
    current_version = _as_int(current_record.get("v"), None)
    return (
        previous_version is not None
        and current_version is not None
        and current_version > previous_version
    )


def dino_id_from_row_value(value):
    state = _dino59_feed_state(value)
    if state:
        return state["dino_id"]
    try:
        return _low_u32(value) & 0xffff
    except Exception:
        return 0


def park_write_has_verified_client_object_tail_removal(
    previous_content,
    incoming_content,
    allow_dino_drop=False,
):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_objects_count = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects_count = max(0, _as_int(incoming_content.get("45"), 0))
    object_drop = previous_objects_count - incoming_objects_count
    if object_drop <= 0:
        return False
    previous_dinos = max(0, _as_int(previous_content.get("57"), 0))
    incoming_dinos = max(0, _as_int(incoming_content.get("57"), 0))
    if allow_dino_drop:
        if incoming_dinos > previous_dinos:
            return False
    elif incoming_dinos != previous_dinos:
        return False
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    if incoming_buildings != previous_buildings:
        return False

    previous_objects = previous_content.get("46")
    incoming_objects = incoming_content.get("46")
    previous_timers = previous_content.get("47")
    incoming_timers = incoming_content.get("47")
    if (
        not isinstance(previous_objects, list)
        or not isinstance(incoming_objects, list)
        or not isinstance(previous_timers, list)
        or not isinstance(incoming_timers, list)
    ):
        return False
    if (
        len(previous_objects) < previous_objects_count
        or len(previous_timers) < previous_objects_count
        or len(incoming_objects) < incoming_objects_count
        or len(incoming_timers) < incoming_objects_count
    ):
        return False
    for index in range(incoming_objects_count):
        if previous_objects[index] != incoming_objects[index]:
            return False
    building_slots = _building_timer_object_slots(previous_content, include_zeroed=True)
    removed_slots = set(range(incoming_objects_count, previous_objects_count))
    if removed_slots & building_slots:
        return False
    return True


def park_record_has_verified_client_object_tail_removal(previous_record, current_record):
    return (
        record_version_increased(previous_record, current_record)
        and park_write_has_verified_client_object_tail_removal(
            saved_content(previous_record),
            saved_content(current_record),
        )
    )


def park_write_has_verified_client_dino_removal(previous_content, incoming_content):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_count = max(0, _as_int(previous_content.get("57"), 0))
    incoming_count = max(0, _as_int(incoming_content.get("57"), 0))
    dino_drop = previous_count - incoming_count
    if dino_drop <= 0:
        return False
    previous_objects = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects = max(0, _as_int(incoming_content.get("45"), 0))
    if previous_objects - incoming_objects != dino_drop:
        return False
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    if incoming_buildings != previous_buildings:
        return False

    previous_values = previous_content.get("59")
    incoming_values = incoming_content.get("59")
    previous_timers = previous_content.get("58")
    incoming_timers = incoming_content.get("58")
    if (
        not isinstance(previous_values, list)
        or not isinstance(incoming_values, list)
        or not isinstance(previous_timers, list)
        or not isinstance(incoming_timers, list)
        or len(previous_values) < previous_count
        or len(previous_timers) < previous_count
        or len(incoming_values) < incoming_count
        or len(incoming_timers) < incoming_count
    ):
        return False
    previous_ids = [
        dino_id_from_row_value(previous_values[index])
        for index in range(previous_count)
    ]
    incoming_ids = [
        dino_id_from_row_value(incoming_values[index])
        for index in range(incoming_count)
    ]
    if any(dino_id <= 0 for dino_id in previous_ids + incoming_ids):
        return False

    previous_index = 0
    for incoming_id in incoming_ids:
        while previous_index < len(previous_ids) and previous_ids[previous_index] != incoming_id:
            previous_index += 1
        if previous_index >= len(previous_ids):
            return False
        previous_index += 1

    # Tail-object sells are ideal, but mid-list sells that remap object slots
    # are still valid when building counts stay put and remaining dino IDs are
    # an ordered subsequence of the previous list.
    return True


def park_record_has_verified_client_dino_removal(previous_record, current_record):
    return (
        record_version_increased(previous_record, current_record)
        and park_write_has_verified_client_dino_removal(
            saved_content(previous_record),
            saved_content(current_record),
        )
    )


def park_write_looks_like_client_removed_building_slots(previous_content, incoming_content):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_objects_count = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects_count = max(0, _as_int(incoming_content.get("45"), 0))
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    object_drop = previous_objects_count - incoming_objects_count
    building_drop = previous_buildings - incoming_buildings
    if object_drop <= 0 or building_drop <= 0:
        return False

    previous_rows = _building_rows_by_slot(previous_content)
    incoming_rows = _building_rows_by_slot(incoming_content)
    removed_slots = sorted(set(previous_rows) - set(incoming_rows))
    if not removed_slots or len(removed_slots) != building_drop:
        return False
    if object_drop < building_drop:
        return False

    previous_objects = previous_content.get("46")
    incoming_objects = incoming_content.get("46")
    if not isinstance(previous_objects, list) or not isinstance(incoming_objects, list):
        return False
    for slot in removed_slots:
        if slot < 0 or slot >= len(previous_objects):
            return False
        if slot >= len(incoming_objects):
            if object_drop != building_drop:
                return False
            continue
        if previous_objects[slot] == incoming_objects[slot]:
            return False
    return True


def park_write_has_verified_client_removed_building_objects(previous_content, incoming_content):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    if incoming_buildings >= previous_buildings:
        return False

    previous_rows = _building_rows_by_slot(previous_content)
    incoming_rows = _building_rows_by_slot(incoming_content)
    removed_slots = sorted(set(previous_rows) - set(incoming_rows))
    if not removed_slots:
        return False

    previous_objects = previous_content.get("46")
    incoming_objects = incoming_content.get("46")
    if not isinstance(previous_objects, list) or not isinstance(incoming_objects, list):
        return False

    incoming_objects_count = min(
        max(0, _as_int(incoming_content.get("45"), 0)),
        len(incoming_objects),
    )
    verified_changed_object = False
    for slot in removed_slots:
        if slot < 0 or slot >= len(previous_objects):
            return False
        if slot >= incoming_objects_count:
            continue
        previous_object = previous_objects[slot]
        incoming_object = incoming_objects[slot]
        if previous_object == incoming_object:
            return False
        if _high_u32(previous_object) == 0:
            return False
        if incoming_object and _high_u32(incoming_object) == 0:
            return False
        verified_changed_object = True
    return verified_changed_object


def park_write_has_verified_client_building_removal(previous_content, incoming_content):
    if not (
        isinstance(previous_content, dict)
        and isinstance(incoming_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_objects_count = max(0, _as_int(previous_content.get("45"), 0))
    incoming_objects_count = max(0, _as_int(incoming_content.get("45"), 0))
    previous_dinos = max(0, _as_int(previous_content.get("57"), 0))
    incoming_dinos = max(0, _as_int(incoming_content.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
    object_drop = previous_objects_count - incoming_objects_count
    building_drop = previous_buildings - incoming_buildings
    # Real sells are often 1 building + 1 object, and bulk deletes can remove
    # dozens at once. Older logic required object_drop > building_drop and
    # capped building_drop at 8, which rejected normal and bulk sells.
    if building_drop <= 0 or incoming_dinos < previous_dinos:
        return False
    # A sell may keep object count flat (reuse/replace) or raise it slightly when
    # the same batch also places something else. Reject only large unexplained
    # object inflation relative to the building drop.
    if object_drop < 0 and (-object_drop) > building_drop + 2:
        return False

    # Strongest live signal from bulk deletes: object count and building count
    # drop by the same amount while dinos stay put (e.g. 70->39 / 36->5).
    if (
        object_drop == building_drop
        and object_drop > 0
        and incoming_dinos == previous_dinos
    ):
        return True

    # Near-match for bulk deletes that also clear a little debris, or keep a
    # couple of non-building objects while removing many buildings.
    if (
        object_drop > 0
        and incoming_dinos == previous_dinos
        and abs(object_drop - building_drop) <= max(2, building_drop // 10)
    ):
        return True

    previous_rows = _building_rows_by_slot(previous_content)
    incoming_rows = _building_rows_by_slot(incoming_content)
    removed_slots = sorted(set(previous_rows) - set(incoming_rows))
    added_slots = sorted(set(incoming_rows) - set(previous_rows))
    if not removed_slots:
        return False
    # Client park writes remap building object slots after a sell, so the set
    # difference can list several "removed" and "added" slots. Accept net row
    # loss matching building_drop (tolerate off-by-one remap noise).
    net_removed_slots = len(removed_slots) - len(added_slots)
    if (
        abs(net_removed_slots - building_drop) <= 1
        and object_drop >= -building_drop
        and incoming_dinos == previous_dinos
    ):
        return True

    if abs(len(removed_slots) - building_drop) <= 1 and (
        park_write_has_verified_client_removed_building_objects(
            previous_content,
            incoming_content,
        )
        or park_write_looks_like_client_removed_building_slots(
            previous_content,
            incoming_content,
        )
    ):
        return True

    if object_drop < building_drop:
        return False

    previous_objects = previous_content.get("46")
    incoming_objects = incoming_content.get("46")
    if not isinstance(previous_objects, list) or not isinstance(incoming_objects, list):
        return False
    incoming_counted_objects = min(incoming_objects_count, len(incoming_objects))
    if not all(slot >= incoming_counted_objects for slot in removed_slots):
        return False
    for slot in removed_slots:
        if slot < 0 or slot >= len(previous_objects):
            return False
        if _as_int(previous_objects[slot], 0) == 0:
            return False
        previous_row = previous_rows.get(slot)
        if previous_row is None or _as_int(previous_row[1], 0) == 0:
            return False
    return abs(len(removed_slots) - building_drop) <= 1


def log_stale_park_write_rejected(
    log,
    command,
    key,
    raw_key,
    sequence,
    previous_content,
    incoming_content,
    reason,
):
    log(
        f"[SAVE-GUARD] rejected stale client snapshot before merge "
        f"co={command!r} key={key!r} client_key={raw_key!r} "
        f"request_seq={sequence} response_seq={sequence} "
        f"saved_park_count={content_int(previous_content, '45', 0)} "
        f"incoming_park_count={content_int(incoming_content, '45', 0)} "
        f"saved_building_count={content_int(previous_content, '60', 0)} "
        f"incoming_building_count={content_int(incoming_content, '60', 0)} "
        f"accepted=False write_ack_ok=True repair_queued=True reason={reason!r}"
    )
    trace_rejected_park_object_diff(previous_content, incoming_content, log, key, sequence)


def trace_rejected_park_object_diff(previous_content, incoming_content, log, key, sequence, limit=16):
    if key not in PARK_OFFLINE_TIMER_KEYS or not callable(log):
        return
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return
    previous_count = max(0, _as_int(previous_content.get("45"), 0))
    incoming_count = max(0, _as_int(incoming_content.get("45"), 0))
    if incoming_count >= previous_count:
        return
    previous_objects = previous_content.get("46")
    incoming_objects = incoming_content.get("46")
    previous_timers = previous_content.get("47")
    incoming_timers = incoming_content.get("47")
    if not isinstance(previous_objects, list) or not isinstance(incoming_objects, list):
        return

    changed_slots = []
    scan_limit = min(previous_count, incoming_count, len(previous_objects), len(incoming_objects))
    for index in range(scan_limit):
        previous_object = previous_objects[index]
        incoming_object = incoming_objects[index]
        previous_timer = previous_timers[index] if isinstance(previous_timers, list) and index < len(previous_timers) else None
        incoming_timer = incoming_timers[index] if isinstance(incoming_timers, list) and index < len(incoming_timers) else None
        if previous_object == incoming_object and previous_timer == incoming_timer:
            continue
        changed_slots.append({
            "i": index,
            "prev46": previous_object,
            "in46": incoming_object,
            "prev47": previous_timer,
            "in47": incoming_timer,
        })
        if len(changed_slots) >= limit:
            break

    removed_tail = []
    tail_end = min(previous_count, len(previous_objects), incoming_count + max(0, limit))
    for index in range(incoming_count, tail_end):
        previous_timer = previous_timers[index] if isinstance(previous_timers, list) and index < len(previous_timers) else None
        removed_tail.append({
            "i": index,
            "prev46": previous_objects[index],
            "prev47": previous_timer,
        })

    log(
        f"[PARK-OBJECT-TRACE] rejected stale park object diff key={key!r} "
        f"seq={sequence} objects {previous_count}->{incoming_count} "
        f"changed_slots={compact_json(changed_slots)} "
        f"removed_tail={compact_json(removed_tail)} "
        f"changed_truncated={len(changed_slots) >= limit} "
        f"tail_truncated={tail_end < min(previous_count, len(previous_objects))}"
    )


def routed_park_storage_key(raw_key, content):
    # The storage key is authoritative. Do not infer park family from content
    # field 57; it is a dino count, not a zone id.
    raw_key = str(raw_key or "")
    return raw_key


def routed_storage_write_item(item, log=None):
    if not isinstance(item, dict):
        return item, str(item.get("k", "")) if isinstance(item, dict) else "", ""
    raw_key = str(item.get("k", ""))
    routed_key = routed_park_storage_key(raw_key, item.get("c"))
    if routed_key == raw_key:
        return item, raw_key, routed_key
    routed = copy.deepcopy(item)
    routed["k"] = routed_key
    if log:
        zone = park_zone_label(item.get("c"))
        log(
            f"[SAVE-ROUTE] routed storage write key {raw_key!r}->{routed_key!r} "
            f"zone={zone} summary={compact_json(trace_content_summary(routed_key, item.get('c')))}"
        )
    return routed, raw_key, routed_key


def protected_park_families(requests, saved, log):
    protected = set()
    writes = {}
    for item in requests:
        if not isinstance(item, dict) or item.get("co") not in ("c.zw", "c.ow"):
            continue
        routed_key = routed_park_storage_key(str(item.get("k", "")), item.get("c"))
        writes[routed_key] = item
    for prefix, family_keys in PARK_SAVE_FAMILIES.items():
        park_key = family_keys[0]
        incoming = writes.get(park_key)
        if not incoming:
            continue
        incoming_content = incoming.get("c")
        existing_content = saved_content(saved.get(park_key, {}))
        saved_slots = content_int(existing_content, "45", 0)
        incoming_slots = content_int(incoming_content, "45", 0)
        rollback_reason = stale_park_write_reject_reason(
            park_key,
            existing_content,
            incoming_content,
        )
        if rollback_reason:
            protected.add(prefix)
            log(
                f"[SAVE-GUARD] rejecting {prefix} rollback family write: "
                f"saved {park_key}/45={saved_slots} incoming={incoming_slots} "
                f"reason={rollback_reason!r}"
            )
    return protected


def park_write_is_forward_after_family_guard(previous_content, incoming_content):
    if not (
        park_content_is_initialized(previous_content)
        and park_content_is_initialized(incoming_content)
    ):
        return False
    previous_slots = content_int(previous_content, "45", 0)
    incoming_slots = content_int(incoming_content, "45", 0)
    previous_buildings = content_int(previous_content, "60", 0)
    incoming_buildings = content_int(incoming_content, "60", 0)
    previous_score = park_progress_score(previous_content)
    incoming_score = park_progress_score(incoming_content)

    # A rollback-looking raw packet can be repaired later in the write path
    # by merging preserved objects/buildings. Once repaired, do not let the
    # broad family guard throw away the forward snapshot it helped create.
    if incoming_slots >= previous_slots and incoming_buildings >= previous_buildings:
        return True
    if incoming_slots >= previous_slots and incoming_score >= previous_score:
        return True
    return False


def protected_family_write_block_reason(
    key,
    family,
    protected_families,
    saved,
    incoming_content,
    rollback_reason="",
):
    if family not in protected_families:
        return ""
    if key == "road" and surface_road_count_decrease_has_snapshot(incoming_content):
        return ""
    existing_content = saved_content(saved.get(key, {}))
    if key in ROAD_PROGRESS_KEYS and road_forward_progress_reason(key, existing_content, incoming_content):
        return ""
    if key in PARK_OFFLINE_TIMER_KEYS and not rollback_reason:
        if park_write_is_forward_after_family_guard(existing_content, incoming_content):
            return ""
    return f"family {family!r} protected by rollback-like park write"


def family_for_save_key(key):
    for prefix, family_keys in PARK_SAVE_FAMILIES.items():
        if key in family_keys:
            return prefix
    return None


def normalize_device_id(value):
    return str(value or "").strip().lower()


def _session_key_set(session_state, name):
    if not isinstance(session_state, dict):
        return set()
    values = session_state.get(name)
    if isinstance(values, set):
        return values
    if isinstance(values, (list, tuple)):
        values = {str(value) for value in values}
    else:
        values = set()
    session_state[name] = values
    return values


def pending_repair_dependent_restore_keys(blocked_keys, touched_keys):
    touched = {str(key or "") for key in (touched_keys or ())}
    restore_keys = set()
    for blocked_key in blocked_keys or ():
        blocked_key = str(blocked_key or "")
        dependent_keys = PENDING_PARK_REPAIR_DEPENDENT_KEYS.get(blocked_key, (blocked_key,))
        for dependent_key in dependent_keys:
            dependent_key = str(dependent_key or "")
            if dependent_key and dependent_key in touched:
                restore_keys.add(dependent_key)
    return sorted(restore_keys)


def save_replay_key_served(session_state, key):
    return str(key or "") in _session_key_set(session_state, "served_save_read_keys")


def mark_save_replay_key_served(session_state, key):
    key = str(key or "")
    if not key or not isinstance(session_state, dict):
        return False
    served_keys = _session_key_set(session_state, "served_save_read_keys")
    before = len(served_keys)
    served_keys.add(key)
    return len(served_keys) != before


def replay_keys_for_protected_write(key, family):
    if family in PARK_SAVE_FAMILIES:
        return tuple(PARK_SAVE_FAMILIES[family])
    key = str(key or "")
    return (key,) if key else ()


def stale_reject_repair_replay_keys(key, family, reason):
    if "stale lower-count building snapshot" not in str(reason or ""):
        return None
    if key == "arpk" and family == "ar":
        return tuple(PARK_SAVE_FAMILIES["ar"])
    key = str(key or "")
    return (key,) if key else ()


def queue_forced_save_repair_replay(
    key,
    family,
    reason,
    forced_replay_keys,
    session_state,
    log,
    replay_keys_override=None,
):
    if replay_keys_override is None:
        replay_keys = replay_keys_for_protected_write(key, family)
    else:
        replay_keys = tuple(str(replay_key) for replay_key in replay_keys_override if str(replay_key or ""))
    if not replay_keys:
        return
    before = set(forced_replay_keys)
    forced_replay_keys.update(replay_keys)
    served_keys = _session_key_set(session_state, "served_save_read_keys")
    repair_reasons = session_state.setdefault("forced_save_replay_reasons", {})
    if not isinstance(repair_reasons, dict):
        repair_reasons = {}
        session_state["forced_save_replay_reasons"] = repair_reasons
    removed = []
    for replay_key in replay_keys:
        repair_reasons[replay_key] = str(reason or "")
        if replay_key in served_keys:
            served_keys.discard(replay_key)
            removed.append(replay_key)
    session_state["force_next_save_replay"] = True
    added = [replay_key for replay_key in replay_keys if replay_key not in before]
    if added or removed:
        log(
            f"[REPAIR-REPLAY] queued protected save replay key={key!r} "
            f"family={family!r} keys={list(replay_keys)!r} "
            f"added={added!r} unserved={removed!r} reason={reason!r}"
        )


def require_authoritative_repair_read(key, session_state, log, reason):
    key = str(key or "")
    if not key or not isinstance(session_state, dict):
        return
    pending_keys = _session_key_set(session_state, "post_replay_pending_repair_keys")
    was_pending = key in pending_keys
    pending_keys.add(key)
    served_keys = _session_key_set(session_state, "served_save_read_keys")
    cleared_served = key in served_keys
    if cleared_served:
        served_keys.discard(key)
    session_state["force_next_save_replay"] = True
    if not was_pending or cleared_served:
        log(
            f"[REPAIR-REPLAY] authoritative repair read required "
            f"key={key!r} pending={sorted(pending_keys)!r} "
            f"cleared_served={cleared_served} reason={reason!r}"
        )


def queue_forced_pre_read_timer_replay(
    keys,
    forced_replay_keys,
    session_state,
    log,
    reason,
):
    if not isinstance(keys, (set, list, tuple)):
        keys = [keys]
    replay_keys = [
        str(key or "")
        for key in keys
        if str(key or "") in OFFLINE_TIMER_REPLAY_KEYS
    ]
    if not replay_keys:
        return
    before = set(forced_replay_keys)
    forced_replay_keys.update(replay_keys)
    session_state["force_next_save_replay"] = True
    added = [key for key in replay_keys if key not in before]
    if added:
        log(
            f"[REPAIR-REPLAY] queued pre-read timer replay "
            f"keys={added!r} reason={reason!r}"
        )


def queue_forced_timer_replay(
    keys,
    forced_replay_keys,
    session_state,
    log,
    reason,
):
    if not isinstance(keys, (set, list, tuple)):
        keys = [keys]
    replay_keys = [
        str(key or "")
        for key in keys
        if str(key or "") in OFFLINE_TIMER_REPLAY_KEYS
    ]
    if not replay_keys:
        return
    before = set(forced_replay_keys)
    forced_replay_keys.update(replay_keys)
    session_state["force_next_save_replay"] = True
    added = [key for key in replay_keys if key not in before]
    if added:
        log(
            f"[REPAIR-REPLAY] queued timer repair replay "
            f"keys={added!r} reason={reason!r}"
        )


def should_replay_saved_content(
    key,
    replay_already_served,
    allow_repeat_save_replay=False,
    can_repeat_battle_read=False,
    session_state=None,
):
    if isinstance(session_state, dict) and not save_replay_key_served(session_state, key):
        return True
    if not replay_already_served:
        return True
    if can_repeat_battle_read and key in ("batl", "prof", "park"):
        return True
    return bool(allow_repeat_save_replay)

def offline_elapsed_should_apply(key, session_state):
    if not isinstance(session_state, dict):
        return True
    if session_state.get("server_key_wall_catchup_applied"):
        return False
    applied = session_state.setdefault("server_offline_elapsed_applied_keys", set())
    if key in applied:
        return False
    applied.add(key)
    return True


def normalize_saved_content_for_replay(key, content, session_state, log, for_replay=True, replay_elapsed_seconds=None):
    if not isinstance(content, dict):
        return content
    normalized = json.loads(json.dumps(content))
    account_username = (
        session_state.get("account_username")
        if isinstance(session_state, dict)
        else ""
    )
    if key == "prof" and account_username:
        old_account = normalized.get("10")
        if old_account != account_username:
            normalized["10"] = account_username
            log(
                "[SAVE] normalized prof account id "
                f"old_ref={sensitive_log_token(old_account)!r} "
                f"new_ref={sensitive_log_token(account_username)!r}"
            )
    normalize_client_timestamp_fields(
        key,
        normalized,
        log,
        "replay" if for_replay else "persist",
    )
    if key in PARK_OFFLINE_TIMER_KEYS:
        _sanitize_completed_plain_id_hatch_feed_values(
            normalized,
            log,
            f"{key} {'replay' if for_replay else 'persist'}",
        )
    if key == "prof":
        clear_prof_error_flag(
            normalized,
            log,
            "replay" if for_replay else "persist",
        )
        if for_replay:
            clear_profile_tournament_volatile_markers(
                normalized,
                log,
                "replay",
            )
        clear_profile_tournament_score_timer_pollution(
            normalized,
            log,
            "profile normalize",
        )
        clear_profile_battle_cooldown_payload(
            normalized,
            log,
            "profile normalize",
        )
    if for_replay and key == "prof":
        if replay_elapsed_seconds is not None:
            replay_state = dict(session_state or {})
            replay_state["server_offline_elapsed_seconds"] = replay_elapsed_seconds
            replay_state["timer_replay_source"] = "explicit-replay"
            apply_profile_offline_timers_for_replay(normalized, replay_state, log)
        elif offline_elapsed_should_apply("prof", session_state):
            apply_profile_offline_timers_for_replay(normalized, session_state, log)
    if for_replay and key == "gen":
        if replay_elapsed_seconds is not None:
            replay_state = dict(session_state or {})
            replay_state["server_offline_elapsed_seconds"] = replay_elapsed_seconds
            replay_state["timer_replay_source"] = "explicit-replay"
            apply_code_red_offline_timer_for_replay(normalized, replay_state, log)
        elif offline_elapsed_should_apply("gen", session_state):
            apply_code_red_offline_timer_for_replay(normalized, session_state, log)
    if for_replay and key in PARK_OFFLINE_TIMER_KEYS:
        if replay_elapsed_seconds is not None:
            replay_state = dict(session_state or {})
            replay_state["server_offline_elapsed_seconds"] = replay_elapsed_seconds
            replay_state["timer_replay_source"] = "explicit-replay"
            apply_active_offline_timers_for_replay(normalized, replay_state, log, park_key=key)
        elif offline_elapsed_should_apply(key, session_state):
            apply_active_offline_timers_for_replay(normalized, session_state, log, park_key=key)
    if for_replay and key in EXPEDITION_GEN_KEYS:
        if replay_elapsed_seconds is not None:
            replay_state = dict(session_state or {})
            replay_state["server_offline_elapsed_seconds"] = replay_elapsed_seconds
            replay_state["timer_replay_source"] = "explicit-replay"
            apply_expedition_offline_timers_for_replay(
                normalized, replay_state, log, gen_key=key
            )
        elif offline_elapsed_should_apply(key, session_state):
            apply_expedition_offline_timers_for_replay(
                normalized, session_state, log, gen_key=key
            )
    if for_replay and key == "batl":
        if replay_elapsed_seconds is not None:
            replay_state = dict(session_state or {})
            replay_state["server_offline_elapsed_seconds"] = replay_elapsed_seconds
            replay_state["timer_replay_source"] = "explicit-replay"
            apply_battle_offline_timers_for_replay(normalized, replay_state, log)
        elif offline_elapsed_should_apply("batl", session_state):
            apply_battle_offline_timers_for_replay(normalized, session_state, log)
    if (
        for_replay
        and replay_elapsed_seconds is not None
        and key in OFFLINE_TIMER_REPLAY_KEYS
    ):
        rebase_client_resume_anchor(
            normalized,
            now_ms=current_network_time_milliseconds(),
            log=log,
            label=f"explicit replay {key}",
        )
    return normalized


def _pack_signed64_from_u64(value):
    value &= 0xffffffffffffffff
    if value >= 0x8000000000000000:
        value -= 0x10000000000000000
    return value


def _add_to_high_u32(value, delta):
    packed = int(value) & 0xffffffffffffffff
    low = packed & 0xffffffff
    high = (packed >> 32) & 0xffffffff
    high = (high + int(delta)) & 0xffffffff
    return _pack_signed64_from_u64((high << 32) | low)


def _saturating_add_to_high_u32(value, delta):
    packed = int(value) & 0xffffffffffffffff
    low = packed & 0xffffffff
    high = (packed >> 32) & 0xffffffff
    high = min(0xffffffff, high + max(0, int(delta)))
    return _pack_signed64_from_u64((high << 32) | low)


def _low_u32(value):
    return int(value) & 0xffffffff


def _high_u32(value):
    return (int(value) & 0xffffffffffffffff) >> 32


def _replace_high_u32(value, high):
    packed = int(value) & 0xffffffffffffffff
    low = packed & 0xffffffff
    return _pack_signed64_from_u64(((int(high) & 0xffffffff) << 32) | low)


def _pack_u32_pair(low, high):
    return _pack_signed64_from_u64(
        ((int(high) & 0xffffffff) << 32) | (int(low) & 0xffffffff)
    )


EXPANSION_TIMER_MAX_WIRE_VALUE = 0xFFFFFFFF
EXPANSION_RECONNECT_READY_MARGIN_MS = 0


def _expansion_timer_cap_ms(state_value):
    state_high = _high_u32(_as_int(state_value, 0))
    if state_high <= 0:
        return 0
    # The native scene compares its internal millisecond timer to
    # duration_seconds*1000, but the storage packer serializes field-50 high as
    # internal_elapsed<<1.  The protocol/save cap is therefore *2000.
    cap_ms = state_high * 2000
    if cap_ms > EXPANSION_TIMER_MAX_WIRE_VALUE:
        return 0
    return cap_ms


def _expansion_timer_manageable(state_value, timer_value):
    cap_ms = _expansion_timer_cap_ms(state_value)
    return cap_ms > 0


def _expansion_timer_active(state_value, timer_value):
    cap_ms = _expansion_timer_cap_ms(state_value)
    if cap_ms <= 0:
        return False
    # Native scnExpansion completes only when elapsed is strictly greater than
    # duration*1000; equality remains a zero-seconds, still-active boundary.
    return _high_u32(_as_int(timer_value, 0)) <= cap_ms


def _expansion_timer_ready_to_clear(state_value, timer_value, ready_margin_ms=0):
    cap_ms = _expansion_timer_cap_ms(state_value)
    if cap_ms <= 0:
        return False
    ready_margin_ms = max(0, min(_as_int(ready_margin_ms, 0), max(0, cap_ms - 1)))
    elapsed_ms = _high_u32(_as_int(timer_value, 0))
    if ready_margin_ms > 0:
        ready_at_ms = max(0, cap_ms - ready_margin_ms)
        return elapsed_ms >= ready_at_ms
    return elapsed_ms > cap_ms


def _expansion_slot_manageable(states, timers, index):
    if not isinstance(states, list) or index < 0 or index >= len(states):
        return False
    state_value = _as_int(states[index], 0)
    if state_value == 0:
        return False
    if not isinstance(timers, list) or index >= len(timers):
        return _expansion_timer_cap_ms(state_value) > 0
    return _expansion_timer_manageable(state_value, timers[index])


def _clamp_expansion_timer_value(timer_value, state_value, ready_margin_ms=0):
    cap_ms = _expansion_timer_cap_ms(state_value)
    if cap_ms <= 0:
        return timer_value
    elapsed_ms = _high_u32(_as_int(timer_value, 0))
    ready_margin_ms = max(0, min(_as_int(ready_margin_ms, 0), max(0, cap_ms - 1)))
    if ready_margin_ms <= 0:
        # Native completion is strict elapsed>cap. Never turn the completed
        # cap+1 sentinel back into the still-active equality boundary.
        return timer_value
    if elapsed_ms < cap_ms or (elapsed_ms == cap_ms and ready_margin_ms <= 0):
        return timer_value
    target_ms = max(0, cap_ms - ready_margin_ms) if ready_margin_ms else cap_ms
    return _replace_high_u32(timer_value, target_ms)


def _clear_completed_expansion_slot(content, index, log=None, label=""):
    if not isinstance(content, dict):
        return 0
    values = content.get("50")
    states = content.get("51")
    starts = content.get("49")
    if (
        not isinstance(values, list)
        or not isinstance(states, list)
        or index < 0
        or index >= len(values)
        or index >= len(states)
    ):
        return 0

    old_value = values[index]
    old_state = states[index]
    cap_ms = _expansion_timer_cap_ms(old_state)
    if cap_ms <= 0:
        return 0

    try:
        new_value = _replace_high_u32(old_value, 0)
        old_high = _high_u32(old_value)
        old_low = _low_u32(old_value)
    except Exception:
        new_value = 0
        old_high = 0
        old_low = 0

    changed = 0
    old_start = None
    if isinstance(starts, list) and index < len(starts):
        old_start = starts[index]
        if starts[index] != 0:
            starts[index] = 0
            changed = 1
    if values[index] != new_value:
        values[index] = new_value
        changed = 1
    if states[index] != 0:
        states[index] = 0
        changed = 1

    if changed and log:
        start_text = f" start {old_start!r}->0" if old_start is not None else ""
        log(
            f"[TIME] {label} server-completed expansion slot[{index}]"
            f"{start_text} high32 {old_high}->0 low32={old_low} "
            f"state {old_state!r}->0 cap_ms={cap_ms}"
        )
    return changed


def complete_ready_expansion_slots_for_content(
    content,
    log=None,
    label="",
    ready_margin_ms=0,
):
    if not isinstance(content, dict):
        return 0
    values = content.get("50")
    states = content.get("51")
    if not isinstance(values, list) or not isinstance(states, list):
        return 0

    changed = 0
    for index in range(min(len(values), len(states))):
        state_value = _as_int(states[index], 0)
        if not _expansion_timer_manageable(state_value, values[index]):
            continue
        if not _expansion_timer_ready_to_clear(
            state_value,
            values[index],
            ready_margin_ms=ready_margin_ms,
        ):
            continue
        changed += _clear_completed_expansion_slot(content, index, log, label)
    return changed


def repair_active_expansion_ready_margins_for_content(content, log=None, label=""):
    return complete_ready_expansion_slots_for_content(
        content,
        log,
        label,
        ready_margin_ms=EXPANSION_RECONNECT_READY_MARGIN_MS,
    )


def repair_active_expansion_ready_margins(data, log=None, label=""):
    if not isinstance(data, dict):
        return 0
    changed = 0
    for key in PARK_OFFLINE_TIMER_KEYS:
        record = data.get(key)
        content = saved_content(record)
        count = repair_active_expansion_ready_margins_for_content(
            content,
            log,
            f"{label} {key}".strip(),
        )
        if count:
            changed += count
            if isinstance(record, dict):
                record["c"] = content
    return changed


def _advance_expansion_timer_value(timer_value, delta_ms, state_value, ready_margin_ms=0):
    if not _expansion_timer_manageable(state_value, timer_value):
        return timer_value
    cap_ms = _expansion_timer_cap_ms(state_value)
    elapsed_ms = _high_u32(_as_int(timer_value, 0))
    advanced_ms = max(0, elapsed_ms) + max(0, _as_int(delta_ms, 0))
    ready_margin_ms = max(0, min(_as_int(ready_margin_ms, 0), max(0, cap_ms - 1)))
    if ready_margin_ms > 0 and advanced_ms >= cap_ms:
        target_ms = max(0, cap_ms - ready_margin_ms)
        new_elapsed = target_ms if elapsed_ms >= cap_ms else max(elapsed_ms, target_ms)
    else:
        # Preserve the native strict completion edge.  cap+1 is sufficient for
        # the caller to clear the completed slot; cap itself remains active.
        new_elapsed = min(cap_ms + 1, advanced_ms)
    return _replace_high_u32(timer_value, new_elapsed)


def _advance_remaining_elapsed_u32_pair(value, delta, reset_elapsed_on_signed_overflow=False):
    """Mirror client resume(): low32 is remaining ms, high32 is elapsed ms."""
    remaining = _low_u32(value)
    elapsed = _high_u32(value)
    if remaining == 0:
        return value
    step = min(max(0, int(delta)), remaining)
    remaining = (remaining - step) & 0xffffffff
    elapsed = (elapsed + step) & 0xffffffff
    if reset_elapsed_on_signed_overflow and elapsed > 0x7fffffff:
        elapsed = 0
    return _pack_signed64_from_u64((elapsed << 32) | remaining)


def _building_type_for_index(content, index):
    types = content.get("62") if isinstance(content, dict) else None
    if isinstance(types, list) and index < len(types):
        return _as_int(types[index], None)
    return None


def _building_cycle_ms(content, index, value):
    # Field 61 carries the exact client/catalog cycle as elapsed+remaining.
    # A small observed-id table cannot safely override that persisted total.
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    if remaining > 0:
        return max(0, elapsed + remaining)
    return max(0, elapsed)


def _building_linked_double_elapsed_matches(linked_elapsed, building_elapsed):
    try:
        linked_elapsed = int(linked_elapsed)
        building_elapsed = int(building_elapsed)
    except Exception:
        return False
    return abs(linked_elapsed - (building_elapsed * 2)) <= BUILDING_LINKED_DOUBLE_TOLERANCE_MS


def _advance_building_production_timer_ms(
    value,
    elapsed_ms,
    total_ms=None,
    ready_grace_ms=0,
):
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    if total_ms is None or _as_int(total_ms, 0) <= 0:
        total = elapsed + remaining if remaining > 0 else elapsed
    else:
        total = max(0, _as_int(total_ms, 0))
    if total <= 0:
        return value
    new_elapsed = min(total, max(0, elapsed) + max(0, int(elapsed_ms or 0)))
    new_remaining = max(0, total - new_elapsed)
    grace = max(0, _as_int(ready_grace_ms, 0))
    if grace > 0 and 0 < new_remaining <= grace:
        new_elapsed = total
        new_remaining = 0
    return _pack_u32_pair(new_remaining, new_elapsed)


def _remaining_elapsed_total_ms(value):
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    if remaining > 0:
        return max(0, elapsed + remaining)
    return max(0, elapsed)


def _elapsed_reset_is_fresh(elapsed_ms, threshold_ms=POST_REPLAY_TIMER_RESET_MS):
    elapsed = max(0, _as_int(elapsed_ms, 0))
    threshold = max(0, _as_int(threshold_ms, 0))
    return elapsed <= threshold


def _building_timer_total_ms(value):
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    if remaining > 0:
        return max(0, elapsed + remaining)
    return max(0, elapsed)


def _building_linked_object_elapsed_ms(content, index):
    if not isinstance(content, dict):
        return None
    object_index = _building_object_index(content, index)
    object_timers = content.get("47")
    if (
        object_index is None
        or not isinstance(object_timers, list)
        or object_index < 0
        or object_index >= len(object_timers)
    ):
        return None
    return _high_u32(object_timers[object_index])


def _building_timer_object_slots(content, include_zeroed=False):
    slots = set()
    if not isinstance(content, dict):
        return slots
    building_count = _as_int(content.get("60"), 0)
    building_timers = content.get("61")
    if not isinstance(building_timers, list):
        return slots
    object_count = max(0, _as_int(content.get("45"), 0))
    for index in range(min(max(building_count, 0), len(building_timers))):
        value = building_timers[index]
        if (
            not include_zeroed
            and _high_u32(value) == 0
            and _low_u32(value) == 0
        ):
            continue
        slot = _building_object_index(content, index)
        if slot is None and object_count <= 0:
            slot = index
        if slot is not None:
            slots.add(slot)
    return slots


def _cap_object_production_timer_value(content, index, value):
    return value


def _building_cycle_ms_from_matching_object(content, object_index, skip_index=None):
    if not isinstance(content, dict):
        return 0
    objects = content.get("46")
    building_timers = content.get("61")
    if (
        not isinstance(objects, list)
        or not isinstance(building_timers, list)
        or object_index is None
        or object_index < 0
        or object_index >= len(objects)
    ):
        return 0
    object_id = objects[object_index]
    building_count = min(max(0, _as_int(content.get("60"), 0)), len(building_timers))
    for index in range(building_count):
        if skip_index is not None and index == skip_index:
            continue
        value = building_timers[index]
        if _high_u32(value) == 0 and _low_u32(value) == 0:
            continue
        sibling_object_index = _building_object_index(content, index)
        if sibling_object_index is None or sibling_object_index >= len(objects):
            continue
        if objects[sibling_object_index] != object_id:
            continue
        total = _building_cycle_ms(content, index, value)
        if total > 0:
            return total
    return 0


def promote_zeroed_building_rows_from_object_timers(content, log=None, label=""):
    """Keep zeroed construction rows neutral while object.47 carries build progress.

    A zeroed building.61 row is not enough evidence to infer a production cycle:
    newly placed construction buildings can arrive as 61=0,0 while object.47 is
    the only meaningful elapsed timer. Copying a sibling production cycle here
    makes new construction finish early and can create bogus coin bubbles.
    """
    if not isinstance(content, dict):
        return 0
    building_count = _as_int(content.get("60"), 0)
    building_timers = content.get("61")
    object_timers = content.get("47")
    if not isinstance(building_timers, list) or not isinstance(object_timers, list):
        return 0
    for index in range(min(max(building_count, 0), len(building_timers))):
        old_val = building_timers[index]
        try:
            if _high_u32(old_val) != 0 or _low_u32(old_val) != 0:
                continue
            object_index = _building_object_index(content, index)
            if object_index is None or object_index >= len(object_timers):
                continue
            object_value = object_timers[object_index]
            object_elapsed = max(0, _high_u32(object_value))
            if object_elapsed <= 0:
                continue
        except Exception as exc:
            if log:
                log(
                    f"[TIME] {label} zeroed building.61[{index}] inspect error: "
                    f"{exc!r}"
                )
            continue
        if log:
            log(
                f"[TIME] {label} kept zeroed construction building.61[{index}] "
                f"slot={object_index} object.47 elapsed={object_elapsed} "
                "reason=object47-construction-authority"
            )
    return 0


def _advance_building_production_timer(
    value,
    elapsed_sec,
    total_ms=None,
    ready_grace_ms=0,
):
    return _advance_building_production_timer_ms(
        value,
        max(0, int(elapsed_sec or 0)) * 1000,
        total_ms,
        ready_grace_ms=ready_grace_ms,
    )


def _normalize_building_production_timer(content, index, value):
    total = _building_cycle_ms(content, index, value)
    return _advance_building_production_timer_ms(value, 0, total)


def _building_object_index(content, index):
    object_count = max(0, _as_int(content.get("45"), 0))
    building_count = max(0, _as_int(content.get("60"), 0))
    slot = _building_type_for_index(content, index)
    if isinstance(slot, int) and 0 <= slot < object_count:
        return slot
    fallback = object_count - building_count + index
    if 0 <= fallback < object_count:
        return fallback
    if 0 <= index < object_count:
        return index
    return None


def _advance_object_visual_timers(
    content,
    elapsed_ms,
    log=None,
    label="",
    should_log=False,
    cap_production_limit_index=None,
):
    object_count = _as_int(content.get("45"), 0)
    object_timers = content.get("47")
    if not isinstance(object_timers, list):
        return 0
    # Native offline resume adds wall milliseconds once to the internal object
    # timer, then the storage packer serializes field-47 high as internal<<1.
    wall_delta = max(0, int(elapsed_ms or 0))
    delta = wall_delta * 2
    if delta <= 0:
        return 0
    changed = 0
    for index in range(min(max(object_count, 0), len(object_timers))):
        try:
            old_val = object_timers[index]
            new_val = _saturating_add_to_high_u32(old_val, delta)
            should_cap_production = (
                cap_production_limit_index is None
                or index < cap_production_limit_index
            )
            if should_cap_production:
                new_val = _cap_object_production_timer_value(content, index, new_val)
        except Exception as exc:
            if should_log and log:
                log(f"[TIME]   object.47[{index}] error: {exc!r}")
            continue
        if new_val == old_val:
            continue
        object_timers[index] = new_val
        changed += 1
        if should_log and log:
            cap_text = (
                f" cap={OBJECT_PRODUCTION_READY_CAP_MS}ms"
                if (
                    should_cap_production
                    and index not in _building_timer_object_slots(content, include_zeroed=True)
                    and _high_u32(new_val) == OBJECT_PRODUCTION_READY_CAP_MS
                    and _high_u32(old_val) + delta > OBJECT_PRODUCTION_READY_CAP_MS
                )
                else ""
            )
            log(
                f"[TIME]   object.47[{index}] advanced: {old_val} -> {new_val} "
                f"(+{delta} field-units from {wall_delta}ms wall{cap_text})"
            )
    return changed


def repair_inflated_object_production_timers(content, log, label):
    # Field 47 is shared by several object-level timers, including debris and
    # building bubble visuals. Capping it globally made longer debris/object
    # timers stall at the five-minute visual threshold.
    return 0


def repair_inflated_building_timers(content, log, label):
    # Persisted field 61 already carries its own elapsed+remaining total.  The
    # small observed-id table is insufficient authority to rewrite that total.
    return 0


def repair_building_ready_visual_offsets(content, log, label):
    # 301000 was produced by an older server-side field-47 cap, not a proven
    # client field-61 encoding.  A value alone is not enough to rewrite it.
    return 0


def _building_ready_elapsed_ms(total_ms):
    total = max(0, _as_int(total_ms, 0))
    return total


def _building_object_ready_elapsed_ms(building_elapsed):
    elapsed = max(0, _as_int(building_elapsed, 0))
    return elapsed


def _building_timer_ready_to_complete(content, index, value, ready_margin_ms=0):
    total = _building_cycle_ms(content, index, value)
    if total <= 0:
        return False
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    ready_margin_ms = max(0, min(_as_int(ready_margin_ms, 0), max(0, total - 1)))
    if remaining <= 0:
        return elapsed >= max(0, total - ready_margin_ms)
    if remaining <= ready_margin_ms:
        return True
    return elapsed >= max(0, total - ready_margin_ms)


def complete_ready_building_rows_for_content(
    content,
    log=None,
    label="",
    ready_margin_ms=0,
):
    # Exact field-61 advancement already caps elapsed at elapsed+remaining and
    # reaches remaining=0.  Generic repair from inferred ids is not needed.
    return 0


def _advance_building_timers_for_content(
    content,
    elapsed_sec,
    log,
    label,
    should_log=False,
    ready_grace_ms=0,
):
    building_count = _as_int(content.get("60"), 0)
    building_timers = content.get("61")
    elapsed_ms = max(0, int(elapsed_sec or 0)) * 1000
    ready_grace_ms = max(0, _as_int(ready_grace_ms, 0))
    if not isinstance(building_timers, list):
        if building_count > 0 and building_timers is not None:
            old_val = building_timers
            try:
                new_val = _advance_building_production_timer(
                    old_val,
                    elapsed_sec,
                    ready_grace_ms=ready_grace_ms,
                )
            except Exception as exc:
                if should_log:
                    log(f"[TIME]   building.61 scalar error: {exc!r}")
                return 0
            if new_val != old_val:
                content["61"] = new_val
                grace_applied = (
                    ready_grace_ms > 0
                    and _low_u32(old_val) > elapsed_ms
                    and _low_u32(new_val) == 0
                )
                if should_log or grace_applied:
                    grace_text = (
                        f" reconnect-ready-grace<={ready_grace_ms}ms"
                        if grace_applied
                        else ""
                    )
                    log(
                        f"[TIME]   building.61 scalar advanced: {old_val} -> {new_val} "
                        f"(+{elapsed_sec}s{grace_text})"
                    )
                return 1
        return 0
    changed = 0
    for index in range(min(max(building_count, 0), len(building_timers))):
        try:
            old_val = building_timers[index]
            total = _building_cycle_ms(content, index, old_val)
            new_val = _advance_building_production_timer(
                old_val,
                elapsed_sec,
                total,
                ready_grace_ms=ready_grace_ms,
            )
        except Exception as exc:
            if should_log:
                log(f"[TIME]   building.61[{index}] error: {exc!r}")
            continue
        if new_val == old_val:
            continue
        building_timers[index] = new_val
        changed += 1
        grace_applied = (
            ready_grace_ms > 0
            and _low_u32(old_val) > elapsed_ms
            and _low_u32(new_val) == 0
        )
        if should_log or grace_applied:
            grace_text = (
                f" reconnect-ready-grace<={ready_grace_ms}ms"
                if grace_applied
                else ""
            )
            log(
                f"[TIME]   building.61[{index}] advanced: {old_val} -> {new_val} "
                f"(+{elapsed_sec}s{grace_text})"
            )
    return changed


def sync_building_object_timers_for_storage(
    content,
    log,
    label,
    repair_zeroed_object_slots=False,
    complete_active_from_object=True,
):
    # Client traces prove these are independent clocks: field 61 advances at
    # one millisecond per wall millisecond and caps at its production cycle,
    # while linked field 47 advances at two units per wall millisecond and can
    # continue after field 61 is ready.  Never floor, complete, or reconstruct
    # either field from the other.
    return 0


def sanitize_building_timers_for_storage(content, elapsed_seconds, log, label):
    if not isinstance(content, dict):
        return 0
    elapsed = max(0, _as_int(elapsed_seconds, 0))
    changed = promote_zeroed_building_rows_from_object_timers(content, log, label)
    changed += repair_inflated_building_timers(content, log, label)
    changed += repair_building_ready_visual_offsets(content, log, label)
    changed += repair_inflated_object_production_timers(content, log, label)
    if elapsed > 0:
        changed += _advance_object_visual_timers(content, elapsed * 1000)
        changed += _advance_building_timers_for_content(
            content,
            elapsed,
            log,
            label,
            should_log=False,
        )
    changed += complete_ready_building_rows_for_content(
        content,
        log,
        label,
    )
    changed += sync_building_object_timers_for_storage(content, log, label)
    return changed


def repair_saved_building_timers(saved, log, label, sync_visuals=True):
    if not isinstance(saved, dict):
        return 0
    changed = 0
    for park_key in PARK_OFFLINE_TIMER_KEYS:
        content = _park_content(saved, park_key)
        if not content:
            continue
        changed += promote_zeroed_building_rows_from_object_timers(
            content,
            log,
            f"{label} {park_key}",
        )
        changed += repair_inflated_building_timers(content, log, f"{label} {park_key}")
        changed += repair_building_ready_visual_offsets(content, log, f"{label} {park_key}")
        changed += repair_inflated_object_production_timers(content, log, f"{label} {park_key}")
        changed += complete_ready_building_rows_for_content(
            content,
            log,
            f"{label} {park_key}",
        )
        if sync_visuals:
            changed += sync_building_object_timers_for_storage(
                content,
                log,
                f"{label} {park_key}",
            )
    return changed


def _zeroed_construction_building_candidates(content, object_ids=None):
    if not isinstance(content, dict):
        return []
    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    object_timers = content.get("47")
    object_ids_in_park = content.get("46")
    if (
        building_count <= 0
        or not isinstance(building_timers, list)
        or not isinstance(object_timers, list)
    ):
        return []
    allowed_ids = None
    if object_ids is not None:
        allowed_ids = {_as_int(item, None) for item in object_ids}
        allowed_ids.discard(None)
    candidates = []
    for index in range(min(building_count, len(building_timers))):
        try:
            building_value = _as_int(building_timers[index], 0)
            if _high_u32(building_value) != 0 or _low_u32(building_value) != 0:
                continue
            slot = _building_object_index(content, index)
            if slot is None or slot < 0 or slot >= len(object_timers):
                continue
            object_id = None
            if isinstance(object_ids_in_park, list) and slot < len(object_ids_in_park):
                object_id = _as_int(object_ids_in_park[slot], None)
            if allowed_ids is not None and object_id not in allowed_ids:
                continue
            object_value = _as_int(object_timers[slot], 0)
            candidates.append(
                {
                    "index": int(index),
                    "slot": int(slot),
                    "object_id": object_id,
                    "object_value": object_value,
                    "elapsed_ms": _high_u32(object_value),
                    "low32": _low_u32(object_value),
                }
            )
        except Exception:
            continue
    return candidates


def complete_zeroed_building_construction_for_content(
    content,
    log=None,
    label="",
    object_ids=None,
    building_name="",
):
    """Preserve save state; Android notifications are observations, not writes."""
    if log:
        log(
            f"[NOTIFY-TIMER] observed construction-ready notification "
            f"building={building_name!r} label={label!r}; save unchanged"
        )
    return 0


def _notification_object_ids_for_building_name(building_name):
    name = " ".join(str(building_name or "").lower().split())
    if not name:
        return None
    object_ids = set()
    for key, values in BUILDING_NOTIFICATION_OBJECT_IDS_BY_NAME.items():
        if key == name or key in name or name in key:
            object_ids.update(values)
    return object_ids or None


def extract_construction_notification_building_name(line):
    if not isinstance(line, str) or "construction has completed" not in line.lower():
        return None
    text = line
    match = re.search(r'"contentText"\s*:\s*"([^"]+)"', line)
    if match:
        text = match.group(1)
    match = re.search(
        r"Construction has completed on your\s+(.+?)\.",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    return match.group(1).strip()


def extract_hatch_notification_species_name(line):
    if not isinstance(line, str) or "ready to hatch" not in line.lower():
        return None
    text = line
    match = re.search(r'"contentText"\s*:\s*"([^"]+)"', line)
    if match:
        text = match.group(1)
    match = re.search(
        r"Your\s+(.+?)\s+is\s+ready\s+to\s+hatch\b",
        text,
        flags=re.IGNORECASE,
    )
    if not match:
        return ""
    return match.group(1).strip()


def trace_hatch_notification_to_saves(species_name, log, source="logcat"):
    save_ids = list_guest_save_ids()
    if not save_ids:
        if log:
            log(
                f"[HATCH-ID-TRACE] notification ignored species={species_name!r} "
                f"source={source!r} reason=no-saves"
            )
        return []
    save_ids.sort(
        key=lambda save_id: os.path.getmtime(guest_save_path(save_id))
        if os.path.exists(guest_save_path(save_id))
        else 0,
        reverse=True,
    )
    traces = []
    with SAVE_FILE_LOCK:
        for save_id in save_ids[:3]:
            path = guest_save_path(save_id)
            try:
                with open(path, "r", encoding="utf-8") as handle:
                    saved = json.load(handle)
            except Exception as exc:
                if log:
                    log(
                        f"[HATCH-ID-TRACE] could not read "
                        f"save_ref={sensitive_log_token(save_id)!r} "
                        f"species={species_name!r} source={source!r} "
                        f"error={compact_json(diagnostic_exception_summary(exc))}"
                    )
                continue
            if not isinstance(saved, dict):
                continue
            meta_slots = (
                saved.get("__meta", {})
                if isinstance(saved.get("__meta"), dict)
                else {}
            )
            hatch_root = (
                meta_slots.get(META_HATCH_READY_DEADLINES_KEY, {})
                if isinstance(meta_slots, dict)
                else {}
            )
            hatch_keys = hatch_root.get("keys", {}) if isinstance(hatch_root, dict) else {}
            for key in PARK_OFFLINE_TIMER_KEYS:
                record = saved.get(key)
                content = saved_content(record)
                if not isinstance(content, dict):
                    continue
                dino_count = max(0, _as_int(content.get("57"), 0))
                dino_timers = content.get("58")
                hatch_values = content.get("59")
                if not isinstance(dino_timers, list) or not isinstance(hatch_values, list):
                    continue
                key_deadlines = (
                    hatch_keys.get(key, {}).get("slots", {})
                    if isinstance(hatch_keys.get(key), dict)
                    else {}
                )
                rows = []
                for index in range(min(dino_count, len(dino_timers), len(hatch_values))):
                    dino_timer = _as_int(dino_timers[index], 0)
                    hatch_value = _as_int(hatch_values[index], 0)
                    if not _is_active_hatch_timer(dino_timer, hatch_value):
                        continue
                    elapsed = _high_u32(hatch_value)
                    dino_id = _low_u32(hatch_value)
                    ready_est = _hatch_ready_elapsed_seconds(dino_id, elapsed)
                    deadline = (
                        key_deadlines.get(str(index))
                        if isinstance(key_deadlines, dict)
                        else None
                    )
                    row = {
                        "slot": index,
                        "dino_id": dino_id,
                        "elapsed": elapsed,
                        "ready_est": ready_est,
                        "remaining_est": max(0, ready_est - elapsed),
                    }
                    if isinstance(deadline, dict):
                        row["deadline_ready_elapsed"] = _as_int(
                            deadline.get("ready_elapsed_seconds"), 0
                        )
                        row["deadline_remaining"] = _as_int(
                            deadline.get("remaining_seconds"), 0
                        )
                        row["deadline_ready_at_ms"] = _as_int(
                            deadline.get("ready_at_ms"), 0
                        )
                    rows.append(row)
                if rows:
                    trace = {
                        "save_id": save_id,
                        "key": key,
                        "species": str(species_name or ""),
                        "active_hatches": rows,
                    }
                    traces.append(trace)
                    if log:
                        trace_for_log = dict(trace)
                        trace_for_log["save_ref"] = sensitive_log_token(
                            trace_for_log.pop("save_id")
                        )
                        log(
                            f"[HATCH-ID-TRACE] notification correlation "
                            f"{compact_json(trace_for_log)} source={source!r}"
                        )
    if not traces and log:
        log(
            f"[HATCH-ID-TRACE] notification had no active hatch rows "
            f"species={species_name!r} source={source!r}"
        )
    return traces


def apply_building_construction_notification_to_saves(building_name, log, source="logcat"):
    if log:
        log(
            f"[NOTIFY-TIMER] observed construction notification "
            f"building={building_name!r} source={source!r}; save unchanged"
        )
    return []


def handle_logcat_notification(line, log):
    try:
        species_name = extract_hatch_notification_species_name(line)
        if species_name is not None:
            trace_hatch_notification_to_saves(
                species_name,
                log,
                source="logcat-hatch",
            )
            return
        building_name = extract_construction_notification_building_name(line)
        if building_name is None:
            return
        apply_building_construction_notification_to_saves(
            building_name,
            log,
            source="logcat-construction",
        )
    except Exception as exc:
        if log:
            log(f"[NOTIFY-TIMER] logcat notification handler error: {exc!r}")


def reset_incomplete_building_timers_after_battle(content, elapsed_seconds, log, label):
    updated = json.loads(json.dumps(content or {}))
    changed = _advance_building_timers_for_content(
        updated,
        elapsed_seconds,
        log,
        label,
        should_log=False,
    )
    return updated, changed


def _advance_port_timer(value, delta, reset_elapsed_on_signed_overflow=False):
    """Mirror client updateItemTimer(): high32 is remaining ms, low32 is elapsed ms."""
    remaining = _high_u32(value)
    elapsed = _low_u32(value)
    if remaining == 0:
        return value
    step = min(max(0, int(delta)), remaining)
    remaining = (remaining - step) & 0xffffffff
    elapsed = (elapsed + step) & 0xffffffff
    if reset_elapsed_on_signed_overflow and elapsed > 0x7fffffff:
        elapsed = 0
    return _pack_signed64_from_u64((remaining << 32) | elapsed)


def _port_cycle_wall_map(data, park_key, create=False):
    if not isinstance(data, dict):
        return {}
    meta = data.setdefault("__meta", {}) if create else data.get("__meta", {})
    if not isinstance(meta, dict):
        return {}
    walls = (
        meta.setdefault("port_cycle_walls", {})
        if create
        else meta.get("port_cycle_walls", {})
    )
    if not isinstance(walls, dict):
        return {}
    park_walls = (
        walls.setdefault(str(park_key), {})
        if create
        else walls.get(str(park_key), {})
    )
    return park_walls if isinstance(park_walls, dict) else {}


def stamp_port_cycle_walls(data, park_key, indexes, now_ms=None, log=None, label=""):
    if not isinstance(data, dict) or not indexes:
        return 0
    now_ms = timer_wall_ms(now_ms)
    park_walls = _port_cycle_wall_map(data, park_key, create=True)
    changed = 0
    for index in indexes:
        wall_key = str(index)
        previous_wall = _as_int(park_walls.get(wall_key), 0)
        park_walls[wall_key] = now_ms
        changed += 1
        if callable(log):
            log(
                f"[TIME] {label} stamped port cycle wall park={park_key!r} "
                f"index={index} wall_ms={now_ms} previous={previous_wall}"
            )
    return changed


def merge_generated_port_cycle_walls(saved, candidate, park_key):
    """Retain only generated harbor cycle anchors from an isolated merge root."""
    source = _port_cycle_wall_map(candidate, park_key, create=False)
    if not source:
        return 0
    destination = _port_cycle_wall_map(saved, park_key, create=True)
    changed = 0
    for index in range(2):
        wall_key = str(index)
        wall_ms = _as_int(source.get(wall_key), 0)
        if wall_ms <= 0 or _as_int(destination.get(wall_key), 0) == wall_ms:
            continue
        destination[wall_key] = wall_ms
        changed += 1
    return changed


def _port_replay_elapsed_ms_for_index(
    data,
    park_key,
    index,
    port_value,
    requested_ms,
    park_record=None,
    now_ms=None,
):
    requested_ms = max(0, _as_int(requested_ms, 0))
    if requested_ms <= 0:
        return 0
    remaining = _high_u32(port_value)
    if remaining <= 0:
        return 0
    now_ms = timer_wall_ms(now_ms)

    if isinstance(data, dict):
        anchor_ms = _as_int(_port_cycle_wall_map(data, park_key).get(str(index)), 0)
        if anchor_ms > 0:
            return min(requested_ms, max(0, now_ms - anchor_ms))

    elapsed = _low_u32(port_value)
    cycle_total = remaining + elapsed
    record_wall_ms = timer_key_record_wall_ms(park_record)
    if (
        cycle_total > 0
        and elapsed <= POST_REPLAY_TIMER_RESET_MS
        and remaining >= min(600_000, cycle_total // 2)
        and record_wall_ms > 0
    ):
        record_age_ms = timer_record_elapsed_since_update_ms(
            park_record,
            now_ms=now_ms,
        )
        return min(requested_ms, elapsed + record_age_ms)

    return requested_ms


def _advance_timer_int(value, elapsed_sec):
    """Reduce a stored countdown by offline elapsed wall time."""
    try:
        current = int(value)
    except (TypeError, ValueError):
        return value
    if current <= 0 or elapsed_sec <= 0:
        return current
    elapsed = int(elapsed_sec)
    if 1 <= current <= 604_800:
        return max(0, current - elapsed)
    if 1_000 <= current <= 604_800_000:
        return max(0, current - elapsed * 1_000)
    if current <= 100_000_000_000_000:
        return max(0, current - elapsed * 1_000_000)
    return current


def _advance_catalog_timer_list(values, elapsed_sec):
    """Advance only large hatch-timer slots; leave level/flag slots untouched."""
    if not isinstance(values, list):
        return values
    out = []
    for item in values:
        try:
            current = int(item)
        except (TypeError, ValueError):
            out.append(item)
            continue
        if current <= 0 or current < GEN_CATALOG_TIMER_MIN:
            out.append(current)
        else:
            out.append(_advance_timer_int(current, elapsed_sec))
    return out


def _advance_incubator_timer_list(values, elapsed_sec):
    if not isinstance(values, list):
        return values
    return [_advance_timer_int(item, elapsed_sec) for item in values]



def _add_to_low32_high_u16(value, delta):
    packed = int(value) & 0xffffffffffffffff
    low16 = packed & 0xffff
    high16 = (packed >> 16) & 0xffff
    rest = packed & 0xffffffff00000000
    high16 = min(0xffff, high16 + max(0, int(delta)))
    return _pack_signed64_from_u64(rest | (high16 << 16) | low16)


def _low32_high_u16(value):
    return (int(value) & 0xffffffff) >> 16


def _add_to_p59_hatch_elapsed(value, delta):
    packed = int(value) & 0xffffffffffffffff
    low32 = packed & 0xffffffff
    elapsed = (packed >> 32) & 0xffffffff
    elapsed = min(0xffffffff, elapsed + max(0, int(delta)))
    return _pack_signed64_from_u64((elapsed << 32) | low32)


def _hatch_reconnect_ready_grace_seconds(session_state):
    if not isinstance(session_state, dict):
        return 0
    source = str(session_state.get("timer_replay_source", "") or "")
    if not (
        source == "offline-login"
        or source == "explicit-replay"
        or source.endswith("-key-wall")
    ):
        return 0
    return max(0, _as_int(HATCH_RECONNECT_READY_GRACE_SECONDS, 0))


def _hatch_reconnect_rounding_grace(value, session_state):
    grace_seconds = _hatch_reconnect_ready_grace_seconds(session_state)
    if grace_seconds <= 0:
        return 0
    source = str(session_state.get("timer_replay_source", "") or "")
    try:
        elapsed = _high_u32(value)
        dino_id = _low_u32(value)
    except Exception:
        return 0
    if source != "offline-login":
        ready_elapsed = _hatch_ready_elapsed_seconds(dino_id, elapsed)
        if ready_elapsed > elapsed and ready_elapsed - elapsed > grace_seconds:
            return 0
    round_seconds = max(0, int(HATCH_RECONNECT_ROUND_SECONDS))
    if round_seconds <= 1:
        return 0
    remainder = elapsed % round_seconds
    if remainder == 0:
        return 0
    return round_seconds - remainder


def _building_reconnect_ready_grace_ms(session_state):
    if not isinstance(session_state, dict):
        return 0
    source = str(session_state.get("timer_replay_source", "") or "")
    if not (
        source == "offline-login"
        or source == "explicit-replay"
        or source.endswith("-key-wall")
    ):
        return 0
    return max(0, _as_int(BUILDING_RECONNECT_READY_GRACE_MS, 0))


def _battle_cooldown_parts(value):
    packed = int(value) & 0xffffffffffffffff
    high = (packed >> 32) & 0xffffffff
    low = packed & 0xffffffff
    return high, low


BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS = 60 * 1000
BATTLE_COOLDOWN_PARTS_META_KEY = "battle_cooldown_parts"
BATTLE_COOLDOWN_PARTS_META_VERSION = 2


def _battle_cooldown_part_key(index, part_name, field="104"):
    return (
        f"{str(field)}:{max(0, _as_int(index, 0))}:{str(part_name)}"
    )


def _battle_cooldown_tracker_root(saved, create=False):
    if not isinstance(saved, dict):
        return {}
    meta = _saved_meta(saved) if create else saved.get("__meta", {})
    if not isinstance(meta, dict):
        return {}
    root = meta.get(BATTLE_COOLDOWN_PARTS_META_KEY)
    if not isinstance(root, dict):
        if not create:
            return {}
        root = {"version": BATTLE_COOLDOWN_PARTS_META_VERSION, "parts": {}}
        meta[BATTLE_COOLDOWN_PARTS_META_KEY] = root
        return root

    version = _as_int(root.get("version"), 1)
    if version == 1 and create:
        old_parts = root.get("parts")
        migrated_parts = {}
        if isinstance(old_parts, dict):
            for key, record in old_parts.items():
                match = re.fullmatch(r"(\d+):(high|low)", str(key))
                if match:
                    migrated_key = _battle_cooldown_part_key(
                        int(match.group(1)),
                        match.group(2),
                        field="104",
                    )
                else:
                    migrated_key = str(key)
                migrated_parts[migrated_key] = record
        root = {
            "version": BATTLE_COOLDOWN_PARTS_META_VERSION,
            "parts": migrated_parts,
        }
        meta[BATTLE_COOLDOWN_PARTS_META_KEY] = root
        return root

    if version not in (1, BATTLE_COOLDOWN_PARTS_META_VERSION):
        if not create:
            return {}
        root = {"version": BATTLE_COOLDOWN_PARTS_META_VERSION, "parts": {}}
        meta[BATTLE_COOLDOWN_PARTS_META_KEY] = root
    return root


def _battle_cooldown_tracker_parts(saved, create=False):
    root = _battle_cooldown_tracker_root(saved, create=create)
    if not isinstance(root, dict):
        return {}
    parts = root.get("parts")
    if not isinstance(parts, dict):
        if not create:
            return {}
        parts = {}
        root["parts"] = parts
    return parts


def _battle_cooldown_tracked_part_sets(saved, now_ms=None, field="104"):
    now = timer_wall_ms(now_ms)
    tracked = set()
    expired = set()
    root = _battle_cooldown_tracker_root(saved)
    version = _as_int(root.get("version"), 1) if isinstance(root, dict) else 1
    for key, record in _battle_cooldown_tracker_parts(saved).items():
        if not isinstance(record, dict):
            continue
        if version == 1:
            if str(field) != "104":
                continue
            match = re.fullmatch(r"(\d+):(high|low)", str(key))
            key_field = "104"
            index_group = 1
            part_group = 2
        else:
            match = re.fullmatch(r"(\d+):(\d+):(high|low)", str(key))
            key_field = match.group(1) if match else ""
            index_group = 2
            part_group = 3
        if not match:
            continue
        if key_field != str(field):
            continue
        part = (int(match.group(index_group)), match.group(part_group))
        tracked.add(part)
        deadline = _as_int(record.get("deadline_ms"), 0)
        if deadline > 0 and deadline <= now:
            expired.add(part)
    return tracked, expired


def _battle_cooldown_tracked_part_sets_by_field(saved, now_ms=None):
    tracked = {}
    expired = {}
    for field in BATTLE_COOLDOWN_FIELDS:
        field_tracked, field_expired = _battle_cooldown_tracked_part_sets(
            saved,
            now_ms=now_ms,
            field=field,
        )
        tracked[field] = field_tracked
        expired[field] = field_expired
    return tracked, expired


def _battle_cooldown_parts_for_field(parts, field):
    if isinstance(parts, dict):
        return set(parts.get(str(field)) or ())
    if str(field) == "104":
        return set(parts or ())
    return set()


def _replace_battle_cooldown_part(value, part_name, remaining_ms):
    high, low = _battle_cooldown_parts(value)
    remaining = max(0, min(0xffffffff, _as_int(remaining_ms, 0)))
    if part_name == "high":
        high = remaining
    else:
        low = remaining
    return _pack_signed64_from_u64((high << 32) | low)


def reconcile_battle_cooldown_tracker(
    saved,
    previous_content,
    final_content,
    log,
    label,
    allow_active_increase=False,
    allow_active_clear=False,
    now_ms=None,
):
    """Persist exact batl cooldown field/slot/half identity after a write."""
    if not isinstance(saved, dict) or not isinstance(final_content, dict):
        return 0
    now = timer_wall_ms(now_ms)
    parts = _battle_cooldown_tracker_parts(saved, create=True)
    changed = 0
    seen = set()
    present_fields = set()

    for field in BATTLE_COOLDOWN_FIELDS:
        values = final_content.get(field)
        if not isinstance(values, list):
            continue
        present_fields.add(field)
        previous_values = (
            previous_content.get(field)
            if isinstance(previous_content, dict)
            and isinstance(previous_content.get(field), list)
            else []
        )

        for index, value in enumerate(values):
            high, low = _battle_cooldown_parts(value)
            previous_high, previous_low = (
                _battle_cooldown_parts(previous_values[index])
                if index < len(previous_values)
                else (0, 0)
            )
            for part_name, raw, previous_raw in (
                ("high", high, previous_high),
                ("low", low, previous_low),
            ):
                key = _battle_cooldown_part_key(index, part_name, field=field)
                seen.add(key)
                record = parts.get(key) if isinstance(parts.get(key), dict) else None
                strongly_identified = (
                    raw >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
                    or previous_raw >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
                    or record is not None
                )
                if not strongly_identified:
                    continue

                if raw <= 0:
                    deadline = _as_int(record.get("deadline_ms"), 0) if record else 0
                    if record and (
                        allow_active_clear or (deadline > 0 and deadline <= now)
                    ):
                        parts.pop(key, None)
                        changed += 1
                        if callable(log):
                            log(
                                f"[BATTLE] {label} cleared tracked "
                                f"batl.{field}[{index}].{part_name} "
                                f"deadline_ms={deadline} now_ms={now}"
                            )
                    continue

                if record:
                    last_remaining = max(
                        0,
                        _as_int(record.get("last_remaining_ms"), 0),
                    )
                    deadline = _as_int(record.get("deadline_ms"), 0)
                    deadline_remaining = (
                        max(0, deadline - now)
                        if deadline > 0
                        else last_remaining
                    )
                    ceiling = max(last_remaining, deadline_remaining)
                    if raw > ceiling and not allow_active_increase:
                        continue

                new_record = {
                    "last_remaining_ms": raw,
                    "deadline_ms": now + raw,
                    "observed_at_ms": now,
                }
                if parts.get(key) != new_record:
                    parts[key] = new_record
                    changed += 1
                    if callable(log):
                        log(
                            f"[BATTLE] {label} tracked "
                            f"batl.{field}[{index}].{part_name} "
                            f"remaining_ms={raw} deadline_ms={now + raw}"
                        )

    if allow_active_clear:
        for key in list(parts.keys()):
            if key in seen:
                continue
            match = re.fullmatch(r"(\d+):(\d+):(high|low)", str(key))
            if not match or match.group(1) not in present_fields:
                continue
            parts.pop(key, None)
            changed += 1
    return changed


def advance_battle_cooldown_tracker(
    saved,
    content,
    elapsed_ms,
    log,
    label,
    now_ms=None,
):
    """Advance discovered cooldown halves through sub-minute values to zero."""
    if not isinstance(saved, dict) or not isinstance(content, dict):
        return 0
    now = timer_wall_ms(now_ms)
    elapsed = max(0, _as_int(elapsed_ms, 0))
    parts = _battle_cooldown_tracker_parts(saved, create=True)
    changed = 0
    seen = set()
    present_fields = set()

    for field in BATTLE_COOLDOWN_FIELDS:
        values = content.get(field)
        if not isinstance(values, list):
            continue
        present_fields.add(field)
        for index, value in enumerate(values):
            current_value = value
            high, low = _battle_cooldown_parts(current_value)
            for part_name, raw in (("high", high), ("low", low)):
                key = _battle_cooldown_part_key(index, part_name, field=field)
                record = parts.get(key) if isinstance(parts.get(key), dict) else None
                if record is None and raw < BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS:
                    continue
                seen.add(key)
                if record:
                    deadline = _as_int(record.get("deadline_ms"), 0)
                    deadline_remaining = (
                        max(0, deadline - now) if deadline > 0 else raw
                    )
                    elapsed_remaining = (
                        max(0, raw - elapsed) if raw > 0 else deadline_remaining
                    )
                    new_remaining = min(deadline_remaining, elapsed_remaining)
                else:
                    new_remaining = max(0, raw - elapsed)

                if new_remaining != raw:
                    current_value = _replace_battle_cooldown_part(
                        current_value,
                        part_name,
                        new_remaining,
                    )
                    changed += 1
                    if callable(log):
                        log(
                            f"[TIME]   {label} "
                            f"batl.{field}[{index}].{part_name} "
                            f"cooldown {raw}->{new_remaining} (+{elapsed}ms)"
                        )
                if new_remaining > 0:
                    parts[key] = {
                        "last_remaining_ms": new_remaining,
                        "deadline_ms": now + new_remaining,
                        "observed_at_ms": now,
                    }
                elif key in parts:
                    parts.pop(key, None)
                    changed += 1
                high, low = _battle_cooldown_parts(current_value)
            values[index] = current_value

    for key in list(parts.keys()):
        if key in seen:
            continue
        match = re.fullmatch(r"(\d+):(\d+):(high|low)", str(key))
        if not match or match.group(1) not in present_fields:
            continue
        values = content.get(match.group(1))
        if isinstance(values, list) and int(match.group(2)) >= len(values):
            parts.pop(key, None)
            changed += 1
    return changed


def _battle_cooldown_remaining_ms(value, tracked_halves=None):
    high, low = _battle_cooldown_parts(value)
    values = []
    tracked_halves = set(tracked_halves or ())
    for part_name, part in (("high", high), ("low", low)):
        # Discover only strong millisecond values, then retain exact half-slot
        # identity through the final minute. Untracked small halves remain
        # opaque flags/state.
        if part >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS or part_name in tracked_halves:
            if part <= 0:
                continue
            values.append(part)
    return values


def _advance_battle_cooldown_value(value, elapsed_ms, tracked_halves=None):
    packed = int(value) & 0xffffffffffffffff
    high, low = _battle_cooldown_parts(value)
    changed = False
    tracked_halves = set(tracked_halves or ())
    if high >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS or "high" in tracked_halves:
        high = max(0, high - elapsed_ms)
        changed = True
    if low >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS or "low" in tracked_halves:
        low = max(0, low - elapsed_ms)
        changed = True
    if not changed:
        return value
    return _pack_signed64_from_u64((high << 32) | low)


def battle_cooldown_remaining_values(
    content,
    elapsed_ms=0,
    tracked_parts=None,
    field="104",
):
    if not isinstance(content, dict):
        return []
    values = content.get(str(field))
    if not isinstance(values, list):
        return []
    remaining = []
    elapsed_ms = max(0, int(elapsed_ms or 0))
    for index, value in enumerate(values):
        tracked_halves = {
            part_name
            for tracked_index, part_name in (tracked_parts or set())
            if tracked_index == index
        }
        for part in _battle_cooldown_remaining_ms(value, tracked_halves):
            part = max(0, part - elapsed_ms)
            if part > 0:
                remaining.append(part)
    remaining.sort(reverse=True)
    return remaining


def battle_cooldown_indexed_remaining_values(
    content,
    elapsed_ms=0,
    tracked_parts=None,
    field="104",
):
    if not isinstance(content, dict):
        return []
    values = content.get(str(field))
    if not isinstance(values, list):
        return []
    remaining = []
    elapsed_ms = max(0, int(elapsed_ms or 0))
    for index, value in enumerate(values):
        tracked_halves = {
            part_name
            for tracked_index, part_name in (tracked_parts or set())
            if tracked_index == index
        }
        slot_remaining = []
        for part in _battle_cooldown_remaining_ms(value, tracked_halves):
            part = max(0, part - elapsed_ms)
            if part > 0:
                slot_remaining.append(part)
        if slot_remaining:
            remaining.append((index, max(slot_remaining)))
    return remaining


def battle_cooldown_indexed_part_remaining_values(
    content,
    elapsed_ms=0,
    tracked_parts=None,
    field="104",
):
    if not isinstance(content, dict):
        return []
    values = content.get(str(field))
    if not isinstance(values, list):
        return []
    remaining = []
    elapsed_ms = max(0, int(elapsed_ms or 0))
    for index, value in enumerate(values):
        high, low = _battle_cooldown_parts(value)
        for part_name, raw_part in (("high", high), ("low", low)):
            if (
                raw_part < BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
                and (index, part_name) not in (tracked_parts or set())
            ):
                continue
            part = max(0, raw_part - elapsed_ms)
            if part > 0:
                remaining.append((index, part_name, part))
    return remaining


def battle_cooldown_remaining_values_by_field(
    content,
    elapsed_ms=0,
    tracked_parts=None,
):
    result = {}
    for field in BATTLE_COOLDOWN_FIELDS:
        remaining = battle_cooldown_remaining_values(
            content,
            elapsed_ms=elapsed_ms,
            tracked_parts=_battle_cooldown_parts_for_field(tracked_parts, field),
            field=field,
        )
        if remaining:
            result[field] = remaining
    return result


def battle_cooldown_remaining_values_all_fields(
    content,
    elapsed_ms=0,
    tracked_parts=None,
):
    remaining = []
    for values in battle_cooldown_remaining_values_by_field(
        content,
        elapsed_ms=elapsed_ms,
        tracked_parts=tracked_parts,
    ).values():
        remaining.extend(values)
    remaining.sort(reverse=True)
    return remaining


def battle_cooldown_indexed_part_remaining_values_all_fields(
    content,
    elapsed_ms=0,
    tracked_parts=None,
):
    remaining = []
    for field in BATTLE_COOLDOWN_FIELDS:
        field_parts = _battle_cooldown_parts_for_field(tracked_parts, field)
        for index, part_name, value in battle_cooldown_indexed_part_remaining_values(
            content,
            elapsed_ms=elapsed_ms,
            tracked_parts=field_parts,
            field=field,
        ):
            remaining.append((field, index, part_name, value))
    return remaining


def _profile_battle_cooldown_remaining_values(content):
    if not isinstance(content, dict):
        return []
    elapsed_values = content.get("111")
    duration_values = content.get("112")
    if not isinstance(elapsed_values, list) or not isinstance(duration_values, list):
        return []
    remaining = []
    for index in range(min(len(elapsed_values), len(duration_values))):
        duration = _as_int(duration_values[index], 0)
        current = _as_int(elapsed_values[index], 0)
        value = current if current > 0 else duration
        if value >= 60 * 1000:
            remaining.append(value)
    remaining.sort(reverse=True)
    return remaining[:3]


def timer_wall_ms(now_ms=None):
    if now_ms is not None:
        return max(0, _as_int(now_ms, 0))
    return int(time.time() * 1000)


def timer_metadata_seed_wall_ms(data, now_ms=None):
    now = timer_wall_ms(now_ms)
    if not isinstance(data, dict):
        return now
    meta = data.get("__meta", {})
    if not isinstance(meta, dict):
        return now
    saved_ms = _as_int(meta.get("last_server_save_time_ms"), 0)
    if saved_ms > 0:
        return saved_ms
    saved_s = _as_int(meta.get("last_server_save_time"), 0)
    if saved_s > 0:
        return saved_s * 1000
    loaded_mtime = _as_int(meta.get("_loaded_file_mtime"), 0)
    if loaded_mtime > 0:
        return loaded_mtime * 1000
    return now


def timer_key_wall_map(data, create=True):
    if not isinstance(data, dict):
        return {}
    meta = data.setdefault("__meta", {}) if create else data.get("__meta", {})
    if not isinstance(meta, dict):
        if not create:
            return {}
        meta = {}
        data["__meta"] = meta
    wall = meta.setdefault(META_TIMER_KEY_WALL_KEY, {}) if create else meta.get(META_TIMER_KEY_WALL_KEY, {})
    if not isinstance(wall, dict):
        if not create:
            return {}
        wall = {}
        meta[META_TIMER_KEY_WALL_KEY] = wall
    return wall


def timer_key_record_wall_ms(record):
    if not isinstance(record, dict):
        return 0
    updated_at_ms = _as_int(record.get("updated_at_ms"), 0)
    if updated_at_ms > 0:
        return updated_at_ms
    updated_at = _as_int(record.get("updated_at"), 0)
    if updated_at > 0:
        return updated_at * 1000
    return 0


def stamp_timer_record_wall(record, now_ms=None):
    if not isinstance(record, dict):
        return 0
    wall_ms = timer_wall_ms(now_ms)
    record["updated_at"] = wall_ms // 1000
    record["updated_at_ms"] = wall_ms
    return wall_ms


def timer_record_elapsed_since_update_ms(record, now_ms=None):
    if not isinstance(record, dict):
        return 0
    current_ms = timer_wall_ms(now_ms)
    exact_previous_ms = _as_int(record.get("updated_at_ms"), 0)
    if exact_previous_ms > 0:
        return max(0, current_ms - exact_previous_ms)
    previous_seconds = _as_int(record.get("updated_at"), 0)
    if previous_seconds <= 0:
        return 0
    return max(
        0,
        current_ms
        - previous_seconds * 1000
        - RECORD_UPDATED_AT_FLOOR_UNCERTAINTY_MS,
    )


def timer_key_seed_wall_ms(data, key, now_ms=None):
    if not isinstance(data, dict):
        return timer_wall_ms(now_ms)
    wall = timer_key_wall_map(data, create=False)
    entry = wall.get(str(key or ""))
    if isinstance(entry, dict):
        wall_ms = _as_int(entry.get("last_wall_ms"), 0)
        if wall_ms > 0:
            return wall_ms
    record_wall = timer_key_record_wall_ms(data.get(str(key or "")))
    if record_wall > 0:
        return record_wall
    return timer_metadata_seed_wall_ms(data, now_ms=now_ms)


def mark_timer_key_wall(data, key, log=None, label="", now_ms=None):
    if not isinstance(data, dict) or not key:
        return False
    key = str(key)
    wall = timer_key_wall_map(data, create=True)
    now = timer_wall_ms(now_ms)
    previous = wall.get(key) if isinstance(wall.get(key), dict) else {}
    old_wall = _as_int(previous.get("last_wall_ms"), 0)
    wall[key] = {
        "last_wall_ms": now,
        "label": str(label or ""),
    }
    if log and old_wall != now:
        log(
            f"[CLOCK] timer-key-wall key={key!r} "
            f"{old_wall}->{now} label={label!r}"
        )
    return old_wall != now


def ensure_timer_key_walls(data, log=None, label="ensure", now_ms=None):
    if not isinstance(data, dict):
        return 0
    changed = 0
    for key in OFFLINE_TIMER_REPLAY_KEYS:
        if not isinstance(data.get(key), dict):
            continue
        wall = timer_key_wall_map(data, create=False)
        entry = wall.get(key)
        if isinstance(entry, dict) and _as_int(entry.get("last_wall_ms"), 0) > 0:
            continue
        seed = timer_key_seed_wall_ms(data, key, now_ms=now_ms)
        changed += 1 if mark_timer_key_wall(data, key, log, f"{label}:seed", now_ms=seed) else 0
    return changed


def timer_key_elapsed_details(data, key, now_seconds=None, now_ms=None):
    if now_ms is None:
        if now_seconds is None:
            now_ms = timer_wall_ms()
        else:
            now_ms = max(0, _as_int(now_seconds, 0)) * 1000
    else:
        now_ms = timer_wall_ms(now_ms)
    wall_ms = timer_key_seed_wall_ms(data, key, now_ms=now_ms)
    raw_elapsed_ms = now_ms - wall_ms if wall_ms > 0 else 0
    raw_elapsed = raw_elapsed_ms // 1000 if raw_elapsed_ms > 0 else 0
    elapsed = _clamped_timer_elapsed_seconds(raw_elapsed)
    applied_wall_ms = wall_ms + elapsed * 1000 if wall_ms > 0 else now_ms
    return {
        "key": str(key or ""),
        "source": "timer_key_wall",
        "elapsed_seconds": elapsed,
        "raw_elapsed_seconds": raw_elapsed,
        "raw_elapsed_ms": raw_elapsed_ms,
        "last_saved_at": wall_ms // 1000 if wall_ms > 0 else 0,
        "last_wall_ms": wall_ms,
        "server_now_seconds": now_ms // 1000,
        "server_now_ms": now_ms,
        "applied_wall_ms": applied_wall_ms,
    }


def log_timer_key_elapsed_details(log, label, details):
    if not callable(log) or not isinstance(details, dict):
        return
    log(
        f"[CLOCK] key-elapsed label={label!r} key={details.get('key')!r} "
        f"elapsed={details.get('elapsed_seconds')}s "
        f"raw={details.get('raw_elapsed_seconds')}s "
        f"raw_ms={details.get('raw_elapsed_ms')} "
        f"last_wall_ms={details.get('last_wall_ms')} "
        f"server_now={details.get('server_now_seconds')} "
        f"server_now_ms={details.get('server_now_ms')} "
        f"applied_wall_ms={details.get('applied_wall_ms')}"
    )


def building_ready_deadline_root(data, create=True):
    if not isinstance(data, dict):
        return {}
    meta = data.setdefault("__meta", {}) if create else data.get("__meta", {})
    if not isinstance(meta, dict):
        if not create:
            return {}
        meta = {}
        data["__meta"] = meta
    root = meta.get(META_BUILDING_READY_DEADLINES_KEY)
    if not isinstance(root, dict):
        if not create:
            return {}
        root = {
            "version": BUILDING_READY_DEADLINES_VERSION,
            "keys": {},
        }
        meta[META_BUILDING_READY_DEADLINES_KEY] = root
    keys = root.get("keys")
    if not isinstance(keys, dict):
        if not create:
            return {}
        keys = {}
        root["keys"] = keys
    root["version"] = BUILDING_READY_DEADLINES_VERSION
    return root


def building_ready_deadline_slots(data, key, create=True):
    root = building_ready_deadline_root(data, create=create)
    if not isinstance(root, dict):
        return {}
    keys = root.get("keys")
    if not isinstance(keys, dict):
        return {}
    key = str(key or "")
    entry = keys.get(key)
    if not isinstance(entry, dict):
        if not create:
            return {}
        entry = {"slots": {}}
        keys[key] = entry
    slots = entry.get("slots")
    if not isinstance(slots, dict):
        if not create:
            return {}
        slots = {}
        entry["slots"] = slots
    return slots


def building_ready_deadline_summary(data):
    root = building_ready_deadline_root(data, create=False)
    keys = root.get("keys", {}) if isinstance(root, dict) else {}
    summary = {}
    if not isinstance(keys, dict):
        return summary
    for key, entry in keys.items():
        slots = entry.get("slots", {}) if isinstance(entry, dict) else {}
        if isinstance(slots, dict) and slots:
            summary[str(key)] = len(slots)
    return summary


def construction_wall_root(data, create=True):
    if not isinstance(data, dict):
        return {}
    meta = data.setdefault("__meta", {}) if create else data.get("__meta", {})
    if not isinstance(meta, dict):
        if not create:
            return {}
        meta = {}
        data["__meta"] = meta
    root = meta.get(META_CONSTRUCTION_WALL_KEY)
    if not isinstance(root, dict):
        if not create:
            return {}
        root = {
            "version": CONSTRUCTION_WALL_VERSION,
            "keys": {},
        }
        meta[META_CONSTRUCTION_WALL_KEY] = root
    keys = root.get("keys")
    if not isinstance(keys, dict):
        if not create:
            return {}
        keys = {}
        root["keys"] = keys
    root["version"] = CONSTRUCTION_WALL_VERSION
    return root


def construction_wall_slots(data, key, create=True):
    root = construction_wall_root(data, create=create)
    if not isinstance(root, dict):
        return {}
    keys = root.get("keys")
    if not isinstance(keys, dict):
        return {}
    key = str(key or "")
    entry = keys.get(key)
    if not isinstance(entry, dict):
        if not create:
            return {}
        entry = {"slots": {}}
        keys[key] = entry
    slots = entry.get("slots")
    if not isinstance(slots, dict):
        if not create:
            return {}
        slots = {}
        entry["slots"] = slots
    return slots


def construction_wall_summary(data):
    root = construction_wall_root(data, create=False)
    keys = root.get("keys", {}) if isinstance(root, dict) else {}
    summary = {}
    if not isinstance(keys, dict):
        return summary
    for key, entry in keys.items():
        slots = entry.get("slots", {}) if isinstance(entry, dict) else {}
        if isinstance(slots, dict) and slots:
            summary[str(key)] = len(slots)
    return summary


def _building_deadline_object_id(content, object_index):
    if not isinstance(content, dict) or object_index is None:
        return None
    objects = content.get("46")
    if isinstance(objects, list) and 0 <= object_index < len(objects):
        return objects[object_index]
    return None


def _building_deadline_record(
    content,
    index,
    value,
    observed_wall_ms,
    label,
):
    slot = _building_object_index(content, index)
    if slot is None:
        return None
    elapsed = _high_u32(value)
    remaining = _low_u32(value)
    if elapsed == 0 and remaining == 0:
        return None
    total = _building_cycle_ms(content, index, value)
    if total <= 0:
        total = max(0, elapsed + remaining)
    return {
        "slot": int(slot),
        "index": int(index),
        "object_id": _building_deadline_object_id(content, slot),
        "building_type": _building_type_for_index(content, index),
        "elapsed_ms": int(elapsed),
        "remaining_ms": int(remaining),
        "total_ms": int(total),
        "observed_wall_ms": int(observed_wall_ms),
        "ready_at_ms": int(observed_wall_ms) + int(remaining),
        "label": str(label or ""),
    }


def _zeroed_construction_wall_record(content, index, observed_wall_ms, label):
    if not isinstance(content, dict):
        return None
    building_timers = content.get("61")
    object_timers = content.get("47")
    if not isinstance(building_timers, list) or index >= len(building_timers):
        return None
    value = _as_int(building_timers[index], 0)
    if _high_u32(value) != 0 or _low_u32(value) != 0:
        return None
    slot = _building_object_index(content, index)
    if slot is None or not isinstance(object_timers, list) or slot >= len(object_timers):
        return None
    object_value = _as_int(object_timers[slot], 0)
    object_elapsed = _high_u32(object_value)
    if object_elapsed <= 0:
        return None
    observed = timer_wall_ms(observed_wall_ms)
    start_wall = max(0, observed - object_elapsed)
    return {
        "slot": int(slot),
        "index": int(index),
        "object_id": _building_deadline_object_id(content, slot),
        "building_type": _building_type_for_index(content, index),
        "object_elapsed_ms": int(object_elapsed),
        "object_low32": int(_low_u32(object_value)),
        "started_wall_ms": int(start_wall),
        "observed_wall_ms": int(observed),
        "label": str(label or ""),
    }


def sync_zeroed_construction_walls_for_key(
    data,
    key,
    content,
    log=None,
    label="sync",
    now_ms=None,
    observed_wall_ms=None,
):
    if not ENABLE_INFERRED_CONSTRUCTION_WALLS:
        meta = data.get("__meta") if isinstance(data, dict) else None
        if isinstance(meta, dict) and meta.pop(META_CONSTRUCTION_WALL_KEY, None) is not None:
            if callable(log):
                log(
                    f"[CONSTRUCTION-WALL] removed inferred ledger "
                    f"label={label!r}; field47 is authoritative"
                )
            return 1
        return 0
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    if not isinstance(building_timers, list):
        return 0

    now = timer_wall_ms(now_ms)
    observed = timer_wall_ms(observed_wall_ms if observed_wall_ms is not None else now)
    slots = construction_wall_slots(data, key, create=True)
    changed = 0
    tolerance = max(0, _as_int(BUILDING_DEADLINE_TOLERANCE_MS, 0))
    active_slots = set()

    for index in range(min(building_count, len(building_timers))):
        record = _zeroed_construction_wall_record(content, index, observed, label)
        if not record:
            continue
        slot_key = str(record["slot"])
        active_slots.add(slot_key)
        existing = slots.get(slot_key)
        replace_reason = ""
        if not isinstance(existing, dict):
            replace_reason = "new-zeroed-construction"
        elif existing.get("object_id") != record.get("object_id"):
            replace_reason = "object-changed"
        else:
            old_start = _as_int(existing.get("started_wall_ms"), 0)
            new_start = _as_int(record.get("started_wall_ms"), 0)
            if old_start <= 0:
                replace_reason = "missing-start-wall"
            elif new_start < old_start - tolerance:
                replace_reason = "earlier-start-observation"

        if replace_reason:
            old_start = (
                _as_int(existing.get("started_wall_ms"), 0)
                if isinstance(existing, dict)
                else 0
            )
            slots[slot_key] = record
            changed += 1
            if log:
                log(
                    f"[CONSTRUCTION-WALL] synced key={key!r} slot={slot_key} "
                    f"index={index} reason={replace_reason} label={label!r} "
                    f"started_wall_ms {old_start}->{record['started_wall_ms']} "
                    f"object_elapsed_ms={record.get('object_elapsed_ms')} "
                    f"object_id={record.get('object_id')!r}"
                )
            continue

        old_observed = _as_int(existing.get("observed_wall_ms"), 0)
        old_elapsed = _as_int(existing.get("object_elapsed_ms"), 0)
        existing.update({
            "index": int(index),
            "building_type": record.get("building_type"),
            "object_elapsed_ms": int(record.get("object_elapsed_ms", 0)),
            "object_low32": int(record.get("object_low32", 0)),
            "observed_wall_ms": int(observed),
            "last_seen_wall_ms": int(now),
            "label": str(label or ""),
        })
        if old_observed != observed or old_elapsed != record.get("object_elapsed_ms"):
            changed += 1
            if log:
                log(
                    f"[CONSTRUCTION-WALL] kept key={key!r} slot={slot_key} "
                    f"index={index} label={label!r} "
                    f"started_wall_ms={existing.get('started_wall_ms')} "
                    f"object_elapsed_ms {old_elapsed}->{record.get('object_elapsed_ms')} "
                    f"observed_wall_ms {old_observed}->{observed}"
                )

    for slot_key in list(slots.keys()):
        if slot_key in active_slots:
            continue
        old = slots.pop(slot_key, None)
        if isinstance(old, dict):
            changed += 1
            if log:
                log(
                    f"[CONSTRUCTION-WALL] cleared key={key!r} slot={slot_key} "
                    f"label={label!r} reason=inactive "
                    f"old_object_id={old.get('object_id')} "
                    f"old_started_wall_ms={old.get('started_wall_ms')}"
                )

    root = construction_wall_root(data, create=True)
    root["updated_wall_ms"] = now
    if log:
        log(
            f"[CONSTRUCTION-WALL] summary label={label!r} key={key!r} "
            f"changed={changed} active={compact_json(construction_wall_summary(data))}"
        )
    return changed


def sync_zeroed_construction_walls_from_save(data, log=None, label="persist", now_ms=None):
    if not isinstance(data, dict):
        return 0
    now = timer_wall_ms(now_ms)
    changed = 0
    for key in PARK_OFFLINE_TIMER_KEYS:
        content = saved_content(data.get(key))
        if not isinstance(content, dict):
            continue
        observed = timer_key_seed_wall_ms(data, key, now_ms=now)
        changed += sync_zeroed_construction_walls_for_key(
            data,
            key,
            content,
            log,
            label=f"{label} {key}",
            now_ms=now,
            observed_wall_ms=observed,
        )
    return changed


def apply_zeroed_construction_walls_for_key(
    data,
    key,
    content,
    log=None,
    label="apply",
    now_ms=None,
):
    if not ENABLE_INFERRED_CONSTRUCTION_WALLS:
        return 0
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    slots = construction_wall_slots(data, key, create=False)
    if not slots:
        return 0
    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    object_timers = content.get("47")
    if not isinstance(building_timers, list) or not isinstance(object_timers, list):
        return 0
    now = timer_wall_ms(now_ms)
    changed = 0

    for index in range(min(building_count, len(building_timers))):
        building_value = _as_int(building_timers[index], 0)
        if _high_u32(building_value) != 0 or _low_u32(building_value) != 0:
            continue
        slot = _building_object_index(content, index)
        if slot is None or slot >= len(object_timers):
            continue
        slot_key = str(slot)
        record = slots.get(slot_key)
        if not isinstance(record, dict):
            continue
        object_id = _building_deadline_object_id(content, slot)
        if record.get("object_id") != object_id:
            continue
        started_wall = _as_int(record.get("started_wall_ms"), 0)
        if started_wall <= 0 or now <= started_wall:
            continue
        target_elapsed = min(0xFFFFFFFF, max(0, now - started_wall))
        old_val = _as_int(object_timers[slot], 0)
        old_elapsed = _high_u32(old_val)
        if target_elapsed <= old_elapsed:
            continue
        object_timers[slot] = _replace_high_u32(old_val, target_elapsed)
        record["object_elapsed_ms"] = int(target_elapsed)
        record["observed_wall_ms"] = int(now)
        record["last_applied_wall_ms"] = int(now)
        changed += 1
        if log:
            log(
                f"[CONSTRUCTION-WALL] advanced key={key!r} slot={slot_key} "
                f"index={index} label={label!r} "
                f"elapsed_ms {old_elapsed}->{target_elapsed} "
                f"started_wall_ms={started_wall} object_id={object_id!r}"
            )

    if changed:
        root = construction_wall_root(data, create=True)
        root["updated_wall_ms"] = now
        if log:
            log(
                f"[CONSTRUCTION-WALL] applied label={label!r} key={key!r} "
                f"changed={changed} active={compact_json(construction_wall_summary(data))}"
            )
    return changed


def sync_building_ready_deadlines_for_key(
    data,
    key,
    content,
    log=None,
    label="sync",
    now_ms=None,
    observed_wall_ms=None,
):
    if not ENABLE_INFERRED_BUILDING_READY_DEADLINES:
        meta = data.get("__meta") if isinstance(data, dict) else None
        if isinstance(meta, dict) and meta.pop(META_BUILDING_READY_DEADLINES_KEY, None) is not None:
            if callable(log):
                log(
                    f"[DEADLINE] removed inferred building deadlines "
                    f"label={label!r}; field61 is authoritative"
                )
            return 1
        return 0
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    if not isinstance(building_timers, list):
        return 0

    now = timer_wall_ms(now_ms)
    observed = timer_wall_ms(observed_wall_ms if observed_wall_ms is not None else now)
    slots = building_ready_deadline_slots(data, key, create=True)
    changed = 0
    tolerance = max(0, _as_int(BUILDING_DEADLINE_TOLERANCE_MS, 0))
    active_slots = set()

    for index in range(min(building_count, len(building_timers))):
        value = _as_int(building_timers[index], 0)
        record = _building_deadline_record(content, index, value, observed, label)
        if not record:
            continue
        slot_key = str(record["slot"])
        active_slots.add(slot_key)
        remaining = _as_int(record.get("remaining_ms"), 0)
        elapsed = _as_int(record.get("elapsed_ms"), 0)

        if remaining <= 0:
            old = slots.pop(slot_key, None)
            if isinstance(old, dict):
                changed += 1
                if log:
                    log(
                        f"[DEADLINE] cleared building slot={slot_key} key={key!r} "
                        f"label={label!r} reason=observed-ready "
                        f"old_ready_at_ms={old.get('ready_at_ms')} elapsed_ms={elapsed}"
                    )
            continue

        existing = slots.get(slot_key)
        replace_reason = ""
        if not isinstance(existing, dict):
            replace_reason = "new-active"
        elif existing.get("object_id") != record.get("object_id"):
            replace_reason = "object-changed"
        else:
            old_ready = _as_int(existing.get("ready_at_ms"), 0)
            new_ready = _as_int(record.get("ready_at_ms"), 0)
            old_total = _as_int(existing.get("total_ms"), 0)
            new_total = _as_int(record.get("total_ms"), 0)
            if old_ready <= 0:
                replace_reason = "missing-ready-at"
            elif new_ready < old_ready - tolerance:
                replace_reason = "earlier-observation"
            elif (
                old_total > 0
                and new_total > 0
                and abs(new_total - old_total) > tolerance
                and new_ready < old_ready
            ):
                replace_reason = "cycle-shortened"

        if replace_reason:
            old_ready = (
                _as_int(existing.get("ready_at_ms"), 0)
                if isinstance(existing, dict)
                else 0
            )
            slots[slot_key] = record
            changed += 1
            if log:
                log(
                    f"[DEADLINE] synced building key={key!r} slot={slot_key} "
                    f"index={index} reason={replace_reason} label={label!r} "
                    f"ready_at_ms {old_ready}->{record['ready_at_ms']} "
                    f"remaining_ms={remaining} elapsed_ms={elapsed} "
                    f"total_ms={record.get('total_ms')} object_id={record.get('object_id')!r}"
                )
            continue

        if isinstance(existing, dict):
            old_observed = _as_int(existing.get("observed_wall_ms"), 0)
            old_remaining = _as_int(existing.get("remaining_ms"), remaining)
            old_elapsed = _as_int(existing.get("elapsed_ms"), elapsed)
            existing.update({
                "index": int(index),
                "building_type": record.get("building_type"),
                "elapsed_ms": int(elapsed),
                "remaining_ms": int(remaining),
                "total_ms": int(record.get("total_ms", 0)),
                "observed_wall_ms": int(observed),
                "last_seen_wall_ms": int(now),
                "label": str(label or ""),
            })
            if (
                old_observed != observed
                or old_remaining != remaining
                or old_elapsed != elapsed
            ):
                changed += 1
                if log:
                    log(
                        f"[DEADLINE] kept building key={key!r} slot={slot_key} "
                        f"index={index} label={label!r} "
                        f"ready_at_ms={existing.get('ready_at_ms')} "
                        f"candidate_ready_at_ms={record.get('ready_at_ms')} "
                        f"remaining_ms {old_remaining}->{remaining} "
                        f"elapsed_ms {old_elapsed}->{elapsed}"
                    )

    for slot_key in list(slots.keys()):
        if slot_key in active_slots:
            continue
        old = slots.pop(slot_key, None)
        if isinstance(old, dict):
            changed += 1
            if log:
                log(
                    f"[DEADLINE] cleared building key={key!r} slot={slot_key} "
                    f"label={label!r} reason=inactive "
                    f"old_object_id={old.get('object_id')} "
                    f"old_ready_at_ms={old.get('ready_at_ms')}"
                )

    root = building_ready_deadline_root(data, create=True)
    root["updated_wall_ms"] = now
    if log:
        log(
            f"[DEADLINE] summary label={label!r} key={key!r} "
            f"changed={changed} active={compact_json(building_ready_deadline_summary(data))}"
        )
    return changed


def sync_building_ready_deadlines_from_save(data, log=None, label="persist", now_ms=None):
    if not isinstance(data, dict):
        return 0
    now = timer_wall_ms(now_ms)
    changed = 0
    for key in PARK_OFFLINE_TIMER_KEYS:
        content = saved_content(data.get(key))
        if not isinstance(content, dict):
            continue
        observed = timer_key_seed_wall_ms(data, key, now_ms=now)
        changed += sync_building_ready_deadlines_for_key(
            data,
            key,
            content,
            log,
            label=f"{label} {key}",
            now_ms=now,
            observed_wall_ms=observed,
        )
    return changed


def apply_building_ready_deadlines_for_key(
    data,
    key,
    content,
    log=None,
    label="apply",
    now_ms=None,
    grace_ms=0,
):
    if not ENABLE_INFERRED_BUILDING_READY_DEADLINES:
        return 0
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    slots = building_ready_deadline_slots(data, key, create=False)
    if not slots:
        return 0
    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    if not isinstance(building_timers, list):
        return 0
    now = timer_wall_ms(now_ms)
    grace = max(0, _as_int(grace_ms, 0))
    changed = 0

    for index in range(min(building_count, len(building_timers))):
        old_val = _as_int(building_timers[index], 0)
        remaining = _low_u32(old_val)
        if remaining <= 0:
            continue
        slot = _building_object_index(content, index)
        if slot is None:
            continue
        slot_key = str(slot)
        deadline = slots.get(slot_key)
        if not isinstance(deadline, dict):
            continue
        object_id = _building_deadline_object_id(content, slot)
        if deadline.get("object_id") != object_id:
            continue
        ready_at = _as_int(deadline.get("ready_at_ms"), 0)
        if ready_at <= 0 or now + grace < ready_at:
            continue
        total = _as_int(deadline.get("total_ms"), 0)
        if total <= 0:
            total = _building_cycle_ms(content, index, old_val)
        if total <= 0:
            total = max(0, _high_u32(old_val) + remaining)
        new_val = _pack_u32_pair(0, _building_ready_elapsed_ms(total))
        if new_val == old_val:
            slots.pop(slot_key, None)
            continue
        building_timers[index] = new_val
        slots.pop(slot_key, None)
        changed += 1
        if log:
            log(
                f"[DEADLINE] completed building key={key!r} slot={slot_key} "
                f"index={index} label={label!r} now_ms={now} "
                f"ready_at_ms={ready_at} grace_ms={grace} "
                f"old_elapsed_ms={_high_u32(old_val)} old_remaining_ms={remaining} "
                f"total_ms={total} object_id={object_id!r}"
            )

    if changed:
        changed += sync_building_object_timers_for_storage(
            content,
            log or (lambda _message: None),
            f"{label} deadline",
        )
        root = building_ready_deadline_root(data, create=True)
        root["updated_wall_ms"] = now
        if log:
            log(
                f"[DEADLINE] applied label={label!r} key={key!r} "
                f"changed={changed} active={compact_json(building_ready_deadline_summary(data))}"
            )
    return changed


def hatch_ready_deadline_root(data, create=True):
    if not isinstance(data, dict):
        return {}
    meta = data.setdefault("__meta", {}) if create else data.get("__meta", {})
    if not isinstance(meta, dict):
        if not create:
            return {}
        meta = {}
        data["__meta"] = meta
    root = meta.get(META_HATCH_READY_DEADLINES_KEY)
    if not isinstance(root, dict):
        if not create:
            return {}
        root = {
            "version": HATCH_READY_DEADLINES_VERSION,
            "keys": {},
        }
        meta[META_HATCH_READY_DEADLINES_KEY] = root
    keys = root.get("keys")
    if not isinstance(keys, dict):
        if not create:
            return {}
        keys = {}
        root["keys"] = keys
    root["version"] = HATCH_READY_DEADLINES_VERSION
    return root


def hatch_ready_deadline_slots(data, key, create=True):
    root = hatch_ready_deadline_root(data, create=create)
    if not isinstance(root, dict):
        return {}
    keys = root.get("keys")
    if not isinstance(keys, dict):
        return {}
    key = str(key or "")
    entry = keys.get(key)
    if not isinstance(entry, dict):
        if not create:
            return {}
        entry = {"slots": {}}
        keys[key] = entry
    slots = entry.get("slots")
    if not isinstance(slots, dict):
        if not create:
            return {}
        slots = {}
        entry["slots"] = slots
    return slots


def hatch_ready_deadline_summary(data):
    root = hatch_ready_deadline_root(data, create=False)
    keys = root.get("keys", {}) if isinstance(root, dict) else {}
    summary = {}
    if not isinstance(keys, dict):
        return summary
    for key, entry in keys.items():
        slots = entry.get("slots", {}) if isinstance(entry, dict) else {}
        if isinstance(slots, dict) and slots:
            summary[str(key)] = len(slots)
    return summary


def _hatch_ready_elapsed_seconds(dino_id, elapsed_seconds=0):
    known = HATCH_READY_SECONDS_BY_DINO_ID.get(_as_int(dino_id, 0))
    if known:
        return max(1, _as_int(known, 0))
    elapsed = max(0, _as_int(elapsed_seconds, 0))
    default_ready = max(1, _as_int(HATCH_DEFAULT_READY_SECONDS, 20 * 60))
    if elapsed < default_ready:
        return default_ready
    for candidate in HATCH_READY_DURATION_SECONDS:
        candidate = max(1, _as_int(candidate, 0))
        if elapsed <= candidate:
            return candidate
    round_to = max(60, _as_int(HATCH_RECONNECT_ROUND_SECONDS, 60))
    return ((elapsed + round_to - 1) // round_to) * round_to


def _hatch_deadline_record(content, index, value, observed_wall_ms, label):
    if not isinstance(content, dict):
        return None
    dino_id = _low_u32(value)
    if dino_id <= 0:
        return None
    elapsed = _high_u32(value)
    ready_elapsed = _hatch_ready_elapsed_seconds(dino_id, elapsed)
    remaining = max(0, ready_elapsed - elapsed)
    return {
        "slot": int(index),
        "index": int(index),
        "dino_id": int(dino_id),
        "elapsed_seconds": int(elapsed),
        "ready_elapsed_seconds": int(ready_elapsed),
        "remaining_seconds": int(remaining),
        "observed_wall_ms": int(observed_wall_ms),
        "ready_at_ms": int(observed_wall_ms) + int(remaining) * 1000,
        "label": str(label or ""),
    }


def sync_hatch_ready_deadlines_for_key(
    data,
    key,
    content,
    log=None,
    label="sync",
    now_ms=None,
    observed_wall_ms=None,
):
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    if not ENABLE_INFERRED_HATCH_READY_DEADLINES:
        root = hatch_ready_deadline_root(data, create=False)
        keys = root.get("keys") if isinstance(root, dict) else None
        removed = 0
        if isinstance(keys, dict) and key in keys:
            keys.pop(key, None)
            removed = 1
            if log:
                log(
                    f"[HATCH-DEADLINE] removed unproven inferred deadlines "
                    f"key={key!r} label={label!r}"
                )
        return removed
    dino_count = max(0, _as_int(content.get("57"), 0))
    dino_timers = content.get("58")
    hatch_values = content.get("59")
    if not isinstance(dino_timers, list) or not isinstance(hatch_values, list):
        return 0

    now = timer_wall_ms(now_ms)
    observed = timer_wall_ms(observed_wall_ms if observed_wall_ms is not None else now)
    slots = hatch_ready_deadline_slots(data, key, create=True)
    changed = 0
    tolerance = max(0, _as_int(HATCH_DEADLINE_TOLERANCE_MS, 0))
    active_slots = set()

    for index in range(min(dino_count, len(dino_timers), len(hatch_values))):
        slot_key = str(index)
        active_hatch = _is_active_hatch_timer(
            dino_timers[index],
            hatch_values[index],
        )
        if not active_hatch:
            continue
        active_slots.add(slot_key)
        value = _as_int(hatch_values[index], 0)
        record = _hatch_deadline_record(content, index, value, observed, label)
        if not record:
            continue
        remaining = _as_int(record.get("remaining_seconds"), 0)
        elapsed = _as_int(record.get("elapsed_seconds"), 0)
        dino_id = _as_int(record.get("dino_id"), 0)

        if remaining <= 0:
            old = slots.pop(slot_key, None)
            if isinstance(old, dict):
                changed += 1
                if log:
                    log(
                        f"[HATCH-DEADLINE] cleared key={key!r} slot={slot_key} "
                        f"label={label!r} reason=observed-ready "
                        f"dino_id={dino_id} elapsed_seconds={elapsed} "
                        f"ready_elapsed_seconds={record.get('ready_elapsed_seconds')}"
                    )
            continue

        existing = slots.get(slot_key)
        replace_reason = ""
        if not isinstance(existing, dict):
            replace_reason = "new-active"
        elif _as_int(existing.get("dino_id"), 0) != dino_id:
            replace_reason = "dino-changed"
        else:
            old_ready = _as_int(existing.get("ready_at_ms"), 0)
            new_ready = _as_int(record.get("ready_at_ms"), 0)
            old_total = _as_int(existing.get("ready_elapsed_seconds"), 0)
            new_total = _as_int(record.get("ready_elapsed_seconds"), 0)
            if old_ready <= 0:
                replace_reason = "missing-ready-at"
            elif new_ready < old_ready - tolerance:
                replace_reason = "earlier-observation"
            elif old_total != new_total and new_ready < old_ready:
                replace_reason = "ready-boundary-shortened"

        if replace_reason:
            old_ready = (
                _as_int(existing.get("ready_at_ms"), 0)
                if isinstance(existing, dict)
                else 0
            )
            slots[slot_key] = record
            changed += 1
            if log:
                log(
                    f"[HATCH-DEADLINE] synced key={key!r} slot={slot_key} "
                    f"reason={replace_reason} label={label!r} "
                    f"dino_id={dino_id} ready_at_ms {old_ready}->{record['ready_at_ms']} "
                    f"elapsed_seconds={elapsed} remaining_seconds={remaining} "
                    f"ready_elapsed_seconds={record.get('ready_elapsed_seconds')}"
                )
            continue

        if isinstance(existing, dict):
            old_observed = _as_int(existing.get("observed_wall_ms"), 0)
            old_remaining = _as_int(existing.get("remaining_seconds"), remaining)
            old_elapsed = _as_int(existing.get("elapsed_seconds"), elapsed)
            existing.update({
                "index": int(index),
                "elapsed_seconds": int(elapsed),
                "remaining_seconds": int(remaining),
                "ready_elapsed_seconds": int(record.get("ready_elapsed_seconds", 0)),
                "observed_wall_ms": int(observed),
                "last_seen_wall_ms": int(now),
                "label": str(label or ""),
            })
            if (
                old_observed != observed
                or old_remaining != remaining
                or old_elapsed != elapsed
            ):
                changed += 1
                if log:
                    log(
                        f"[HATCH-DEADLINE] kept key={key!r} slot={slot_key} "
                        f"label={label!r} dino_id={dino_id} "
                        f"ready_at_ms={existing.get('ready_at_ms')} "
                        f"candidate_ready_at_ms={record.get('ready_at_ms')} "
                        f"remaining_seconds {old_remaining}->{remaining} "
                        f"elapsed_seconds {old_elapsed}->{elapsed}"
                    )

    for slot_key in list(slots.keys()):
        if slot_key in active_slots:
            continue
        old = slots.pop(slot_key, None)
        if isinstance(old, dict):
            changed += 1
            if log:
                log(
                    f"[HATCH-DEADLINE] cleared key={key!r} slot={slot_key} "
                    f"label={label!r} reason=inactive old_dino_id={old.get('dino_id')}"
                )

    root = hatch_ready_deadline_root(data, create=True)
    root["updated_wall_ms"] = now
    if log:
        log(
            f"[HATCH-DEADLINE] summary label={label!r} key={key!r} "
            f"changed={changed} active={compact_json(hatch_ready_deadline_summary(data))}"
        )
    return changed


def sync_hatch_ready_deadlines_from_save(data, log=None, label="persist", now_ms=None):
    if not isinstance(data, dict):
        return 0
    now = timer_wall_ms(now_ms)
    changed = 0
    for key in PARK_OFFLINE_TIMER_KEYS:
        content = saved_content(data.get(key))
        if not isinstance(content, dict):
            continue
        observed = timer_key_seed_wall_ms(data, key, now_ms=now)
        changed += sync_hatch_ready_deadlines_for_key(
            data,
            key,
            content,
            log,
            label=f"{label} {key}",
            now_ms=now,
            observed_wall_ms=observed,
        )
    return changed


def apply_hatch_ready_deadlines_for_key(
    data,
    key,
    content,
    log=None,
    label="apply",
    now_ms=None,
    grace_seconds=0,
):
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    if not ENABLE_INFERRED_HATCH_READY_DEADLINES:
        return 0
    slots = hatch_ready_deadline_slots(data, key, create=False)
    if not slots:
        return 0
    dino_count = max(0, _as_int(content.get("57"), 0))
    dino_timers = content.get("58")
    hatch_values = content.get("59")
    if not isinstance(dino_timers, list) or not isinstance(hatch_values, list):
        return 0
    now = timer_wall_ms(now_ms)
    grace_ms = max(0, _as_int(grace_seconds, 0)) * 1000
    changed = 0

    for index in range(min(dino_count, len(dino_timers), len(hatch_values))):
        if not _is_active_hatch_timer(dino_timers[index], hatch_values[index]):
            continue
        slot_key = str(index)
        deadline = slots.get(slot_key)
        if not isinstance(deadline, dict):
            continue
        old_val = _as_int(hatch_values[index], 0)
        dino_id = _low_u32(old_val)
        if _as_int(deadline.get("dino_id"), 0) != dino_id:
            continue
        ready_at = _as_int(deadline.get("ready_at_ms"), 0)
        if ready_at <= 0 or now + grace_ms < ready_at:
            continue
        ready_elapsed = _as_int(deadline.get("ready_elapsed_seconds"), 0)
        if ready_elapsed <= 0:
            ready_elapsed = _hatch_ready_elapsed_seconds(dino_id, _high_u32(old_val))
        old_elapsed = _high_u32(old_val)
        new_elapsed = max(old_elapsed, ready_elapsed)
        if new_elapsed != old_elapsed:
            hatch_values[index] = _replace_high_u32(old_val, new_elapsed)
            changed += 1
            if log:
                log(
                    f"[HATCH-DEADLINE] completed key={key!r} slot={slot_key} "
                    f"index={index} label={label!r} dino_id={dino_id} "
                    f"now_ms={now} ready_at_ms={ready_at} grace_ms={grace_ms} "
                    f"elapsed_seconds {old_elapsed}->{new_elapsed}"
                )
        slots.pop(slot_key, None)

    if changed:
        root = hatch_ready_deadline_root(data, create=True)
        root["updated_wall_ms"] = now
        if log:
            log(
                f"[HATCH-DEADLINE] applied label={label!r} key={key!r} "
                f"changed={changed} active={compact_json(hatch_ready_deadline_summary(data))}"
            )
    return changed


def purge_timer_ledger(data, log=None, label="purge"):
    if not isinstance(data, dict):
        return 0
    meta = data.get("__meta")
    if not isinstance(meta, dict) or META_TIMER_LEDGER_KEY not in meta:
        return 0
    old = meta.pop(META_TIMER_LEDGER_KEY, None)
    count = 0
    if isinstance(old, dict):
        records = old.get("records")
        if isinstance(records, dict):
            count = len(records)
    if log:
        log(f"[TIMER-FIELDS] removed legacy timer_ledger label={label!r} records={count}")
    return 1


def _timer_field_item(value, index=None, **extra):
    encoded = _as_int(value, 0)
    item = {
        "value": encoded,
        "high32": _high_u32(encoded),
        "low32": _low_u32(encoded),
    }
    if index is not None:
        item["index"] = index
    item.update(extra)
    return item


def _timer_field_add_scalar(categories, category, field, value, include_zero=False, **extra):
    encoded = _as_int(value, 0)
    if not include_zero and encoded == 0:
        return
    categories.setdefault(category, {})[str(field)] = _timer_field_item(encoded, **extra)


def _timer_field_add_array(
    categories,
    category,
    field,
    values,
    include_zero=False,
    limit=None,
    enrich=None,
):
    if not isinstance(values, list):
        return
    items = []
    count = len(values) if limit is None else min(max(0, _as_int(limit, 0)), len(values))
    for index in range(count):
        value = _as_int(values[index], 0)
        if not include_zero and value == 0:
            continue
        extra = enrich(index, value) if enrich else {}
        items.append(_timer_field_item(value, index=index, **(extra or {})))
    if items:
        categories.setdefault(category, {})[str(field)] = items


def extract_timer_field_snapshot_for_content(key, content, now_ms=None):
    if not isinstance(content, dict):
        return {}
    key = str(key)
    categories = {}
    now_ms = timer_wall_ms(now_ms)

    if key in PARK_OFFLINE_TIMER_KEYS:
        object_count = max(0, _as_int(content.get("45"), 0))
        _timer_field_add_array(
            categories,
            "objects",
            "47",
            content.get("47"),
            limit=object_count,
            enrich=lambda index, value: {
                "object_id": content.get("46", [None] * object_count)[index]
                if isinstance(content.get("46"), list) and index < len(content.get("46"))
                else None
            },
        )

        starts = content.get("49")
        timers = content.get("50")
        states = content.get("51")
        if isinstance(timers, list):
            expansion_items = []
            for index, value in enumerate(timers):
                state = (
                    _as_int(states[index], 0)
                    if isinstance(states, list) and index < len(states)
                    else 0
                )
                start = (
                    _as_int(starts[index], 0)
                    if isinstance(starts, list) and index < len(starts)
                    else 0
                )
                if state == 0 and _as_int(value, 0) == 0:
                    continue
                if state == 0 and index < 40:
                    continue
                expansion_items.append(
                    _timer_field_item(
                        value,
                        index=index,
                        state_value=state,
                        state_high32=_high_u32(state),
                        state_low32=_low_u32(state),
                        start_value=start,
                        cap_ms=_expansion_timer_cap_ms(state),
                        active=_expansion_timer_active(state, value),
                        ready=_expansion_timer_ready_to_clear(state, value),
                    )
                )
            if expansion_items:
                categories.setdefault("expansions", {})["50"] = expansion_items
        if isinstance(states, list):
            state_items = []
            for index, state in enumerate(states):
                state = _as_int(state, 0)
                if state == 0:
                    continue
                state_items.append(
                    _timer_field_item(
                        state,
                        index=index,
                        cap_ms=_expansion_timer_cap_ms(state),
                    )
                )
            if state_items:
                categories.setdefault("expansions", {})["51"] = state_items

        _timer_field_add_array(categories, "ports", "55", content.get("55"), limit=2)
        _timer_field_add_array(categories, "ports", "56", content.get("56"), limit=2)

        dino_count = max(0, _as_int(content.get("57"), 0))
        _timer_field_add_array(categories, "dinos", "58", content.get("58"), limit=dino_count)
        _timer_field_add_array(categories, "dinos", "59", content.get("59"), limit=dino_count)

        building_count = max(0, _as_int(content.get("60"), 0))
        _timer_field_add_array(
            categories,
            "buildings",
            "61",
            content.get("61"),
            limit=building_count,
            enrich=lambda index, value: {
                "object_index": _building_object_index(content, index),
                "total_ms": _building_cycle_ms(content, index, value),
            },
        )
        _timer_field_add_array(
            categories,
            "buildings",
            "62",
            content.get("62"),
            include_zero=True,
            limit=building_count,
        )

    elif key == "prof":
        for field in ("1", "146"):
            if field in content:
                _timer_field_add_scalar(categories, "profile", field, content.get(field), include_zero=True)
        for field in ("111", "112", "113", "114"):
            _timer_field_add_array(categories, "battle_cooldowns", field, content.get(field), include_zero=True)
        for field in ("144", "145"):
            if field in content:
                _timer_field_add_scalar(categories, "profile_timer", field, content.get(field), include_zero=True)

    elif key == "batl":
        for field in BATTLE_COOLDOWN_FIELDS:
            _timer_field_add_array(
                categories,
                "battle",
                field,
                content.get(field),
                include_zero=False,
            )

    elif key == "gen":
        for field in ("22", "23", "24", "25"):
            if field in content:
                _timer_field_add_scalar(
                    categories,
                    "code_red",
                    field,
                    content.get(field),
                    include_zero=True,
                )

    elif key in EXPEDITION_GEN_KEYS:
        for field in ("77", "79", "80", "82"):
            if field in content:
                _timer_field_add_scalar(categories, "expedition", field, content.get(field), include_zero=True)

    if not categories:
        return {}
    return {
        "updated_wall_ms": now_ms,
        "categories": categories,
    }


def timer_field_snapshot_summary(data):
    meta = data.get("__meta", {}) if isinstance(data, dict) else {}
    snapshots = meta.get(META_TIMER_FIELDS_KEY, {}) if isinstance(meta, dict) else {}
    keys = snapshots.get("keys", {}) if isinstance(snapshots, dict) else {}
    counts = {}
    for key, snapshot in keys.items():
        if not isinstance(snapshot, dict):
            continue
        categories = snapshot.get("categories", {})
        if not isinstance(categories, dict):
            continue
        for category, fields in categories.items():
            if not isinstance(fields, dict):
                continue
            for field, value in fields.items():
                bucket = f"{key}.{category}.{field}"
                counts[bucket] = len(value) if isinstance(value, list) else 1
    return {"keys": len(keys), "counts": counts}


def sync_timer_field_snapshot_for_key(data, key, content, log=None, label="sync", now_ms=None):
    if key not in OFFLINE_TIMER_REPLAY_KEYS or not isinstance(data, dict) or not isinstance(content, dict):
        return 0
    purge_timer_ledger(data, log, label=f"{label} legacy")
    now_ms = timer_wall_ms(now_ms)
    meta = data.setdefault("__meta", {})
    if not isinstance(meta, dict):
        meta = {}
        data["__meta"] = meta
    root = meta.setdefault(META_TIMER_FIELDS_KEY, {"version": TIMER_FIELDS_VERSION, "keys": {}})
    if not isinstance(root, dict):
        root = {"version": TIMER_FIELDS_VERSION, "keys": {}}
        meta[META_TIMER_FIELDS_KEY] = root
    keys = root.setdefault("keys", {})
    if not isinstance(keys, dict):
        keys = {}
        root["keys"] = keys

    snapshot = extract_timer_field_snapshot_for_content(key, content, now_ms)
    previous = keys.get(key)
    if snapshot:
        keys[key] = snapshot
    else:
        keys.pop(key, None)
    root["version"] = TIMER_FIELDS_VERSION
    root["updated_wall_ms"] = now_ms
    changed = 1 if previous != keys.get(key) else 0
    if log:
        key_summary = timer_field_snapshot_summary(data).get("counts", {})
        scoped = {k: v for k, v in key_summary.items() if k.startswith(f"{key}.")}
        log(
            f"[TIMER-FIELDS] synced key={key!r} label={label!r} "
            f"changed={changed} summary={compact_json(scoped)}"
        )
    return changed


def sync_timer_field_snapshots_from_save(data, log=None, label="persist", now_ms=None):
    if not isinstance(data, dict):
        return 0
    purge_timer_ledger(data, log, label=f"{label} legacy")
    now_ms = timer_wall_ms(now_ms)
    meta = data.setdefault("__meta", {})
    if not isinstance(meta, dict):
        meta = {}
        data["__meta"] = meta
    old = meta.get(META_TIMER_FIELDS_KEY)
    root = {
        "version": TIMER_FIELDS_VERSION,
        "updated_wall_ms": now_ms,
        "keys": {},
    }
    for key in OFFLINE_TIMER_REPLAY_KEYS:
        content = saved_content(data.get(key))
        snapshot = extract_timer_field_snapshot_for_content(key, content, now_ms)
        if snapshot:
            root["keys"][key] = snapshot
    meta[META_TIMER_FIELDS_KEY] = root
    changed = 1 if old != root else 0
    if log:
        log(
            f"[TIMER-FIELDS] snapshot label={label!r} changed={changed} "
            f"summary={compact_json(timer_field_snapshot_summary(data))}"
        )
    return changed


def _prune_metadata_keyed_entries(meta, root_key, allowed_keys, log=None, label="scrub"):
    if not isinstance(meta, dict):
        return 0
    root = meta.get(root_key)
    if not isinstance(root, dict):
        if root_key in meta:
            meta.pop(root_key, None)
            if log:
                log(f"[META-SCRUB] removed malformed {root_key} label={label!r}")
            return 1
        return 0
    keys = root.get("keys")
    if not isinstance(keys, dict):
        root["keys"] = {}
        if log:
            log(f"[META-SCRUB] reset malformed {root_key}.keys label={label!r}")
        return 1

    changed = 0
    for key in list(keys.keys()):
        if key not in allowed_keys:
            keys.pop(key, None)
            changed += 1
            if log:
                log(
                    f"[META-SCRUB] removed stale {root_key} key={key!r} "
                    f"label={label!r}"
                )
            continue
        entry = keys.get(key)
        if not isinstance(entry, dict):
            keys.pop(key, None)
            changed += 1
            if log:
                log(
                    f"[META-SCRUB] removed malformed {root_key} key={key!r} "
                    f"label={label!r}"
                )
            continue
        slots = entry.get("slots")
        if isinstance(slots, dict) and not slots:
            keys.pop(key, None)
            changed += 1
            if log:
                log(
                    f"[META-SCRUB] removed empty {root_key} key={key!r} "
                    f"label={label!r}"
                )
    if not keys:
        meta.pop(root_key, None)
        changed += 1
        if log:
            log(f"[META-SCRUB] removed empty {root_key} root label={label!r}")
    return changed


def scrub_server_metadata(data, log=None, label="scrub", now_ms=None, persist=False):
    """Make derived server metadata match the current save payload exactly."""
    if not isinstance(data, dict):
        return 0
    changed = 0
    now_ms = timer_wall_ms(now_ms)
    meta = data.setdefault("__meta", {})
    if not isinstance(meta, dict):
        meta = {}
        data["__meta"] = meta
        changed += 1
        if log:
            log(f"[META-SCRUB] reset malformed __meta label={label!r}")

    changed += purge_timer_ledger(data, log, label=f"{label} legacy")

    allowed_timer_keys = {
        key
        for key in OFFLINE_TIMER_REPLAY_KEYS
        if isinstance(data.get(key), dict) and isinstance(saved_content(data.get(key)), dict)
    }

    wall = meta.get(META_TIMER_KEY_WALL_KEY)
    if isinstance(wall, dict):
        for key in list(wall.keys()):
            entry = wall.get(key)
            if key not in allowed_timer_keys:
                wall.pop(key, None)
                changed += 1
                if log:
                    log(
                        f"[META-SCRUB] removed stale timer_key_wall key={key!r} "
                        f"label={label!r}"
                    )
            elif not isinstance(entry, dict) or _as_int(entry.get("last_wall_ms"), 0) <= 0:
                seed = timer_key_seed_wall_ms(data, key, now_ms=now_ms)
                wall[key] = {"last_wall_ms": seed, "label": f"{label}:reseed"}
                changed += 1
                if log:
                    log(
                        f"[META-SCRUB] reseeded timer_key_wall key={key!r} "
                        f"seed={seed} label={label!r}"
                    )
    elif META_TIMER_KEY_WALL_KEY in meta:
        meta.pop(META_TIMER_KEY_WALL_KEY, None)
        changed += 1
        if log:
            log(f"[META-SCRUB] removed malformed timer_key_wall label={label!r}")

    changed += sync_building_ready_deadlines_from_save(
        data, log, f"{label}:deadline", now_ms=now_ms
    )
    changed += sync_zeroed_construction_walls_from_save(
        data, log, f"{label}:construction", now_ms=now_ms
    )
    changed += sync_hatch_ready_deadlines_from_save(
        data, log, f"{label}:deadline", now_ms=now_ms
    )
    changed += _prune_metadata_keyed_entries(
        meta,
        META_BUILDING_READY_DEADLINES_KEY,
        allowed_timer_keys,
        log=log,
        label=label,
    )
    changed += _prune_metadata_keyed_entries(
        meta,
        META_HATCH_READY_DEADLINES_KEY,
        allowed_timer_keys,
        log=log,
        label=label,
    )
    changed += _prune_metadata_keyed_entries(
        meta,
        META_CONSTRUCTION_WALL_KEY,
        allowed_timer_keys,
        log=log,
        label=label,
    )
    changed += sync_timer_field_snapshots_from_save(
        data, log, label=f"{label}:fields", now_ms=now_ms
    )

    if persist and "_loaded_file_mtime" in meta:
        meta.pop("_loaded_file_mtime", None)
        changed += 1
        if log:
            log(f"[META-SCRUB] removed transient _loaded_file_mtime label={label!r}")

    if log:
        log(
            f"[META-SCRUB] summary label={label!r} changed={changed} "
            f"allowed_timer_keys={sorted(allowed_timer_keys)!r} "
            f"deadline_buildings={compact_json(building_ready_deadline_summary(data))} "
            f"construction_wall={compact_json(construction_wall_summary(data))} "
            f"deadline_hatches={compact_json(hatch_ready_deadline_summary(data))} "
            f"timer_fields={compact_json(timer_field_snapshot_summary(data))}"
        )
    return changed


def _cooldown_value_matches(existing, candidate):
    candidate = _as_int(candidate, 0)
    for value in existing:
        value = _as_int(value, 0)
        if value <= 0 or candidate <= 0:
            continue
        tolerance = max(15 * 60 * 1000, int(max(value, candidate) * 0.15))
        if abs(value - candidate) <= tolerance:
            return True
    return False


def synthesize_battle_cooldowns_from_profile(saved, log, label, session_state=None, batch_sequence=None):
    # batl.104 is the persisted per-slot source.  prof.111-prof.114 are UI and
    # packed identity projections whose exact slot mapping is not proven.
    # Inventing a batl slot from profile magnitude created ghost cooldowns.
    return 0


def _merge_battle_cooldown_value(
    previous_value,
    incoming_value,
    allow_active_increase=False,
    allow_active_clear=False,
    tracked_halves=None,
    expired_halves=None,
):
    previous_high, previous_low = _battle_cooldown_parts(previous_value)
    incoming_high, incoming_low = _battle_cooldown_parts(incoming_value)
    tracked_halves = set(tracked_halves or ())
    expired_halves = set(expired_halves or ())
    changed = False

    for part_name, previous_part, incoming_part in (
        ("high", previous_high, incoming_high),
        ("low", previous_low, incoming_low),
    ):
        is_tracked = (
            previous_part >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
            or part_name in tracked_halves
        )
        replacement = incoming_part
        if incoming_part >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS:
            if not allow_active_increase and (
                not is_tracked or incoming_part > previous_part
            ):
                replacement = previous_part
        elif is_tracked:
            if (
                incoming_part == 0
                and not allow_active_clear
                and part_name not in expired_halves
            ):
                replacement = previous_part
            elif (
                incoming_part > previous_part
                and not allow_active_increase
            ):
                replacement = previous_part
        if replacement == incoming_part:
            continue
        if part_name == "high":
            incoming_high = replacement
        else:
            incoming_low = replacement
        changed = True

    if not changed:
        return incoming_value, False
    return _pack_signed64_from_u64((incoming_high << 32) | incoming_low), True


def normalize_battle_cooldown_slots(content, log, label):
    changed = 0
    if not isinstance(content, dict):
        return changed
    for field in BATTLE_COOLDOWN_FIELDS:
        values = content.get(field)
        if not isinstance(values, list):
            continue
        for index, value in enumerate(values):
            try:
                high, low = _battle_cooldown_parts(value)
            except Exception:
                continue
            if high < 60 * 1000 or low < 60 * 1000:
                continue
            # The client can send two active cooldown parts in one packed
            # field slot. Preserve both halves; dropping either loses one.
            log(
                f"[BATTLE] {label} preserved mixed "
                f"batl.{field}[{index}] high={high} low={low}"
            )
    return changed


def _batl_cooldown_clear_indices(previous_batl, merged_batl, tracked_parts=None):
    cleared = []
    if not isinstance(previous_batl, dict) or not isinstance(merged_batl, dict):
        return cleared
    for field in BATTLE_COOLDOWN_FIELDS:
        previous_values = previous_batl.get(field)
        merged_values = merged_batl.get(field)
        if not isinstance(previous_values, list) or not isinstance(merged_values, list):
            continue
        field_tracked = _battle_cooldown_parts_for_field(tracked_parts, field)
        for index in range(min(len(previous_values), len(merged_values))):
            previous_high, previous_low = _battle_cooldown_parts(
                previous_values[index]
            )
            merged_high, merged_low = _battle_cooldown_parts(
                merged_values[index]
            )
            high_tracked = (
                previous_high >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
                or (index, "high") in field_tracked
            )
            low_tracked = (
                previous_low >= BATTLE_COOLDOWN_PART_DISCOVERY_MIN_MS
                or (index, "low") in field_tracked
            )
            if (
                (high_tracked and merged_high == 0)
                or (low_tracked and merged_low == 0)
            ):
                cleared.append((field, index))
    return cleared


def _batl_write_preserves_non_cooldown_progress(previous_batl, merged_batl):
    for key in BATTLE_PROGRESS_KEYS:
        if key in BATTLE_COOLDOWN_FIELDS:
            continue
        previous_score = _battle_progress_value_score(previous_batl.get(key))
        merged_score = _battle_progress_value_score(merged_batl.get(key))
        if previous_score > 0 and merged_score < previous_score:
            return False, key
    return True, ""


def _merge_battle_cooldown_floor(
    previous_batl,
    merged_batl,
    log,
    label,
    allow_active_increase=False,
    allow_active_clear=False,
    tracked_parts=None,
    expired_parts=None,
):
    changed = 0
    for field in BATTLE_COOLDOWN_FIELDS:
        previous_values = previous_batl.get(field)
        merged_values = merged_batl.get(field)
        if not isinstance(previous_values, list) or not isinstance(merged_values, list):
            continue
        field_tracked = _battle_cooldown_parts_for_field(tracked_parts, field)
        field_expired = _battle_cooldown_parts_for_field(expired_parts, field)
        for index in range(min(len(previous_values), len(merged_values))):
            tracked_halves = {
                part_name
                for tracked_index, part_name in field_tracked
                if tracked_index == index
            }
            try:
                new_value, did_change = _merge_battle_cooldown_value(
                    previous_values[index],
                    merged_values[index],
                    allow_active_increase=allow_active_increase,
                    allow_active_clear=allow_active_clear,
                    tracked_halves=tracked_halves,
                    expired_halves={
                        part_name
                        for expired_index, part_name in field_expired
                        if expired_index == index
                    },
                )
            except Exception:
                continue
            if not did_change:
                continue
            old_value = merged_values[index]
            merged_values[index] = new_value
            changed += 1
            old_remaining = _battle_cooldown_remaining_ms(
                old_value,
                tracked_halves,
            )
            new_remaining = _battle_cooldown_remaining_ms(
                new_value,
                tracked_halves,
            )
            action = (
                f"rejected stale batl.{field}"
                if old_remaining and not new_remaining
                else f"preserved batl.{field}"
            )
            log(
                f"[BATTLE] {label} {action}[{index}] cooldown "
                f"{old_value!r} -> {new_value!r}"
            )
    return changed


# Native code derives the visible Starts In value from TOURNAMENT_TIME and the
# synchronized network clock. Save fields 119/120/125/126/134/135 remain opaque,
# so they must be traced and preserved as client-owned data, never treated as a
# server-owned countdown.
BATTLE_TOURNAMENT_CARD_TIMER_FLOOR_FIELDS = ()
BATTLE_TOURNAMENT_CARD_REMAINING_MS_FIELDS = ()
BATTLE_TOURNAMENT_CARD_TIMER_MAX_REMAINING_MS = 24 * 60 * 60 * 1000
BATTLE_TOURNAMENT_CARD_TIMER_PRESERVE_IF_MISSING_FIELDS = ("134", "135")
BATTLE_TOURNAMENT_SCALED_REMAINING_MS_REPAIR_FIELDS = ()


def _is_plausible_epoch_second_value(value):
    return (
        isinstance(value, int)
        and MIN_PLAUSIBLE_EPOCH_SECONDS <= value <= MAX_PLAUSIBLE_EPOCH_SECONDS
    )


def repair_batl_tournament_scaled_remaining_ms(content, session_state, log, label):
    if not isinstance(content, dict):
        return 0

    changed = 0
    for field in BATTLE_TOURNAMENT_SCALED_REMAINING_MS_REPAIR_FIELDS:
        raw_value = _as_int(content.get(field), None)
        if raw_value is None or raw_value <= 0:
            continue
        if raw_value <= BATTLE_TOURNAMENT_CARD_TIMER_MAX_REMAINING_MS:
            continue
        if raw_value % 1000 != 0:
            continue

        unscaled_value = raw_value // 1000
        if not (0 < unscaled_value <= BATTLE_TOURNAMENT_CARD_TIMER_MAX_REMAINING_MS):
            continue

        old_value = content.get(field)
        content[field] = unscaled_value
        changed += 1
        log(
            f"[TOURNAMENT-CARD] {label} repaired scaled batl.{field} "
            f"remaining-ms {old_value!r}->{unscaled_value!r}"
        )
    return changed


def battle_tournament_card_remaining_values(content):
    if not isinstance(content, dict):
        return []
    values = []
    for field in BATTLE_TOURNAMENT_CARD_REMAINING_MS_FIELDS:
        value = _as_int(content.get(field), None)
        if (
            isinstance(value, int)
            and 0 < value <= BATTLE_TOURNAMENT_CARD_TIMER_MAX_REMAINING_MS
        ):
            values.append((field, value))
    return values


def ensure_batl_tournament_card_timer_fields(content, session_state, log, label):
    if not isinstance(content, dict):
        return 0
    return repair_batl_tournament_scaled_remaining_ms(
        content,
        session_state,
        log,
        label,
    )


def _merge_battle_tournament_card_timer_floor(
    previous_batl,
    merged_batl,
    log,
    label,
    allow_remaining_increase=False,
):
    if not isinstance(previous_batl, dict) or not isinstance(merged_batl, dict):
        return 0

    changed = 0
    if not allow_remaining_increase:
        for field in BATTLE_TOURNAMENT_CARD_TIMER_PRESERVE_IF_MISSING_FIELDS:
            if field not in previous_batl or field in merged_batl:
                continue
            merged_batl[field] = previous_batl[field]
            changed += 1
            log(
                f"[TOURNAMENT-CARD] {label} preserved missing batl.{field} "
                f"value={previous_batl[field]!r}"
            )
    for field in BATTLE_TOURNAMENT_CARD_TIMER_FLOOR_FIELDS:
        if field not in previous_batl or field not in merged_batl:
            continue
        previous_value = _as_int(previous_batl.get(field), None)
        incoming_value = _as_int(merged_batl.get(field), None)
        if previous_value is None or incoming_value is None:
            continue
        if allow_remaining_increase and previous_value != 0:
            continue
        if incoming_value <= previous_value:
            continue
        old_value = merged_batl.get(field)
        merged_batl[field] = previous_batl.get(field)
        changed += 1
        log(
            f"[TOURNAMENT-CARD] {label} preserved batl.{field} "
            f"against backward card timer {old_value!r}->{merged_batl[field]!r} "
            f"delta={incoming_value - previous_value}"
        )
    return changed


def apply_battle_offline_timers_for_replay(
    content,
    session_state,
    log,
    saved=None,
    now_ms=None,
):
    elapsed = _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    source = str(session_state.get("timer_replay_source", "") or "unknown")
    normalize_battle_cooldown_slots(content, log, "replay")
    if elapsed <= 0:
        return
    elapsed_ms = _clamped_timer_elapsed_seconds(elapsed) * 1000
    for field in BATTLE_TOURNAMENT_CARD_REMAINING_MS_FIELDS:
        card_remaining = _as_int(content.get(field), None)
        if (
            isinstance(card_remaining, int)
            and 0 < card_remaining <= BATTLE_TOURNAMENT_CARD_TIMER_MAX_REMAINING_MS
        ):
            new_card_remaining = max(0, card_remaining - elapsed_ms)
            if new_card_remaining != card_remaining:
                content[field] = new_card_remaining
                log(
                    f"[TIME]   batl.{field} tournament card remaining-ms advanced: "
                    f"{card_remaining!r} -> {new_card_remaining!r} "
                    f"(+{elapsed_ms}ms source={source!r})"
                )
    cooldown_fields = [
        field
        for field in BATTLE_COOLDOWN_FIELDS
        if isinstance(content.get(field), list)
    ]
    if not cooldown_fields:
        return
    if isinstance(saved, dict):
        changed = advance_battle_cooldown_tracker(
            saved,
            content,
            elapsed_ms,
            log,
            f"replay source={source!r}",
            now_ms=now_ms,
        )
        if changed:
            log(
                f"[TIME] replay advanced tracked battle cooldown parts={changed} "
                f"source={source!r}"
            )
        return
    changed = 0
    for field in cooldown_fields:
        cooldowns = content[field]
        for index in range(len(cooldowns)):
            old_value = cooldowns[index]
            try:
                new_value = _advance_battle_cooldown_value(old_value, elapsed_ms)
            except Exception:
                continue
            if new_value != old_value:
                cooldowns[index] = new_value
                changed += 1
                log(
                    f"[TIME]   batl.{field}[{index}] cooldown advanced: "
                    f"{old_value!r} -> {new_value!r} (+{elapsed_ms}ms)"
                )
    if changed:
        log(f"[TIME] replay advanced battle cooldown slots={changed} source={source!r}")


def apply_profile_offline_timers_for_replay(
    content,
    session_state,
    log,
    now_ms=None,
):
    elapsed = _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    if elapsed <= 0:
        return
    elapsed_ms = _clamped_timer_elapsed_seconds(elapsed) * 1000
    source = str(session_state.get("timer_replay_source", "") or "unknown")

    touched = session_state.setdefault("server_offline_elapsed_logged_keys", set())
    should_log = "prof" not in touched
    if should_log:
        log_tournament_timer_trace(
            log,
            "profile-offline-replay-before",
            content,
            session_state=session_state,
            elapsed_seconds=elapsed,
            elapsed_ms=elapsed_ms,
            source=source,
        )

    if "144" in content:
        old_val = _as_int(content.get("144"), 0)
        limit = _as_int(content.get("145"), 8 * 60 * 60 * 1000)
        new_val = min(max(old_val, 0) + elapsed_ms, max(limit, 0))
        content["144"] = new_val
        if should_log:
            log(
                f"[TIME]   prof.144 profile timer advanced: "
                f"{old_val} -> {new_val} (+{elapsed_ms}ms limit={limit})"
            )

    applied_now_ms = (
        current_network_time_milliseconds()
        if now_ms is None
        else max(0, _as_int(now_ms, 0))
    )
    for key in ("1", "146"):
        if key not in content:
            continue
        old_val = _as_int(content.get(key), None)
        if old_val is None or old_val <= 0:
            continue
        if _client_epoch_milliseconds(old_val) is None:
            continue
        new_val = applied_now_ms
        content[key] = new_val
        if should_log:
            log(
                f"[TIME]   prof.{key} epoch-ms anchor advanced: "
                f"{old_val} -> {new_val} (rebased after +{elapsed_ms}ms)"
            )

    if should_log:
        log(
            f"[TIME] replay applied profile offline elapsed={elapsed}s "
            f"source={source!r}"
        )
        touched.add("prof")
        log_tournament_timer_trace(
            log,
            "profile-offline-replay-after",
            content,
            session_state=session_state,
            elapsed_seconds=elapsed,
            elapsed_ms=elapsed_ms,
            source=source,
        )


def apply_active_offline_timers_for_replay(
    content,
    session_state,
    log,
    park_key="park",
    saved=None,
    park_record=None,
    skip_port_indexes=None,
):
    elapsed = _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    if elapsed <= 0:
        return
    elapsed = _clamped_timer_elapsed_seconds(elapsed)
    elapsed_ms = elapsed * 1000

    touched = session_state.setdefault("server_offline_elapsed_logged_keys", set())
    should_log = park_key not in touched

    changed_buildings = promote_zeroed_building_rows_from_object_timers(
        content,
        log if should_log else None,
        f"replay {park_key}",
    )

    changed_objects = _advance_object_visual_timers(
        content,
        elapsed_ms,
        log,
        park_key,
        should_log=should_log,
    )

    changed_expansions = 0
    expansion_timers = content.get("50")
    expansion_states = content.get("51")
    if isinstance(expansion_timers, list) and isinstance(expansion_states, list):
        for index in range(min(len(expansion_timers), len(expansion_states))):
            state_value = _as_int(expansion_states[index], 0)
            if state_value == 0:
                continue
            try:
                old_val = expansion_timers[index]
                if not _expansion_timer_manageable(state_value, old_val):
                    if should_log and _expansion_timer_cap_ms(state_value) > 0:
                        log(
                            f"[TIME]   expansion.50[{index}] skipped legacy/overrun: "
                            f"elapsed_ms={_high_u32(old_val)} "
                            f"cap_ms={_expansion_timer_cap_ms(state_value)}"
                        )
                    continue
                new_val = _advance_expansion_timer_value(
                    old_val,
                    elapsed_ms * 2,
                    state_value,
                    ready_margin_ms=0,
                )
                slot_changed = False
                if new_val != old_val:
                    expansion_timers[index] = new_val
                    slot_changed = True
                if should_log and new_val != old_val:
                    log(
                        f"[TIME]   expansion.50[{index}] advanced: {old_val} -> {new_val} "
                        f"(+{elapsed_ms}ms cap_ms={_expansion_timer_cap_ms(state_value)})"
                    )
                if _expansion_timer_ready_to_clear(state_value, expansion_timers[index]):
                    slot_changed = bool(
                        _clear_completed_expansion_slot(
                            content,
                            index,
                            log if should_log else None,
                            f"replay {park_key}",
                        )
                    ) or slot_changed
                elif not slot_changed and should_log and _expansion_timer_cap_ms(state_value) > 0:
                    log(
                        f"[TIME]   expansion.50[{index}] skipped: "
                        f"elapsed_ms={_high_u32(old_val)} "
                        f"cap_ms={_expansion_timer_cap_ms(state_value)}"
                    )
                if slot_changed:
                    changed_expansions += 1
            except Exception as exc:
                if should_log:
                    log(f"[TIME]   expansion.50[{index}] error: {exc!r}")
                continue

    changed_dinos = 0
    dino_count = _as_int(content.get("57"), 0)
    dino_timers = content.get("58")
    if isinstance(dino_timers, list):
        for index in range(min(max(dino_count, 0), len(dino_timers))):
            try:
                old_val = dino_timers[index]
                old_remaining = _low_u32(old_val)
                old_elapsed = _high_u32(old_val)
                new_val = _advance_remaining_elapsed_u32_pair(old_val, elapsed_ms)
                dino_timers[index] = new_val
                changed_dinos += 1
                if should_log:
                    log(
                        f"[TIME]   dino.58[{index}] resumed: {old_val} -> {new_val} "
                        f"remaining {old_remaining}->{_low_u32(new_val)} "
                        f"elapsed {old_elapsed}->{_high_u32(new_val)} (+{elapsed_ms}ms max-aware)"
                    )
            except Exception as exc:
                if should_log:
                    log(f"[TIME]   dino.58[{index}] error: {exc!r}")
                continue

    changed_hatching = 0
    hatch_values = content.get("59")
    if isinstance(hatch_values, list) and isinstance(dino_timers, list):
        for index in range(min(len(hatch_values), len(dino_timers))):
            if not _is_active_hatch_timer(dino_timers[index], hatch_values[index]):
                continue
            try:
                old_val = hatch_values[index]
                new_val = _add_to_p59_hatch_elapsed(old_val, elapsed)
                hatch_grace = _hatch_reconnect_rounding_grace(new_val, session_state)
                if hatch_grace > 0:
                    new_val = _add_to_p59_hatch_elapsed(new_val, hatch_grace)
                hatch_values[index] = new_val
                changed_hatching += 1
                if should_log:
                    grace_text = (
                        f" +{hatch_grace}s reconnect-round"
                        if hatch_grace > 0
                        else ""
                    )
                    log(
                        f"[TIME]   hatch dino.59[{index}] advanced: "
                        f"{old_val} -> {new_val} (+{elapsed}s{grace_text})"
                    )
            except Exception as exc:
                if should_log:
                    log(f"[TIME]   hatch dino.59[{index}] error: {exc!r}")
                continue

    changed_ports = 0
    port_timers = content.get("55")
    skip_port_indexes = {
        max(0, _as_int(index, -1))
        for index in (skip_port_indexes or ())
        if _as_int(index, -1) >= 0
    }
    if isinstance(port_timers, list):
        for index in range(min(2, len(port_timers))):
            if index in skip_port_indexes:
                if should_log:
                    log(
                        f"[TIME]   port.55[{index}] skipped reconnect replay: "
                        "ordered new cycle"
                    )
                continue
            try:
                old_val = port_timers[index]
                old_remaining = _high_u32(old_val)
                old_elapsed = _low_u32(old_val)
                port_replay_ms = _port_replay_elapsed_ms_for_index(
                    saved,
                    park_key,
                    index,
                    old_val,
                    elapsed_ms,
                    park_record=park_record,
                )
                new_val = _advance_port_timer(
                    old_val,
                    port_replay_ms,
                    reset_elapsed_on_signed_overflow=False,
                )
                port_timers[index] = new_val
                changed_ports += 1
                if should_log:
                    cap_note = (
                        f" capped={port_replay_ms}ms"
                        if port_replay_ms != elapsed_ms
                        else ""
                    )
                    log(
                        f"[TIME]   port.55[{index}] resumed: {old_val} -> {new_val} "
                        f"remaining {old_remaining}->{_high_u32(new_val)} "
                        f"elapsed {old_elapsed}->{_low_u32(new_val)} "
                        f"(+{elapsed_ms}ms max-aware{cap_note})"
                    )
            except Exception as exc:
                if should_log:
                    log(f"[TIME]   port.55[{index}] error: {exc!r}")
                continue

    building_ready_grace_ms = _building_reconnect_ready_grace_ms(session_state)
    changed_buildings += repair_inflated_building_timers(content, log, f"replay {park_key}")
    changed_buildings += repair_building_ready_visual_offsets(content, log, f"replay {park_key}")
    changed_buildings += _advance_building_timers_for_content(
        content,
        elapsed,
        log,
        park_key,
        should_log=should_log,
        ready_grace_ms=building_ready_grace_ms,
    )
    changed_buildings += complete_ready_building_rows_for_content(
        content,
        log if should_log else None,
        f"replay {park_key}",
        ready_margin_ms=building_ready_grace_ms,
    )
    changed_objects += sync_building_object_timers_for_storage(
        content,
        log,
        f"replay {park_key}",
    )
    changed_objects += sync_dino_object_timers_for_storage(
        content,
        log,
        f"replay {park_key}",
    )

    if should_log:
        touched.add(park_key)
        log(
            f"[TIME] replay applied active offline elapsed={elapsed}s key={park_key!r} "
            f"source={str(session_state.get('timer_replay_source', '') or 'unknown')!r} "
            f"objects={changed_objects} expansions={changed_expansions} "
            f"dinos={changed_dinos} hatching={changed_hatching} "
            f"buildings={changed_buildings} ports={changed_ports} "
            f"building_ready_grace_ms={building_ready_grace_ms}"
        )


def _advance_code_red_timer(content, elapsed_seconds, log, label, should_log=True):
    """Advance only the captured gen.22/23/24 Code Red timer family."""
    if not isinstance(content, dict):
        return 0
    progress = content.get("23")
    limit = content.get("24")
    if (
        isinstance(progress, bool)
        or not isinstance(progress, int)
        or isinstance(limit, bool)
        or not isinstance(limit, int)
        or limit <= 0
        or progress < 0
        or progress > limit
    ):
        return 0
    elapsed = _clamped_timer_elapsed_seconds(elapsed_seconds)
    new_progress = min(limit, progress + elapsed * 1_000)
    changed = 0
    if new_progress != progress:
        content["23"] = new_progress
        changed += 1
    if new_progress >= limit and content.get("22") is not True:
        content["22"] = True
        changed += 1
    if should_log and changed:
        log(
            f"[TIME] {label} Code Red progress {progress}->{new_progress} "
            f"limit={limit} ready={content.get('22')!r} (+{elapsed}s)"
        )
    return changed


def apply_code_red_offline_timer_for_replay(content, session_state, log):
    elapsed = _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    elapsed = _clamped_timer_elapsed_seconds(elapsed)
    touched = session_state.setdefault("server_offline_elapsed_logged_keys", set())
    should_log = "gen" not in touched
    changed = _advance_code_red_timer(
        content,
        elapsed,
        log,
        "gen.22/23/24",
        should_log=should_log,
    )
    if should_log and changed:
        touched.add("gen")
        log(
            f"[TIME] replay applied Code Red offline elapsed={elapsed}s key='gen' "
            f"source={str(session_state.get('timer_replay_source', '') or 'unknown')!r} "
            f"changed={changed}"
        )
    return changed


def _gen_expedition_active(content):
    if not isinstance(content, dict):
        return False
    return bool(content.get("77")) and not bool(content.get("78"))


def _gen_expedition_total_ms(content):
    if not isinstance(content, dict):
        return 0
    return _as_int(content.get("80"), 0)


def _gen_expedition_ready_to_collect(content):
    total_ms = _gen_expedition_total_ms(content)
    return total_ms > 0 and _as_int(content.get("79"), 0) >= total_ms


def _advance_gen_expedition_elapsed(value, elapsed_sec, total_ms):
    try:
        current = int(value)
    except (TypeError, ValueError):
        return value
    if elapsed_sec <= 0:
        return current
    new_val = current + int(elapsed_sec) * 1_000
    total = _as_int(total_ms, 0)
    if total > 0:
        new_val = min(new_val, total)
    return new_val


def _merge_gen_expedition_elapsed_scalar(incoming, disk, total_ms):
    try:
        inc = int(incoming)
        dsk = int(disk)
    except (TypeError, ValueError):
        return incoming
    merged = max(inc, dsk)
    total = _as_int(total_ms, 0)
    if total > 0:
        merged = min(merged, total)
    return merged


def _advance_gen_expedition_timers(content, elapsed_sec, log, label, should_log):
    if not _gen_expedition_active(content):
        return 0
    total_ms = _gen_expedition_total_ms(content)
    changed = 0
    if "79" in content:
        old_val = content["79"]
        new_val = _advance_gen_expedition_elapsed(old_val, elapsed_sec, total_ms)
        if new_val != old_val:
            content["79"] = new_val
            changed += 1
            if should_log:
                log(
                    f"[TIME]   {label}.79 expedition elapsed advanced: "
                    f"{old_val} -> {new_val} (+{elapsed_sec}s)"
                )
    if total_ms > 0 and _as_int(content.get("79"), 0) >= total_ms:
        if should_log:
            log(
                f"[TIME]   {label}.79 expedition reached total; "
                f"kept 77 active/collectable {content.get('77')!r}"
            )
    return changed


def _expedition_wall_times(meta):
    if not isinstance(meta, dict):
        return {}
    wall_times = meta.get(META_EXPEDITION_WALL_KEY)
    return wall_times if isinstance(wall_times, dict) else {}


def mark_expedition_wall_sync(data, log, keys=None, now_seconds=None, label=""):
    if not isinstance(data, dict):
        return
    meta = data.get("__meta")
    if not isinstance(meta, dict):
        return
    if meta.pop(META_EXPEDITION_WALL_KEY, None) is not None and label:
        log(
            f"[TIME] removed legacy expedition wall ledger label={label!r}; "
            "timer_key_wall is authoritative"
        )


def sync_expedition_wall_timers(data, log, label="", now_seconds=None):
    if not isinstance(data, dict):
        return []
    meta = data.get("__meta")
    if not isinstance(meta, dict):
        return []
    if meta.pop(META_EXPEDITION_WALL_KEY, None) is not None:
        if log:
            log(
                f"[TIME] removed legacy expedition wall ledger label={label!r}; "
                "timer_key_wall is authoritative"
            )
    return []


def apply_expedition_offline_timers_for_replay(content, session_state, log, gen_key="aqge"):
    elapsed = _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    elapsed = _clamped_timer_elapsed_seconds(elapsed)
    touched = session_state.setdefault("server_offline_elapsed_logged_keys", set())
    should_log = gen_key not in touched
    changed_expedition = _advance_gen_expedition_timers(
        content, elapsed, log, gen_key, should_log
    )
    if should_log and changed_expedition and elapsed > 0:
        touched.add(gen_key)
        log(
            f"[TIME] replay applied expedition offline elapsed={elapsed}s "
            f"key={gen_key!r} "
            f"source={str(session_state.get('timer_replay_source', '') or 'unknown')!r} "
            f"expedition={changed_expedition}"
        )
    elif should_log and changed_expedition:
        touched.add(gen_key)
        log(
            f"[TIME] replay normalized expedition timer state "
            f"key={gen_key!r} "
            f"source={str(session_state.get('timer_replay_source', '') or 'unknown')!r} "
            f"expedition={changed_expedition}"
        )


def advance_saved_expedition_timers(data, elapsed_seconds, log):
    elapsed = _clamped_timer_elapsed_seconds(elapsed_seconds)
    if elapsed <= 0:
        return []
    timer_state = {
        "server_offline_elapsed_seconds": elapsed,
        "server_offline_elapsed_logged_keys": set(),
    }
    changed_keys = []
    for gen_key in EXPEDITION_GEN_KEYS:
        record = data.get(gen_key)
        content = saved_content(record)
        if not isinstance(record, dict) or not isinstance(content, dict):
            continue
        previous = json.loads(json.dumps(content))
        apply_expedition_offline_timers_for_replay(
            content, timer_state, log, gen_key=gen_key
        )
        rebase_client_resume_anchor(
            content,
            now_ms=current_network_time_milliseconds(),
            log=log,
            label=f"offline-login expedition {gen_key}",
        )
        if content != previous:
            record["c"] = content
            changed_keys.append(gen_key)
            mark_timer_key_wall(
                data,
                gen_key,
                log,
                "offline-login expedition",
            )
    if elapsed > 0:
        mark_expedition_wall_sync(data, log, label="offline-login")
    return changed_keys


def advance_saved_session_wall_timers(data, session_state, log, label="session"):
    """Trace session elapsed time without mutating saved gameplay timers.

    Older refactors used this path to advance park/profile timers from keepalive
    traffic. That made ordinary polls such as c.gs/c.sg authoritative timer
    writers, while the client was also ticking and writing the same fields. The
    per-key wall clock metadata now owns catchup because each save category
    advances from, and then refreshes, its own last-applied wall timestamp.
    """
    if not isinstance(data, dict) or not isinstance(session_state, dict):
        return []
    now_monotonic = time.monotonic()
    last_monotonic = session_state.get("last_session_timer_monotonic")
    session_state["last_session_timer_monotonic"] = now_monotonic
    if not isinstance(last_monotonic, (int, float)):
        log(f"[TRACE] session-wall {label} initialized monotonic={now_monotonic:.3f}")
        return []
    raw_elapsed = now_monotonic - last_monotonic
    elapsed = _clamped_timer_elapsed_seconds(int(raw_elapsed))
    session_state["last_session_timer_raw_elapsed_seconds"] = raw_elapsed
    session_state["last_session_timer_elapsed_seconds"] = elapsed
    log(
        f"[TRACE] session-wall {label} elapsed={elapsed}s "
        f"raw={raw_elapsed:.3f}s source='server-monotonic' "
        f"last={last_monotonic:.3f} now={now_monotonic:.3f} "
        "changed=[] timer_authority='timer_key_wall'"
    )
    return []


def maintain_saved_timers_for_direct_command(
    save_id,
    fallback_save_ids,
    session_state,
    log,
    label,
):
    """Advance saved timers for direct commands that are not c.c composites."""
    if not save_id or not isinstance(session_state, dict):
        return {}, []
    saved = load_guest_save(save_id, log, fallback_save_ids or [])
    changed_keys = advance_saved_key_wall_timers(
        saved,
        session_state,
        log,
        f"direct {label}",
    )
    session_changed_keys = advance_saved_session_wall_timers(
        saved,
        session_state,
        log,
        f"direct {label}",
    )
    changed_keys = list(dict.fromkeys(changed_keys + session_changed_keys))
    if changed_keys:
        save_guest_data(save_id, saved, log)
        session_state["last_save_persist_monotonic"] = time.monotonic()
        log(
            f"[TIME] direct command persisted session-wall timers "
            f"label={label!r} keys={changed_keys!r}"
        )
    return saved, changed_keys


def advance_saved_key_wall_timers(
    data,
    session_state,
    log,
    label="pre-write",
    active_read_keys=None,
):
    """Catch up initial or explicitly requested saved timers from per-key walls."""
    if not isinstance(data, dict) or not isinstance(session_state, dict):
        return []

    active_session = bool(session_state.get("server_key_wall_catchup_applied"))
    if active_session:
        requested_keys = {
            str(key or "")
            for key in (active_read_keys or ())
            if str(key or "") in OFFLINE_TIMER_REPLAY_KEYS
        }
        replay_keys = tuple(
            key for key in OFFLINE_TIMER_REPLAY_KEYS if key in requested_keys
        )
        if not replay_keys:
            # Non-storage polls and writes must not make an unrelated park look
            # freshly observed.  Accepted writes stamp only their routed key;
            # reads below catch up only the key whose content will be returned.
            return []
        log(
            f"[TIME] active-session on-demand key-wall catch-up "
            f"label={label!r} read_keys={list(replay_keys)!r}"
        )
    else:
        replay_keys = OFFLINE_TIMER_REPLAY_KEYS

    # Consume the connection's offline interval even when it is zero or the
    # first extension is write-only.  Timers created later in this connection
    # must never inherit the frozen login interval.
    if not active_session:
        session_state["server_key_wall_catchup_applied"] = True
    applied_keys = session_state.setdefault(
        "server_offline_elapsed_applied_keys",
        set(),
    )

    changed_keys = []
    for key in replay_keys:
        record = data.get(key)
        content = saved_content(record)
        if not isinstance(record, dict) or not isinstance(content, dict):
            continue

        details = timer_key_elapsed_details(data, key)
        elapsed = _as_int(details.get("elapsed_seconds"), 0)
        log_timer_key_elapsed_details(log, f"{label} key-wall", details)
        now_ms = (
            _as_int(details.get("applied_wall_ms"), 0)
            or _as_int(details.get("server_now_ms"), 0)
            or _as_int(details.get("server_now_seconds"), int(time.time())) * 1000
        )
        if key in applied_keys and not active_session:
            if mark_timer_key_wall(
                data,
                key,
                log,
                f"{label} key-wall already-applied",
                now_ms=now_ms,
            ):
                if key not in changed_keys:
                    changed_keys.append(key)
            continue
        applied_keys.add(key)
        if elapsed <= 0:
            anchor_changed = rebase_client_resume_anchor(
                content,
                now_ms=current_network_time_milliseconds(),
                log=log,
                label=f"{label} key-wall zero {key}",
            )
            if anchor_changed:
                record["c"] = content
                stamp_timer_record_wall(record, now_ms=now_ms)
                if key not in changed_keys:
                    changed_keys.append(key)
            if mark_timer_key_wall(
                data,
                key,
                log,
                f"{label} key-wall zero",
                now_ms=now_ms,
            ):
                if key not in changed_keys:
                    changed_keys.append(key)
            continue
        timer_state = dict(session_state)
        timer_state["server_offline_elapsed_seconds"] = elapsed
        timer_state["timer_replay_source"] = f"{label}-key-wall"
        previous = json.loads(json.dumps(content))
        metadata_changed = 0

        if key == "prof":
            apply_profile_offline_timers_for_replay(
                content,
                timer_state,
                log,
                now_ms=current_network_time_milliseconds(),
            )
        elif key == "batl":
            apply_battle_offline_timers_for_replay(
                content,
                timer_state,
                log,
                saved=data,
                now_ms=now_ms,
            )
            hydrate_battle_context_from_saved(data, content, log, f"{label} {key}")
        elif key == "gen":
            apply_code_red_offline_timer_for_replay(
                content,
                timer_state,
                log,
            )
        elif key in PARK_OFFLINE_TIMER_KEYS:
            observed_wall_ms = _as_int(details.get("last_wall_ms"), 0) or timer_key_seed_wall_ms(data, key, now_ms=now_ms)
            metadata_changed += sync_zeroed_construction_walls_for_key(
                data,
                key,
                content,
                log,
                f"{label} pre-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=observed_wall_ms,
            )
            metadata_changed += sync_building_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} pre-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=observed_wall_ms,
            )
            metadata_changed += sync_hatch_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} pre-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=observed_wall_ms,
            )
            apply_active_offline_timers_for_replay(
                content,
                timer_state,
                log,
                park_key=key,
                saved=data,
                park_record=record,
            )
            metadata_changed += apply_zeroed_construction_walls_for_key(
                data,
                key,
                content,
                log,
                f"{label} key-wall {key}",
                now_ms=now_ms,
            )
            metadata_changed += apply_building_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} key-wall {key}",
                now_ms=now_ms,
                grace_ms=_building_reconnect_ready_grace_ms(timer_state),
            )
            metadata_changed += apply_hatch_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} key-wall {key}",
                now_ms=now_ms,
                grace_seconds=_hatch_reconnect_ready_grace_seconds(timer_state),
            )
        elif key in EXPEDITION_GEN_KEYS:
            apply_expedition_offline_timers_for_replay(
                content,
                timer_state,
                log,
                gen_key=key,
            )

        metadata_changed += rebase_client_resume_anchor(
            content,
            now_ms=current_network_time_milliseconds(),
            log=log,
            label=f"{label} key-wall {key}",
        )

        if content == previous and not metadata_changed:
            mark_timer_key_wall(
                data,
                key,
                log,
                f"{label} key-wall no-change",
                now_ms=now_ms,
            )
            continue

        record["c"] = content
        stamp_timer_record_wall(record, now_ms=now_ms)
        mark_timer_key_wall(
            data,
            key,
            log,
            f"{label} key-wall",
            now_ms=now_ms,
        )
        if key in PARK_OFFLINE_TIMER_KEYS:
            metadata_changed += sync_zeroed_construction_walls_for_key(
                data,
                key,
                content,
                log,
                f"{label} post-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=now_ms,
            )
            metadata_changed += sync_building_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} post-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=now_ms,
            )
            metadata_changed += sync_hatch_ready_deadlines_for_key(
                data,
                key,
                content,
                log,
                f"{label} post-key-wall {key}",
                now_ms=now_ms,
                observed_wall_ms=now_ms,
            )
        changed_keys.append(key)

    if (
        ("prof" in changed_keys or "batl" in changed_keys)
        and isinstance(data.get("prof"), dict)
        and isinstance(saved_content(data.get("prof")), dict)
    ):
        profile_content = saved_content(data.get("prof"))
        if clear_profile_battle_cooldown_payload(
            profile_content,
            log,
            f"{label} post-key-wall prof",
        ):
            profile_record = data.get("prof")
            profile_now_ms = timer_wall_ms()
            profile_record["c"] = profile_content
            stamp_timer_record_wall(profile_record, now_ms=profile_now_ms)
            mark_timer_key_wall(
                data,
                "prof",
                log,
                f"{label} post-key-wall prof",
                now_ms=profile_now_ms,
            )
            if "prof" not in changed_keys:
                changed_keys.append("prof")

    if changed_keys:
        sync_timer_field_snapshots_from_save(
            data,
            log,
            label=f"{label} key-wall",
        )
        log(
            f"[TIME] {label} key-wall advanced stored timers "
            f"keys={changed_keys!r}"
        )
        log_trace_storage(log, f"{label} key-wall", data, changed_keys)
    return changed_keys


def _merge_expedition_content_timer_floor(previous_gen, merged_gen, log, label):
    if not previous_gen or not merged_gen:
        return 0
    changed = 0
    previous_active = _gen_expedition_active(previous_gen)
    merged_active = _gen_expedition_active(merged_gen)
    incoming_elapsed = _as_int(merged_gen.get("79"), 0)
    previous_elapsed = _as_int(previous_gen.get("79"), 0)
    previous_total_ms = _gen_expedition_total_ms(previous_gen)
    incoming_total_ms = _gen_expedition_total_ms(merged_gen)
    previous_start = _as_int(previous_gen.get("82"), 0)
    incoming_start = _as_int(merged_gen.get("82"), 0)
    total_ms = previous_total_ms
    incoming_newer_active_timer = (
        previous_active
        and merged_active
        and (
            incoming_total_ms > previous_total_ms > 0
            or (
                incoming_start > previous_start >= 0
                and incoming_elapsed < previous_elapsed
            )
        )
    )

    if previous_active and merged_active and incoming_newer_active_timer:
        log(
            f"[TIME] {label} accepted newer active expedition timer "
            f"elapsed={incoming_elapsed} total={incoming_total_ms} "
            f"start={incoming_start} over previous elapsed={previous_elapsed} "
            f"total={previous_total_ms} start={previous_start}"
        )
    elif previous_active and merged_active:
        if "79" in merged_gen:
            new_elapsed = _merge_gen_expedition_elapsed_scalar(
                incoming_elapsed,
                previous_elapsed,
                total_ms,
            )
            if new_elapsed != incoming_elapsed:
                merged_gen["79"] = new_elapsed
                changed += 1
                log(
                    f"[TIME] {label} preserved expedition.79 elapsed "
                    f"{incoming_elapsed!r} -> {new_elapsed!r}"
                )
        for field in ("80", "82"):
            if field not in previous_gen:
                continue
            incoming_field = merged_gen.get(field)
            previous_field = previous_gen.get(field)
            if field == "82":
                if _as_int(incoming_field, 0) < _as_int(previous_field, 0):
                    merged_gen[field] = previous_field
                    changed += 1
                    log(
                        f"[TIME] {label} preserved expedition.{field} "
                        f"{incoming_field!r} -> {previous_field!r}"
                    )
            elif incoming_field != previous_field:
                merged_gen[field] = previous_field
                changed += 1
                log(
                    f"[TIME] {label} preserved expedition.{field} "
                    f"{incoming_field!r} -> {previous_field!r}"
                )
    elif previous_active and not merged_active and incoming_elapsed == 0:
        merged_gen["77"] = previous_gen.get("77")
        merged_gen["79"] = previous_elapsed
        if "80" in previous_gen:
            merged_gen["80"] = previous_gen.get("80")
        if "82" in previous_gen:
            merged_gen["82"] = previous_gen.get("82")
        changed += 1
        log(
            f"[TIME] {label} preserved active expedition during park bootstrap "
            f"elapsed {incoming_elapsed} -> {previous_elapsed}"
        )
    elif previous_active and incoming_elapsed < previous_elapsed:
        merged_gen["79"] = previous_elapsed
        if not merged_active:
            merged_gen["77"] = previous_gen.get("77")
        changed += 1
        log(
            f"[TIME] {label} preserved expedition.79 against stale client rollback "
            f"{incoming_elapsed} -> {previous_elapsed}"
        )
    return changed


def merge_expedition_timer_floor(previous, current, log, label):
    merged = json.loads(json.dumps(current or {}))
    total_changed = 0
    for gen_key in EXPEDITION_GEN_KEYS:
        previous_gen = _gen_content(previous, gen_key)
        merged_gen = _gen_content(merged, gen_key)
        if not previous_gen or not merged_gen:
            continue
        record = merged.get(gen_key)
        if not isinstance(record, dict):
            continue
        merged_gen_copy = json.loads(json.dumps(merged_gen))
        changed = _merge_expedition_content_timer_floor(
            previous_gen,
            merged_gen_copy,
            log,
            f"{label} {gen_key}",
        )
        if changed:
            record["c"] = merged_gen_copy
            total_changed += changed
            log(f"[TIME] {label} preserved expedition slots={changed} key={gen_key!r}")
    return merged


def merge_incoming_expedition_write_item(item, saved, log):
    if not isinstance(item, dict):
        return item
    key = str(item.get("k", ""))
    if key not in EXPEDITION_GEN_KEYS:
        return item
    incoming_content = item.get("c")
    if not isinstance(incoming_content, dict):
        return item
    previous_content = saved_content(saved.get(key, {}))
    if not isinstance(previous_content, dict):
        return item
    merged_content = copy.deepcopy(incoming_content)
    changed = _merge_expedition_content_timer_floor(
        previous_content,
        merged_content,
        log,
        f"write-merge {key}",
    )
    if changed:
        item = copy.deepcopy(item)
        item["c"] = merged_content
        log(f"[TIME] write-merge preserved expedition timers key={key!r} slots={changed}")
    return item


def _clamped_timer_elapsed_seconds(elapsed):
    elapsed = max(0, _as_int(elapsed, 0))
    if MAX_TIMER_ELAPSED_SECONDS is None:
        return elapsed
    return min(elapsed, max(0, _as_int(MAX_TIMER_ELAPSED_SECONDS, 0)))


def saved_offline_elapsed_details(data, now_seconds=None):
    if now_seconds is None:
        now_seconds = int(time.time())
    details = {
        "server_now_seconds": now_seconds,
        "elapsed_seconds": 0,
        "raw_elapsed_seconds": 0,
        "last_saved_at": 0,
        "source": "none",
        "meta_last_server_save_time": None,
        "meta_last_server_save_time_ms": None,
        "loaded_file_mtime": None,
    }
    if not isinstance(data, dict):
        details["source"] = f"invalid:{type(data).__name__}"
        return details
    meta = data.get("__meta", {})
    if isinstance(meta, dict):
        candidates = []
        meta_last_s = _as_int(meta.get("last_server_save_time"), None)
        meta_last_ms = _as_int(meta.get("last_server_save_time_ms"), None)
        loaded_mtime = _as_int(meta.get("_loaded_file_mtime"), None)
        details["meta_last_server_save_time"] = meta_last_s
        details["meta_last_server_save_time_ms"] = meta_last_ms
        details["loaded_file_mtime"] = loaded_mtime
        if isinstance(meta_last_s, int) and meta_last_s > 0:
            candidates.append(("meta.last_server_save_time", meta_last_s))
        if isinstance(meta_last_ms, int) and meta_last_ms > 0:
            candidates.append(("meta.last_server_save_time_ms", meta_last_ms // 1000))
        if isinstance(loaded_mtime, int) and loaded_mtime > 0:
            candidates.append(("file.mtime", loaded_mtime))
        if candidates:
            source, last_saved_at = max(candidates, key=lambda item: item[1])
            raw_elapsed = now_seconds - last_saved_at
            details.update({
                "elapsed_seconds": _clamped_timer_elapsed_seconds(raw_elapsed),
                "raw_elapsed_seconds": raw_elapsed,
                "last_saved_at": last_saved_at,
                "source": source,
            })
            return details
    last_saved_at = 0
    source = "none"
    park = data.get("park", {})
    content = park.get("c", {}) if isinstance(park, dict) else {}
    if isinstance(content, dict):
        last_saved_ms = _client_epoch_milliseconds(content.get("1"))
        last_saved_at = last_saved_ms // 1000 if last_saved_ms is not None else 0
        if last_saved_at > 0:
            source = "park.c.1"
    if last_saved_at <= 0:
        for storage_key in EXPEDITION_GEN_KEYS:
            record = data.get(storage_key, {})
            expedition_content = saved_content(record)
            if isinstance(expedition_content, dict):
                candidate_ms = _client_epoch_milliseconds(
                    content_int(expedition_content, 1, 0)
                )
                candidate = candidate_ms // 1000 if candidate_ms is not None else 0
                if candidate > last_saved_at:
                    last_saved_at = candidate
                    source = f"{storage_key}.c.1"
    if last_saved_at <= 0:
        return details
    elapsed = now_seconds - last_saved_at
    details.update({
        "elapsed_seconds": _clamped_timer_elapsed_seconds(elapsed),
        "raw_elapsed_seconds": elapsed,
        "last_saved_at": last_saved_at,
        "source": source,
    })
    return details


def saved_offline_elapsed_seconds(data, now_seconds=None):
    return saved_offline_elapsed_details(data, now_seconds).get("elapsed_seconds", 0)


def remember_offline_elapsed_details(session_state, details):
    if not isinstance(session_state, dict) or not isinstance(details, dict):
        return
    for key in (
        "source",
        "raw_elapsed_seconds",
        "last_saved_at",
        "server_now_seconds",
        "meta_last_server_save_time",
        "meta_last_server_save_time_ms",
        "loaded_file_mtime",
    ):
        session_state[f"offline_elapsed_{key}"] = details.get(key)


def log_saved_offline_elapsed_details(log, label, details):
    if not callable(log) or not isinstance(details, dict):
        return
    log(
        f"[CLOCK] offline-elapsed label={label!r} "
        f"source={details.get('source')!r} "
        f"elapsed={details.get('elapsed_seconds')}s "
        f"raw={details.get('raw_elapsed_seconds')}s "
        f"server_now={details.get('server_now_seconds')} "
        f"last_saved_at={details.get('last_saved_at')} "
        f"meta_s={details.get('meta_last_server_save_time')} "
        f"meta_ms={details.get('meta_last_server_save_time_ms')} "
        f"mtime={details.get('loaded_file_mtime')}"
    )


