def merge_server_resource_floor(
    previous,
    current,
    log,
    label,
    allow_softcash_decrease=False,
    allow_softcash_decrease_reason="",
    allow_resource_decrease_keys=None,
    allow_resource_decrease_reason="",
):
    merged = json.loads(json.dumps(current or {}))
    allowed_resource_decreases = {
        str(key)
        for key in (allow_resource_decrease_keys or ())
    }
    previous_res = (
        previous.get("res", {}).get("c", {})
        if isinstance(previous, dict)
        else {}
    )
    merged_res = (
        merged.get("res", {}).get("c", {})
        if isinstance(merged, dict)
        else {}
    )
    if isinstance(previous_res, dict) and isinstance(merged_res, dict):
        for resource_key in ("2", "4", "6", "7", "Softcash", "Food", "Hardcash", "hardcash"):
            old_value = _as_int(previous_res.get(resource_key), None)
            new_value = _as_int(merged_res.get(resource_key), None)
            if old_value is not None and new_value is not None and old_value > new_value:
                if allow_softcash_decrease and str(resource_key) in ("2", "Softcash"):
                    reason = str(allow_softcash_decrease_reason or "client-progress")
                    log(
                        f"[SAVE] {label} accepted res.{resource_key} decrease "
                        f"{old_value} -> {new_value} reason={reason}"
                    )
                    continue
                if str(resource_key) in allowed_resource_decreases:
                    reason = str(allow_resource_decrease_reason or "client-progress")
                    log(
                        f"[SAVE] {label} accepted res.{resource_key} decrease "
                        f"{old_value} -> {new_value} reason={reason}"
                    )
                    continue
                merged_res[resource_key] = old_value
                log(
                    f"[SAVE] {label} preserved res.{resource_key} "
                    f"{new_value} -> {old_value}"
                )
    return merged


