def client_verified_park_removal_progress_reason(requests, saved):
    iter_requests = requests if isinstance(requests, list) else []
    saved = saved if isinstance(saved, dict) else {}
    for item in iter_requests:
        if not isinstance(item, dict) or item.get("co") not in ("c.zw", "c.ow"):
            continue
        raw_key = str(item.get("k", ""))
        incoming_content = item.get("c")
        if not isinstance(incoming_content, dict):
            continue
        key = routed_park_storage_key(raw_key, incoming_content)
        if key not in PARK_OFFLINE_TIMER_KEYS:
            continue
        previous_content = saved_content(saved.get(key, {}))
        if not park_write_has_verified_client_building_removal(
            previous_content,
            incoming_content,
        ):
            continue
        return (
            f"{key}-verified-building-removal "
            f"objects {content_int(previous_content, '45', 0)}"
            f"->{content_int(incoming_content, '45', 0)} "
            f"buildings {content_int(previous_content, '60', 0)}"
            f"->{content_int(incoming_content, '60', 0)}"
        )
    return ""


def client_transaction_resource_spend_reason(requests):
    iter_requests = requests if isinstance(requests, list) else []
    for item in iter_requests:
        if not isinstance(item, dict) or str(item.get("co", "")).lower() != "c.rt":
            continue
        transaction_type = str(item.get("t", "")).strip().upper()
        debit_amount = _as_int(item.get("da"), 0)
        debit_type = _as_int(item.get("dt"), 0)
        if debit_amount > 0 or debit_type:
            transaction_id = str(item.get("o", "")).strip() or "none"
            return (
                f"c.rt-{transaction_type or 'UNKNOWN'}-{transaction_id} "
                f"da={debit_amount} dt={debit_type}"
            )
    return ""


def merge_new_client_building_slots(
    previous_content,
    incoming_content,
    log,
    label,
    allowed_slots=None,
):
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return copy.deepcopy(previous_content if isinstance(previous_content, dict) else {}), []

    incoming_slot_indexes = _building_slot_indexes(incoming_content)
    previous_slots = set(_building_slot_indexes(previous_content))
    allowed_slot_set = None
    if allowed_slots is not None:
        allowed_slot_set = {
            slot
            for slot in (_as_int(value, None) for value in allowed_slots)
            if slot is not None
        }
    new_slots = [
        slot
        for slot in sorted(incoming_slot_indexes)
        if slot not in previous_slots
        and (allowed_slot_set is None or slot in allowed_slot_set)
    ]
    if not new_slots:
        return copy.deepcopy(previous_content), []

    incoming_objects = incoming_content.get("46")
    incoming_timers = incoming_content.get("47")
    incoming_values = incoming_content.get("61")
    if not isinstance(incoming_objects, list) or not isinstance(incoming_values, list):
        return copy.deepcopy(previous_content), []

    merged = copy.deepcopy(previous_content)
    merged_objects = merged.get("46")
    if not isinstance(merged_objects, list):
        merged_objects = []
        merged["46"] = merged_objects
    merged_timers = merged.get("47")
    if not isinstance(merged_timers, list):
        merged_timers = []
        merged["47"] = merged_timers
    merged_values = merged.get("61")
    if not isinstance(merged_values, list):
        merged_values = []
        merged["61"] = merged_values
    merged_slots = merged.get("62")
    if not isinstance(merged_slots, list):
        merged_slots = []
        merged["62"] = merged_slots

    previous_building_count = max(0, _as_int(merged.get("60"), 0))
    merged_values[:] = merged_values[:previous_building_count]
    merged_slots[:] = merged_slots[:previous_building_count]
    previous_object_count = max(0, _as_int(merged.get("45"), 0))

    added_slots = []
    for slot in new_slots:
        incoming_index = incoming_slot_indexes.get(slot)
        if incoming_index is None or incoming_index < 0 or incoming_index >= len(incoming_values):
            continue
        if slot < 0 or slot >= len(incoming_objects):
            continue

        incoming_object = copy.deepcopy(incoming_objects[slot])
        incoming_timer = (
            copy.deepcopy(incoming_timers[slot])
            if isinstance(incoming_timers, list) and slot < len(incoming_timers)
            else 0
        )
        if (
            _high_u32(incoming_object) == 0
            and _low_u32(incoming_object) == 0
            and _high_u32(incoming_timer) == 0
            and _low_u32(incoming_timer) == 0
        ):
            log(
                f"[SAVE-GUARD] skipped client-added building slot={slot} "
                f"label={label} reason=empty-object-and-timer"
            )
            continue

        while len(merged_objects) <= slot:
            merged_objects.append(0)
        while len(merged_timers) <= slot:
            merged_timers.append(0)

        old_object = merged_objects[slot]
        old_timer = merged_timers[slot]
        merged_objects[slot] = incoming_object
        merged_timers[slot] = incoming_timer
        merged_values.append(copy.deepcopy(incoming_values[incoming_index]))
        merged_slots.append(slot)
        added_slots.append(slot)
        log(
            f"[SAVE-GUARD] merged client-added building slot={slot} "
            f"row={incoming_index} label={label} "
            f"old_object={old_object!r} old_timer={old_timer!r} "
            f"new_object={incoming_object!r} new_timer={incoming_timer!r}"
        )

    if added_slots:
        merged["45"] = max(previous_object_count, max(added_slots) + 1)
        merged["60"] = previous_building_count + len(added_slots)
    return merged, added_slots


def merge_new_client_dino_rows(previous_content, incoming_content, log, label):
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return copy.deepcopy(previous_content if isinstance(previous_content, dict) else {}), []

    previous_count = max(0, _as_int(previous_content.get("57"), 0))
    incoming_count = max(0, _as_int(incoming_content.get("57"), 0))
    if incoming_count <= previous_count:
        return copy.deepcopy(previous_content), []

    incoming_timers = incoming_content.get("58")
    incoming_values = incoming_content.get("59")
    if not isinstance(incoming_timers, list) or not isinstance(incoming_values, list):
        return copy.deepcopy(previous_content), []

    merged = copy.deepcopy(previous_content)
    merged_timers = merged.get("58")
    if not isinstance(merged_timers, list):
        merged_timers = []
        merged["58"] = merged_timers
    merged_values = merged.get("59")
    if not isinstance(merged_values, list):
        merged_values = []
        merged["59"] = merged_values

    merged_timers[:] = merged_timers[:previous_count]
    merged_values[:] = merged_values[:previous_count]

    added_rows = []
    limit = min(incoming_count, len(incoming_timers), len(incoming_values))
    for index in range(previous_count, limit):
        incoming_timer = copy.deepcopy(incoming_timers[index])
        incoming_value = copy.deepcopy(incoming_values[index])
        if _as_int(incoming_timer, 0) == 0 and _as_int(incoming_value, 0) == 0:
            log(
                f"[SAVE-GUARD] skipped client-added dino row={index} "
                f"label={label} reason=empty-row"
            )
            continue
        merged_timers.append(incoming_timer)
        merged_values.append(incoming_value)
        row = {
            "row": index,
            "dino_id": _low_u32(incoming_value),
            "58h": _high_u32(incoming_timer),
            "58l": _low_u32(incoming_timer),
            "59h": _high_u32(incoming_value),
            "59l": _low_u32(incoming_value),
        }
        added_rows.append(row)
        log(
            f"[SAVE-GUARD] merged client-added dino row={index} "
            f"dino_id={row['dino_id']} label={label} "
            f"timer={incoming_timer!r} value={incoming_value!r}"
        )

    if added_rows:
        merged["57"] = previous_count + len(added_rows)
    return merged, added_rows


def merge_new_client_tail_object_rows(previous_content, incoming_content, log, label):
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return copy.deepcopy(previous_content if isinstance(previous_content, dict) else {}), []

    previous_count = max(0, _as_int(previous_content.get("45"), 0))
    incoming_count = max(0, _as_int(incoming_content.get("45"), 0))
    if incoming_count <= previous_count:
        return copy.deepcopy(previous_content), []

    incoming_objects = incoming_content.get("46")
    incoming_timers = incoming_content.get("47")
    if not isinstance(incoming_objects, list):
        return copy.deepcopy(previous_content), []

    merged = copy.deepcopy(previous_content)
    merged_objects = merged.get("46")
    if not isinstance(merged_objects, list):
        merged_objects = []
        merged["46"] = merged_objects
    merged_timers = merged.get("47")
    if not isinstance(merged_timers, list):
        merged_timers = []
        merged["47"] = merged_timers

    added_slots = []
    limit = min(incoming_count, len(incoming_objects))
    for slot in range(previous_count, limit):
        incoming_object = copy.deepcopy(incoming_objects[slot])
        incoming_timer = (
            copy.deepcopy(incoming_timers[slot])
            if isinstance(incoming_timers, list) and slot < len(incoming_timers)
            else 0
        )
        if _as_int(incoming_object, 0) == 0 and _as_int(incoming_timer, 0) == 0:
            log(
                f"[SAVE-GUARD] skipped client-added object slot={slot} "
                f"label={label} reason=empty-object-and-timer"
            )
            continue

        while len(merged_objects) <= slot:
            merged_objects.append(0)
        while len(merged_timers) <= slot:
            merged_timers.append(0)

        old_object = merged_objects[slot]
        old_timer = merged_timers[slot]
        merged_objects[slot] = incoming_object
        merged_timers[slot] = incoming_timer
        added_slots.append(slot)
        log(
            f"[SAVE-GUARD] merged client-added object slot={slot} "
            f"label={label} old_object={old_object!r} old_timer={old_timer!r} "
            f"new_object={incoming_object!r} new_timer={incoming_timer!r}"
        )

    if added_slots:
        merged["45"] = max(previous_count, max(added_slots) + 1)
    return merged, added_slots


def merge_new_client_stale_arctic_rows(existing_record, item, reason, log, label):
    if "stale lower-count building snapshot" not in str(reason or ""):
        return {}, [], [], []
    if str(item.get("k", "")) != "arpk":
        return {}, [], [], []

    existing_version = _as_int(existing_record.get("v"), None) if isinstance(existing_record, dict) else None
    incoming_version = _as_int(item.get("v"), None)
    if existing_version is not None and incoming_version is not None and incoming_version <= existing_version:
        log(
            f"[SAVE-GUARD] skipped Arctic mixed snapshot row merge "
            f"label={label} reason=non-increasing-version {existing_version}->{incoming_version}"
        )
        return {}, [], [], []

    existing_content = saved_content(existing_record)
    incoming_content = item.get("c")
    layout_reason = arctic_versioned_building_layout_reason(
        existing_record,
        item,
    )
    if layout_reason:
        incoming_buildings = max(0, _as_int(incoming_content.get("60"), 0))
        incoming_slots = incoming_content.get("62")
        accepted_slots = (
            list(incoming_slots[:incoming_buildings])
            if isinstance(incoming_slots, list)
            else []
        )
        log(
            "[SAVE-GUARD] accepted Arctic versioned building layout correction "
            f"label={label} reason={layout_reason} slots={accepted_slots!r}"
        )
        return copy.deepcopy(incoming_content), [], accepted_slots, []

    merged_content, added_object_slots = merge_new_client_tail_object_rows(
        existing_content,
        incoming_content,
        log,
        label,
    )
    added_building_slots = []
    if added_object_slots:
        # Arctic can send a mixed snapshot: old building count plus new tail
        # object slots. Only attach building rows for tail objects already
        # accepted above; broader stale building salvage stays disabled.
        merged_content, added_building_slots = merge_new_client_building_slots(
            merged_content,
            incoming_content,
            log,
            label,
            allowed_slots=added_object_slots,
        )
    merged_content, added_dino_rows = merge_new_client_dino_rows(
        merged_content,
        incoming_content,
        log,
        label,
    )
    if not added_object_slots and not added_building_slots and not added_dino_rows:
        return {}, [], [], []
    return merged_content, added_object_slots, added_building_slots, added_dino_rows


def arctic_versioned_building_layout_reason(previous_record, current_record):
    if not isinstance(previous_record, dict) or not isinstance(current_record, dict):
        return ""
    previous_version = _as_int(previous_record.get("v"), None)
    current_version = _as_int(current_record.get("v"), None)
    if previous_version is None or current_version is None or current_version <= previous_version:
        return ""
    previous_content = saved_content(previous_record)
    current_content = saved_content(current_record)
    if not (
        isinstance(previous_content, dict)
        and isinstance(current_content, dict)
        and park_content_is_initialized(previous_content)
        and park_content_is_initialized(current_content)
    ):
        return ""
    previous_objects = max(0, _as_int(previous_content.get("45"), 0))
    current_objects = max(0, _as_int(current_content.get("45"), 0))
    previous_dinos = max(0, _as_int(previous_content.get("57"), 0))
    current_dinos = max(0, _as_int(current_content.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_content.get("60"), 0))
    current_buildings = max(0, _as_int(current_content.get("60"), 0))
    if (
        current_objects != previous_objects
        or current_dinos < previous_dinos
        or current_buildings <= 0
        or current_buildings >= previous_buildings
    ):
        return ""
    current_slots = current_content.get("62")
    current_values = current_content.get("61")
    previous_slots = previous_content.get("62")
    if (
        not isinstance(previous_slots, list)
        or not isinstance(current_slots, list)
        or not isinstance(current_values, list)
    ):
        return ""
    if len(current_slots) < current_buildings or len(current_values) < current_buildings:
        return ""
    accepted_slots = list(current_slots[:current_buildings])
    if list(previous_slots[:current_buildings]) == accepted_slots:
        return ""
    if len(set(accepted_slots)) != len(accepted_slots):
        return ""
    for slot in accepted_slots:
        slot_int = _as_int(slot, None)
        if slot_int is None or slot_int < 0 or slot_int >= current_objects:
            return ""
    return (
        f"arpk version increased {previous_version}->{current_version} "
        f"objects stable {previous_objects}->{current_objects} "
        f"dinos {previous_dinos}->{current_dinos} "
        f"building rows {previous_buildings}->{current_buildings}"
    )


def _ready_building_rows_by_slot(content):
    rows = {}
    if not isinstance(content, dict):
        return rows
    values = content.get("61")
    if not isinstance(values, list):
        return rows
    object_count = max(0, _as_int(content.get("45"), 0))
    count = min(max(0, _as_int(content.get("60"), 0)), len(values))
    for index in range(count):
        slot = _building_object_index(content, index)
        if slot is None and object_count <= 0:
            slot = index
        if slot is None:
            continue
        value = values[index]
        if _high_u32(value) == 0 and _low_u32(value) == 0:
            continue
        if _low_u32(value) > 0:
            continue
        rows.setdefault(slot, (index, value))
    return rows


def _preserve_building_object_rows(previous_park, merged_park, log, label):
    previous_building_count = max(0, _as_int(previous_park.get("60"), 0))
    if previous_building_count <= 0:
        return 0
    previous_objects = previous_park.get("46")
    previous_timers = previous_park.get("47")
    previous_building_values = previous_park.get("61")
    if not isinstance(previous_objects, list) or not isinstance(previous_building_values, list):
        return 0

    merged_objects = merged_park.get("46")
    if not isinstance(merged_objects, list):
        merged_objects = []
        merged_park["46"] = merged_objects
    merged_timers = merged_park.get("47")
    if not isinstance(merged_timers, list):
        merged_timers = []
        merged_park["47"] = merged_timers

    building_slots = merged_park.get("62")
    if not isinstance(building_slots, list):
        building_slots = []
        merged_park["62"] = building_slots

    changed = 0
    target_slots_used = set()
    for building_index in range(min(previous_building_count, len(previous_building_values))):
        is_zeroed_construction = _zeroed_construction_building_row_active(
            previous_park,
            building_index,
        )
        if _low_u32(previous_building_values[building_index]) <= 0 and not is_zeroed_construction:
            continue
        previous_slot = _building_object_index(previous_park, building_index)
        if previous_slot is None or previous_slot >= len(previous_objects):
            continue

        previous_object = previous_objects[previous_slot]
        previous_timer = (
            previous_timers[previous_slot]
            if isinstance(previous_timers, list) and previous_slot < len(previous_timers)
            else 0
        )
        active_count = min(max(0, _as_int(merged_park.get("45"), 0)), len(merged_objects))
        target_slot = None
        for index in range(active_count):
            if index in target_slots_used:
                continue
            if merged_objects[index] == previous_object:
                target_slot = index
                break

        if target_slot is None and is_zeroed_construction:
            continue

        if target_slot is None:
            if (
                0 <= previous_slot < active_count
                and previous_slot < len(merged_objects)
                and merged_objects[previous_slot] != previous_object
            ):
                log(
                    f"[SAVE-GUARD] {label} skipped restoring building object "
                    f"slot={previous_slot} reason=object-slot-changed"
                )
                continue
            target_slot = active_count
            if target_slot < len(merged_objects):
                merged_objects[target_slot] = previous_object
            else:
                merged_objects.append(previous_object)
            while len(merged_timers) < target_slot:
                merged_timers.append(0)
            if target_slot < len(merged_timers):
                merged_timers[target_slot] = previous_timer
            else:
                merged_timers.append(previous_timer)
            old_count = _as_int(merged_park.get("45"), 0)
            if old_count <= target_slot:
                merged_park["45"] = target_slot + 1
            changed += 1
            log(
                f"[SAVE-GUARD] {label} restored building object "
                f"slot={previous_slot} -> {target_slot}"
            )
        target_slots_used.add(target_slot)
    return changed


def _preserve_active_construction_deadline_rows(saved, key, content, log, label):
    if key not in PARK_OFFLINE_TIMER_KEYS:
        return 0
    if not isinstance(saved, dict) or not isinstance(content, dict):
        return 0
    deadlines = building_ready_deadline_slots(saved, key, create=False)
    if not deadlines:
        return 0
    previous_park = saved_content(saved.get(key, {}))
    if not isinstance(previous_park, dict):
        return 0
    previous_object_count = max(0, _as_int(previous_park.get("45"), 0))
    incoming_object_count = max(0, _as_int(content.get("45"), 0))
    if incoming_object_count < previous_object_count:
        log(
            f"[SAVE-GUARD] {label} skipped active construction row preservation "
            f"key={key!r} reason=lower-object-count "
            f"objects={previous_object_count}->{incoming_object_count}"
        )
        return 0
    previous_rows = _building_rows_by_slot(previous_park)
    incoming_rows = _building_rows_by_slot(content)
    if not previous_rows:
        return 0

    previous_objects = previous_park.get("46")
    previous_timers = previous_park.get("47")
    incoming_objects = content.get("46")
    incoming_timers = content.get("47")
    incoming_values = content.get("61")
    incoming_slots = content.get("62")
    if (
        not isinstance(previous_objects, list)
        or not isinstance(previous_timers, list)
        or not isinstance(incoming_objects, list)
        or not isinstance(incoming_timers, list)
        or not isinstance(incoming_values, list)
        or not isinstance(incoming_slots, list)
    ):
        return 0

    now_ms = timer_wall_ms()
    active_count = min(max(0, _as_int(content.get("45"), 0)), len(incoming_objects))
    changed = 0
    for slot_key, deadline in list(deadlines.items()):
        if not isinstance(deadline, dict):
            continue
        ready_at = _as_int(deadline.get("ready_at_ms"), 0)
        remaining = _as_int(deadline.get("remaining_ms"), 0)
        if ready_at <= now_ms or remaining <= 0:
            continue
        slot = _as_int(slot_key, None)
        if slot is None or slot in incoming_rows:
            continue
        previous_row = previous_rows.get(slot)
        if previous_row is None:
            continue
        previous_index, previous_value = previous_row
        if _low_u32(previous_value) <= 0:
            continue
        if slot < 0 or slot >= len(previous_objects) or slot >= len(previous_timers):
            continue
        previous_object = previous_objects[slot]
        previous_timer = previous_timers[slot]
        if deadline.get("object_id") != _building_deadline_object_id(previous_park, slot):
            continue

        target_slot = None
        if slot < active_count and incoming_objects[slot] == previous_object:
            target_slot = slot
        else:
            for candidate in range(active_count):
                if candidate in incoming_rows:
                    continue
                if incoming_objects[candidate] == previous_object:
                    target_slot = candidate
                    break
        if target_slot is None:
            target_slot = active_count
            if target_slot < len(incoming_objects):
                incoming_objects[target_slot] = previous_object
            else:
                incoming_objects.append(previous_object)
            while len(incoming_timers) < target_slot:
                incoming_timers.append(0)
            if target_slot < len(incoming_timers):
                incoming_timers[target_slot] = previous_timer
            else:
                incoming_timers.append(previous_timer)
            if _as_int(content.get("45"), 0) <= target_slot:
                content["45"] = target_slot + 1
            active_count = max(active_count, target_slot + 1)

        incoming_values.append(previous_value)
        incoming_slots.append(target_slot)
        incoming_rows[target_slot] = (len(incoming_values) - 1, previous_value)
        old_count = _as_int(content.get("60"), 0)
        content["60"] = len(incoming_values)
        changed += 1
        log(
            f"[SAVE-GUARD] {label} preserved active construction row "
            f"key={key!r} slot={slot}->{target_slot} previous_index={previous_index} "
            f"building_count={old_count}->{content['60']} ready_at_ms={ready_at}"
        )
    return changed


def _restore_dropped_observed_construction_rows(previous_park, merged_park, log, label):
    if not isinstance(previous_park, dict) or not isinstance(merged_park, dict):
        return 0
    previous_object_count = max(0, _as_int(previous_park.get("45"), 0))
    merged_object_count = max(0, _as_int(merged_park.get("45"), 0))
    if merged_object_count < previous_object_count:
        return 0

    previous_objects = previous_park.get("46")
    previous_timers = previous_park.get("47")
    previous_values = previous_park.get("61")
    if (
        not isinstance(previous_objects, list)
        or not isinstance(previous_timers, list)
        or not isinstance(previous_values, list)
    ):
        return 0

    merged_objects = merged_park.get("46")
    merged_timers = merged_park.get("47")
    if not isinstance(merged_objects, list) or not isinstance(merged_timers, list):
        return 0

    merged_values = merged_park.get("61")
    if not isinstance(merged_values, list):
        merged_values = []
        merged_park["61"] = merged_values
    merged_slots = merged_park.get("62")
    if not isinstance(merged_slots, list):
        merged_slots = []
        merged_park["62"] = merged_slots

    existing_slots = set()
    for index in range(max(0, _as_int(merged_park.get("60"), 0))):
        slot = _building_object_index(merged_park, index)
        if slot is not None:
            existing_slots.add(slot)

    changed = 0
    previous_building_count = min(
        max(0, _as_int(previous_park.get("60"), 0)),
        len(previous_values),
    )
    for index in range(previous_building_count):
        if not _observed_zeroed_construction_building_row(previous_park, index):
            continue
        slot = _building_object_index(previous_park, index)
        if slot is None or slot in existing_slots:
            continue
        if slot < 0 or slot >= merged_object_count:
            continue
        if slot >= len(previous_objects) or slot >= len(previous_timers):
            continue

        previous_object = previous_objects[slot]
        previous_timer = previous_timers[slot]
        current_object = merged_objects[slot] if slot < len(merged_objects) else None
        current_timer = merged_timers[slot] if slot < len(merged_timers) else None
        merged_objects[slot] = previous_object
        merged_timers[slot] = previous_timer
        merged_values.append(_pack_u32_pair(0, 0))
        merged_slots.append(slot)
        existing_slots.add(slot)
        changed += 1
        log(
            f"[SAVE-GUARD] {label} restored dropped construction building row "
            f"slot={slot} index={index} object={current_object!r}->{previous_object!r} "
            f"timer={current_timer!r}->{previous_timer!r}"
        )

    if changed:
        old_count = _as_int(merged_park.get("60"), 0)
        merged_park["60"] = len(merged_values)
        if merged_park["60"] != old_count:
            changed += 1
            log(
                f"[SAVE-GUARD] {label} adjusted construction building count "
                f"{old_count!r}->{merged_park['60']!r}"
            )
    return changed


def _synthesize_missing_building_rows(
    previous_park,
    merged_park,
    log,
    label,
    allow_missing_client_rows=False,
):
    previous_objects = previous_park.get("46")
    merged_objects = merged_park.get("46")
    merged_timers = merged_park.get("47")
    if not isinstance(previous_objects, list) or not isinstance(merged_objects, list):
        return 0
    if not isinstance(merged_timers, list):
        return 0

    previous_count = max(0, _as_int(previous_park.get("45"), 0))
    merged_count = min(max(0, _as_int(merged_park.get("45"), 0)), len(merged_objects))
    if merged_count <= 0:
        return 0

    building_values = merged_park.get("61")
    if not isinstance(building_values, list):
        building_values = []
        merged_park["61"] = building_values
    building_slots = merged_park.get("62")
    if not isinstance(building_slots, list):
        building_slots = []
        merged_park["62"] = building_slots

    previous_slots = []
    previous_slot_set = set()
    previous_zeroed_construction_slots = {}
    for index in range(max(0, _as_int(previous_park.get("60"), 0))):
        slot = _building_object_index(previous_park, index)
        if slot is not None:
            previous_slots.append(slot)
            previous_slot_set.add(slot)
            if _zeroed_construction_building_row_active(previous_park, index):
                previous_zeroed_construction_slots.setdefault(slot, index)
    existing_slots = set()
    for index in range(max(0, _as_int(merged_park.get("60"), 0))):
        slot = _building_object_index(merged_park, index)
        if slot is not None:
            existing_slots.add(slot)

    candidate_start = min(previous_slots) if previous_slots else previous_count
    candidate_start = max(0, min(candidate_start, merged_count))
    changed = 0
    for slot in range(candidate_start, merged_count):
        if slot in existing_slots:
            continue
        zeroed_construction_index = previous_zeroed_construction_slots.get(slot)
        same_previous_object = (
            slot < previous_count
            and slot < len(previous_objects)
            and merged_objects[slot] == previous_objects[slot]
        )
        if zeroed_construction_index is None:
            if not allow_missing_client_rows:
                continue
            is_new_tail_object = slot >= previous_count
            if not is_new_tail_object and (slot not in previous_slot_set or not same_previous_object):
                log(
                    f"[SAVE-GUARD] {label} skipped synthesized building row "
                    f"slot={slot} reason=unproven-client-object"
                )
                continue
        if zeroed_construction_index is not None and not same_previous_object:
            continue
        object_timer = merged_timers[slot] if slot < len(merged_timers) else 0
        try:
            object_elapsed = max(0, _high_u32(object_timer))
        except Exception:
            object_elapsed = 0
        building_values.append(_pack_u32_pair(0, 0))
        building_slots.append(slot)
        existing_slots.add(slot)
        changed += 1
        log(
            f"[SAVE-GUARD] {label} synthesized zeroed building row "
            f"slot={slot} object_elapsed={object_elapsed} "
            f"reason={'missing-zeroed-construction-row' if zeroed_construction_index is not None else 'missing-client-building-row'}"
        )

    if changed:
        old_count = _as_int(merged_park.get("60"), 0)
        merged_park["60"] = len(building_values)
        if merged_park["60"] != old_count:
            changed += 1
    return changed


def _building_collect_reset_visual_is_sane(merged_park, index, merged_value, total):
    total = max(0, _as_int(total, 0))
    if total <= 0:
        return False, "missing-total"
    object_elapsed_wire = _building_linked_object_elapsed_ms(merged_park, index)
    if object_elapsed_wire is None:
        return False, "missing-linked-object"
    object_elapsed = object_elapsed_wire // 2
    incoming_elapsed = _high_u32(merged_value)
    incoming_remaining = _low_u32(merged_value)
    if incoming_remaining <= 0:
        return True, "incoming-ready"
    if not _elapsed_reset_is_fresh(incoming_elapsed):
        return (
            False,
            (
                "incoming-reset-not-fresh "
                f"incoming_elapsed={incoming_elapsed} "
                f"incoming_remaining={incoming_remaining} "
                f"threshold_ms={POST_REPLAY_TIMER_RESET_MS}"
            ),
        )
    if not _elapsed_reset_is_fresh(object_elapsed):
        return (
            False,
            (
                "linked-object-reset-not-fresh "
                f"object_elapsed={object_elapsed} "
                f"incoming_elapsed={incoming_elapsed} "
                f"incoming_remaining={incoming_remaining} "
                f"threshold_ms={POST_REPLAY_TIMER_RESET_MS}"
            ),
        )
    if object_elapsed >= total:
        return (
            False,
            (
                "linked-object-still-ready "
                f"object_elapsed={object_elapsed} total={total} "
                f"incoming_elapsed={incoming_elapsed} "
                f"incoming_remaining={incoming_remaining}"
            ),
        )
    if object_elapsed > incoming_elapsed + STALE_CLIENT_BUILDING_CONTINUATION_MS:
        return (
            False,
            (
                "linked-object-ahead-of-reset "
                f"object_elapsed={object_elapsed} "
                f"incoming_elapsed={incoming_elapsed} "
                f"incoming_remaining={incoming_remaining}"
            ),
        )
    return True, "linked-object-reset"


def _proven_building_cycle_reconfiguration_reason(
    previous_park,
    merged_park,
    previous_index,
    merged_index,
    slot,
    previous_value,
    merged_value,
    ordered_record_reason="",
):
    """Prove a client-owned c.61 cycle change for one stable building row."""
    if not ordered_record_reason:
        return ""
    previous_slot = _building_object_index(previous_park, previous_index)
    merged_slot = _building_object_index(merged_park, merged_index)
    if previous_slot != slot or merged_slot != slot:
        return ""
    previous_total = _building_timer_total_ms(previous_value)
    merged_total = _building_timer_total_ms(merged_value)
    if previous_total <= 0 or merged_total <= 0 or previous_total == merged_total:
        return ""
    merged_elapsed = _high_u32(merged_value)
    merged_remaining = _low_u32(merged_value)
    if merged_remaining <= 0 or not _elapsed_reset_is_fresh(merged_elapsed):
        return ""

    previous_objects = previous_park.get("46")
    merged_objects = merged_park.get("46")
    previous_object_timers = previous_park.get("47")
    merged_object_timers = merged_park.get("47")
    previous_object_count = max(0, _as_int(previous_park.get("45"), 0))
    merged_object_count = max(0, _as_int(merged_park.get("45"), 0))
    if not (
        isinstance(previous_objects, list)
        and isinstance(merged_objects, list)
        and isinstance(previous_object_timers, list)
        and isinstance(merged_object_timers, list)
        and 0 <= slot < previous_object_count
        and slot < merged_object_count
        and slot < len(previous_objects)
        and slot < len(merged_objects)
        and slot < len(previous_object_timers)
        and slot < len(merged_object_timers)
    ):
        return ""
    previous_object = previous_objects[slot]
    if _as_int(previous_object, 0) == 0 or previous_object != merged_objects[slot]:
        return ""
    if _low_u32(previous_object_timers[slot]) != _low_u32(merged_object_timers[slot]):
        return ""
    linked_elapsed = _high_u32(merged_object_timers[slot])
    if not _building_linked_double_elapsed_matches(linked_elapsed, merged_elapsed):
        return ""
    return (
        f"stable-building-cycle total={previous_total}->{merged_total} "
        f"object={previous_object!r} linked_elapsed={linked_elapsed} "
        f"{ordered_record_reason}"
    )


def _projected_building_collect_reset_reason(
    previous_park,
    merged_park,
    previous_index,
    merged_index,
    slot,
    previous_value,
    merged_value,
    previous_write_elapsed_ms,
):
    """Prove that one active saved c.61 row was due at the client claim instant."""
    previous_elapsed = _high_u32(previous_value)
    previous_remaining = _low_u32(previous_value)
    merged_elapsed = _high_u32(merged_value)
    merged_remaining = _low_u32(merged_value)
    previous_total = _building_timer_total_ms(previous_value)
    merged_total = _building_timer_total_ms(merged_value)
    if previous_remaining <= 0:
        return "previous-already-ready"
    if merged_remaining <= 0:
        return "incoming-not-active"
    if previous_total <= 0 or merged_total != previous_total:
        return "cycle-mismatch"
    if not _elapsed_reset_is_fresh(merged_elapsed):
        return "incoming-reset-not-fresh"
    if merged_elapsed >= previous_elapsed or merged_remaining <= previous_remaining:
        return "not-reset-direction"

    previous_slots = previous_park.get("62")
    merged_slots = merged_park.get("62")
    if not (
        isinstance(previous_slots, list)
        and isinstance(merged_slots, list)
        and previous_index < len(previous_slots)
        and merged_index < len(merged_slots)
        and _as_int(previous_slots[previous_index], None) == slot
        and _as_int(merged_slots[merged_index], None) == slot
    ):
        return "building-slot-mismatch"
    for park in (previous_park, merged_park):
        building_count = max(0, _as_int(park.get("60"), 0))
        slot_matches = 0
        for index in range(building_count):
            if _building_object_index(park, index) == slot:
                slot_matches += 1
        if slot_matches != 1:
            return "ambiguous-building-slot"

    previous_objects = previous_park.get("46")
    merged_objects = merged_park.get("46")
    previous_object_timers = previous_park.get("47")
    merged_object_timers = merged_park.get("47")
    previous_object_count = max(0, _as_int(previous_park.get("45"), 0))
    merged_object_count = max(0, _as_int(merged_park.get("45"), 0))
    if not (
        isinstance(previous_objects, list)
        and isinstance(merged_objects, list)
        and isinstance(previous_object_timers, list)
        and isinstance(merged_object_timers, list)
        and 0 <= slot < previous_object_count
        and slot < merged_object_count
        and slot < len(previous_objects)
        and slot < len(merged_objects)
        and slot < len(previous_object_timers)
        and slot < len(merged_object_timers)
        and _as_int(previous_objects[slot], 0) != 0
        and previous_objects[slot] == merged_objects[slot]
    ):
        return "object-identity-mismatch"
    if _low_u32(previous_object_timers[slot]) != _low_u32(merged_object_timers[slot]):
        return "linked-object-identity-mismatch"
    linked_elapsed = _high_u32(merged_object_timers[slot])
    if not _building_linked_double_elapsed_matches(linked_elapsed, merged_elapsed):
        return "linked-object-reset-mismatch"

    claim_projection_ms = max(
        0,
        max(0, _as_int(previous_write_elapsed_ms, 0)) - merged_elapsed,
    )
    projected = _advance_building_production_timer_ms(
        previous_value,
        claim_projection_ms,
        previous_total,
    )
    if _low_u32(projected) > 0:
        return "previous-not-due"
    if merged_elapsed >= _high_u32(projected):
        return "not-reset-from-projected-ready"
    return "proven"


def _preserve_building_production_timers(
    previous_park,
    merged_park,
    log,
    label,
    allow_building_collects=False,
    allow_visual_building_collect_resets=True,
    server_elapsed_ms=None,
    previous_write_elapsed_ms=0,
    building_ready_grace_ms=0,
    ordered_record_reason="",
):
    previous_values = previous_park.get("61")
    merged_values = merged_park.get("61")
    if not isinstance(previous_values, list) or not isinstance(merged_values, list):
        return 0
    changed = 0
    merged_slots = merged_park.get("62")
    if not isinstance(merged_slots, list):
        merged_slots = []
        merged_park["62"] = merged_slots
    merged_count = min(max(_as_int(merged_park.get("60"), 0), 0), len(merged_values))
    previous_count = min(max(_as_int(previous_park.get("60"), 0), 0), len(previous_values))
    preserve_ready_rows = previous_count <= merged_count + 8
    previous_by_slot = _building_rows_by_slot(previous_park, active_only=not preserve_ready_rows)
    previous_ready_by_slot = (
        {}
        if preserve_ready_rows
        else _ready_building_rows_by_slot(previous_park)
    )
    elapsed_ms = max(0, _as_int(server_elapsed_ms, 0))
    write_elapsed_ms = max(0, _as_int(previous_write_elapsed_ms, 0))
    building_ready_grace_ms = max(0, _as_int(building_ready_grace_ms, 0))
    seen_slots = set()
    merged_object_count = max(0, _as_int(merged_park.get("45"), 0))
    for index in range(merged_count):
        slot = _building_object_index(merged_park, index)
        if slot is None and merged_object_count <= 0:
            slot = index
        if slot is None:
            continue
        seen_slots.add(slot)
        previous_row = previous_by_slot.get(slot)
        matched_ready_row = False
        if previous_row is None and previous_ready_by_slot:
            ready_row = previous_ready_by_slot.get(slot)
            if ready_row is not None:
                try:
                    if _low_u32(merged_values[index]) > 0:
                        previous_row = ready_row
                        matched_ready_row = True
                except Exception:
                    pass
        if previous_row is None:
            continue
        previous_index, previous_value = previous_row
        try:
            merged_value = merged_values[index]
            projected_reset_direction = (
                _low_u32(previous_value) > 0
                and _low_u32(merged_value) > _low_u32(previous_value)
                and _high_u32(merged_value) < _high_u32(previous_value)
            )
            if projected_reset_direction:
                projected_reset_reason = _projected_building_collect_reset_reason(
                    previous_park,
                    merged_park,
                    previous_index,
                    index,
                    slot,
                    previous_value,
                    merged_value,
                    write_elapsed_ms,
                )
                if projected_reset_reason == "proven":
                    log(
                        f"[TIME] {label} accepted projected-ready collected building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"value {previous_value!r}->{merged_value!r} "
                        f"previous_write_elapsed_ms={write_elapsed_ms} "
                        "reason=projected-ready+linked-object"
                    )
                    continue
                if (
                    allow_building_collects
                    and projected_reset_reason
                    in _WALLET_PROVEN_PROJECTED_COLLECT_OVERRIDE_REASONS
                    and _elapsed_reset_is_fresh(_high_u32(merged_value))
                ):
                    log(
                        f"[TIME] {label} accepted collected building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"value {previous_value!r}->{merged_value!r} "
                        f"previous_write_elapsed_ms={write_elapsed_ms} "
                        f"reason=coin-wallet-delta projected_override={projected_reset_reason}"
                    )
                    continue
                log(
                    f"[TIME] {label} blocked active collected building.61 reset "
                    f"slot={slot} index={index} prev_index={previous_index} "
                    f"previous_write_elapsed_ms={write_elapsed_ms} "
                    f"reason={projected_reset_reason}"
                )
            cycle_change_reason = _proven_building_cycle_reconfiguration_reason(
                previous_park,
                merged_park,
                previous_index,
                index,
                slot,
                previous_value,
                merged_value,
                ordered_record_reason=ordered_record_reason,
            )
            if cycle_change_reason:
                log(
                    f"[TIME] {label} accepted ordered building.61 cycle reconfiguration "
                    f"slot={slot} index={index} prev_index={previous_index} "
                    f"value {previous_value!r}->{merged_value!r} "
                    f"reason={cycle_change_reason}"
                )
                continue
            total = _building_cycle_ms(previous_park, previous_index, previous_value)
            previous_normalized = _advance_building_production_timer_ms(
                previous_value,
                0,
                total,
            )
            previous_authoritative = previous_normalized
            if elapsed_ms > 0 and _low_u32(previous_normalized) > 0:
                previous_authoritative = _advance_building_production_timer_ms(
                    previous_normalized,
                    elapsed_ms,
                    total,
                    ready_grace_ms=building_ready_grace_ms,
                )
            previous_at_write = previous_authoritative
            if (
                elapsed_ms <= 0
                and write_elapsed_ms > 0
                and _low_u32(previous_normalized) > 0
            ):
                previous_at_write = _advance_building_production_timer_ms(
                    previous_normalized,
                    write_elapsed_ms,
                    total,
                    ready_grace_ms=building_ready_grace_ms,
            )
            previous_remaining = _low_u32(previous_authoritative)
            previous_elapsed = _high_u32(previous_authoritative)
            previous_write_remaining = _low_u32(previous_at_write)
            previous_write_elapsed = _high_u32(previous_at_write)
            merged_normalized = _advance_building_production_timer_ms(
                merged_value,
                0,
                total,
            )
            merged_remaining = _low_u32(merged_normalized)
            merged_elapsed = _high_u32(merged_normalized)
            merged_cycle_total = _building_timer_total_ms(merged_normalized)
            authoritative = None

            if previous_remaining == 0 and merged_remaining > 0:
                merged_total = _building_timer_total_ms(merged_value)
                max_delayed_reset_ms = OFFLINE_RECONNECT_WRITE_CATCHUP_SECONDS * 1000
                stable_building_object = not _building_object_identity_changed(
                    previous_park,
                    merged_park,
                    slot,
                )
                independent_cycle_reset = (
                    preserve_ready_rows
                    and stable_building_object
                    and previous_elapsed > 0
                    and merged_total == previous_elapsed
                    and merged_elapsed > 0
                    and merged_elapsed + merged_remaining == merged_total
                )
                if independent_cycle_reset:
                    log(
                        f"[TIME] {label} accepted client-owned building.61 cycle reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={merged_elapsed} "
                        f"incoming_remaining={merged_remaining} "
                        f"incoming_total={merged_total}"
                    )
                    continue
                visual_collect_ok, visual_collect_reason = (
                    _building_collect_reset_visual_is_sane(
                        merged_park,
                        index,
                        merged_value,
                        merged_total,
                    )
                )
                linked_object_elapsed = _building_linked_object_elapsed_ms(
                    merged_park,
                    index,
                )
                exact_linked_reset = (
                    preserve_ready_rows
                    and stable_building_object
                    and previous_elapsed > 0
                    and merged_total > 0
                    and previous_elapsed == merged_total
                    and merged_elapsed > 0
                    and merged_elapsed + merged_remaining == merged_total
                    and _building_linked_double_elapsed_matches(
                        linked_object_elapsed,
                        merged_elapsed,
                    )
                )
                exact_doubled_linked_reset = (
                    preserve_ready_rows
                    and stable_building_object
                    and previous_elapsed > 0
                    and merged_total > 0
                    and previous_elapsed == merged_total
                    and POST_REPLAY_TIMER_RESET_MS < merged_elapsed <= max_delayed_reset_ms
                    and merged_elapsed + merged_remaining == merged_total
                    and _building_linked_double_elapsed_matches(linked_object_elapsed, merged_elapsed)
                )
                if allow_visual_building_collect_resets and exact_linked_reset:
                    log(
                    f"[TIME] {label} accepted doubled linked-object building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={merged_remaining} "
                        f"incoming_total={merged_total} "
                        f"linked_object_elapsed={linked_object_elapsed} "
                        f"visual={visual_collect_reason}"
                    )
                elif allow_visual_building_collect_resets and exact_doubled_linked_reset:
                    log(
                        f"[TIME] {label} accepted doubled linked-object building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={merged_remaining} "
                        f"incoming_total={merged_total} "
                        f"linked_object_elapsed={linked_object_elapsed} "
                        f"double_diff_ms={abs(linked_object_elapsed - (merged_elapsed * 2))} "
                        f"tolerance_ms={BUILDING_LINKED_DOUBLE_TOLERANCE_MS} "
                        f"threshold_ms={max_delayed_reset_ms} "
                        f"visual={visual_collect_reason}"
                    )
                elif (
                    allow_visual_building_collect_resets
                    and stable_building_object
                    and visual_collect_ok
                    and visual_collect_reason == "linked-object-reset"
                    and previous_elapsed > 0
                    and merged_total > 0
                    and (
                        previous_elapsed == merged_total
                        or _building_cycle_ms(merged_park, index, merged_value) == merged_total
                    )
                ):
                    log(
                        f"[TIME] {label} accepted linked-object building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={merged_remaining} "
                        f"incoming_total={merged_total} "
                        f"visual={visual_collect_reason}"
                    )
                elif (
                    allow_building_collects
                    and stable_building_object
                    and previous_elapsed > 0
                    and merged_total > 0
                    and visual_collect_ok
                    and (
                        previous_elapsed == merged_total
                        or _building_cycle_ms(merged_park, index, merged_value) == merged_total
                    )
                ):
                    log(
                        f"[TIME] {label} accepted collected building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={merged_remaining} "
                        f"incoming_total={merged_total} "
                        f"visual={visual_collect_reason}"
                    )
                elif (
                    not allow_visual_building_collect_resets
                    and (
                        exact_linked_reset
                        or exact_doubled_linked_reset
                        or (
                            visual_collect_ok
                            and visual_collect_reason == "linked-object-reset"
                            and previous_elapsed > 0
                            and merged_total > 0
                            and (
                                previous_elapsed == merged_total
                                or _building_cycle_ms(merged_park, index, merged_value) == merged_total
                            )
                        )
                    )
                ):
                    authoritative = previous_authoritative
                    log(
                        f"[TIME] {label} blocked pre-read linked-object building.61 reset "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={_low_u32(merged_value)} "
                        f"incoming_total={merged_total} "
                        f"visual={visual_collect_reason}"
                    )
                elif allow_building_collects:
                    authoritative = previous_normalized
                    log(
                        f"[TIME] {label} blocked collected building.61 reset "
                        f"for inconsistent timer slot={slot} index={index} "
                        f"prev_index={previous_index} ready_elapsed={previous_elapsed} "
                        f"incoming_elapsed={_high_u32(merged_value)} "
                        f"incoming_remaining={_low_u32(merged_value)} incoming_total={merged_total} "
                        f"visual={visual_collect_reason}"
                    )
                elif 0 < merged_total < previous_elapsed:
                    authoritative = _pack_u32_pair(0, merged_total)
                    log(
                        f"[TIME] {label} corrected inflated ready building.61 "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"ready_elapsed={previous_elapsed} -> cycle={merged_total} "
                        f"from incoming active row"
                    )
                else:
                    authoritative = previous_authoritative
            else:
                if (
                    elapsed_ms <= 0
                    and write_elapsed_ms > 0
                    and previous_remaining > 0
                    and previous_write_remaining > 0
                    and total > 0
                    and merged_cycle_total == total
                    and merged_elapsed
                    > previous_write_elapsed + PRODUCTION_TIMER_CLIENT_AHEAD_TOLERANCE_MS
                ):
                    authoritative = previous_at_write
                    log(
                        f"[TIME] {label} blocked premature client-ahead building.61 "
                        f"slot={slot} index={index} prev_index={previous_index} "
                        f"elapsed {merged_elapsed}->{previous_write_elapsed} "
                        f"remaining {merged_remaining}->{previous_write_remaining} "
                        f"previous_write_elapsed_ms={write_elapsed_ms} "
                        f"tolerance_ms={PRODUCTION_TIMER_CLIENT_AHEAD_TOLERANCE_MS}"
                    )
                elif (
                    merged_elapsed < previous_elapsed
                    or merged_remaining > previous_remaining
                    or (total > 0 and merged_elapsed > total)
                ):
                    authoritative = previous_at_write
                elif merged_normalized != merged_value:
                    authoritative = merged_normalized
        except Exception as exc:
            log(f"[TIME] {label} building.61[{index}] preserve error: {exc!r}")
            continue

        if authoritative is None or authoritative == merged_value:
            continue
        merged_values[index] = authoritative
        changed += 1
        grace_applied = (
            building_ready_grace_ms > 0
            and previous_remaining > elapsed_ms
            and _low_u32(authoritative) == 0
        )
        grace_text = (
            f" reconnect-ready-grace<={building_ready_grace_ms}ms"
            if grace_applied
            else ""
        )
        active_over_ready = previous_remaining == 0 and merged_remaining > 0
        ready_match_text = (
            " stale-active-over-ready"
            if matched_ready_row or active_over_ready
            else ""
        )
        log(
            f"[TIME] {label} preserved building.61 slot={slot} "
            f"index {index} prev_index {previous_index} "
            f"{merged_value!r} -> {authoritative!r}{grace_text}{ready_match_text}"
        )
    object_count = max(0, _as_int(merged_park.get("45"), 0))
    for slot, (previous_index, previous_value) in previous_by_slot.items():
        if slot in seen_slots or slot >= object_count:
            continue
        if not _building_slot_object_matches(previous_park, merged_park, slot):
            log(
                f"[TIME] {label} skipped restoring missing building.61 slot={slot} "
                f"prev_index={previous_index} reason=object-slot-changed"
            )
            continue
        total = _building_cycle_ms(previous_park, previous_index, previous_value)
        authoritative = _advance_building_production_timer_ms(
            previous_value,
            elapsed_ms,
            total,
            ready_grace_ms=building_ready_grace_ms,
        )
        remaining = _low_u32(authoritative)
        if remaining <= 0:
            linked_object_elapsed = _building_linked_object_elapsed_ms(
                merged_park,
                previous_index,
            )
            if not (
                preserve_ready_rows
                and (
                    allow_building_collects
                    or (
                        linked_object_elapsed is not None
                        and linked_object_elapsed >= (_high_u32(authoritative) * 2)
                    )
                )
            ):
                continue
        merged_values.append(authoritative)
        merged_slots.append(slot)
        seen_slots.add(slot)
        changed += 1
        state_text = "ready" if remaining <= 0 else "active"
        log(
            f"[TIME] {label} restored {state_text} building.61 slot={slot} "
            f"prev_index={previous_index} value={authoritative!r}"
        )
    if changed:
        old_count = _as_int(merged_park.get("60"), 0)
        merged_park["60"] = len(merged_values)
        if merged_park["60"] != old_count:
            changed += 1
            log(
                f"[TIME] {label} adjusted building count "
                f"{old_count!r} -> {merged_park['60']!r}"
            )
    return changed


def _composite_allows_dino_collects(requests, saved_before, session_state, log):
    if not isinstance(session_state, dict):
        session_state = {}
    login_guard = bool(
        session_state.get("block_login_building_collects")
        and not session_state.get("served_save_read")
    )

    previous_res = saved_before.get("res", {}).get("c", {}) if isinstance(saved_before, dict) else {}
    previous_coins = content_int(previous_res, "2", 0)
    for item in requests or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("co", "")) not in ("c.ow", "c.zw"):
            continue
        if str(item.get("k", "")) != "res":
            continue
        content = item.get("c")
        if not isinstance(content, dict):
            continue
        new_coins = content_int(content, "2", previous_coins)
        if new_coins > previous_coins:
            log(
                f"[TIME] wallet delta allows dino collect reset "
                f"coins {previous_coins} -> {new_coins}"
            )
            return True
    if login_guard:
        log("[TIME] blocked pre-replay dino collect reset without wallet delta")
    return False


def _composite_allows_building_collects(requests, saved_before, session_state, log):
    if not isinstance(session_state, dict):
        session_state = {}
    login_guard = bool(session_state.pop("block_login_building_collects", False))
    login_guard = bool(login_guard and not session_state.get("served_save_read"))

    previous_res = saved_before.get("res", {}).get("c", {}) if isinstance(saved_before, dict) else {}
    previous_coins = content_int(previous_res, "2", 0)
    for item in requests or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("co", "")) not in ("c.ow", "c.zw"):
            continue
        if str(item.get("k", "")) != "res":
            continue
        content = item.get("c")
        if not isinstance(content, dict):
            continue
        new_coins = content_int(content, "2", previous_coins)
        if new_coins > previous_coins:
            log(
                f"[TIME] wallet delta allows production collect reset "
                f"coins {previous_coins} -> {new_coins}"
            )
            return True
    if login_guard:
        log("[TIME] blocked pre-replay building collect reset without wallet delta")
    return False


def _client_building_rows_for_requests(requests):
    snapshots = {}
    for item in requests or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("co", "")) not in ("c.ow", "c.zw"):
            continue
        key = str(item.get("k", ""))
        if key not in PARK_OFFLINE_TIMER_KEYS:
            continue
        content = item.get("c")
        if not isinstance(content, dict):
            continue
        rows = {}
        for slot, (index, value) in _building_rows_by_slot(content).items():
            rows[str(slot)] = {
                "index": index,
                "elapsed": _high_u32(value),
                "remaining": _low_u32(value),
                "total": _building_timer_total_ms(value),
            }
        if rows:
            snapshots[key] = rows
    return snapshots


def remember_client_building_rows(requests, session_state, log, label):
    if not isinstance(session_state, dict):
        return
    snapshots = _client_building_rows_for_requests(requests)
    if not snapshots:
        return
    remembered = session_state.get("last_client_building_rows_by_key")
    if not isinstance(remembered, dict):
        remembered = {}
    # A park write updates only that park's client snapshot.  Retain the other
    # parks so Surface -> Aquatic -> Surface navigation cannot erase the row
    # history used to classify a later production collection.
    remembered.update(snapshots)
    session_state["last_client_building_rows_by_key"] = remembered
    session_state["last_client_building_rows_label"] = str(label or "")
    session_state["last_client_building_rows_monotonic"] = time.monotonic()
    if log:
        log(
            f"[TIME] remembered client building rows label={label!r} "
            f"keys={sorted(snapshots)!r}"
        )


def _building_collect_reset_looks_like_stale_client(
    requests,
    saved_before,
    session_state,
    log,
):
    if not isinstance(session_state, dict):
        return False
    previous_client_rows = session_state.get("last_client_building_rows_by_key")
    if not isinstance(previous_client_rows, dict):
        previous_client_rows = {}
    stale = 0
    candidates = 0
    non_stale = 0
    details = []
    for item in requests or []:
        if not isinstance(item, dict):
            continue
        if str(item.get("co", "")) not in ("c.ow", "c.zw"):
            continue
        key = str(item.get("k", ""))
        if key not in PARK_OFFLINE_TIMER_KEYS:
            continue
        incoming = item.get("c")
        previous = _park_content(saved_before, key)
        if not isinstance(incoming, dict) or not previous:
            continue
        previous_ready = _ready_building_rows_by_slot(previous)
        incoming_rows = _building_rows_by_slot(incoming)
        remembered_rows = previous_client_rows.get(key, {})
        if not isinstance(remembered_rows, dict):
            remembered_rows = {}
        for slot, (_incoming_index, incoming_value) in incoming_rows.items():
            previous_row = previous_ready.get(slot)
            if previous_row is None:
                continue
            _previous_index, previous_value = previous_row
            previous_elapsed = _high_u32(previous_value)
            incoming_elapsed = _high_u32(incoming_value)
            incoming_remaining = _low_u32(incoming_value)
            incoming_total = _building_timer_total_ms(incoming_value)
            if incoming_remaining <= 0:
                continue
            if previous_elapsed <= 0 or incoming_total <= 0:
                continue
            remembered = remembered_rows.get(str(slot))
            candidates += 1
            long_cycle = (
                previous_elapsed > OBJECT_PRODUCTION_READY_CAP_MS
                or incoming_total > OBJECT_PRODUCTION_READY_CAP_MS
            )
            if not isinstance(remembered, dict):
                if long_cycle:
                    stale += 1
                    details.append(
                        f"key={key} slot={slot} no-remembered-row "
                        f"incoming={incoming_elapsed} remaining={incoming_remaining} "
                        f"total={incoming_total} previous_ready={previous_elapsed}"
                    )
                else:
                    non_stale += 1
                continue
            remembered_elapsed = _as_int(remembered.get("elapsed"), 0)
            remembered_remaining = _as_int(remembered.get("remaining"), 0)
            if remembered_remaining <= 0:
                non_stale += 1
                continue
            advance = incoming_elapsed - remembered_elapsed
            row_detail = (
                f"key={key} slot={slot} remembered={remembered_elapsed} "
                f"incoming={incoming_elapsed} advance={advance} "
                f"remaining={incoming_remaining} total={incoming_total} "
                f"previous_ready={previous_elapsed}"
            )
            if 0 <= advance <= STALE_CLIENT_BUILDING_CONTINUATION_MS:
                stale += 1
                details.append(row_detail)
            else:
                non_stale += 1
    if candidates > 0 and stale > 0:
        if log:
            log(
                f"[TIME] stale client building collect pattern "
                f"candidates={candidates} stale={stale} non_stale={non_stale} "
                f"details={details!r}"
            )
        return True
    return False


def _merge_park_timer_floor(
    previous_park,
    merged_park,
    log,
    label,
    allow_client_timer_resets=False,
    allow_building_collects=False,
    allow_dino_collects=False,
    allow_visual_building_collect_resets=True,
    allow_dino_count_decrease=False,
    server_elapsed_ms=None,
    previous_write_elapsed_ms=0,
    building_ready_grace_ms=0,
    synthesize_missing_building_rows=True,
    ordered_record_reason="",
    saved=None,
    park_key=None,
    park_record=None,
    proven_port_cycle_change_indexes=None,
):
    if not previous_park or not merged_park:
        return 0
    if _park_write_orphans_buildings(previous_park, merged_park):
        log(f"[SAVE-GUARD] {label} repairing park snapshot that would orphan buildings")
    changed = 0
    building_ready_grace_ms = max(0, _as_int(building_ready_grace_ms, 0))
    if proven_port_cycle_change_indexes is None:
        proven_port_cycle_change_indexes = _proven_port_cycle_change_indexes(
            previous_park,
            merged_park,
            ordered_record_reason=ordered_record_reason,
        )
    else:
        proven_port_cycle_change_indexes = list(proven_port_cycle_change_indexes)
    if _as_int(server_elapsed_ms, 0) > 0:
        elapsed_ms = _as_int(server_elapsed_ms, 0)
        changed += apply_park_reconnect_timer_catchup(
            merged_park,
            elapsed_ms,
            log,
            label,
            uncapped_object_start_index=max(0, _as_int(previous_park.get("45"), 0)),
            park_key=park_key,
            saved=saved,
            park_record=park_record,
            skip_port_indexes=proven_port_cycle_change_indexes,
        )
    changed += _preserve_counted_array_group(
        previous_park,
        merged_park,
        "45",
        ("46", "47"),
        log,
        label,
        "park objects",
        allow_client_count_decrease=True,
    )
    if allow_dino_count_decrease:
        previous_count = _as_int(previous_park.get("57"), 0)
        merged_count = _as_int(merged_park.get("57"), 0)
        if previous_count > merged_count:
            log(
                f"[SAVE] {label} accepted dino count decrease "
                f"{previous_count}->{merged_count} reason=verified-client-building-removal"
            )
    else:
        changed += _preserve_missing_dino_rows_by_identity(
            previous_park,
            merged_park,
            log,
            label,
        )
    changed += _preserve_dino_timer_progress(
        previous_park,
        merged_park,
        log,
        label,
        allow_client_timer_resets=allow_client_timer_resets,
        allow_dino_collects=allow_dino_collects,
        server_elapsed_ms=server_elapsed_ms,
        previous_write_elapsed_ms=previous_write_elapsed_ms,
        ordered_record_reason=ordered_record_reason,
    )
    changed += _preserve_counted_array_group(
        previous_park,
        merged_park,
        "60",
        ("61", "62"),
        log,
        label,
        "buildings",
        allow_client_count_decrease=True,
    )
    changed += _preserve_building_object_rows(previous_park, merged_park, log, label)
    changed += _preserve_building_production_timers(
        previous_park,
        merged_park,
        log,
        label,
        allow_building_collects=allow_building_collects,
        allow_visual_building_collect_resets=allow_visual_building_collect_resets,
        server_elapsed_ms=server_elapsed_ms,
        previous_write_elapsed_ms=previous_write_elapsed_ms,
        building_ready_grace_ms=building_ready_grace_ms,
        ordered_record_reason=ordered_record_reason,
    )
    if synthesize_missing_building_rows:
        changed += _synthesize_missing_building_rows(
            previous_park,
            merged_park,
            log,
            label,
            allow_missing_client_rows=_as_int(server_elapsed_ms, 0) > 0,
        )
    changed += promote_zeroed_building_rows_from_object_timers(
        merged_park,
        log,
        label,
    )
    changed += _preserve_object_timer_progress(
        previous_park,
        merged_park,
        log,
        label,
        allow_client_timer_resets=allow_client_timer_resets or allow_building_collects,
        allow_visual_building_collect_resets=allow_visual_building_collect_resets,
        object_reset_threshold=POST_REPLAY_TIMER_RESET_MS,
    )
    changed += repair_inflated_object_production_timers(
        merged_park,
        log,
        label,
    )
    changed += repair_building_ready_visual_offsets(
        merged_park,
        log,
        label,
    )
    changed += complete_ready_building_rows_for_content(
        merged_park,
        log,
        label,
        ready_margin_ms=building_ready_grace_ms,
    )
    changed += _preserve_active_expansion_state(
        previous_park,
        merged_park,
        log,
        label,
        allow_client_timer_resets=allow_client_timer_resets,
    )
    changed += _preserve_active_expansion_timers(
        previous_park,
        merged_park,
        log,
        label,
        allow_client_timer_resets=allow_client_timer_resets,
    )
    changed += _preserve_port_resume_progress(
        previous_park,
        merged_park,
        log,
        label,
        allow_client_timer_resets=allow_client_timer_resets,
        ordered_record_reason=ordered_record_reason,
        proven_cycle_change_indexes=proven_port_cycle_change_indexes,
    )
    changed += _preserve_p59_hatch_elapsed(previous_park, merged_park, log, label)
    changed += sync_dino_object_timers_for_storage(
        merged_park,
        log,
        label,
    )
    changed += sync_building_object_timers_for_storage(
        merged_park,
        log,
        label,
        complete_active_from_object=not allow_building_collects,
    )
    return changed


def merge_server_timer_floor(
    previous,
    current,
    log,
    label,
    allow_client_timer_resets=False,
    allow_building_collects=False,
    allow_dino_collects=False,
    allow_visual_building_collect_resets=True,
    allow_dino_count_decrease_keys=None,
    server_elapsed_ms=None,
    previous_write_elapsed_ms_by_key=None,
    building_ready_grace_ms=0,
    synthesize_missing_building_rows=True,
    served_save_read_keys=None,
):
    merged = json.loads(json.dumps(current or {}))
    allow_dino_count_decrease_keys = {
        str(key)
        for key in (allow_dino_count_decrease_keys or ())
    }
    previous_write_elapsed_ms_by_key = (
        previous_write_elapsed_ms_by_key
        if isinstance(previous_write_elapsed_ms_by_key, dict)
        else {}
    )
    total_changed = 0
    for park_key in PARK_OFFLINE_TIMER_KEYS:
        previous_park = _park_content(previous, park_key)
        merged_park = _park_content(merged, park_key)
        ordered_record_reason = _ordered_served_park_write_reason(
            park_key,
            previous.get(park_key) if isinstance(previous, dict) else None,
            merged.get(park_key) if isinstance(merged, dict) else None,
            served_save_read_keys=served_save_read_keys,
        )
        proven_port_indexes = _proven_port_cycle_change_indexes(
            previous_park,
            merged_park,
            ordered_record_reason=ordered_record_reason,
        )
        changed = _merge_park_timer_floor(
            previous_park,
            merged_park,
            log,
            f"{label} {park_key}",
            allow_client_timer_resets=allow_client_timer_resets,
            allow_building_collects=allow_building_collects,
            allow_dino_collects=allow_dino_collects,
            allow_visual_building_collect_resets=allow_visual_building_collect_resets,
            allow_dino_count_decrease=park_key in allow_dino_count_decrease_keys,
            server_elapsed_ms=server_elapsed_ms,
            previous_write_elapsed_ms=previous_write_elapsed_ms_by_key.get(park_key, 0),
            building_ready_grace_ms=building_ready_grace_ms,
            synthesize_missing_building_rows=synthesize_missing_building_rows,
            ordered_record_reason=ordered_record_reason,
            saved=previous,
            park_key=park_key,
            park_record=previous.get(park_key) if isinstance(previous, dict) else None,
            proven_port_cycle_change_indexes=proven_port_indexes,
        )
        if changed:
            total_changed += changed
            log(f"[TIME] {label} preserved timer slots={changed} key={park_key!r}")
        if proven_port_indexes:
            stamp_port_cycle_walls(
                merged,
                park_key,
                proven_port_indexes,
                log=log,
                label=f"{label} {park_key}",
            )
    if isinstance(previous, dict) and isinstance(merged, dict):
        previous_gen_record = previous.get("gen")
        incoming_gen_record = merged.get("gen")
        if isinstance(previous_gen_record, dict) and isinstance(incoming_gen_record, dict):
            ordered_gen_reason = _ordered_served_gen_write_reason(
                previous_gen_record,
                incoming_gen_record,
                served_save_read_keys=served_save_read_keys,
            )
            gen_timer_changed = _preserve_code_red_timer_progress(
                previous_gen_record,
                incoming_gen_record,
                log,
                f"{label} gen",
                ordered_record_reason=ordered_gen_reason,
            )
            if gen_timer_changed:
                log(
                    f"[TIME] {label} preserved Code Red timer slots="
                    f"{gen_timer_changed}"
                )
    return merged


def _postreplay_park_snapshot_regressed(previous_park, current_park):
    if not isinstance(previous_park, dict) or not isinstance(current_park, dict):
        return False
    if not park_content_is_initialized(previous_park):
        return False
    previous_objects = max(0, _as_int(previous_park.get("45"), 0))
    current_objects = max(0, _as_int(current_park.get("45"), 0))
    previous_dinos = max(0, _as_int(previous_park.get("57"), 0))
    current_dinos = max(0, _as_int(current_park.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_park.get("60"), 0))
    current_buildings = max(0, _as_int(current_park.get("60"), 0))
    object_drop = previous_objects - current_objects
    dino_drop = previous_dinos - current_dinos
    building_drop = previous_buildings - current_buildings
    if object_drop <= 0 and dino_drop <= 0 and building_drop <= 0:
        return False
    return building_drop > 0 or dino_drop > 0 or object_drop >= 3


def _postreplay_park_object_tail_regressed(previous_park, current_park):
    if not isinstance(previous_park, dict) or not isinstance(current_park, dict):
        return False
    if not park_content_is_initialized(previous_park):
        return False
    previous_objects = max(0, _as_int(previous_park.get("45"), 0))
    current_objects = max(0, _as_int(current_park.get("45"), 0))
    if previous_objects <= current_objects:
        return False
    previous_dinos = max(0, _as_int(previous_park.get("57"), 0))
    current_dinos = max(0, _as_int(current_park.get("57"), 0))
    previous_buildings = max(0, _as_int(previous_park.get("60"), 0))
    current_buildings = max(0, _as_int(current_park.get("60"), 0))
    return previous_dinos <= current_dinos and previous_buildings <= current_buildings


def _restore_missing_park_object_tail(previous_park, current_park, log, label):
    if not _postreplay_park_object_tail_regressed(previous_park, current_park):
        return 0
    previous_objects = previous_park.get("46")
    previous_timers = previous_park.get("47")
    current_objects = current_park.get("46")
    current_timers = current_park.get("47")
    if (
        not isinstance(previous_objects, list)
        or not isinstance(previous_timers, list)
        or not isinstance(current_objects, list)
        or not isinstance(current_timers, list)
    ):
        return 0
    old_count = max(0, _as_int(current_park.get("45"), 0))
    target_count = min(
        max(0, _as_int(previous_park.get("45"), 0)),
        len(previous_objects),
        len(previous_timers),
    )
    if old_count >= target_count:
        return 0
    current_objects.extend(copy.deepcopy(previous_objects[old_count:target_count]))
    current_timers.extend(copy.deepcopy(previous_timers[old_count:target_count]))
    current_park["45"] = target_count
    log(
        f"[SAVE-GUARD] {label} restored missing park object tail "
        f"objects {old_count}->{target_count}"
    )
    return 1


def _protect_richer_postreplay_park_snapshots(previous, merged, log, label):
    if not isinstance(previous, dict) or not isinstance(merged, dict):
        return 0
    changed = 0
    for park_key in PARK_OFFLINE_TIMER_KEYS:
        previous_record = previous.get(park_key)
        merged_record = merged.get(park_key)
        previous_park = saved_content(previous_record)
        merged_park = saved_content(merged_record)
        if park_record_has_verified_client_dino_removal(previous_record, merged_record):
            log(
                "[SAVE-GUARD] post-replay merge accepted verified client dino removal "
                f"key={park_key!r} "
                f"dinos {_as_int(previous_park.get('57'), 0)}->{_as_int(merged_park.get('57'), 0)} "
                f"objects {_as_int(previous_park.get('45'), 0)}->{_as_int(merged_park.get('45'), 0)}"
            )
            continue
        if park_key == "arpk":
            arctic_layout_reason = arctic_versioned_building_layout_reason(
                previous_record,
                merged_record,
            )
            if arctic_layout_reason:
                log(
                    "[SAVE-GUARD] post-replay merge accepted Arctic versioned "
                    "building layout correction instead of restoring richer snapshot "
                    f"reason={arctic_layout_reason}"
                )
                continue
        if _postreplay_park_object_tail_regressed(previous_park, merged_park):
            if park_record_has_verified_client_object_tail_removal(
                previous_record,
                merged_record,
            ):
                log(
                    "[SAVE-GUARD] post-replay merge accepted verified client "
                    f"object-tail removal key={park_key!r} "
                    f"objects {_as_int(previous_park.get('45'), 0)}->{_as_int(merged_park.get('45'), 0)}"
                )
                continue
            changed += _restore_missing_park_object_tail(
                previous_park,
                merged_park,
                log,
                f"{label} {park_key}",
            )
            continue
        if not _postreplay_park_snapshot_regressed(previous_park, merged_park):
            continue
        merged[park_key] = copy.deepcopy(previous_record)
        changed += 1
        log(
            f"[SAVE-GUARD] {label} kept richer {park_key!r} snapshot "
            f"objects {_as_int(merged_park.get('45'), 0)}->{_as_int(previous_park.get('45'), 0)} "
            f"dinos {_as_int(merged_park.get('57'), 0)}->{_as_int(previous_park.get('57'), 0)} "
            f"buildings {_as_int(merged_park.get('60'), 0)}->{_as_int(previous_park.get('60'), 0)}"
        )
    return changed


def richer_park_snapshot_regression_reason(previous, current, touched_keys):
    touched = {str(key or "") for key in (touched_keys or ())}
    if not isinstance(previous, dict) or not isinstance(current, dict):
        return ""
    for park_key in PARK_OFFLINE_TIMER_KEYS:
        if touched and park_key not in touched:
            continue
        previous_park = saved_content(previous.get(park_key, {}))
        current_park = saved_content(current.get(park_key, {}))
        reason = stale_park_write_reject_reason(
            park_key,
            previous_park,
            current_park,
        )
        if not reason:
            continue
        return (
            f"{reason}; final richer snapshot protection "
            f"objects {_as_int(previous_park.get('45'), 0)}->{_as_int(current_park.get('45'), 0)} "
            f"dinos {_as_int(previous_park.get('57'), 0)}->{_as_int(current_park.get('57'), 0)} "
            f"buildings {_as_int(previous_park.get('60'), 0)}->{_as_int(current_park.get('60'), 0)}"
        )
    return ""


def merge_postreplay_client_progress(
    previous,
    current,
    log,
    allow_client_timer_resets=False,
    allow_card_pack_claim_reset=False,
    allow_building_collects=False,
    allow_dino_collects=False,
    allow_softcash_decrease=False,
    allow_softcash_decrease_reason="",
    allow_resource_decrease_keys=None,
    allow_resource_decrease_reason="",
    server_elapsed_ms=None,
    previous_write_elapsed_ms_by_key=None,
    server_now_seconds=None,
    building_ready_grace_ms=0,
    protect_richer_park_snapshots=False,
    profile_tournament_skip_keys=None,
    profile_tournament_force_preserve_keys=None,
    profile_tournament_force_preserve_reason="",
    served_save_read_keys=None,
):
    """Keep client progress after replay, without letting stale local floors win."""
    merged = merge_server_resource_floor(
        previous,
        current,
        log,
        "post-replay merge",
        allow_softcash_decrease=allow_softcash_decrease,
        allow_softcash_decrease_reason=allow_softcash_decrease_reason,
        allow_resource_decrease_keys=allow_resource_decrease_keys,
        allow_resource_decrease_reason=allow_resource_decrease_reason,
    )
    protected_park_changed = 0
    if protect_richer_park_snapshots:
        protected_park_changed = _protect_richer_postreplay_park_snapshots(
            previous,
            merged,
            log,
            "post-replay merge",
        )
    battle_changed = _preserve_battle_progress(
        previous,
        merged,
        log,
        "post-replay merge",
    )
    battle_changed += remember_battle_context(
        merged,
        _batl_content(merged),
        log,
        "post-replay merge",
    )
    harbor_changed = _preserve_harbor_level_guard(
        previous,
        merged,
        log,
        "post-replay merge",
    )
    profile_changed = _preserve_profile_timer_progress(
        previous,
        merged,
        log,
        "post-replay merge",
        # 143-146 are the card-pack timer family. No proven TNSEASON or generic
        # post-replay transition authorizes a reset of this timer.
        allow_client_timer_resets=False,
        allow_card_pack_claim_reset=allow_card_pack_claim_reset,
        server_now_seconds=server_now_seconds,
    )
    arctic_layout_overrides = {}
    verified_dino_removal_keys = set()
    if isinstance(previous, dict) and isinstance(merged, dict):
        arctic_layout_reason = arctic_versioned_building_layout_reason(
            previous.get("arpk"),
            merged.get("arpk"),
        )
        if arctic_layout_reason:
            arctic_layout_overrides["arpk"] = copy.deepcopy(merged.get("arpk", {}))
            log(
                "[SAVE-GUARD] post-replay merge preserving Arctic versioned "
                "building layout through timer floor "
                f"reason={arctic_layout_reason}"
            )
        for park_key in PARK_OFFLINE_TIMER_KEYS:
            if park_record_has_verified_client_dino_removal(
                previous.get(park_key),
                merged.get(park_key),
            ):
                verified_dino_removal_keys.add(park_key)
                log(
                    "[SAVE-GUARD] post-replay merge preserving verified client "
                    f"dino removal through timer floor key={park_key!r}"
                )
    merged = merge_server_timer_floor(
        previous,
        merged,
        log,
        "post-replay merge",
        allow_client_timer_resets=allow_client_timer_resets,
        allow_building_collects=allow_building_collects,
        allow_dino_collects=allow_dino_collects,
        allow_dino_count_decrease_keys=verified_dino_removal_keys,
        server_elapsed_ms=server_elapsed_ms,
        previous_write_elapsed_ms_by_key=previous_write_elapsed_ms_by_key,
        building_ready_grace_ms=building_ready_grace_ms,
        served_save_read_keys=served_save_read_keys,
    )
    for key, record in arctic_layout_overrides.items():
        merged[key] = record
        log(
            "[SAVE-GUARD] post-replay merge restored Arctic versioned "
            f"building layout after timer floor key={key!r}"
        )
    merged = merge_expedition_timer_floor(previous, merged, log, "post-replay merge")
    gen_changed = 0
    if isinstance(previous, dict) and isinstance(merged, dict):
        if "gen" not in merged and "gen" in previous:
            merged["gen"] = copy.deepcopy(previous.get("gen", {}))
            gen_changed = 1
            log("[GEN] post-replay merge restored missing gen record")
        else:
            gen_changed = merge_gen_catalog_record_floor(
                previous.get("gen", {}),
                merged.get("gen", {}),
                log,
                "post-replay merge",
                preserve_catalog_numeric_progress=False,
            )
    tournament_changed = _preserve_profile_tournament_progress(
        previous,
        merged,
        log,
        "post-replay merge",
        skip_keys=profile_tournament_skip_keys,
        force_preserve_keys=profile_tournament_force_preserve_keys,
        force_preserve_reason=profile_tournament_force_preserve_reason,
    )
    if profile_changed:
        log(f"[TIME] post-replay merge preserved profile timer slots={profile_changed}")
    if tournament_changed:
        log(f"[TOURNAMENT] post-replay merge preserved profile slots={tournament_changed}")
    if harbor_changed:
        log(f"[SAVE] post-replay merge preserved harbor level slots={harbor_changed}")
    if battle_changed:
        log(f"[BATTLE] post-replay merge preserved battle state slots={battle_changed}")
    if gen_changed:
        log(f"[GEN] post-replay merge preserved catalog slots={gen_changed}")
    if protected_park_changed:
        log(f"[SAVE-GUARD] post-replay merge protected park snapshots={protected_park_changed}")
    return merged


def merge_rejected_stale_park_progress(
    saved,
    key,
    incoming_entry,
    log,
    label,
    allow_building_collects=False,
    allow_dino_collects=False,
    previous_write_elapsed_ms=0,
):
    if key not in PARK_OFFLINE_TIMER_KEYS:
        return 0
    if not isinstance(saved, dict) or not isinstance(incoming_entry, dict):
        return 0
    if not (allow_building_collects or allow_dino_collects):
        return 0
    previous_entry = saved.get(key, {})
    previous_content = saved_content(previous_entry)
    incoming_content = saved_content(incoming_entry)
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return 0
    previous_slots = previous_content.get("62")
    incoming_slots = incoming_content.get("62")
    previous_building_count = max(0, _as_int(previous_content.get("60"), 0))
    incoming_building_count = max(0, _as_int(incoming_content.get("60"), 0))
    previous_dino_count = max(0, _as_int(previous_content.get("57"), 0))
    incoming_dino_count = max(0, _as_int(incoming_content.get("57"), 0))
    if (
        (previous_building_count > 0 and incoming_building_count == 0)
        or (previous_dino_count > 0 and incoming_dino_count == 0)
    ):
        log(
            f"[SAVE-GUARD] {label} skipped stale progress merge because "
            f"packet zeroed counted rows dinos {previous_dino_count}->{incoming_dino_count} "
            f"buildings {previous_building_count}->{incoming_building_count}"
        )
        return 0
    if isinstance(previous_slots, list) and isinstance(incoming_slots, list):
        incoming_slot_prefix = incoming_slots[:incoming_building_count]
        previous_slot_prefix = previous_slots[:len(incoming_slot_prefix)]
        if incoming_slot_prefix != previous_slot_prefix:
            log(
                f"[SAVE-GUARD] {label} skipped stale progress merge because "
                f"building slot prefix changed saved={previous_slot_prefix!r} "
                f"incoming={incoming_slot_prefix!r}"
            )
            return 0

    candidate_entry = copy.deepcopy(incoming_entry)
    candidate_content = saved_content(candidate_entry)
    if not isinstance(candidate_content, dict):
        return 0

    layout_changed = 0
    layout_changed += _preserve_counted_array_group(
        previous_content,
        candidate_content,
        "45",
        ("46", "47"),
        log,
        label,
        "park objects",
        append_missing_tail=True,
    )
    layout_changed += _preserve_missing_dino_rows_by_identity(
        previous_content,
        candidate_content,
        log,
        label,
    )
    layout_changed += _preserve_counted_array_group(
        previous_content,
        candidate_content,
        "60",
        ("61", "62"),
        log,
        label,
        "buildings",
        append_missing_tail=True,
    )
    layout_changed += _preserve_building_object_rows(
        previous_content,
        candidate_content,
        log,
        label,
    )

    merged_save = merge_server_timer_floor(
        {key: previous_entry},
        {key: candidate_entry},
        log,
        label,
        allow_building_collects=allow_building_collects,
        allow_dino_collects=allow_dino_collects,
        allow_visual_building_collect_resets=allow_building_collects,
        previous_write_elapsed_ms_by_key={
            key: max(0, _as_int(previous_write_elapsed_ms, 0)),
        },
        synthesize_missing_building_rows=False,
    )
    merged_entry = merged_save.get(key)
    merged_content = saved_content(merged_entry)
    if not isinstance(merged_entry, dict) or not isinstance(merged_content, dict):
        return 0
    if merged_content == previous_content:
        return 0

    saved[key] = merged_entry
    write_wall_ms = timer_wall_ms()
    mark_timer_key_wall(
        saved,
        key,
        log,
        f"{label} stale-progress-merge",
        now_ms=write_wall_ms,
    )
    sync_timer_field_snapshot_for_key(
        saved,
        key,
        merged_content,
        log,
        f"{label} stale-progress-merge",
    )
    log(
        f"[SAVE-GUARD] {label} merged safe progress from rejected stale park write "
        f"layout_restored={layout_changed} "
        f"saved={compact_json(trace_record_summary(key, previous_entry))} "
        f"merged={compact_json(trace_record_summary(key, merged_entry))}"
    )
    return 1


def should_preserve_existing_save(previous, current, threshold_bytes=2048):
    previous_size = save_payload_size(previous)
    current_size = save_payload_size(current)
    if previous_size < 0 or current_size < 0:
        return False, previous_size, current_size
    return previous_size > current_size + threshold_bytes, previous_size, current_size


EXTRA_MEANINGFUL_SAVE_KEYS = {
    "batl", "aqpk", "aqrd", "aqge", "arpk", "arrd", "arge",
}


def _payload_size_or_zero(value):
    try:
        return len(json.dumps(value, ensure_ascii=True, sort_keys=True))
    except Exception:
        return 0


def _pre_read_addon_progress_allowed(key, previous_content, current_content):
    return bool(_pre_read_addon_progress_reason(key, previous_content, current_content))


def _park_write_adds_timer_slots(previous_content, current_content):
    if not isinstance(current_content, dict):
        return False
    if not isinstance(previous_content, dict):
        previous_content = {}
    if not park_content_is_initialized(previous_content) and park_content_is_initialized(current_content):
        return True
    for count_key in ("45", "57", "60"):
        if content_int(current_content, count_key, 0) > content_int(previous_content, count_key, 0):
            return True
    return False


def _park_content_has_active_timers(content):
    if not isinstance(content, dict):
        return False
    object_count = max(0, _as_int(content.get("45"), 0))
    object_timers = content.get("47")
    if isinstance(object_timers, list):
        for value in object_timers[:object_count]:
            try:
                if _high_u32(value) > 0 or _low_u32(value) > 0:
                    return True
            except Exception:
                continue

    dino_count = max(0, _as_int(content.get("57"), 0))
    for key in ("58", "59"):
        values = content.get(key)
        if isinstance(values, list):
            for value in values[:dino_count]:
                try:
                    if _as_int(value, 0) != 0:
                        return True
                except Exception:
                    continue

    building_count = max(0, _as_int(content.get("60"), 0))
    building_timers = content.get("61")
    if isinstance(building_timers, list):
        for value in building_timers[:building_count]:
            try:
                if _as_int(value, 0) != 0:
                    return True
            except Exception:
                continue

    expansion_timers = content.get("50")
    expansion_states = content.get("51")
    if isinstance(expansion_timers, list) and isinstance(expansion_states, list):
        for index in range(min(len(expansion_timers), len(expansion_states))):
            if _as_int(expansion_states[index], 0) != 0:
                return True

    port_timers = content.get("55")
    if isinstance(port_timers, list):
        for value in port_timers[:2]:
            try:
                if _as_int(value, 0) != 0:
                    return True
            except Exception:
                continue
    return False


def _park_write_needs_reconnect_timer_catchup(previous_content, current_content):
    return (
        _park_write_adds_timer_slots(previous_content, current_content)
        or _park_content_has_active_timers(previous_content)
        or _park_content_has_active_timers(current_content)
    )


def offline_reconnect_write_catchup_elapsed_ms(
    key,
    previous_content,
    current_content,
    session_state,
    log,
):
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(session_state, dict):
        return 0
    if session_state.get("server_key_wall_catchup_applied"):
        # The authoritative saved copy was already caught up before this
        # write. Applying the same interval to the incoming client snapshot is
        # a second tick and can finish timers early.
        return 0
    key_elapsed_map = session_state.get("timer_key_elapsed_seconds_by_key", {})
    key_elapsed = (
        _as_int(key_elapsed_map.get(key), None)
        if isinstance(key_elapsed_map, dict)
        else None
    )
    elapsed_seconds = _clamped_timer_elapsed_seconds(
        key_elapsed
        if isinstance(key_elapsed, int)
        else _as_int(session_state.get("server_offline_elapsed_seconds"), 0)
    )
    if elapsed_seconds <= 0:
        return 0
    if session_state.get("timer_replay_source") != "offline-login":
        return 0
    started = session_state.get("offline_reconnect_started_monotonic")
    if isinstance(started, (int, float)):
        age = time.monotonic() - started
        if age > OFFLINE_RECONNECT_WRITE_CATCHUP_SECONDS:
            return 0
    if not _park_write_needs_reconnect_timer_catchup(previous_content, current_content):
        return 0
    applied = session_state.setdefault("offline_write_catchup_applied_keys", set())
    if key in applied:
        return 0
    applied.add(key)
    elapsed_ms = elapsed_seconds * 1000
    log(
        f"[TIME] reconnect write catch-up key={key!r} "
        f"elapsed={elapsed_seconds}s slots previous="
        f"{content_int(previous_content, '45', 0)}/{content_int(previous_content, '60', 0)} "
        f"incoming={content_int(current_content, '45', 0)}/{content_int(current_content, '60', 0)}"
    )
    return elapsed_ms


def _pre_read_addon_progress_reason(key, previous_content, current_content):
    if not isinstance(current_content, dict):
        return ""
    if key in ("aqpk", "arpk"):
        previous_slots = content_int(previous_content, "45", 0)
        current_slots = content_int(current_content, "45", 0)
        if not park_content_is_initialized(previous_content) and park_content_is_initialized(current_content):
            return f"{key} initialized {previous_slots}->{current_slots}"
        if current_slots > previous_slots:
            return f"{key} slot-count increased {previous_slots}->{current_slots}"
        return ""
    if key in ROAD_PROGRESS_KEYS:
        return road_forward_progress_reason(key, previous_content, current_content)
    if key in ("aqrd", "aqge", "arrd", "arge"):
        if not isinstance(previous_content, dict):
            previous_content = {}
        if not previous_content and bool(current_content):
            return f"{key} first non-empty payload"
        previous_size = _payload_size_or_zero(previous_content)
        current_size = _payload_size_or_zero(current_content)
        if current_size > previous_size + 128:
            return f"{key} payload grew {previous_size}->{current_size}"
    return ""


def _pre_read_battle_progress_allowed(key, previous_content, current_content):
    return bool(_pre_read_battle_progress_reason(key, previous_content, current_content))


def _pre_read_battle_progress_reason(key, previous_content, current_content):
    if not isinstance(current_content, dict):
        return ""
    if not isinstance(previous_content, dict):
        previous_content = {}
    if key == "batl":
        previous_score = _battle_progress_score(previous_content)
        current_score = _battle_progress_score(current_content)
        if current_score > previous_score:
            return f"batl score increased {previous_score}->{current_score}"
        previous_cooldowns = len(
            battle_cooldown_remaining_values_all_fields(previous_content)
        )
        current_cooldowns = len(
            battle_cooldown_remaining_values_all_fields(current_content)
        )
        if current_cooldowns > previous_cooldowns:
            return f"batl cooldown count increased {previous_cooldowns}->{current_cooldowns}"
        return ""
    if key == "prof":
        previous_active = _profile_has_active_battle_cooldowns(previous_content)
        current_active = _profile_has_active_battle_cooldowns(current_content)
        if current_active and not previous_active:
            return "prof battle cooldown became active"
        previous_score = _battle_progress_value_score(previous_content.get("111"))
        current_score = _battle_progress_value_score(current_content.get("111"))
        if current_score > previous_score:
            return f"prof.111 score increased {previous_score}->{current_score}"
    return ""


PRE_READ_RESOURCE_PROGRESS_KEYS = ("2", "4", "6", "7")


def _pre_read_resource_progress_reason(key, previous_content, current_content):
    if key != "res" or not isinstance(current_content, dict):
        return ""
    if not isinstance(previous_content, dict):
        previous_content = {}
    for resource_key in PRE_READ_RESOURCE_PROGRESS_KEYS:
        previous_value = content_int(previous_content, resource_key, 0)
        current_value = content_int(current_content, resource_key, previous_value)
        if current_value > previous_value:
            return f"res.{resource_key} increased {previous_value}->{current_value}"
    return ""


def _pre_read_park_progress_reason(key, previous_content, current_content):
    if key not in PARK_OFFLINE_TIMER_KEYS or not isinstance(current_content, dict):
        return ""
    if not isinstance(previous_content, dict):
        previous_content = {}
    if stale_park_write_reject_reason(key, previous_content, current_content):
        return ""
    if park_write_rollback_reason(key, previous_content, current_content):
        return ""
    if (
        park_write_has_verified_client_removed_building_objects(previous_content, current_content)
        or park_write_looks_like_client_removed_building_slots(previous_content, current_content)
    ):
        return (
            f"{key}-verified-client-building-removal "
            f"objects {content_int(previous_content, '45', 0)}->{content_int(current_content, '45', 0)} "
            f"dinos {content_int(previous_content, '57', 0)}->{content_int(current_content, '57', 0)} "
            f"buildings {content_int(previous_content, '60', 0)}->{content_int(current_content, '60', 0)}"
        )
    return ""


def _batl_record_version_progress_reason(previous_record, current_record):
    if not isinstance(previous_record, dict) or not isinstance(current_record, dict):
        return ""
    previous_version = _as_int(previous_record.get("v"), None)
    current_version = _as_int(current_record.get("v"), None)
    if previous_version is None or current_version is None or current_version <= previous_version:
        return ""
    current_content = saved_content(current_record)
    if (
        not isinstance(current_content, dict)
        or (
            _battle_progress_score(current_content) <= 0
            and not battle_cooldown_remaining_values_all_fields(current_content)
        )
    ):
        return ""
    return f"batl version increased {previous_version}->{current_version}"


def _gen_catalog_rows_by_id(content):
    rows = {}
    if not isinstance(content, dict):
        return rows
    catalog = content.get("40")
    if not isinstance(catalog, list):
        return rows
    for index, row in enumerate(catalog):
        if not isinstance(row, dict):
            continue
        row_id = _as_int(row.get("41"), None)
        if row_id is None:
            continue
        rows.setdefault(row_id, (index, row))
    return rows


def _gen_catalog_true_count(row):
    flags = row.get("42") if isinstance(row, dict) else None
    if not isinstance(flags, list):
        return 0
    return sum(1 for value in flags if bool(value))


def _gen_catalog_progress_count(row):
    if not isinstance(row, dict):
        return 0
    total = 0
    for key in ("43", "44"):
        values = row.get(key)
        if isinstance(values, list):
            total += sum(max(0, _as_int(value, 0)) for value in values)
    return total


GEN_CATALOG_MONOTONIC_SCALAR_PROGRESS_KEYS = ("28", "39")
GEN_CATALOG_VOLATILE_SCALAR_PROGRESS_KEYS = ("64", "65", "68", "69")
GEN_CATALOG_SCALAR_PROGRESS_KEYS = (
    GEN_CATALOG_MONOTONIC_SCALAR_PROGRESS_KEYS
    + GEN_CATALOG_VOLATILE_SCALAR_PROGRESS_KEYS
)


def _gen_catalog_progress_reason(previous_content, current_content, include_catalog_numeric_progress=True):
    if not isinstance(current_content, dict):
        return ""
    scalar_keys = (
        GEN_CATALOG_SCALAR_PROGRESS_KEYS
        if include_catalog_numeric_progress
        else GEN_CATALOG_MONOTONIC_SCALAR_PROGRESS_KEYS
    )
    for key in scalar_keys:
        previous_int = _as_int(previous_content.get(key), None) if isinstance(previous_content, dict) else None
        current_int = _as_int(current_content.get(key), None)
        if previous_int is not None and current_int is not None and current_int > previous_int:
            return f"gen.{key} increased {previous_int}->{current_int}"
    previous_rows = _gen_catalog_rows_by_id(previous_content)
    current_rows = _gen_catalog_rows_by_id(current_content)
    for row_id, (_index, current_row) in current_rows.items():
        previous_row = previous_rows.get(row_id, (None, {}))[1]
        previous_true = _gen_catalog_true_count(previous_row)
        current_true = _gen_catalog_true_count(current_row)
        if current_true > previous_true:
            return f"gen.40 unlock flags increased id={row_id} {previous_true}->{current_true}"
        if include_catalog_numeric_progress:
            previous_progress = _gen_catalog_progress_count(previous_row)
            current_progress = _gen_catalog_progress_count(current_row)
            if current_progress > previous_progress:
                return f"gen.40 progress increased id={row_id} {previous_progress}->{current_progress}"
    return ""


def _gen_catalog_has_new_signal_row(previous_content, current_content):
    if not isinstance(previous_content, dict) or not isinstance(current_content, dict):
        return False
    previous_rows = _gen_catalog_rows_by_id(previous_content)
    current_rows = _gen_catalog_rows_by_id(current_content)
    for row_id, (_index, current_row) in current_rows.items():
        if row_id in previous_rows:
            continue
        if _gen_catalog_true_count(current_row) > 0:
            return True
        if _gen_catalog_progress_count(current_row) > 0:
            return True
    return False


def pre_read_gen_catalog_progress_details(previous, current, touched_keys):
    touched = {str(key or "") for key in (touched_keys or ())}
    details = []
    for key in GEN_PROGRESS_KEYS:
        if key not in touched:
            continue
        previous_content = saved_content(previous.get(key, {})) if isinstance(previous, dict) else {}
        current_content = saved_content(current.get(key, {})) if isinstance(current, dict) else {}
        reason = _gen_catalog_progress_reason(
            previous_content,
            current_content,
            include_catalog_numeric_progress=False,
        )
        if reason:
            details.append((key, reason))
    return details


def pre_read_gen_catalog_progress_reason(previous, current, touched_keys):
    details = pre_read_gen_catalog_progress_details(previous, current, touched_keys)
    if len(details) == 1 and details[0][0] == "gen":
        return details[0][1]
    return "; ".join(f"{key}: {reason}" for key, reason in details)


def merge_gen_catalog_progress_into(
    target_content,
    source_content,
    log=None,
    label="gen",
    preserve_catalog_numeric_progress=True,
):
    if not isinstance(target_content, dict) or not isinstance(source_content, dict):
        return 0
    target_catalog = target_content.get("40")
    source_catalog = source_content.get("40")
    if not isinstance(source_catalog, list):
        return 0
    if not isinstance(target_catalog, list):
        target_catalog = []
        target_content["40"] = target_catalog

    changed = 0
    target_rows = _gen_catalog_rows_by_id(target_content)
    for source_index, source_row in enumerate(source_catalog):
        if not isinstance(source_row, dict):
            continue
        row_id = _as_int(source_row.get("41"), None)
        if row_id is None:
            continue
        target_match = target_rows.get(row_id)
        if target_match is None:
            if _gen_catalog_true_count(source_row) <= 0 and _gen_catalog_progress_count(source_row) <= 0:
                continue
            target_catalog.append(copy.deepcopy(source_row))
            target_rows[row_id] = (len(target_catalog) - 1, target_catalog[-1])
            changed += 1
            if log:
                log(
                    f"[GEN] {label} appended catalog row id={row_id} "
                    f"source_index={source_index}"
                )
            continue

        target_index, target_row = target_match
        for key in ("42",):
            source_values = source_row.get(key)
            target_values = target_row.get(key)
            if not isinstance(source_values, list):
                continue
            if not isinstance(target_values, list):
                target_values = []
                target_row[key] = target_values
            while len(target_values) < len(source_values):
                target_values.append(False)
                changed += 1
            for value_index, source_value in enumerate(source_values):
                if bool(source_value) and not bool(target_values[value_index]):
                    target_values[value_index] = True
                    changed += 1
                    if log:
                        log(
                            f"[GEN] {label} preserved unlock flag "
                            f"id={row_id} row={target_index} {key}[{value_index}]=true"
                        )
        if preserve_catalog_numeric_progress:
            for key in ("43", "44"):
                source_values = source_row.get(key)
                target_values = target_row.get(key)
                if not isinstance(source_values, list):
                    continue
                if not isinstance(target_values, list):
                    target_values = []
                    target_row[key] = target_values
                while len(target_values) < len(source_values):
                    target_values.append(0)
                    changed += 1
                for value_index, source_value in enumerate(source_values):
                    source_int = _as_int(source_value, 0)
                    target_int = _as_int(target_values[value_index], 0)
                    if source_int > target_int:
                        target_values[value_index] = source_int
                        changed += 1
                        if log:
                            log(
                                f"[GEN] {label} preserved catalog progress "
                                f"id={row_id} row={target_index} {key}[{value_index}] "
                                f"{target_int}->{source_int}"
                            )

    scalar_keys = (
        GEN_CATALOG_SCALAR_PROGRESS_KEYS
        if preserve_catalog_numeric_progress
        else GEN_CATALOG_MONOTONIC_SCALAR_PROGRESS_KEYS
    )
    for key in scalar_keys:
        source_int = _as_int(source_content.get(key), None)
        target_int = _as_int(target_content.get(key), None)
        if source_int is not None and target_int is not None and source_int > target_int:
            target_content[key] = source_int
            changed += 1
            if log:
                log(f"[GEN] {label} preserved {key} {target_int}->{source_int}")
    return changed


def merge_gen_catalog_record_floor(
    source_record,
    target_record,
    log=None,
    label="gen",
    preserve_catalog_numeric_progress=True,
):
    source_content = saved_content(source_record)
    if not isinstance(source_content, dict):
        return 0
    if not isinstance(target_record, dict):
        return 0
    target_content = saved_content(target_record)
    if not isinstance(target_content, dict):
        target_record["c"] = copy.deepcopy(source_content)
        if log:
            log(f"[GEN] {label} copied missing gen catalog content")
        return 1
    return merge_gen_catalog_progress_into(
        target_content,
        source_content,
        log,
        label,
        preserve_catalog_numeric_progress=preserve_catalog_numeric_progress,
    )


def pre_read_write_progress_reason(previous, current, touched_keys):
    if not isinstance(previous, dict) or not isinstance(current, dict):
        return ""
    for key in touched_keys or ():
        key = str(key or "")
        previous_content = saved_content(previous.get(key, {}))
        current_content = saved_content(current.get(key, {}))
        reason = _pre_read_addon_progress_reason(key, previous_content, current_content)
        if reason:
            return reason
        reason = _pre_read_battle_progress_reason(key, previous_content, current_content)
        if reason:
            return reason
        reason = _pre_read_resource_progress_reason(key, previous_content, current_content)
        if reason:
            return reason
        reason = _pre_read_park_progress_reason(key, previous_content, current_content)
        if reason:
            return reason
    return ""


def pending_repair_forward_progress_reason(
    previous,
    current,
    key,
    touched_keys,
    allow_card_pack_claim_reset=False,
    server_now_seconds=None,
):
    key = str(key or "")
    touched = {str(item or "") for item in (touched_keys or ())}
    previous_record = previous.get(key, {}) if isinstance(previous, dict) else {}
    current_record = current.get(key, {}) if isinstance(current, dict) else {}
    previous_content = saved_content(previous.get(key, {})) if isinstance(previous, dict) else {}
    current_content = saved_content(current.get(key, {})) if isinstance(current, dict) else {}
    if key in ("batl", "prof"):
        if key == "prof" and allow_card_pack_claim_reset:
            card_pack_reason = _profile_card_pack_claim_reset_validation_reason(
                previous_content,
                current_content,
                server_now_seconds=server_now_seconds,
            )
            if not card_pack_reason:
                return "validated COLLCARD card-pack claim reset"
        reason = _pre_read_battle_progress_reason(key, previous_content, current_content)
        if reason:
            return reason
        if key == "batl":
            reason = _batl_record_version_progress_reason(previous_record, current_record)
            if reason:
                return reason
        if key == "prof" and "batl" in touched:
            previous_batl_record = previous.get("batl", {}) if isinstance(previous, dict) else {}
            current_batl_record = current.get("batl", {}) if isinstance(current, dict) else {}
            previous_batl = saved_content(previous_batl_record)
            current_batl = saved_content(current_batl_record)
            batl_reason = _pre_read_battle_progress_reason("batl", previous_batl, current_batl)
            if batl_reason:
                return f"companion prof write with {batl_reason}"
            batl_reason = _batl_record_version_progress_reason(previous_batl_record, current_batl_record)
            if batl_reason:
                return f"companion prof write with {batl_reason}"
        return ""
    if key == "gen":
        return _gen_catalog_progress_reason(
            previous_content,
            current_content,
            include_catalog_numeric_progress=False,
        )
    if key in EXPEDITION_GEN_KEYS:
        reason = expedition_timer_forward_progress_reason(previous_content, current_content)
        if reason:
            return reason
        return _gen_catalog_progress_reason(
            previous_content,
            current_content,
            include_catalog_numeric_progress=False,
        )
    if key in ROAD_PROGRESS_KEYS:
        return road_forward_progress_reason(key, previous_content, current_content)
    if key == "arpk":
        return arctic_versioned_building_layout_reason(previous_record, current_record)
    return ""


def expedition_timer_forward_progress_reason(previous_content, incoming_content):
    if not isinstance(previous_content, dict) or not isinstance(incoming_content, dict):
        return ""
    previous_active = _gen_expedition_active(previous_content)
    incoming_active = _gen_expedition_active(incoming_content)
    if not previous_active or not incoming_active:
        return ""
    previous_elapsed = _as_int(previous_content.get("79"), 0)
    incoming_elapsed = _as_int(incoming_content.get("79"), 0)
    previous_total_ms = _gen_expedition_total_ms(previous_content)
    incoming_total_ms = _gen_expedition_total_ms(incoming_content)
    previous_start = _as_int(previous_content.get("82"), 0)
    incoming_start = _as_int(incoming_content.get("82"), 0)
    if incoming_total_ms > previous_total_ms > 0:
        return (
            "newer active expedition duration "
            f"{previous_total_ms}->{incoming_total_ms}"
        )
    if incoming_start > previous_start >= 0 and incoming_elapsed < previous_elapsed:
        return (
            "newer active expedition start "
            f"{previous_start}->{incoming_start} elapsed {previous_elapsed}->{incoming_elapsed}"
        )
    if (
        incoming_start == previous_start
        and incoming_total_ms == previous_total_ms
        and incoming_elapsed > previous_elapsed
    ):
        return (
            "active expedition elapsed advanced "
            f"{previous_elapsed}->{incoming_elapsed}"
        )
    return ""


def merge_expedition_timer_fields_into(target_content, source_content, log, label):
    if not isinstance(target_content, dict) or not isinstance(source_content, dict):
        return 0
    changed = 0
    for field in ("77", "79", "80", "82"):
        if field not in source_content:
            continue
        source_value = copy.deepcopy(source_content.get(field))
        if target_content.get(field) != source_value:
            target_content[field] = source_value
            changed += 1
            if log:
                log(
                    f"[TIME] {label} preserved protected expedition.{field} "
                    f"from incoming value {source_value!r}"
                )
    return changed


def merge_protected_gen_catalog_write(saved, command, item, key, protected_block_reason, log, label):
    if key not in GEN_PROGRESS_KEYS or not protected_block_reason:
        return 0
    incoming_entry = stored_write_record(command, item)
    existing_record = saved.get(key, {})
    incoming_content = saved_content(incoming_entry)
    existing_content = saved_content(existing_record)
    changed = 0
    reason = _gen_catalog_progress_reason(
        existing_content,
        incoming_content,
        include_catalog_numeric_progress=False,
    )
    if reason:
        changed += merge_gen_catalog_record_floor(
            incoming_entry,
            existing_record,
            log,
            label,
            preserve_catalog_numeric_progress=False,
        )
    timer_reason = (
        expedition_timer_forward_progress_reason(existing_content, incoming_content)
        if key in EXPEDITION_GEN_KEYS
        else ""
    )
    if timer_reason:
        changed += merge_expedition_timer_fields_into(
            existing_content,
            incoming_content,
            log,
            label,
        )
    if changed:
        log(
            "[SAVE-GUARD] merged protected gen catalog progress "
            f"key={key!r} reason={reason or timer_reason!r} "
            f"timer_reason={timer_reason!r} changed={changed}"
        )
    return changed


def merge_protected_road_write(saved, command, item, key, protected_block_reason, log, label):
    if key not in ROAD_PROGRESS_KEYS or not protected_block_reason:
        return 0
    incoming_entry = stored_write_record(command, item)
    incoming_content = saved_content(incoming_entry)
    existing_content = saved_content(saved.get(key, {}))
    reason = road_forward_progress_reason(key, existing_content, incoming_content)
    if not reason:
        return 0
    saved[key] = incoming_entry
    if log:
        log(
            "[SAVE-GUARD] merged protected road progress "
            f"key={key!r} reason={reason!r} "
            f"stored={compact_json(trace_record_summary(key, incoming_entry))}"
        )
    return 1


def pre_read_write_has_persistable_progress(previous, current, touched_keys):
    return bool(pre_read_write_progress_reason(previous, current, touched_keys))


def is_meaningful_save_content(key, content):
    if not isinstance(content, dict):
        return False
    key = str(key or "")
    if key in EXTRA_MEANINGFUL_SAVE_KEYS:
        return bool(content)
    if key == "res":
        return (
            _as_int(content.get("1"), 3) != 3
            or _as_int(content.get("2"), 1000) != 1000
            or _as_int(content.get("4"), 0) != 0
            or _as_int(content.get("6"), 100) != 100
            or _as_int(content.get("7"), 100) != 100
        )
    if key == "gen":
        if _as_int(content.get("28"), 0) != 0:
            return True
        if _as_int(content.get("39"), 0) != 0:
            return True
        if _as_int(content.get("65"), 0) != 0:
            return True
        if isinstance(content.get("29"), list) and content.get("29"):
            return True
        if isinstance(content.get("30"), list) and content.get("30"):
            return True
        return False
    if key == "park":
        return _as_int(content.get("45"), 0) not in (0, 18)
    if key == "road":
        return _as_int(content.get("52"), 0) > 0
    if key == "prof":
        return _as_int(content.get("5"), 0) != 0 or _as_int(content.get("9"), 1) != 1
    return bool(content)

def _as_int(value, default=0):
    try:
        return int(value)
    except Exception:
        return default

def empty_notification_fields():
    return [("ne", e_int(0)), ("e", e_arr([]))]


def make_direct_generic_fields(params):
    payload = params if isinstance(params, dict) else {}
    fields = []
    for key in ("s", "h", "k", "t", "as"):
        if key in payload:
            fields.append((key, e_value(payload[key])))
    fields.extend([
        ("r", e_int(0)),
        ("ok", e_bool(True)),
        ("v", e_int(0)),
        ("c", e_int(0)),
        ("n", e_int(0)),
        ("vs", e_arr([])),
    ])
    fields.extend(empty_notification_fields())
    return fields


def _in_game_bucks_from_res(saved):
    if not isinstance(saved, dict):
        return 0
    res_content = saved.get("res", {}).get("c", {})
    if not isinstance(res_content, dict):
        return 0
    return max(0, _as_int(res_content.get("4"), 0))


def premium_wallet_state(saved):
    if not isinstance(saved, dict):
        return {}
    state = saved.get(WALLET_STATE_KEY)
    if not isinstance(state, dict):
        state = {}
        saved[WALLET_STATE_KEY] = state
    state["balance"] = max(0, _as_int(state.get("balance"), 0))
    seen = state.get("seen_transaction_ids")
    if not isinstance(seen, list):
        state["seen_transaction_ids"] = []
    return state


def set_saved_hardcash_balance(saved, balance, source="", log=None):
    state = premium_wallet_state(saved)
    if not state:
        return 0
    old_balance = max(0, _as_int(state.get("balance"), 0))
    balance = max(0, _as_int(balance, 0))
    state["balance"] = balance
    if balance > 0:
        state["last_positive_bucks"] = balance
    if source:
        state["last_update_source"] = str(source)
    state["updated_at"] = int(time.time())
    if log and old_balance != balance:
        log(f"[WALLET] balance {old_balance} -> {balance} source={source or 'unknown'}")
    return balance


def adjust_saved_hardcash(saved, delta, source="", log=None):
    balance = saved_hardcash_estimate(saved)
    return set_saved_hardcash_balance(saved, balance + _as_int(delta, 0), source, log)


def apply_hardcash_transaction(saved, item, log=None, tournament_cycle_start=None):
    if not isinstance(saved, dict) or not isinstance(item, dict):
        return False
    transaction_type = str(item.get("t", ""))
    if transaction_type == "COLLCARD":
        invalid_reason = collcard_transaction_validation_reason(item)
        if invalid_reason:
            if log:
                log(f"[WALLET] invalid COLLCARD c.rt ignored reason={invalid_reason}")
            return False
    if transaction_type == "TNSEASON":
        invalid_reason = tnseason_transaction_validation_reason(item)
        if invalid_reason:
            if log:
                log(f"[WALLET] invalid TNSEASON c.rt ignored reason={invalid_reason}")
            return False
    if transaction_type == "BRESET":
        invalid_reason = breset_transaction_validation_reason(item)
        if invalid_reason:
            if log:
                log(f"[WALLET] invalid BRESET c.rt ignored reason={invalid_reason}")
            return False
    if transaction_type == "BUILD":
        invalid_reason = build_transaction_validation_reason(item)
        if invalid_reason:
            if log:
                log(f"[WALLET] invalid BUILD c.rt ignored reason={invalid_reason}")
            return False
    item_type = _as_int(item.get("it"), 0) or _as_int(item.get("dt"), 0)
    if item_type != HARDCASH_TRANSACTION_ITEM_TYPE:
        return False

    state = premium_wallet_state(saved)
    transaction_id = str(item.get("o", "")).strip()
    seen = [str(value) for value in state.get("seen_transaction_ids", [])]
    if transaction_id and transaction_id in seen:
        if log:
            log(f"[WALLET] duplicate c.rt ignored id={transaction_id}")
        return False

    if transaction_id:
        seen.append(transaction_id)
        state["seen_transaction_ids"] = seen[-WALLET_SEEN_TRANSACTION_LIMIT:]

    if transaction_type == "TNSEASON":
        now_seconds = int(time.time())
        cycle_start = _as_int(tournament_cycle_start, None)
        if cycle_start is None:
            cycle_start = tournament_season_cycle_start_seconds(now_seconds)
        state["last_tnseason_cycle_start"] = cycle_start
        state["last_tnseason_transaction_id"] = transaction_id
        state["last_tnseason_recorded_at"] = now_seconds
    increase = max(0, _as_int(item.get("ia"), 0))
    decrease = max(0, _as_int(item.get("da"), 0))
    if transaction_type == "MAILGIFT":
        # c.mc persists this reward before the client emits its audit record.
        if log:
            log(
                f"[WALLET] c.rt mail audit recorded id={transaction_id or 'none'} "
                f"amount={increase}"
            )
        return bool(transaction_id)

    delta = increase - decrease
    if delta:
        balance = adjust_saved_hardcash(
            saved,
            delta,
            f"c.rt:{transaction_type or 'unknown'}:{transaction_id or 'none'}",
            log,
        )
        state["last_transaction"] = {
            "id": transaction_id,
            "type": transaction_type,
            "delta": delta,
            "balance": balance,
        }
    elif log:
        log(
            f"[WALLET] zero-delta c.rt recorded id={transaction_id or 'none'} "
            f"type={transaction_type!r}"
        )
    return bool(transaction_id or delta)


def record_ignored_hardcash_transaction(saved, item, reason="", log=None):
    if not isinstance(saved, dict) or not isinstance(item, dict):
        return False
    if not transaction_has_scalar_id(item):
        if log:
            log("[WALLET] ignored blocked c.rt has invalid transaction id shape")
        return False
    transaction_id = str(item.get("o", "")).strip()

    state = premium_wallet_state(saved)
    seen = [str(value) for value in state.get("seen_transaction_ids", [])]
    transaction_type = str(item.get("t", ""))
    if transaction_id in seen:
        if log:
            log(
                f"[WALLET] ignored blocked c.rt duplicate id={transaction_id} "
                f"type={transaction_type!r} reason={reason or 'unknown'}"
            )
        return False

    seen.append(transaction_id)
    state["seen_transaction_ids"] = seen[-WALLET_SEEN_TRANSACTION_LIMIT:]
    state["last_ignored_transaction"] = {
        "id": transaction_id,
        "type": transaction_type,
        "reason": str(reason or ""),
    }
    state["updated_at"] = int(time.time())
    if log:
        log(
            f"[WALLET] ignored blocked c.rt recorded id={transaction_id} "
            f"type={transaction_type!r} reason={reason or 'unknown'}"
        )
    return True


def composite_hardcash_transaction_plan(
    requests,
    saved,
    card_pack_block_reason=None,
    session_state=None,
    now_seconds=None,
    tournament_cycle_start=None,
):
    """Simulate c.rt acceptance in request order without mutating the save.

    Batch-wide state-clear authority must be derived from the same duplicate-id
    and special-transaction decisions that the wallet will later apply.  The
    simulation deliberately calls the production wallet functions on a deep
    copy so their validation and bounded ledger behavior cannot drift apart.
    """
    request_items = list(requests or ())
    simulated = copy.deepcopy(saved) if isinstance(saved, dict) else {}
    if card_pack_block_reason is None:
        card_pack_block_reason = card_pack_claim_transition_block_reason_for_batch(
            request_items,
            simulated,
            now_seconds=now_seconds,
        )

    accepted_indexes = set()
    blocked_reasons = {}
    for index, item in enumerate(request_items):
        if not isinstance(item, dict) or item.get("co") != "c.rt":
            continue
        transaction_type = str(item.get("t", ""))
        if transaction_type == "COLLCARD":
            item_block_reason = (
                collcard_transaction_validation_reason(item)
                or str(card_pack_block_reason or "")
            )
            if item_block_reason:
                blocked_reasons[index] = item_block_reason
                continue
        elif transaction_type == "TNSEASON":
            item_block_reason = tnseason_transaction_reset_block_reason(
                item,
                simulated,
                session_state=session_state,
                now_seconds=now_seconds,
            )
            if item_block_reason:
                record_ignored_hardcash_transaction(
                    simulated,
                    item,
                    item_block_reason,
                )
                blocked_reasons[index] = item_block_reason
                continue

        if apply_hardcash_transaction(
            simulated,
            item,
            tournament_cycle_start=tournament_cycle_start,
        ):
            accepted_indexes.add(index)
        else:
            blocked_reasons[index] = "transaction rejected by wallet validation or ledger"

    return {
        "accepted_indexes": frozenset(accepted_indexes),
        "blocked_reasons": blocked_reasons,
    }


def composite_transaction_plan_accepts_type(plan, requests, transaction_type):
    accepted_indexes = (
        plan.get("accepted_indexes", ()) if isinstance(plan, dict) else ()
    )
    needle = str(transaction_type or "")
    return any(
        isinstance(item, dict)
        and index in accepted_indexes
        and item.get("co") == "c.rt"
        and str(item.get("t", "")) == needle
        for index, item in enumerate(requests or ())
    )


def recompute_hardcash_from_transactions(meta):
    total = _as_int(meta.get("hardcash_baseline"), 3)
    for item in meta.get("reward_transactions", []):
        if not isinstance(item, dict):
            continue
        tx_type = str(item.get("t", ""))
        if tx_type == "MAILGIFT":
            continue
        item_type = _as_int(item.get("it"), 0) or _as_int(item.get("dt"), 0)
        ia = _as_int(item.get("ia"), 0)
        da = _as_int(item.get("da"), 0)
        if item_type == 1:
            if ia:
                total += ia
            elif da:
                total -= da
    return max(0, total)


def repair_inflated_hardcash_meta(saved, log=None):
    """Undo mistaken v98 mapping of res/4 in-game bucks to premium hardcash."""
    if not isinstance(saved, dict):
        return False
    meta = saved.get("__meta", {})
    if not isinstance(meta, dict):
        return False
    res_bucks = _in_game_bucks_from_res(saved)
    estimate = _as_int(meta.get("hardcash_balance_estimate"), 0)
    if res_bucks < 100 or estimate != res_bucks:
        return False
    baseline = _as_int(meta.get("hardcash_baseline"), 3)
    repaired = (
        recompute_hardcash_from_transactions(meta)
        if meta.get("reward_transactions")
        else baseline
    )
    meta["hardcash_balance_estimate"] = repaired
    meta["hardcash_last_good_estimate"] = repaired
    meta["hardcash_delta_total"] = repaired - baseline
    if _as_int(meta.get("hardcash_mail_delivered_balance"), 0) >= res_bucks:
        meta["hardcash_mail_delivered_balance"] = repaired
    delivered_by_device = meta.get("hardcash_mail_last_delivered_by_device")
    if isinstance(delivered_by_device, dict):
        for device_id, value in list(delivered_by_device.items()):
            if _as_int(value, 0) >= res_bucks:
                delivered_by_device[device_id] = repaired
    if log:
        log(
            f"[MAILBOX] repaired inflated hardcash meta "
            f"{estimate} -> {repaired} (res/4 bucks are not premium hardcash)"
        )
    return True


def saved_hardcash_estimate(saved, log=None):
    if not isinstance(saved, dict):
        return 0
    state = premium_wallet_state(saved)
    return max(0, _as_int(state.get("balance"), 0))


def make_account_resources_fields(sequence, saved):
    # AGNetworkResourceManager::onGetAccountResourcesCallback reads `s`,
    # then optional array `r`, with items containing long `t` and long `a`.
    # The native reward dispatcher maps resource type 1 to premium hardcash.
    hardcash = saved_hardcash_estimate(saved)
    pairs = [e_obj([
        ("t", e_long(HARDCASH_RESOURCE_TYPE)),
        ("a", e_long(hardcash)),
    ])]
    return [
        ("s", e_long(sequence)),
        ("r", e_arr(pairs)),
    ]


def make_reward_callback_fields(saved):
    hardcash = saved_hardcash_estimate(saved)
    return [
        ("r", e_arr([e_obj([
            ("t", e_long(HARDCASH_RESOURCE_TYPE)),
            ("a", e_long(hardcash)),
        ])])),
        ("g", e_arr([])),
        ("m", e_obj([])),
        ("f", e_bool(True)),
        ("d", e_str("")),
    ]


def hardcash_mail_claim_state(saved, create=False):
    if not isinstance(saved, dict):
        return {}
    wallet = saved.get(WALLET_STATE_KEY)
    if not isinstance(wallet, dict):
        if not create:
            return {}
        wallet = premium_wallet_state(saved)
    claims = wallet.get(HARDCASH_MAIL_CLAIMS_KEY)
    if not isinstance(claims, dict):
        if not create:
            return {}
        claims = {}
        wallet[HARDCASH_MAIL_CLAIMS_KEY] = claims
    return claims


def configured_hardcash_mail_policy(session_state):
    session_state = session_state if isinstance(session_state, dict) else {}
    policy = str(
        session_state.get("hardcash_mail_policy") or HARDCASH_MAIL_GIFT_POLICY
    ).strip().lower()
    if policy not in HARDCASH_MAIL_GIFT_POLICIES:
        return "per_login"
    return policy


def configured_hardcash_mail_amount(session_state):
    session_state = session_state if isinstance(session_state, dict) else {}
    amount = _as_int(
        session_state.get("hardcash_mail_amount"), HARDCASH_MAIL_GIFT_AMOUNT
    )
    if amount <= 0:
        amount = random.randint(HARDCASH_MAIL_MIN, HARDCASH_MAIL_MAX)
    return min(HARDCASH_MAIL_MAX_AMOUNT, max(0, amount))


def eligible_hardcash_mail_offer(saved, session_state, now_seconds=None):
    """Return the one proven mail offer without changing persistent eligibility."""
    session_state = session_state if isinstance(session_state, dict) else {}
    if session_state.get("hardcash_mail_claimed"):
        return None
    if "hardcash_mail_session_offer" in session_state:
        cached = session_state.get("hardcash_mail_session_offer")
        return cached if isinstance(cached, dict) and cached.get("amount", 0) > 0 else None

    now_seconds = int(time.time()) if now_seconds is None else _as_int(now_seconds, 0)
    now_seconds = max(0, now_seconds)
    policy = configured_hardcash_mail_policy(session_state)
    claims = hardcash_mail_claim_state(saved, create=False)
    amount = 0
    components = []

    if policy == "legit":
        daily_at = max(0, _as_int(claims.get("legit_daily_at"), 0))
        weekly_anchor_at = max(0, _as_int(claims.get("legit_weekly_anchor_at"), 0))
        if daily_at <= 0 or now_seconds - daily_at >= HARDCASH_DAILY_SECONDS:
            amount += HARDCASH_LEGIT_DAILY_AMOUNT
            components.append("legit_daily")
        if (
            weekly_anchor_at > 0
            and now_seconds - weekly_anchor_at >= HARDCASH_WEEKLY_SECONDS
        ):
            amount += HARDCASH_LEGIT_WEEKLY_AMOUNT
            components.append("legit_weekly")
    elif policy == "sandbox_once":
        if max(0, _as_int(claims.get("sandbox_once_at"), 0)) <= 0:
            amount = 99_999_999
            components.append("sandbox_once")
    elif policy == "daily":
        daily_at = max(0, _as_int(claims.get("custom_daily_at"), 0))
        if daily_at <= 0 or now_seconds - daily_at >= HARDCASH_DAILY_SECONDS:
            amount = configured_hardcash_mail_amount(session_state)
            components.append("custom_daily")
    else:
        amount = configured_hardcash_mail_amount(session_state)
        components.append("per_login")

    offer = {
        "amount": min(HARDCASH_MAIL_MAX_AMOUNT, max(0, _as_int(amount, 0))),
        "components": components,
        "offered_at": now_seconds,
        "policy": policy,
    }
    # Cache an ineligible result too.  Eligibility is frozen for this login,
    # matching the only observable boundary the server has for "open game".
    session_state["hardcash_mail_session_offer"] = offer
    return offer if offer["amount"] > 0 else None


def mark_hardcash_mail_offer_claimed(saved, session_state, now_seconds=None):
    session_state = session_state if isinstance(session_state, dict) else {}
    offer = session_state.get("hardcash_mail_session_offer")
    if not isinstance(offer, dict) or session_state.get("hardcash_mail_claimed"):
        return 0
    amount = min(
        HARDCASH_MAIL_MAX_AMOUNT,
        max(0, _as_int(offer.get("amount"), 0)),
    )
    if amount <= 0:
        return 0

    now_seconds = int(time.time()) if now_seconds is None else _as_int(now_seconds, 0)
    claim_time = max(
        0,
        now_seconds,
        _as_int(offer.get("offered_at"), 0),
    )
    policy = str(offer.get("policy") or "per_login")
    components = {str(value) for value in offer.get("components", [])}
    if policy != "per_login":
        claims = hardcash_mail_claim_state(saved, create=True)
        if "legit_daily" in components:
            claims["legit_daily_at"] = claim_time
            if max(0, _as_int(claims.get("legit_weekly_anchor_at"), 0)) <= 0:
                claims["legit_weekly_anchor_at"] = claim_time
        if "legit_weekly" in components:
            claims["legit_weekly_anchor_at"] = claim_time
        if "sandbox_once" in components:
            claims["sandbox_once_at"] = claim_time
        if "custom_daily" in components:
            claims["custom_daily_at"] = claim_time
        claims["last_claimed_at"] = claim_time
        claims["last_claimed_policy"] = policy
        claims["last_claimed_amount"] = amount

    session_state["hardcash_mail_claimed"] = True
    session_state["hardcash_mail_claimed_offer"] = copy.deepcopy(offer)
    return amount


def session_hardcash_mail_amount(saved, session_state, now_seconds=None):
    offer = eligible_hardcash_mail_offer(saved, session_state, now_seconds)
    return max(0, _as_int(offer.get("amount"), 0)) if offer else 0


def hardcash_mail_content_fields(amount):
    amount = max(0, _as_int(amount, 0))
    return [
        ("t", e_long(HARDCASH_MAIL_CONTENT_TYPE)),
        ("a", e_long(HARDCASH_MAIL_ACTION)),
        ("v", e_long(5)),
        ("l", e_bool(False)),
        ("ti", e_str(HARDCASH_MAIL_SENDER_NAME)),
        (
            "te",
            e_str(f"{HARDCASH_MAIL_SENDER_NAME} sent you {amount:,} Bucks!"),
        ),
        ("gt", e_long(2)),
        ("gv", e_long(amount)),
        ("i", e_long(2)),
        ("img", e_str(HARDCASH_MAIL_GIFT_IMAGE)),
    ]


def make_hardcash_mail_gift(saved, session_state=None, now_seconds=None):
    # MailManager::executeMailActionCollectGift reads content fields `gt` and
    # `gv`; gt=2 calls Program::inGameHardCashModify(gv, 0x15, false, true).
    session_state = session_state if isinstance(session_state, dict) else {}
    # Premium hardcash is not stored reliably in park saves. Test sessions send
    # one configured gift amount; c.mc marks it claimed so reopening the mailbox
    # in the same session does not duplicate it.
    pending_hardcash = session_hardcash_mail_amount(saved, session_state, now_seconds)
    if pending_hardcash <= 0:
        return None, 0
    return e_obj([
        ("id", e_long(HARDCASH_MAIL_GIFT_ID)),
        ("st", e_str("n")),
        ("f", e_long(1780276007)),
        ("p", e_long(1)),
        ("dp", e_long(259200)),
        ("de", e_long(259200)),
        ("c", e_obj(hardcash_mail_content_fields(pending_hardcash))),
    ]), pending_hardcash


def make_mailbox_fields(sequence, saved, log, session_state=None, now_seconds=None):
    mail, hardcash = make_hardcash_mail_gift(saved, session_state, now_seconds)
    if mail is None:
        log("[MAILBOX] c.mg callback sent mails=0")
        return [
            ("s", e_long(sequence)),
            ("nm", e_long(0)),
            ("m", e_arr([])),
        ]
    log(
        f"[MAILBOX] c.mg hardcash gift sent "
        f"hardcash={hardcash} mail_id={HARDCASH_MAIL_GIFT_ID} "
        f"policy={configured_hardcash_mail_policy(session_state)} "
        f"content_t={HARDCASH_MAIL_CONTENT_TYPE} action_a={HARDCASH_MAIL_ACTION}"
    )
    log(
        "[MAILBOX-IDENTITY] "
        + compact_json({
            "label": "hardcash-gift-response",
            "request_seq": sequence,
            "response_seq": sequence,
            "mail_id": HARDCASH_MAIL_GIFT_ID,
            "from_field": 1780276007,
            "hardcash": hardcash,
            "top_fields": ["id", "st", "f", "p", "dp", "de", "c"],
            "content_fields": [
                "t", "a", "v", "l", "ti", "te", "gt", "gv", "i", "img",
            ],
            "image": HARDCASH_MAIL_GIFT_IMAGE,
            "name_fields_sent": ["c.ti"],
            "text_fields_sent": ["c.te"],
            "avatar_fields_sent": [],
            "picture_fields_sent": ["c.img"],
        })
    )
    return [
        ("s", e_long(sequence)),
        ("nm", e_long(1)),
        ("m", e_arr([mail])),
    ]


def make_mail_consume_fields(
    sequence, params, saved, log, session_state=None, now_seconds=None
):
    mail_id = _as_int(params.get("id") if isinstance(params, dict) else None, -1)
    meta = saved.setdefault("__meta", {}) if isinstance(saved, dict) else {}
    baseline = _as_int(meta.get("hardcash_baseline"), 3) if isinstance(meta, dict) else 3
    session_state = session_state if isinstance(session_state, dict) else {}
    device_id = normalize_device_id(session_state.get("device_id"))
    offer = session_state.get("hardcash_mail_session_offer")
    pending_hardcash = (
        max(0, _as_int(offer.get("amount"), 0))
        if isinstance(offer, dict)
        else 0
    )
    log(
        f"[MAILBOX] c.mc consume hardcash payload acknowledged "
        f"id={mail_id} hardcash={pending_hardcash} content_t={HARDCASH_MAIL_CONTENT_TYPE} "
        f"action_a={HARDCASH_MAIL_ACTION}"
    )
    if (
        mail_id == HARDCASH_MAIL_GIFT_ID
        and pending_hardcash
        and not session_state.get("hardcash_mail_claimed")
    ):
        pending_hardcash = mark_hardcash_mail_offer_claimed(
            saved, session_state, now_seconds
        )
        hardcash = adjust_saved_hardcash(
            saved, pending_hardcash, f"mail:{mail_id}", log
        )
        if isinstance(meta, dict):
            if device_id:
                delivered_by_device = meta.get("hardcash_mail_last_delivered_by_device")
                if not isinstance(delivered_by_device, dict):
                    delivered_by_device = {}
                delivered_by_device[device_id] = pending_hardcash
                meta["hardcash_mail_last_delivered_by_device"] = delivered_by_device
            # Keep the old diagnostic fields coherent, but the dedicated
            # _server_currency wallet is the only authoritative balance.
            meta["hardcash_balance_estimate"] = hardcash
            meta["hardcash_last_good_estimate"] = hardcash
            meta["hardcash_delta_total"] = hardcash - baseline
        session_state["hardcash_meta_changed"] = True
        log(
            f"[MAILBOX] c.mc marked session-delivered hardcash gift={pending_hardcash} "
            f"device_ref={sensitive_log_token(device_id or 'unknown')!r} "
            f"estimate={hardcash}"
        )
    else:
        if mail_id != HARDCASH_MAIL_GIFT_ID:
            log(
                f"[MAILBOX] c.mc ignored unknown mail id={mail_id}; "
                f"expected={HARDCASH_MAIL_GIFT_ID}"
            )
        pending_hardcash = 0
    gift_content = e_obj(hardcash_mail_content_fields(pending_hardcash))
    return [
        ("s", e_long(sequence)),
        ("ok", e_bool(True)),
        ("id", e_long(mail_id)),
        ("t", e_long(HARDCASH_MAIL_CONTENT_TYPE)),
        ("gt", e_long(2)),
        ("gv", e_long(pending_hardcash)),
        ("c", gift_content),
        ("m", e_obj([
            ("id", e_long(mail_id)),
            ("f", e_long(1780276007)),
            ("c", gift_content),
        ])),
    ]


def mailbox_state(saved):
    state = saved.get("_server_mail")
    if not isinstance(state, dict):
        state = {}
        saved["_server_mail"] = state
    return state


def ensure_adult_coppa_state(saved, log):
    changed = False
    state = saved.get(COPPA_STATE_KEY)
    if not isinstance(state, dict):
        state = {}
        saved[COPPA_STATE_KEY] = state
        changed = True
    expected = {
        "birth_date": SERVER_BIRTH_DATE,
        "status": SERVER_COPPA_STATUS,
        "overage": True,
    }
    for key, value in expected.items():
        if state.get(key) != value:
            state[key] = value
            changed = True

    # The client flips prof/73 from true to false immediately after accepting
    # an adult DOB. Keep that accepted state across login/profile reloads.
    prof_record = saved.get("prof")
    prof_content = saved_content(prof_record)
    if isinstance(prof_content, dict) and prof_content.get("73") is not False:
        prof_content["73"] = False
        if isinstance(prof_record, dict):
            stamp_timer_record_wall(prof_record)
        log("[COPPA] preserved accepted adult profile flag prof/73=false")
        changed = True
    return changed


def normalize_prof_coppa_content(content, log, reason=""):
    if not isinstance(content, dict):
        return content
    if content.get("73") is not False:
        content["73"] = False
        log(f"[COPPA] normalized prof/73 to accepted adult state {reason}".strip())
    return content


def stable_login_identity(saved, fallback_username):
    profile = saved_content(saved.get("prof")) if isinstance(saved, dict) else None
    saved_username = profile.get("10") if isinstance(profile, dict) else None
    if not isinstance(saved_username, str) or not saved_username.strip():
        saved_username = fallback_username or "guest"
    saved_username = saved_username.strip()

    account_id = content_int(profile, "9", 1)
    if account_id <= 0:
        account_id = 1
    return saved_username, account_id


def make_pending_gift(saved, log):
    state = mailbox_state(saved)
    pending = state.get("pending")
    if isinstance(pending, dict):
        log(
            f"[MAILBOX] existing pending player gift id={pending.get('id')} "
            f"sender={pending.get('sender')!r} bucks={pending.get('bucks')}"
        )
        return pending, False
    now = int(time.time())
    if now < content_int(state, "next_gift_at", 0):
        log(
            f"[MAILBOX] player gift cooldown active "
            f"now={now} next_gift_at={content_int(state, 'next_gift_at', 0)}"
        )
        return None, False
    pending = {
        "id": random.randint(1, 0x7fffffff),
        "sender": random.choice(MAIL_SENDERS),
        "bucks": random.randint(MAIL_GIFT_MIN_BUCKS, MAIL_GIFT_MAX_BUCKS),
        "created_at": now,
    }
    state["pending"] = pending
    log(
        f"[MAILBOX] queued player gift id={pending['id']} "
        f"sender={pending['sender']!r} bucks={pending['bucks']}"
    )
    log(
        "[MAILBOX-IDENTITY] "
        + compact_json({
            "label": "queued-player-gift",
            "mail_id": pending["id"],
            "sender": pending["sender"],
            "bucks": pending["bucks"],
            "created_at": pending["created_at"],
            "next_gift_at": state.get("next_gift_at"),
            "known_sender_pool": list(MAIL_SENDERS),
        })
    )
    return pending, True


def encoded_gift_mail(pending):
    sender = str(pending.get("sender", "A park visitor"))
    bucks = max(1, int(pending.get("bucks", 1)))
    return e_obj([
        ("id", e_long(int(pending.get("id", 0)))),
        # Android mail factory: t=0 is the generic mail class; a=5 is Player Gift.
        ("t", e_long(0)),
        ("a", e_long(5)),
        ("v", e_long(5)),
        ("l", e_bool(False)),
        ("ti", e_str(sender)),
        ("te", e_str(f"{sender} sent you {bucks:,} bucks!")),
        # GiftHardcash is the third Gift* enum entry in the Android data table.
        ("gt", e_long(2)),
        ("gv", e_long(bucks)),
    ])


def mailbox_result_fields(sequence, saved, mail_mode, log):
    mail_items = []
    changed = False
    if mail_mode == "gift":
        pending, changed = make_pending_gift(saved, log)
        if pending:
            mail_items.append(encoded_gift_mail(pending))
            log(
                "[MAILBOX-IDENTITY] "
                + compact_json({
                    "label": "player-gift-response",
                    "request_seq": sequence,
                    "response_seq": sequence,
                    "mail_id": pending.get("id"),
                    "sender": pending.get("sender"),
                    "bucks": pending.get("bucks"),
                    "top_fields": ["s", "nm", "m"],
                    "mail_fields": ["id", "t", "a", "v", "l", "ti", "te", "gt", "gv"],
                    "name_fields_sent": ["ti", "te"],
                    "avatar_fields_sent": [],
                    "picture_fields_sent": [],
                    "mail_mode": mail_mode,
                })
            )
    return [
        ("s", e_long(sequence)),
        ("nm", e_long(len(mail_items))),
        ("m", e_arr(mail_items)),
    ], changed


def claim_pending_gift(saved, log):
    state = mailbox_state(saved)
    pending = state.get("pending")
    if not isinstance(pending, dict):
        return False
    amount = max(0, content_int(pending, "bucks", 0))
    res_record = saved.get("res")
    if not isinstance(res_record, dict):
        res_record = {"kind": "c.ow", "k": "res", "v": 0, "c": {}}
        saved["res"] = res_record
    content = res_record.get("c")
    if not isinstance(content, dict):
        content = {}
        res_record["c"] = content
    old_bucks = content_int(content, "4", 0)
    new_bucks = old_bucks + amount
    content["4"] = new_bucks
    stamp_timer_record_wall(res_record)
    state["hardcash_floor"] = new_bucks
    state["pending"] = None
    state["next_gift_at"] = int(time.time()) + random.randint(
        MAIL_GIFT_MIN_COOLDOWN, MAIL_GIFT_MAX_COOLDOWN
    )
    log(
        f"[MAILBOX] claimed player gift id={pending.get('id')} "
        f"bucks {old_bucks} + {amount} -> {new_bucks}"
    )
    log(
        "[MAILBOX-IDENTITY] "
        + compact_json({
            "label": "claimed-player-gift",
            "mail_id": pending.get("id"),
            "sender": pending.get("sender"),
            "bucks": amount,
            "old_bucks": old_bucks,
            "new_bucks": new_bucks,
        })
    )
    return True


def sanitize_persisted_park_content(content, prof_record, log, reason=""):
    if not isinstance(content, dict):
        return content
    prof_content = saved_content(prof_record) or {}
    level = max(1, content_int(prof_content, "5", 1))
    slot_cap = max(1, level)
    grid_len = PARK_GRID_BASE + slot_cap
    changed = False
    if content_int(content, "45", 0) > slot_cap:
        old_p45 = content_int(content, "45", 0)
        content["45"] = slot_cap
        log(f"[BATTLE] park save cap park/45 {old_p45} -> {slot_cap}{reason}")
        changed = True
    for grid_key in ("46", "47"):
        grid = content.get(grid_key)
        if isinstance(grid, list) and len(grid) > grid_len:
            log(
                f"[BATTLE] park save trim park/{grid_key} len {len(grid)} -> "
                f"{grid_len}{reason}"
            )
            content[grid_key] = grid[:grid_len]
            changed = True
    return changed


def sanitize_write_item(
    item,
    saved,
    log,
    allow_building_collects=False,
    allow_dino_collects=False,
    server_elapsed_ms=None,
    building_ready_grace_ms=0,
):
    if not isinstance(item, dict):
        return item
    item = copy.deepcopy(item)
    item = merge_incoming_expedition_write_item(item, saved, log)
    key = str(item.get("k", ""))
    content = item.get("c")
    if key == "prof" and isinstance(content, dict):
        normalize_prof_coppa_content(content, log, "on write")
        clear_profile_tournament_score_timer_pollution(
            content,
            log,
            "profile write",
        )
        return item
    if key in PARK_OFFLINE_TIMER_KEYS and isinstance(content, dict):
        trace_building_slot_removals(
            saved_content(saved.get(key, {})),
            content,
            log,
            f"direct park write key={key!r}",
        )
        # Direct park writes must stay lossless. The older working script did
        # not merge previous park rows into these writes; doing so can resurrect
        # debris or completed construction XP bubbles after the client cleared
        # them. Only active construction rows with server deadline metadata are
        # preserved here, because those are known to be in-flight timers.
        _preserve_active_construction_deadline_rows(
            saved,
            key,
            content,
            log,
            "direct park write",
        )
        _restore_dropped_observed_construction_rows(
            saved_content(saved.get(key, {})),
            content,
            log,
            f"direct park write {key}",
        )
        _sanitize_completed_plain_id_hatch_feed_values(
            content,
            log,
            f"direct park write {key}",
        )
        return item
    if key != "res" or not isinstance(content, dict):
        return item

    existing = saved_content(saved.get("res", {})) or {}
    old_bucks = content_int(existing, "4", 0)
    new_bucks = content_int(content, "4", 0)
    state = saved.get("_server_mail")
    hardcash_floor = content_int(state, "hardcash_floor", 0)
    protected_bucks = max(old_bucks if old_bucks > 0 and new_bucks == 0 else 0, hardcash_floor)
    if new_bucks < protected_bucks:
        content["4"] = protected_bucks
        log(
            f"[SAVE-GUARD] protected res/4 bucks "
            f"incoming={new_bucks} -> {protected_bucks}"
        )
    elif hardcash_floor and new_bucks >= hardcash_floor and isinstance(state, dict):
        state["hardcash_floor"] = 0
        log(f"[MAILBOX] client acknowledged bucks balance={new_bucks}")
    return item


def make_empty_battle_park_shell(level, timestamp=None):
    grid_len = PARK_GRID_BASE + max(1, level)
    ts = timestamp or int(time.time())
    aquatic_base = -3746994889972252672
    return {
        "1": ts,
        "8": 1,
        "13": 0,
        "14": 4037477065937649665,
        "45": max(1, level),
        "46": [0] * grid_len,
        "47": [0] * grid_len,
        "48": 64,
        "49": [aquatic_base + i for i in range(64)],
        "50": [0] * 64,
        "57": BATTLE_ZONE,
        "60": 0,
    }


def park_needs_battle_bootstrap(content, level):
    if not isinstance(content, dict) or not content:
        return True, "missing park content"
    grid_len = PARK_GRID_BASE + max(1, level)
    slot_cap = max(1, level)
    park45 = content_int(content, "45", 0)
    zone = content_int(content, "57", SURFACE_ZONE)
    inflated_grids = any(
        isinstance(content.get(key), list) and len(content[key]) > grid_len
        for key in ("46", "47")
    )
    reasons = []
    if park45 > slot_cap:
        reasons.append(f"inflated park/45 ({park45}>{slot_cap})")
    if zone != BATTLE_ZONE:
        reasons.append(f"zone={zone}")
    if inflated_grids:
        reasons.append("inflated grids")
    if not reasons:
        return False, ""
    return True, ", ".join(reasons)


