FRESH_RELOAD_PROBE_KEYS = (
    "prof", "res", "park", "road", "gen", "batl",
    "aqpk", "aqrd", "aqge", "arpk", "arrd", "arge",
)


def log_fresh_reload_after_save(save_id, path, expected_data, log):
    try:
        with open(path, "r", encoding="utf-8") as handle:
            fresh_data = json.load(handle)
    except Exception as exc:
        log(
            f"[SAVE-VERIFY] fresh-reload failed "
            f"save_ref={sensitive_log_token(save_id)!r} "
            f"path_ref={sensitive_log_token(path)!r} "
            f"error={compact_json(diagnostic_exception_summary(exc))}"
        )
        return
    expected_fp, expected_bytes = trace_payload_fingerprint(expected_data)
    fresh_fp, fresh_bytes = trace_payload_fingerprint(fresh_data)
    log(
        f"[SAVE-VERIFY] fresh-reload save_ref={sensitive_log_token(save_id)!r} "
        f"path_ref={sensitive_log_token(path)!r} "
        f"match={expected_fp == fresh_fp} "
        f"expected_fp={expected_fp} expected_bytes={expected_bytes} "
        f"fresh_fp={fresh_fp} fresh_bytes={fresh_bytes}"
    )
    log_save_probe(
        log,
        f"fresh-reload-after-write save_ref={sensitive_log_token(save_id)!r}",
        fresh_data,
        FRESH_RELOAD_PROBE_KEYS,
    )


def save_guest_data(save_id, data, log, limited_purchase_evidence=None):
    with SAVE_FILE_LOCK:
        os.makedirs(SAVE_DIR, exist_ok=True)
        path = guest_save_path(save_id)
        backup_path = f"{path}.bak"
        temp_path = f"{path}.tmp"
        now_ms = int(time.time() * 1000)
        existing_present = os.path.isfile(path)
        existing_valid_save = False
        existing_on_disk = {}
        if existing_present:
            try:
                with open(path, "r", encoding="utf-8") as handle:
                    loaded = json.load(handle)
                if isinstance(loaded, dict):
                    existing_on_disk = loaded
                    existing_valid_save = True
            except Exception as exc:
                log(
                    "[CREATURE-OWNERSHIP] could not read current disk ledger "
                    f"path_ref={sensitive_log_token(path)!r} "
                    f"error={compact_json(diagnostic_exception_summary(exc))}"
                )
        sync_creature_rotation_ownership(
            existing_on_disk,
            data,
            limited_purchase_evidence=limited_purchase_evidence,
            now_ms=now_ms,
            existing_present=existing_present,
            log=log,
        )
        repair_completed_dna_rescue_state(
            data,
            now_ms=now_ms,
            log=log,
            label="persist",
        )
        repair_active_expansion_ready_margins(data, log, "persist")
        repair_saved_dino_object_timers(data, log, "persist")
        sync_expedition_wall_timers(data, log, "persist")
        ensure_timer_key_walls(data, log, label="persist", now_ms=now_ms)
        scrub_server_metadata(data, log, "persist", now_ms=now_ms, persist=True)
        meta = data.setdefault("__meta", {})
        if isinstance(meta, dict):
            meta["last_server_save_time"] = now_ms // 1000
            meta["last_server_save_time_ms"] = now_ms
        if existing_valid_save:
            shutil.copy2(path, backup_path)
        elif existing_present:
            # Never rotate unreadable primary bytes over a known-good backup.
            # Recovery versus refusal remains a separate policy decision; this
            # branch only preserves the existing backup before atomic replace.
            log(
                "[SAVE] skipped backup rotation for unreadable primary "
                f"path_ref={sensitive_log_token(path)!r}"
            )
        try:
            with open(temp_path, "w", encoding="utf-8") as handle:
                json.dump(data, handle, ensure_ascii=True, indent=2, sort_keys=True)
                handle.flush()
                os.fsync(handle.fileno())
            os.replace(temp_path, path)
        finally:
            if os.path.exists(temp_path):
                os.remove(temp_path)
        log(
            f"[SAVE] wrote path_ref={sensitive_log_token(path)!r} "
            f"keys={sorted(data.keys())!r}"
        )
        log_fresh_reload_after_save(save_id, path, data, log)


def saved_content(record):
    if not record:
        return None
    if isinstance(record, dict) and "c" in record:
        return record.get("c")
    return record


def trace_payload_fingerprint(value):
    try:
        payload = json.dumps(value, ensure_ascii=True, sort_keys=True, separators=(",", ":"))
    except Exception:
        payload = repr(value)
    digest = hashlib.sha1(payload.encode("utf-8", "replace")).hexdigest()[:12]
    return digest, len(payload)


