def _identity_command_reason(command):
    lower = str(command or "").lower()
    reasons = []
    if lower in IDENTITY_FOLLOWUP_DIRECT_COMMANDS:
        reasons.append("direct-command")
    for hint in IDENTITY_FOLLOWUP_COMMAND_HINTS:
        if hint in lower:
            reasons.append(f"command-hint:{hint}")
    return reasons


def log_identity_command_trace(log, label, command, params, session_state=None, **context):
    if not callable(log):
        return
    try:
        request_seq = None
        if isinstance(params, dict):
            request_seq = params.get("s")
        since_cgrs = None
        last_cgrs = None
        if isinstance(session_state, dict):
            last_cgrs = session_state.get("last_cgrs_monotonic")
            if isinstance(last_cgrs, (int, float)):
                since_cgrs = round(time.monotonic() - last_cgrs, 3)
        entry = {
            "label": str(label),
            "command": str(command or ""),
            "request_seq": request_seq,
            "since_last_cgrs_seconds": since_cgrs,
            "reasons": _identity_command_reason(command),
            "params": trace_request_summary(params),
            "context": {
                str(key): _trace_json_safe(value, key) for key, value in context.items()
            },
        }
        if isinstance(session_state, dict):
            entry["last_cgrs"] = session_state.get("last_cgrs_summary", {})
        log(f"[IDENTITY-CMD-TRACE] {compact_json(entry)}")
    except Exception as exc:
        log(f"[IDENTITY-CMD-TRACE] logging failed: {type(exc).__name__}: {exc}")


def log_identity_followup_if_relevant(log, command, params, session_state):
    if not isinstance(session_state, dict):
        return
    lower = str(command or "").lower()
    last_cgrs = session_state.get("last_cgrs_monotonic")
    if not isinstance(last_cgrs, (int, float)):
        return
    elapsed = time.monotonic() - last_cgrs
    if elapsed < 0 or elapsed > 120:
        return
    reasons = _identity_command_reason(lower)
    if not reasons:
        return
    log_identity_command_trace(
        log,
        "post-cgrs-followup",
        command,
        params,
        session_state,
        elapsed_seconds=round(elapsed, 3),
    )


def remember_cgrs_identity_probe(log, command, params, sequence, session_state, path, response_fields):
    payload = params.get("p") if isinstance(params, dict) else None
    if not isinstance(payload, dict):
        payload = params if isinstance(params, dict) else {}
    bot_ids = battle_random_bot_ids(payload.get("n"))
    bot_tokens = battle_random_bot_account_tokens(bot_ids)
    summary = {
        "path": str(path or ""),
        "command": str(command or ""),
        "request_seq": sequence,
        "requested_count": payload.get("n"),
        "bot_ids": bot_ids,
        "bot_account_token_refs": [
            sensitive_log_token(item) for item in bot_tokens
        ],
        "response_fields": list(response_fields or ()),
    }
    if isinstance(session_state, dict):
        session_state["last_cgrs_monotonic"] = time.monotonic()
        session_state["last_cgrs_summary"] = summary
    log_identity_command_trace(
        log,
        "cgrs-response",
        command,
        params,
        session_state,
        cgrs_summary=summary,
    )


