def trace_save_probe_summary(saved, keys=None):
    if not isinstance(saved, dict):
        return {"type": type(saved).__name__}
    if keys is None:
        keys = (
            "prof", "res", "park", "aqpk", "aqrd", "aqge",
            "arpk", "arrd", "arge", "batl", "gen",
        )
    selected_keys = []
    for key in keys:
        key = str(key)
        if key not in selected_keys:
            selected_keys.append(key)
    digest, payload_size = trace_payload_fingerprint(saved)
    summary = {
        "fp": digest,
        "bytes": payload_size,
        "keys": sorted(str(key) for key in saved.keys() if not str(key).startswith("__")),
        "records": {},
    }
    for key in selected_keys:
        if key not in saved:
            summary["records"][key] = {"missing": True}
            continue
        record_summary = trace_record_summary(key, saved.get(key))
        content = saved_content(saved.get(key, {}))
        if key in PARK_OFFLINE_TIMER_KEYS and isinstance(content, dict):
            building_slots = _building_slot_indexes(content)
            building_count = max(0, _as_int(content.get("60"), 0))
            object_count = max(0, _as_int(content.get("45"), 0))
            dino_count = max(0, _as_int(content.get("57"), 0))
            record_summary["probe"] = {
                "object_count": object_count,
                "dino_count": dino_count,
                "building_count": building_count,
                "building_slots_all": sorted(building_slots.keys()),
                "building_slot_rows": {
                    str(slot): index
                    for slot, index in sorted(building_slots.items())
                },
                "park62_counted": (
                    content.get("62")[:building_count]
                    if isinstance(content.get("62"), list)
                    else None
                ),
                "park46_counted_fp": trace_payload_fingerprint(
                    content.get("46")[:object_count]
                    if isinstance(content.get("46"), list)
                    else None
                )[0],
                "park47_counted_fp": trace_payload_fingerprint(
                    content.get("47")[:object_count]
                    if isinstance(content.get("47"), list)
                    else None
                )[0],
                "park61_counted_fp": trace_payload_fingerprint(
                    content.get("61")[:building_count]
                    if isinstance(content.get("61"), list)
                    else None
                )[0],
                "dino58_counted": (
                    content.get("58")[:dino_count]
                    if isinstance(content.get("58"), list)
                    else None
                ),
                "dino59_counted": (
                    content.get("59")[:dino_count]
                    if isinstance(content.get("59"), list)
                    else None
                ),
            }
        summary["records"][key] = record_summary
    return summary


